class RomajiIMETextInput(TextInput):
    """TextInput with simple romaji→kana IME.

    When ime_enabled is True:
    - Characters are inserted via Kivy’s normal pipeline, then trailing
      ASCII romaji is greedily converted to hiragana in a post-processing step.
    - Before punctuation/space, trailing romaji is force-flushed (n→ん).
    - ASCII punctuation is auto-mapped to Japanese equivalents.
    - get_submit_text() converts any remaining trailing romaji before returning.
    """
    ime_enabled = BooleanProperty(False)

    _PUNCT_MAP = {',': '\u3001', '.': '\u3002', '?': '\uff1f', '!': '\uff01',
                  ':': '\uff1a', ';': '\uff1b', '(': '\uff08', ')': '\uff09'}

    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self._ime_updating = False

    def set_ime_enabled(self, enabled: bool):
        self.ime_enabled = enabled

    def insert_text(self, substring, from_undo=False):
        if not self.ime_enabled or not substring:
            return super().insert_text(substring, from_undo=from_undo)
        # Non-ASCII: pass through directly
        if not all(ord(c) < 128 for c in substring):
            return super().insert_text(substring, from_undo=from_undo)
        # Non-alpha (punct, space, digits): flush trailing romaji first, then insert mapped char
        if not substring.isalpha():
            self._flush_trailing_romaji()
            mapped = ''.join(self._PUNCT_MAP.get(ch, ch) for ch in substring)
            return super().insert_text(mapped, from_undo=from_undo)
        # Alpha: insert normally, then try greedy conversion
        super().insert_text(substring, from_undo=from_undo)
        self._try_convert_trailing_romaji()

    def _flush_trailing_romaji(self):
        """Force-convert trailing romaji before punctuation (e.g. n→ん)."""
        import re
        text = self.text or ''
        m = re.search(r'[a-zA-Z]+$', text)
        if not m:
            return
        romaji = m.group()
        from dictionary.learning import convert_greedy_romaji, romaji_to_hiragana
        conv, rem = convert_greedy_romaji(romaji)
        if rem:
            maybe = romaji_to_hiragana(rem)
            if maybe:
                conv += maybe
                rem = ''
            elif rem.lower() == 'n':
                # romaji_to_hiragana('n') returns None (trailing-n special case)
                conv += 'ん'
                rem = ''
        if conv and conv + rem != romaji:
            prefix = text[:m.start()]
            new_text = prefix + conv + rem
            self._ime_updating = True
            self.text = new_text
            self.cursor = self.get_cursor_from_index(len(new_text))
            self._ime_updating = False

    def _try_convert_trailing_romaji(self):
        if self._ime_updating:
            return
        import re
        text = self.text or ''
        m = re.search(r'[a-zA-Z]+$', text)
        if not m:
            return
        romaji = m.group()
        from dictionary.learning import convert_greedy_romaji
        conv, rem = convert_greedy_romaji(romaji)
        if not conv:
            return
        prefix = text[:m.start()]
        new_text = prefix + conv + rem
        if new_text != text:
            self._ime_updating = True
            self.text = new_text
            self.cursor = self.get_cursor_from_index(len(new_text))
            self._ime_updating = False

    def get_submit_text(self) -> str:
        """Return text with any trailing romaji finalized to kana."""
        if not self.ime_enabled:
            return (self.text or '').strip()
        import re
        text = (self.text or '').strip()
        m = re.search(r'[a-zA-Z]+$', text)
        if not m:
            return text
        prefix = text[:m.start()]
        romaji = m.group()
        from dictionary.learning import convert_greedy_romaji, romaji_to_hiragana
        conv, rem = convert_greedy_romaji(romaji)
        total = prefix + conv
        if rem:
            maybe = romaji_to_hiragana(rem)
            if maybe:
                total += maybe
            elif rem.lower() == 'n':
                total += 'ん'
            else:
                total += rem
        return total

