# Small helper classes to safely handle missing UI ids when Study screen has been stripped
class _NullWidget:
    """A no-op widget that safely swallows attribute access and method calls."""
    def __init__(self):
        self.text = ''
        self.disabled = True
        self.opacity = 0
        self.height = 0
        self.size = (0, 0)
        self.pos = (0, 0)
    def __getattr__(self, name):
        # return a callable no-op for methods, or self for attribute reads
        def _noop(*args, **kwargs):
            return None
        return _noop
    def __call__(self, *args, **kwargs):
        return None

class SafeIds(dict):
    """Dict-like wrapper that returns _NullWidget for missing ids and supports attribute access."""
    def __getattr__(self, name):
        try:
            return self[name]
        except Exception:
            return _NullWidget()
    def get(self, name, default=None):
        return dict.get(self, name, _NullWidget())

