class SakuboLessonRow(RecycleDataViewBehavior, BoxLayout):
    """RecycleView viewclass for a Sakubo lesson row with progress bar."""
    lesson_title = StringProperty('')
    lesson_path = StringProperty('')
    is_queued = BooleanProperty(False)
    known_pct = NumericProperty(0)
    in_srs_pct = NumericProperty(0)
    unknown_pct = NumericProperty(0)
    has_progress = BooleanProperty(False)
    index = NumericProperty(0)
    is_reading = BooleanProperty(False)
    reading_filepath = StringProperty('')

    def refresh_view_attrs(self, rv, index, data):
        self.index = index
        # Reset reading-specific properties to defaults before applying data
        # (prevents stale values when RecycleView recycles a reading row for a lesson)
        self.is_reading = data.get('is_reading', False)
        self.reading_filepath = data.get('reading_filepath', '')
        return super().refresh_view_attrs(rv, index, data)

    def on_lesson_press(self):
        app = App.get_running_app()
        if self.is_reading and self.reading_filepath:
            app.root.ids.lessons_screen.open_graded_reading(self.reading_filepath)
        else:
            app._show_lesson_page(self.lesson_path)

    def on_queue_press(self):
        app = App.get_running_app()
        if self.is_reading and self.reading_filepath:
            # Toggle graded reading queue using graded: prefix key
            q_key = f'graded:{self.reading_filepath}'
            queue = getattr(app, '_lesson_queue', [])
            if q_key in queue:
                queue.remove(q_key)
                app._save_lesson_queue()
                is_now_queued = False
                app._lessons_needs_reload = True
                self.is_queued = is_now_queued
                try:
                    rv = self.parent.parent
                    if hasattr(rv, 'data') and self.index is not None and self.index < len(rv.data):
                        rv.data[self.index]['is_queued'] = is_now_queued
                except Exception:
                    pass
            else:
                row = self
                def _do_reading_enqueue(position):
                    if position == 'front':
                        queue.insert(0, q_key)
                    else:
                        queue.append(q_key)
                    app._save_lesson_queue()
                    app._lessons_needs_reload = True
                    row.is_queued = True
                    try:
                        rv = row.parent.parent
                        if hasattr(rv, 'data') and row.index is not None and row.index < len(rv.data):
                            rv.data[row.index]['is_queued'] = True
                    except Exception:
                        pass
                app._show_queue_position_popup(_do_reading_enqueue)
            return
        else:
            app.toggle_lesson_queue(self.lesson_path)
            is_now_queued = str(self.lesson_path) in getattr(app, '_lesson_queue', [])
        app._lessons_needs_reload = True
        self.is_queued = is_now_queued
        # Persist change in RV data so it survives scroll recycling
        try:
            rv = self.parent.parent
            if hasattr(rv, 'data') and self.index is not None and self.index < len(rv.data):
                rv.data[self.index]['is_queued'] = is_now_queued
        except Exception:
            pass

# ── End SakuboLessonRow ──────────────────────────────────────────────


class LessonsScreen(BoxLayout):
    def on_kv_post(self, *args):
        # Keep a reference to the lessons container. Do NOT clear it here,
        # since the initial menu is defined in KV.
        try:
            self._quick_area = self.ids.get('lessons_quick')
        except Exception:
            self._quick_area = None
        # bind search input for lessons (global top bar input)
        try:
            app = App.get_running_app()
            self.lessons_search_input = (app.root.ids.get('lessons_search_input') if getattr(app, 'root', None) else None)
            if self.lessons_search_input is not None:
                # bind into the same method used for local scheduling
                self.lessons_search_input.bind(text=lambda *_: self.schedule_lessons_search())
        except Exception:
            self.lessons_search_input = None
        # current view tracking for search (spoonfed/custom)
        self._current_lessons_view = 'main'
        self._last_lessons_query = ''

        # internal navigation stack for Lessons (subpages inside the Lessons tab)
        self._nav_stack = []
        self._view_payload = {}
        self._queue_filter = 'all'

    def _get_lessons_rv(self):
        """Find the RecycleView in the lessons quick_area, if any."""
        try:
            from kivy.uix.recycleview import RecycleView
            qa = self._get_quick_area()
            if qa is None:
                return None
            for w in qa.walk(restrict=True):
                if isinstance(w, RecycleView):
                    return w
        except Exception:
            pass
        return None

    def _schedule_scroll_restore(self, scroll_y):
        """Schedule restoring scroll_y on the lessons RV after async rebuild."""
        if scroll_y is None:
            return
        self._pending_scroll_y = scroll_y
        def _try_restore(dt, attempts=[0]):
            pending = getattr(self, '_pending_scroll_y', None)
            if pending is None:
                return
            rv = self._get_lessons_rv()
            if rv is not None and rv.data:
                rv.scroll_y = pending
                self._pending_scroll_y = None
            elif attempts[0] < 30:
                attempts[0] += 1
                Clock.schedule_once(_try_restore, 0.15)
            else:
                self._pending_scroll_y = None
        Clock.schedule_once(_try_restore, 0.2)

    def _capture_view_state(self):
        try:
            view = getattr(self, '_current_lessons_view', 'main') or 'main'
            payload = getattr(self, '_view_payload', None)
            if not isinstance(payload, dict):
                payload = {}
            payload = dict(payload)
            if view == 'queue':
                payload.setdefault('filter', getattr(self, '_queue_filter', 'all') or 'all')
            # Save scroll position so we can restore it on back
            rv = self._get_lessons_rv()
            if rv is not None:
                payload['_scroll_y'] = rv.scroll_y
            return (view, payload)
        except Exception:
            return ('main', {})

    def _push_view_state(self):
        try:
            st = self._capture_view_state()
            stack = getattr(self, '_nav_stack', None)
            if not isinstance(stack, list):
                stack = []
                self._nav_stack = stack
            # Don't push duplicate states
            if stack and stack[-1] == st:
                return
            stack.append(st)
            if len(stack) > 50:
                self._nav_stack = stack[-50:]
        except Exception:
            pass

    def _restore_view_state(self, st):
        try:
            view, payload = st if isinstance(st, (tuple, list)) and len(st) == 2 else ('main', {})
            if not isinstance(payload, dict):
                payload = {}
            if view == 'main':
                self.show_main_menu(record_nav=False)
                return
            if view == 'lessons_submenu':
                self.show_lessons_submenu(record_nav=False)
                return
            if view == 'reading_submenu':
                self.show_reading_submenu(record_nav=False)
                return
            if view == 'custom_reading':
                self.show_custom_reading(record_nav=False)
                return
            if view == 'sakubo_reading':
                self.show_sakubo_reading(record_nav=False)
                return
            if view == 'sakubo_reading_level':
                lv = payload.get('level', 'n5')
                self.show_sakubo_reading_level(lv, record_nav=False)
                self._schedule_scroll_restore(payload.get('_scroll_y'))
                return
            if view == 'graded_reading_view':
                fp = payload.get('filepath')
                if fp:
                    self.open_graded_reading(fp, record_nav=False)
                else:
                    lv = payload.get('level', 'n5')
                    self.show_sakubo_reading_level(lv, record_nav=False)
                return
            if view == 'reading_view':
                material_id = payload.get('material_id')
                if material_id:
                    self.open_reading_material(material_id)
                else:
                    self.show_custom_reading(record_nav=False)
                return
            if view == 'spoonfed':
                self.show_spoonfed_menu(query=None, record_nav=False)
                return
            if view == 'custom':
                self.show_custom_lessons(query=None, record_nav=False)
                return
            if view == 'queue':
                app = App.get_running_app()
                if app and hasattr(app, 'show_my_queue'):
                    app.show_my_queue(active_filter=payload.get('filter') or 'all', record_nav=False)
                else:
                    self.show_main_menu(record_nav=False)
                return
            if view == 'kana_lessons':
                self.show_kana_lessons(query=payload.get('query'), record_nav=False)
                self._schedule_scroll_restore(payload.get('_scroll_y'))
                return
            if view == 'n5_vocab_lessons':
                self.show_n5_vocab_lessons(query=payload.get('query'), record_nav=False)
                self._schedule_scroll_restore(payload.get('_scroll_y'))
                return
            if view == 'n4_vocab_lessons':
                self.show_n4_vocab_lessons(query=payload.get('query'), record_nav=False)
                self._schedule_scroll_restore(payload.get('_scroll_y'))
                return
            if view == 'n3_vocab_lessons':
                self.show_n3_vocab_lessons(query=payload.get('query'), record_nav=False)
                self._schedule_scroll_restore(payload.get('_scroll_y'))
                return
            if view == 'n2_vocab_lessons':
                self.show_n2_vocab_lessons(query=payload.get('query'), record_nav=False)
                self._schedule_scroll_restore(payload.get('_scroll_y'))
                return
            if view == 'n1_vocab_lessons':
                self.show_n1_vocab_lessons(query=payload.get('query'), record_nav=False)
                self._schedule_scroll_restore(payload.get('_scroll_y'))
                return
            self.show_main_menu(record_nav=False)
        except Exception:
            try:
                self.show_main_menu(record_nav=False)
            except Exception:
                pass

    def nav_back(self) -> bool:
        """Pop Lessons internal subpage history.

        Returns True if handled; False means Lessons is already at its root.
        """
        try:
            view = getattr(self, '_current_lessons_view', 'main') or 'main'
            if view == 'main':
                return False
            # Stop reading timer when leaving the reading view
            if view == 'reading_view':
                self._stop_reading_timer()
            stack = getattr(self, '_nav_stack', None)
            if isinstance(stack, list) and stack:
                prev = stack.pop()
                self._restore_view_state(prev)
            else:
                self.show_main_menu(record_nav=False)
            return True
        except Exception:
            return False

    def schedule_lessons_search(self, *args):
        try:
            if getattr(self, '_lessons_search_ev', None):
                try:
                    self._lessons_search_ev.cancel()
                except Exception:
                    pass
            # capture latest query from global input if set
            try:
                app = App.get_running_app()
                if getattr(app, 'root', None):
                    gi = app.root.ids.get('lessons_search_input')
                    if gi is not None:
                        self._last_lessons_query = (gi.text or '').strip()
            except Exception:
                pass
            self._lessons_search_ev = Clock.schedule_once(self._do_scheduled_lessons_search, 0.15)
        except Exception:
            pass

    def schedule_dict_search(self, *args):
        """Schedule a dictionary search using the top-bar dictionary input."""
        try:
            if getattr(self, '_dict_search_ev', None):
                try:
                    self._dict_search_ev.cancel()
                except Exception:
                    pass
            
            # Check if we're on add_items_to_lesson screen
            try:
                sm = self._get_screen_manager()
                if sm and sm.current == 'add_items_to_lesson':
                    # Trigger add_items search instead
                    self._dict_search_ev = Clock.schedule_once(lambda dt: self.on_add_items_search(), 0.15)
                    return
            except Exception:
                pass
            
            # delegate to DictionaryScreen's schedule_search
            try:
                ds = self.root.ids.get('dict_screen') if getattr(self, 'root', None) else None
                if ds and hasattr(ds, 'schedule_search'):
                    # schedule an immediate delegate (DictionaryScreen already debounces)
                    ds.schedule_search()
                else:
                    # fallback: call directly later
                    self._dict_search_ev = Clock.schedule_once(lambda dt: ds.schedule_search() if ds and hasattr(ds, 'schedule_search') else None, 0.15)
            except Exception:
                pass
        except Exception:
            pass

    def trigger_dict_search(self):
        """Immediate trigger for dictionary search button."""
        try:
            # Check if we're on add_items_to_lesson screen
            sm = self._get_screen_manager()
            if sm and sm.current == 'add_items_to_lesson':
                # Trigger add_items search immediately
                self.on_add_items_search()
                return
            
            ds = self.root.ids.get('dict_screen') if getattr(self, 'root', None) else None
            if ds and hasattr(ds, 'on_search'):
                try:
                    ds.on_search()
                except Exception:
                    pass
        except Exception:
            pass



    def _do_scheduled_lessons_search(self, dt):
        # prefer global input first
        q = ''
        try:
            app = App.get_running_app()
            if getattr(app, 'root', None):
                gi = app.root.ids.get('lessons_search_input')
                if gi is not None:
                    q = (gi.text or '').strip()
        except Exception:
            pass
        # fallback to last captured query
        if not q:
            q = (getattr(self, '_last_lessons_query', '') or '').strip()
        self._last_lessons_query = q
        try:
            view = self._current_lessons_view
            if view == 'spoonfed':
                self.show_spoonfed_menu(query=q, record_nav=False)
            elif view == 'custom':
                self.show_custom_lessons(query=q, record_nav=False)
            elif view == 'queue':
                app = App.get_running_app()
                if app:
                    filt = getattr(app, '_queue_active_filter', 'all')
                    app.show_my_queue(active_filter=filt, record_nav=False, query=q)
            elif view == 'kana_lessons':
                self.show_kana_lessons(query=q, record_nav=False)
            elif view == 'n5_vocab_lessons':
                self.show_n5_vocab_lessons(query=q, record_nav=False)
            elif view == 'n4_vocab_lessons':
                self.show_n4_vocab_lessons(query=q, record_nav=False)
            elif view == 'n3_vocab_lessons':
                self.show_n3_vocab_lessons(query=q, record_nav=False)
            elif view == 'n2_vocab_lessons':
                self.show_n2_vocab_lessons(query=q, record_nav=False)
            elif view == 'n1_vocab_lessons':
                self.show_n1_vocab_lessons(query=q, record_nav=False)
            elif view == 'custom_reading':
                self.show_custom_reading(query=q, record_nav=False)
            elif view == 'sakubo_reading':
                self.show_sakubo_reading(record_nav=False)
            elif view == 'sakubo_reading_level':
                lv = self._view_payload.get('level', 'n5')
                self.show_sakubo_reading_level(lv, query=q, record_nav=False)
            else:
                # On the main/submenu views, only search when there is actually a query
                # (guard: clearing search on Back triggers on_text → don't auto-navigate)
                if q:
                    self.show_spoonfed_menu(query=q, record_nav=False)
        except Exception:
            pass

    def _get_quick_area(self):
        qa = getattr(self, '_quick_area', None) or self.ids.get('lessons_quick')
        if qa is None:
            try:
                app = App.get_running_app()
                if app and getattr(app, 'root', None) is not None:
                    qa = app.root.ids.get('lessons_quick')
            except Exception:
                return None
        if qa is not None:
            # Restore default padding/spacing (queue view zeroes these out)
            qa.padding = [dp(6), dp(6), dp(6), dp(6)]
            qa.spacing = dp(6)
        return qa

    def _make_menu_button(self, text: str, on_press=None, height_dp: int = 56):
        b = Button(text=text, size_hint_y=None, height=dp(height_dp))
        try:
            b.font_name = 'fonts/NotoSansJP-Regular.ttf'
        except Exception:
            pass
        
        b.background_normal = ''
        
        # "My Queue" button gets special green color
        if text == 'My Queue':
            b.background_color = (0.20, 0.45, 0.25, 1)
            b.color = (0.90, 0.88, 0.85, 1)
            # Set up state binding for press feedback
            def update_color_green(instance, value):
                if value == 'normal':
                    instance.background_color = (0.20, 0.45, 0.25, 1)
                else:
                    instance.background_color = (0.15, 0.35, 0.18, 1)
            b.bind(state=update_color_green)
        else:
            # Default dark stone color for other buttons
            b.background_color = (0.22, 0.22, 0.25, 1)
            b.color = (0.90, 0.88, 0.85, 1)
            def update_color_beige(instance, value):
                if value == 'normal':
                    instance.background_color = (0.22, 0.22, 0.25, 1)
                else:
                    instance.background_color = (0.15, 0.15, 0.17, 1)
            b.bind(state=update_color_beige)
        
        if on_press is not None:
            b.bind(on_release=lambda *_: on_press())
        return b

    def _build_sakubo_lessons_rv(self, header_widget, rv_data, back_handler, no_data_msg):
        """Build a RecycleView-based lessons screen with header, list, back button.
        
        Replaces the old ScrollView + for-loop widget creation approach.
        Renders only visible rows for dramatically faster loading on large collections.
        """
        from kivy.uix.anchorlayout import AnchorLayout
        from kivy.uix.recycleview import RecycleView
        from kivy.uix.recycleboxlayout import RecycleBoxLayout

        qa = self._get_quick_area()
        if qa is None:
            return
        qa.clear_widgets()

        anchor = AnchorLayout(anchor_x='center', anchor_y='top')
        outer = BoxLayout(orientation='vertical', spacing=4, padding=8)

        # Header row (fixed at top)
        outer.add_widget(header_widget)

        if rv_data:
            rv = RecycleView(size_hint_y=1)
            rv_layout = RecycleBoxLayout(
                default_size=(None, dp(48)),
                default_size_hint=(1, None),
                size_hint_y=None,
                orientation='vertical',
                spacing=dp(8),
            )
            rv_layout.bind(minimum_height=rv_layout.setter('height'))
            rv.add_widget(rv_layout)
            rv.viewclass = 'SakuboLessonRow'
            rv.data = rv_data
            outer.add_widget(rv)
        else:
            outer.add_widget(Label(text=no_data_msg, size_hint_y=1))

        # Back button (fixed at bottom)
        outer.add_widget(self._make_menu_button('Back', back_handler, height_dp=48))

        anchor.add_widget(outer)
        qa.add_widget(anchor)

        # Consume pending scroll restore now that the RV is built with data
        if rv_data:
            _pending = getattr(self, '_pending_scroll_y', None)
            if _pending is not None:
                self._pending_scroll_y = None
                def _apply_scroll(dt):
                    try:
                        rv.scroll_y = _pending
                    except Exception:
                        pass
                # Wait 2 frames for layout to settle
                Clock.schedule_once(lambda dt: Clock.schedule_once(_apply_scroll, 0), 0)

