    def _process_pasted_text(self, popup, title: str, text: str):
        """Process pasted Japanese text and save to database."""
        from kivy.uix.popup import Popup
        from kivy.uix.label import Label
        from kivy.uix.progressbar import ProgressBar
        from kivy.clock import Clock
        from kivy.logger import Logger
        import threading
        
        # Validate input
        title = title.strip()
        text = text.strip()
        
        if not title:
            error_popup = Popup(
                title='Error',
                content=Label(text='Please enter a title'),
                size_hint=(0.6, 0.3)
            )
            error_popup.open()
            return
        
        if not text:
            error_popup = Popup(
                title='Error',
                content=Label(text='Please paste some Japanese text'),
                size_hint=(0.6, 0.3)
            )
            error_popup.open()
            return
        
        # Close input popup
        popup.dismiss()
        
        # Show processing popup
        progress_content = BoxLayout(orientation='vertical', spacing=8, padding=8)
        progress_label = Label(text='Processing text...\nThis may take a moment.')
        progress_bar = ProgressBar(max=100, value=0)
        progress_content.add_widget(progress_label)
        progress_content.add_widget(progress_bar)
        
        progress_popup = Popup(
            title='Processing',
            content=progress_content,
            size_hint=(0.6, 0.3),
            auto_dismiss=False
        )
        progress_popup.open()
        
        # Process in background thread
        def process():
            try:
                from reading.db_schema import create_reading_tables
                from reading.processor import ReadingProcessor
                
                # Ensure tables exist
                db_path = get_db_path()
                create_reading_tables(db_path)
                
                # Process text
                processor = ReadingProcessor(db_path)
                material_id = processor.process_text(title, text)
                
                # Update UI on main thread
                def on_complete(dt):
                    progress_popup.dismiss()
                    self._show_processing_complete(material_id)
                    self.show_custom_reading(record_nav=False)  # Refresh list
                
                Clock.schedule_once(on_complete, 0)
                
            except Exception as e:
                Logger.error(f'LessonsScreen: Error processing text: {e}')
                
                def on_error(dt):
                    progress_popup.dismiss()
                    error_popup = Popup(
                        title='Error',
                        content=Label(text=f'Error processing text:\\n{str(e)}'),
                        size_hint=(0.7, 0.4)
                    )
                    error_popup.open()
                
                Clock.schedule_once(on_error, 0)
        
        thread = threading.Thread(target=process, daemon=True)
        thread.start()

    def _show_processing_complete(self, material_id: int):
        """Show completion message with stats."""
        from kivy.uix.popup import Popup
        from kivy.uix.label import Label
        from reading.db_schema import get_reading_material
        
        try:
            material = get_reading_material(get_db_path(), material_id)
            if material:
                match_rate = (material['matched_words'] / material['word_count'] * 100) if material['word_count'] > 0 else 0
                message = (
                    f"✓ Reading material added!\n\n"
                    f"Words: {material['word_count']}\n"
                    f"Matched: {material['matched_words']} ({match_rate:.1f}%)"
                )
            else:
                message = "✓ Reading material added!"
        except Exception:
            message = "✓ Reading material added!"
        
        success_popup = Popup(
            title='Success',
            content=Label(text=message, halign='center'),
            size_hint=(0.6, 0.4)
        )
        success_popup.open()

