            conn = dict_db.init_db(get_db_path())
            lessons = dict_db.get_all_custom_lessons(conn)
            conn.close()
            
            if not lessons:
                msg_layout = BoxLayout(orientation='vertical', padding=dp(12), spacing=dp(8))
                msg_label = Label(text='No custom lessons found.\nCreate one first in the Lessons tab.', halign='center')
                msg_label.bind(size=msg_label.setter('text_size'))
                msg_layout.add_widget(msg_label)
                
                ok_btn = Button(text='OK', size_hint_y=None, height=dp(40), background_normal='', 
                              background_color=(0.25, 0.35, 0.50, 1))
