    def restore_popup_state(self):
        """Restore saved popup state after returning from dictionary."""
        if not hasattr(self, '_saved_popup_state') or not self._saved_popup_state:
            return
        
        from kivy.clock import Clock
        state = self._saved_popup_state
        self._saved_popup_state = None
        
        # Restore in reverse order (parent first, then child)
        if state.get('parent_popup_state'):
            parent_state = state['parent_popup_state']
            if parent_state['type'] == 'translation':
                # Reopen translation popup
                Clock.schedule_once(
                    lambda dt: self._show_translation_result(
                        parent_state['original'],
                        parent_state['translation']
                    ),
                    0.1
                )
                # Then reopen word definition popup on top
                Clock.schedule_once(
                    lambda dt: self._show_word_definition_popup(
                        state['token'],
                        parent_popup=getattr(self, '_last_opened_popup', None)
                    ),
                    0.3
                )
        else:
            # Just reopen word definition popup
            Clock.schedule_once(
                lambda dt: self._show_word_definition_popup(state['token']),
                0.1
            )

    def _rename_reading_material(self, material_id: int):
        """Show popup to rename reading material."""
        try:
            from kivy.uix.popup import Popup
            from kivy.uix.textinput import TextInput
            from kivy.uix.button import Button
            from kivy.metrics import dp
            import sqlite3
            
            # Get current title
            conn = sqlite3.connect(get_db_path())
            cursor = conn.cursor()
            cursor.execute('SELECT title FROM custom_reading_materials WHERE id = ?', (material_id,))
            row = cursor.fetchone()
            conn.close()
            
            if not row:
                return
            
            current_title = row[0]
            
            # Create popup content
            content = BoxLayout(orientation='vertical', spacing=8, padding=8)
            
            title_input = TextInput(
                text=current_title,
                multiline=False,
                size_hint_y=None,
                height=dp(40),
                font_name='fonts/NotoSansJP-Regular.ttf'
            )
            content.add_widget(title_input)
            
            # Buttons
            btn_box = BoxLayout(size_hint_y=None, height=dp(50), spacing=8)
            
            cancel_btn = Button(
                text='Cancel',
                background_normal='',
                background_color=(0.40, 0.40, 0.42, 1)
            )
            
            save_btn = Button(
                text='Save',
                background_normal='',
                background_color=(0.20, 0.45, 0.25, 1)
            )
            
            btn_box.add_widget(cancel_btn)
            btn_box.add_widget(save_btn)
            content.add_widget(btn_box)
            
            # Create popup
            rename_popup = Popup(
                title='Rename Reading',
                content=content,
                size_hint=(0.7, 0.3)
            )
            
            # Wire up buttons
            cancel_btn.bind(on_release=lambda *_: rename_popup.dismiss())
            save_btn.bind(on_release=lambda *_: self._save_renamed_reading(
                rename_popup, material_id, title_input.text
            ))
            
            rename_popup.open()
            
        except Exception as e:
            from kivy.logger import Logger
            Logger.error(f'LessonsScreen: Error showing rename popup: {e}')

    def _save_renamed_reading(self, popup, material_id: int, new_title: str):
        """Save renamed reading material."""
        try:
            import sqlite3
            
            new_title = new_title.strip()
            if not new_title:
                from kivy.uix.popup import Popup
                from kivy.uix.label import Label
                error_popup = Popup(
                    title='Error',
                    content=Label(text='Title cannot be empty'),
                    size_hint=(0.6, 0.3)
                )
                error_popup.open()
                return
            
            # Update database
            conn = sqlite3.connect(get_db_path())
            cursor = conn.cursor()
            cursor.execute(
                'UPDATE custom_reading_materials SET title = ? WHERE id = ?',
                (new_title, material_id)
            )
            conn.commit()
            conn.close()
            
            # Close popup
            popup.dismiss()
            
            # Refresh the current view
            self.open_reading_material(material_id)
            
        except Exception as e:
            from kivy.logger import Logger
            Logger.error(f'LessonsScreen: Error saving renamed reading: {e}')
            from kivy.uix.popup import Popup
            from kivy.uix.label import Label
            error_popup = Popup(
                title='Error',
                content=Label(text=f'Error saving title:\n{str(e)}'),
                size_hint=(0.6, 0.3)
            )
            error_popup.open()

    def _lookup_token_in_dictionary(self, token_data, word_label):
        """Look up a token in the dictionary and show popup with options."""
        try:
            from kivy.uix.popup import Popup
            from kivy.uix.boxlayout import BoxLayout
            from kivy.uix.button import Button
            from kivy.uix.label import Label
            from kivy.metrics import dp
            
            surface = token_data.get('surface', '')
            base_form = token_data.get('base_form') or token_data.get('lemma') or surface
            pos = token_data.get('pos', '')
            entry_id = token_data.get('entry_id')
            
            # Skip punctuation/symbols
            if not surface.strip() or pos and 'Symbol' in pos:
                return
            
            # Search database for this word
            import sqlite3
            conn = sqlite3.connect(get_db_path())
            conn.row_factory = sqlite3.Row
            cursor = conn.cursor()
            
            # Try to find entry by base form or surface
            entries = []
            for search_term in [base_form, surface]:
                cursor.execute('''
                    SELECT id, kanji, kana as reading, gloss as glosses
                    FROM entries
                    WHERE kanji = ? OR kana = ?
                    LIMIT 5
                ''', (search_term, search_term))
                results = cursor.fetchall()
                if results:
                    entries = results
                    break
            
            conn.close()
            
            # Create popup content
            content = BoxLayout(orientation='vertical', spacing=8, padding=8)
            
            # Word header
            header = Label(
                text=f'[b]{surface}[/b]' + (f' ({base_form})' if base_form != surface else ''),
                markup=True,
                size_hint_y=None,
                height=dp(32),
                font_size='18sp'
            )
            try:
                header.font_name = 'fonts/NotoSansJP-Regular.ttf'
            except:
                pass
            content.add_widget(header)
            
            if entries:
                # Show first few meanings
                for entry in entries[:3]:
                    entry_text = f"{entry['kanji'] or ''} [{entry['reading'] or ''}]"
                    glosses = entry['glosses'] or 'No definition'
                    if len(glosses) > 100:
                        glosses = glosses[:100] + '...'
                    
                    meaning_label = Label(
                        text=f"{entry_text}\n{glosses}",
                        size_hint_y=None,
                        height=dp(60),
                        text_size=(300, None),
                        halign='left',
                        valign='top',
                        font_size='14sp'
                    )
                    try:
                        meaning_label.font_name = 'fonts/NotoSansJP-Regular.ttf'
                    except:
                        pass
                    content.add_widget(meaning_label)
                
                # Button to add to lessons
                add_btn = Button(
                    text='Add to Lessons',
                    size_hint_y=None,
                    height=dp(44),
                    background_normal='',
                    background_color=(0.20, 0.55, 0.30, 1)
                )
                
                def add_to_lessons(*args, entry=entries[0]):
                    popup.dismiss()
                    self._add_entry_to_lessons(entry['id'], surface)
                
                add_btn.bind(on_release=add_to_lessons)
                content.add_widget(add_btn)
                
                # Button to view full entry
                view_btn = Button(
                    text='View Full Entry',
                    size_hint_y=None,
                    height=dp(44),
                    background_normal='',
                    background_color=(0.35, 0.35, 0.70, 1)
                )
                
                def view_entry(*args, entry=entries[0]):
                    popup.dismiss()
                    # Switch to dictionary tab and show entry
                    app = App.get_running_app()
                    if app and app.root:
                        app.root.ids.nav_tabs.switch_to(app.root.ids.nav_tabs.tab_list[0])
                        # Search for the word
                        dict_screen = app.root.ids.screen_manager.get_screen('dictionary')
                        if dict_screen:
                            dict_screen.search_word(surface)
                
                view_btn.bind(on_release=view_entry)
                content.add_widget(view_btn)
            else:
                # No entry found
                no_entry = Label(
                    text='No dictionary entry found',
                    size_hint_y=None,
                    height=dp(40)
                )
                content.add_widget(no_entry)
            
            # Close button
            close_btn = Button(
                text='Close',
                size_hint_y=None,
                height=dp(40),
                background_normal='',
                background_color=(0.4, 0.4, 0.4, 1)
            )
            close_btn.bind(on_release=lambda *_: popup.dismiss())
            content.add_widget(close_btn)
            
            popup = Popup(
                title='Word Lookup',
                content=content,
                size_hint=(0.85, 0.6),
                auto_dismiss=True
            )
            popup.open()
            
        except Exception as e:
            from kivy.logger import Logger
            import traceback
            Logger.error(f'LessonsScreen: Error looking up token: {e}')
            Logger.error(traceback.format_exc())

    def _add_entry_to_lessons(self, entry_id, surface):
        """Add a dictionary entry to user's lessons."""
        try:
            from kivy.uix.popup import Popup
            from kivy.uix.label import Label
            
            # Add to user's study list
            import sqlite3
            conn = sqlite3.connect(get_db_path())
            cursor = conn.cursor()
            
            # Check if already in lessons
            cursor.execute('SELECT id FROM user_lessons WHERE entry_id = ?', (entry_id,))
            if cursor.fetchone():
                popup = Popup(
                    title='Already Added',
                    content=Label(text=f'{surface} is already in your lessons!'),
                    size_hint=(0.7, 0.3)
                )
                popup.open()
                conn.close()
                return
            
            # Add to lessons
            cursor.execute('''
                INSERT INTO user_lessons (entry_id, added_date, study_order)
                VALUES (?, datetime('now'), (SELECT COALESCE(MAX(study_order), 0) + 1 FROM user_lessons))
            ''', (entry_id,))
            conn.commit()
            conn.close()
            
            popup = Popup(
                title='Added!',
                content=Label(text=f'{surface} added to your lessons!'),
                size_hint=(0.7, 0.3),
                auto_dismiss=True
            )
            popup.open()
            
            # Auto dismiss
            from kivy.clock import Clock
            Clock.schedule_once(lambda dt: popup.dismiss(), 1.5)
            
        except Exception as e:
            from kivy.logger import Logger
            Logger.error(f'LessonsScreen: Error adding to lessons: {e}')
        """Find and show definition for word at touch position."""
        try:
            # Get the cursor position at the touch point
            cursor_pos = text_widget.cursor_index(touch_pos)
            
            if cursor_pos is None:
                return
            
            # Ensure it's an integer
            cursor_pos = int(round(cursor_pos))
            
            # Find which token contains this cursor position
            current_pos = 0
            for token in self._reading_tokens:
                token_len = len(token['surface'])
                token_end = current_pos + token_len
                
                # Check if cursor is within this token
                if current_pos <= cursor_pos < token_end:
                    # Found the token!
                    if token.get('entry_id'):
                        # Highlight the word by selecting it
                        text_widget.select_text(current_pos, token_end)
                        # Show definition popup
                        self._show_word_definition_popup(token)
                    return
                
                current_pos = token_end
                
        except Exception as e:
            from kivy.logger import Logger
            import traceback
            Logger.error(f'LessonsScreen: Error looking up word at position: {e}')
            Logger.error(traceback.format_exc())

    # ------------------------------------------------------------------
    #  Sakubo Graded Reading  (list + viewer)
    # ------------------------------------------------------------------

    _graded_readings_cache: dict = {}  # level -> list of reading dicts
    _graded_mat_stats_cache: dict = {}  # level -> {filename: material_stats_dict}

    def _load_graded_readings(self, level: str = 'n5'):
        """Load all graded reading JSON files for a level, sorted by grammar_position then filename.
        Results are cached after first load since reading files are static content."""
        if level in self._graded_readings_cache:
            return self._graded_readings_cache[level]
        import json, glob
        from pathlib import Path
        readings_dir = Path('readings') / level
        if not readings_dir.exists():
            self._graded_readings_cache[level] = []
            return []
        results = []
        for fp in sorted(readings_dir.glob('*.json')):
            if fp.name.startswith('_'):
                continue
            try:
                with open(fp, 'r', encoding='utf-8') as f:
                    data = json.load(f)
                data['_filename'] = fp.name
                data['_filepath'] = str(fp)
                results.append(data)
            except Exception:
                pass
        results.sort(key=lambda r: (r.get('grammar_position', 999), r.get('_filename', '')))
        self._graded_readings_cache[level] = results
        return results

    def show_sakubo_reading(self, record_nav: bool = True):
        """Show Sakubo Reading level-selection menu (N5–N1)."""
        try:
            if record_nav:
                try:
                    self._push_view_state()
                except Exception:
                    pass
            self._current_lessons_view = 'sakubo_reading'
            self._view_payload = {}
            qa = self._get_quick_area()
            if qa is None:
                return
            qa.clear_widgets()
            from kivy.uix.anchorlayout import AnchorLayout
            container = BoxLayout(orientation='vertical', spacing=dp(8), padding=dp(8), size_hint_y=None)
            container.bind(minimum_height=container.setter('height'))
            scroll = ScrollView(size_hint=(1, 1))
            scroll.add_widget(container)

            for level in ('n5', 'n4', 'n3', 'n2', 'n1'):
                label = f'JLPT {level.upper()}'
                lv = level
                container.add_widget(self._make_menu_button(label, lambda _lv=lv: self.show_sakubo_reading_level(_lv)))
            anchor = AnchorLayout(anchor_x='center', anchor_y='top')
            anchor.add_widget(scroll)
            qa.add_widget(anchor)
        except Exception as e:
            from kivy.logger import Logger
            Logger.error(f'LessonsScreen: Error showing Sakubo Reading menu: {e}')

    def show_sakubo_reading_level(self, level: str = 'n5', record_nav: bool = True, query: str | None = None):
        """Show Sakubo Graded Reading list for a specific JLPT level."""
        try:
            if record_nav:
                try:
                    self._push_view_state()
                except Exception:
                    pass
            self._current_lessons_view = 'sakubo_reading_level'
            self._view_payload = {'level': level}
            qa = self._get_quick_area()
            if qa is None:
                return
            qa.clear_widgets()

            from kivy.uix.anchorlayout import AnchorLayout
            from kivy.uix.label import Label
            from kivy.metrics import dp

            # Show loading state immediately
            loading_label = Label(text='Loading readings...', halign='center', valign='middle')
            loading_label.bind(size=loading_label.setter('text_size'))
            qa.add_widget(loading_label)

            # Show modal overlay if loading takes > 0.3s
            _overlay = [None]
            def _show_overlay(dt):
                _overlay[0] = self._show_loading_overlay('Loading readings')
            _overlay_event = Clock.schedule_once(_show_overlay, 0.3)

            q = (query or '').strip().lower()

            def _fetch_data():
                """Background: load readings + DB stats (stats cached)."""
                readings = self._load_graded_readings(level)
                _completed = self._load_graded_reading_completed()
                # Use cached mat_stats if available
                if level in self._graded_mat_stats_cache:
                    _mat_stats = self._graded_mat_stats_cache[level]
                else:
                    _mat_stats = {}
                    try:
                        import json as _json
                        from pathlib import Path as _Path
                        _map_file = _Path('dictionary/graded_reading_map.json')
                        if _map_file.exists():
                            with open(_map_file, 'r', encoding='utf-8') as _f:
                                _gmap = _json.load(_f)
                            from reading.db_schema import get_all_reading_materials
                            _all_mats = get_all_reading_materials(get_db_path())
                            _mats_by_id = {m['id']: m for m in _all_mats}
                            for _fname, _mid in _gmap.items():
                                if _mid in _mats_by_id:
                                    _mat_stats[_fname] = _mats_by_id[_mid]
                    except Exception:
                        pass
                    self._graded_mat_stats_cache[level] = _mat_stats
                return readings, _completed, _mat_stats

            def _build_ui(dt):
                """Main thread: build UI with pre-fetched data."""
                _overlay_event.cancel()
                if _overlay[0]:
                    _overlay[0]['dismiss']()
                try:
                    readings, _completed, _mat_stats = _result[0]
                    qa.clear_widgets()

                    main_container = BoxLayout(orientation='vertical', spacing=0)
                    header_box = BoxLayout(size_hint_y=None, height=dp(48), spacing=8, padding=[8, 8, 8, 8])
                    header_label = Label(
                        text=f'Sakubo Reading — {level.upper()}',
                        size_hint_x=1.0, font_size='18sp', bold=True,
                        halign='left', valign='middle'
                    )
                    header_label.bind(size=header_label.setter('text_size'))
                    try:
                        header_label.font_name = 'fonts/NotoSansJP-Regular.ttf'
                    except Exception:
                        pass
                    header_box.add_widget(header_label)
                    main_container.add_widget(header_box)

                    scroll = ScrollView(size_hint=(1, 1))
                    content = BoxLayout(orientation='vertical', spacing=dp(6), padding=dp(8), size_hint_y=None)
                    content.bind(minimum_height=content.setter('height'))

                    if readings:
                        g_readings = [r for r in readings if r['_filename'].startswith('G')]
                        s_readings = [r for r in readings if r['_filename'].startswith('S')]

                        _suffix_map = {}
                        from collections import defaultdict as _ddict
                        _by_lesson = _ddict(lambda: {'G': [], 'S': []})
                        for r in readings:
                            _ln = r.get('lesson_number')
                            _fn = r['_filename']
                            _kind = 'G' if _fn.startswith('G') else 'S'
                            _by_lesson[_ln][_kind].append(_fn)
                        for _ln, _groups in _by_lesson.items():
                            _letter = ord('a')
                            for _gfn in sorted(_groups['G']):
                                _suffix_map[_gfn] = chr(_letter)
                                _letter += 1
                            for _sfn in sorted(_groups['S']):
                                _suffix_map[_sfn] = chr(_letter)
                                _letter += 1

                        for group_label, group in [('Grammar Readings', g_readings), ('Supplementary Readings', s_readings)]:
                            filtered = group
                            if q:
                                filtered = [r for r in group if q in r.get('title_ja', '').lower()
                                            or q in r.get('title_en', '').lower()
                                            or q in r.get('theme', '').lower()
                                            or q in r.get('grammar_kana', '').lower()]
                            if not filtered:
                                continue

                            sec_label = Label(
                                text=f'[b]{group_label}[/b]  ({len(filtered)})',
                                markup=True, font_size='14sp',
                                size_hint_y=None, height=dp(32),
                                halign='left', valign='middle',
                                color=(0.65, 0.80, 1.0, 1)
                            )
                            sec_label.bind(size=sec_label.setter('text_size'))
                            try:
                                sec_label.font_name = 'fonts/NotoSansJP-Regular.ttf'
                            except Exception:
                                pass
                            content.add_widget(sec_label)

                            for r in filtered:
                                _sfx = _suffix_map.get(r['_filename'], '')
                                row = self._make_graded_reading_row(r, _completed, _mat_stats, suffix=_sfx)
                                content.add_widget(row)
                    else:
                        placeholder = Label(
                            text=f'No graded readings found for {level.upper()}.',
                            halign='center', size_hint_y=None, height=dp(80)
                        )
                        content.add_widget(placeholder)

                    scroll.add_widget(content)
                    main_container.add_widget(scroll)
                    qa.add_widget(main_container)
                except Exception as e:
                    from kivy.logger import Logger
                    Logger.error(f'LessonsScreen: Error building reading level UI: {e}')

            _result = [None]
            def _do_fetch():
                _result[0] = _fetch_data()
                Clock.schedule_once(_build_ui, 0)

            import threading
            threading.Thread(target=_do_fetch, daemon=True).start()
        except Exception as e:
            from kivy.logger import Logger
            Logger.error(f'LessonsScreen: Error showing Sakubo Reading level: {e}')

    def _load_graded_reading_completed(self) -> set:
        """Load set of completed graded reading filenames from app config."""
        try:
            app = App.get_running_app()
            raw = app.config.get('sakubo', 'graded_completed') if app.config.has_option('sakubo', 'graded_completed') else ''
            return set(raw.split('|')) if raw else set()
        except Exception:
            return set()

    def _save_graded_reading_completed(self, completed: set):
        """Persist completed graded reading filenames."""
        try:
            app = App.get_running_app()
            if not app.config.has_section('sakubo'):
                app.config.add_section('sakubo')
            app.config.set('sakubo', 'graded_completed', '|'.join(sorted(completed)))
            app.config.write()
        except Exception:
            pass

    def _reading_display_title(self, reading_data: dict, suffix: str = '') -> str:
        """Build a display title for a graded reading.

        Args:
            reading_data: Reading JSON dict (must have lesson_number, title_ja, title_en, _filename).
            suffix: Pre-computed letter suffix like 'a', 'b', 'c'.
                    If empty, computed from filename: G→'a', S→'b'.
        Returns:
            e.g. "Lesson 69a. (Reading) 友達 (Friends)"
            or   "Lesson 79b. (Extra Reading) これとあれ (This and That)"
        """
        lesson_num = reading_data.get('lesson_number', '?')
        title_ja = reading_data.get('title_ja', '')
        title_en = reading_data.get('title_en', '')
        fname = reading_data.get('_filename', '')
        is_supp = fname.startswith('S')
        if not suffix:
            suffix = 'b' if is_supp else 'a'
        label = '(Extra Reading)' if is_supp else '(Reading)'
        return f'Lesson {lesson_num}{suffix}. {label} {title_ja} ({title_en})'

    def _make_graded_reading_row(self, reading: dict, completed: set, mat_stats: dict = None, suffix: str = ''):
        """Build a row for a graded reading, matching Custom Reading row style."""
        from kivy.metrics import dp
        from kivy.uix.label import Label
        from kivy.uix.widget import Widget
        from kivy.uix.anchorlayout import AnchorLayout
        from kivy.graphics import Color, Rectangle

        fname = reading['_filename']
        is_done = fname in completed
        title_ja = reading.get('title_ja', '')
        title_en = reading.get('title_en', '')
        lines = reading.get('lines', [])
        num_lines = len(lines)
        word_count = sum(len(ln.get('ja', '')) for ln in lines)

        # Build display title: "Lesson 69a. (Reading) 友達 (Friends)"
        display_title = self._reading_display_title(reading, suffix=suffix)

        # Stats from pre-loaded custom reading DB lookup
        words_read = 0
        times_read = 0
        total_words_listened = 0
        total_words_dictated = 0
        m = (mat_stats or {}).get(fname)
        if m:
            words_read = m.get('words_read', 0) or 0
            times_read = m.get('times_read', 0) or 0
            total_words_listened = m.get('total_words_listened', 0) or 0
            total_words_dictated = m.get('total_words_dictated', 0) or 0
            word_count = m.get('word_count', 0) or word_count
        read_percent = (words_read / word_count * 100) if word_count > 0 else (100 if is_done else 0)
        read_percent = min(read_percent, 100)

        check = '\u2713 ' if is_done else ''
        first_line = f"{read_percent:.0f}% complete, {times_read}x"
        reading_line = f"Reading: {words_read} words"
        listening_stats = f"Listening: {total_words_listened} words"
        dictation_stats = f"Dictation: {total_words_dictated} words"

        collapsed_text = (
            f"{check}{display_title}\n"
            f"[size=11sp][color=999999]{first_line}[/color][/size]"
        )
        expanded_text = (
            f"{check}{display_title}\n"
            f"[size=11sp][color=999999]{first_line}[/color][/size]\n"
            f"[size=11sp][color=999999]{reading_line}[/color][/size]\n"
            f"[size=11sp][color=999999]{listening_stats}[/color][/size]\n"
            f"[size=11sp][color=999999]{dictation_stats}[/color][/size]"
        )
        expand_delta = dp(48)  # 3 extra lines

        # Outer container
        container = BoxLayout(orientation='vertical', size_hint_y=None, height=dp(62), spacing=0)

        # Card row: button + action btn
        row = BoxLayout(size_hint_y=None, height=dp(58), spacing=dp(4))

        bg = (0.20, 0.30, 0.22, 1) if is_done else (0.25, 0.25, 0.28, 1)
        btn = Button(
            text=collapsed_text,
            markup=True, font_size='15sp',
            size_hint_x=1.0,
            background_normal='', background_color=bg,
            halign='left', valign='top',
            padding=[16, 8]
        )
        btn.bind(size=btn.setter('text_size'))
        btn._collapsed = collapsed_text
        btn._expanded = expanded_text
        btn._is_expanded = False
        try:
            btn.font_name = 'fonts/NotoSansJP-Regular.ttf'
        except Exception:
            pass

        def update_btn_color(instance, value, _bg=bg):
            if value == 'normal':
                instance.background_color = _bg
            else:
                instance.background_color = (0.18, 0.18, 0.20, 1)
        btn.bind(state=update_btn_color)

        filepath = reading['_filepath']
        btn.bind(on_release=lambda *_, fp=filepath: self.open_graded_reading(fp))
        row.add_widget(btn)

        # Action menu button (grey +) pinned to top
        x_anchor = AnchorLayout(anchor_x='center', anchor_y='top',
                                size_hint=(None, 1.0), width=dp(44))
        action_btn = Button(
            text='+',
            size_hint=(None, None), width=dp(44), height=dp(44),
            background_normal='', background_down='',
            background_color=(0.40, 0.40, 0.42, 1),
            color=(0.90, 0.88, 0.85, 1),
            font_size='24sp'
        )

        def make_action_handler(fn, tja, ten, fp):
            def handler(*args):
                self._show_graded_reading_action_menu(fn, f'{tja} ({ten})', fp)
            return handler

        action_btn.bind(on_release=make_action_handler(fname, title_ja, title_en, filepath))
        x_anchor.add_widget(action_btn)
        row.add_widget(x_anchor)

        container.add_widget(row)

        # Progress bar (green=read fraction, red=unread)
        progress_row = BoxLayout(size_hint_y=None, height=dp(4), spacing=0)
        done_frac = min(words_read / word_count, 1.0) if word_count > 0 else (1.0 if is_done else 0.0)
        undone_frac = 1.0 - done_frac

        if done_frac > 0:
            done_w = Widget(size_hint_x=done_frac)
            with done_w.canvas.before:
                Color(0.15, 0.65, 0.15, 1)
                done_w._rect = Rectangle(pos=done_w.pos, size=done_w.size)
            done_w.bind(
                pos=lambda inst, val: setattr(inst._rect, 'pos', val),
                size=lambda inst, val: setattr(inst._rect, 'size', val)
            )
            progress_row.add_widget(done_w)

        if undone_frac > 0:
            undone_w = Widget(size_hint_x=undone_frac)
            with undone_w.canvas.before:
                Color(0.85, 0.20, 0.15, 1)
                undone_w._rect = Rectangle(pos=undone_w.pos, size=undone_w.size)
            undone_w.bind(
                pos=lambda inst, val: setattr(inst._rect, 'pos', val),
                size=lambda inst, val: setattr(inst._rect, 'size', val)
            )
            progress_row.add_widget(undone_w)

        progress_row.add_widget(Widget(size_hint_x=None, width=dp(48)))
        container.add_widget(progress_row)

        # Show More / Less toggle
        toggle_label = Label(
            text='[ref=toggle]Show More >>[/ref]',
            markup=True,
            size_hint_y=None, height=dp(22),
            font_size='11sp',
            color=(0.55, 0.75, 1.0, 1),
            halign='center', valign='middle',
        )
        toggle_label.bind(size=toggle_label.setter('text_size'))

        def make_toggle_handler(b, toggle, r, cont, delta):
            def on_toggle(*_):
                if b._is_expanded:
                    b.text = b._collapsed
                    b._is_expanded = False
                    toggle.text = '[ref=toggle]Show More >>[/ref]'
                    r.height = dp(58)
                    cont.height = cont.height - delta
                else:
                    b.text = b._expanded
                    b._is_expanded = True
                    toggle.text = '[ref=toggle]Show Less <<[/ref]'
                    r.height = dp(58) + delta
                    cont.height = cont.height + delta
            return on_toggle

        toggle_label.bind(on_ref_press=make_toggle_handler(btn, toggle_label, row, container, expand_delta))
        container.add_widget(toggle_label)
        container.height += dp(22)

        return container

    def _show_graded_reading_action_menu(self, filename: str, display_name: str, filepath: str):
        """Show action menu for a graded reading — Add to Queue, Add to Lesson, Close."""
        from kivy.uix.popup import Popup
        from kivy.metrics import dp

        app = App.get_running_app()
        queue_key = f'graded:{filepath}'
        is_queued = queue_key in getattr(app, '_lesson_queue', [])

        content = BoxLayout(orientation='vertical', spacing=dp(8), padding=dp(12))

        queue_btn = Button(
            text='Remove from Queue' if is_queued else 'Add to Queue',
            size_hint_y=None, height=dp(44),
            background_normal='',
            background_color=(0.55, 0.25, 0.25, 1) if is_queued else (0.35, 0.35, 0.70, 1),
            color=(1, 1, 1, 1)
        )

        lesson_btn = Button(
            text='Add to Lesson',
            size_hint_y=None, height=dp(44),
            background_normal='',
            background_color=(0.30, 0.50, 0.35, 1),
            color=(1, 1, 1, 1)
        )

        close_btn = Button(
            text='Close',
            size_hint_y=None, height=dp(44),
            background_normal='',
            background_color=(0.35, 0.35, 0.38, 1),
            color=(0.80, 0.78, 0.75, 1)
        )

        popup = Popup(
            title=display_name,
            title_font='fonts/NotoSansJP-Regular.ttf',
            content=content,
            size_hint=(0.8, None), height=dp(220),
            auto_dismiss=True
        )

        def on_queue(*_):
            popup.dismiss()
            self._toggle_graded_reading_queue(filepath)

        def on_lesson(*_):
            popup.dismiss()
            self._pick_lesson_for_graded_reading(filepath, display_name)

        queue_btn.bind(on_release=on_queue)
        lesson_btn.bind(on_release=on_lesson)
        close_btn.bind(on_release=lambda *_: popup.dismiss())

        content.add_widget(queue_btn)
        content.add_widget(lesson_btn)
        content.add_widget(close_btn)
        popup.open()

    def _toggle_graded_reading_queue(self, filepath: str):
        """Add or remove a graded reading from the lesson queue."""
        app = App.get_running_app()
        if not hasattr(app, '_lesson_queue'):
            app._lesson_queue = []

        queue_key = f'graded:{filepath}'
        if queue_key in app._lesson_queue:
            app._lesson_queue.remove(queue_key)
            app._save_lesson_queue()
            Logger.info('GradedReadingQueue: Removed from queue')
        else:
            def _do_add(position):
                if queue_key not in app._lesson_queue:
                    if position == 'front':
                        app._lesson_queue.insert(0, queue_key)
                    else:
                        app._lesson_queue.append(queue_key)
                    app._save_lesson_queue()
                    Logger.info('GradedReadingQueue: Added to queue')
            app._show_queue_position_popup(_do_add)

    def _pick_lesson_for_graded_reading(self, filepath: str, display_name: str):
        """Show popup to pick a custom lesson to add this graded reading to."""
        from kivy.uix.popup import Popup
        from kivy.uix.scrollview import ScrollView
        from kivy.uix.gridlayout import GridLayout
        from kivy.uix.widget import Widget
        from kivy.metrics import dp
        from kivy.core.window import Window

        try:
            import dictionary.db as dict_db
            conn = dict_db.init_db(get_db_path())
            lessons = dict_db.get_all_custom_lessons(conn)
            conn.close()
        except Exception:
            lessons = []

        if not lessons:
            msg_layout = BoxLayout(orientation='vertical', padding=dp(12), spacing=dp(8))
            msg_label = Label(text='No custom lessons found.\nCreate one first in My Stuff.', halign='center')
            msg_label.bind(size=msg_label.setter('text_size'))
            msg_layout.add_widget(msg_label)
            ok_btn = Button(text='OK', size_hint_y=None, height=dp(40))
            ok_btn.background_normal = ''
            ok_btn.background_color = (0.25, 0.35, 0.50, 1)
            ok_btn.color = (1, 1, 1, 1)
            msg_popup = Popup(title='No Custom Lessons', content=msg_layout,
                            size_hint=(None, None), size=(dp(300), dp(180)), auto_dismiss=True)
            ok_btn.bind(on_release=lambda *_: msg_popup.dismiss())
            msg_layout.add_widget(ok_btn)
            msg_popup.open()
            return

        layout = BoxLayout(orientation='vertical', spacing=dp(8), padding=dp(12))
        scroll = ScrollView(do_scroll_x=False)
        grid = GridLayout(cols=1, spacing=dp(8), size_hint_y=None)
        grid.bind(minimum_height=grid.setter('height'))

        picker_popup = Popup(
            title=f'Add to Lesson: {display_name}',
            title_font='fonts/NotoSansJP-Regular.ttf',
            content=layout,
            size_hint=(0.9, 0.7),
            auto_dismiss=True
        )

        standalone_lessons = [l for l in lessons if not l.get('is_collection') and not l.get('parent_id')]
        for lesson in standalone_lessons:
            btn = Button(
                text=lesson['name'],
                size_hint_y=None, height=dp(44),
                background_normal='',
                background_color=(0.30, 0.30, 0.33, 1),
                color=(0.90, 0.88, 0.85, 1),
                font_name='fonts/NotoSansJP-Regular.ttf'
            )
            btn.bind(on_release=lambda _, lid=lesson['id'], lname=lesson['name']:
                     self._add_graded_reading_to_lesson(filepath, lid, display_name, lname, picker_popup))
            grid.add_widget(btn)

        scroll.add_widget(grid)
        layout.add_widget(scroll)
        picker_popup.open()

    def _add_graded_reading_to_lesson(self, filepath: str, lesson_id: int,
                                       reading_name: str, lesson_name: str, popup):
        """Add a graded reading to a custom lesson by filepath."""
        try:
            import dictionary.db as dict_db
            conn = dict_db.init_db(get_db_path())
            cursor = conn.cursor()
            # Check if already added (use graded_reading_path column)
            cursor.execute(
                'SELECT id FROM custom_lesson_items WHERE lesson_id = ? AND graded_reading_path = ?',
                (lesson_id, filepath)
            )
            if cursor.fetchone():
                conn.close()
                popup.dismiss()
                Logger.info('GradedReading: Already in that lesson')
                return
            # Get next position
            cursor.execute(
                'SELECT COALESCE(MAX(position), -1) + 1 FROM custom_lesson_items WHERE lesson_id = ?',
                (lesson_id,)
            )
            next_pos = cursor.fetchone()[0]
            cursor.execute('PRAGMA foreign_keys = OFF')
            cursor.execute(
                'INSERT INTO custom_lesson_items (lesson_id, entry_id, position, graded_reading_path) VALUES (?, 0, ?, ?)',
                (lesson_id, next_pos, filepath)
            )
            cursor.execute('PRAGMA foreign_keys = ON')
            conn.commit()
            conn.close()
            popup.dismiss()
            Logger.info(f'GradedReading: Added to {lesson_name}')
        except Exception as e:
            popup.dismiss()
            Logger.error(f'GradedReading: Error adding to lesson: {e}')

    def open_graded_reading(self, filepath: str, record_nav: bool = True):
        """Open a graded reading by importing it as a custom reading material, then
        opening with the full custom reading viewer (all modes, stat tracking)."""
        import json
        try:
            with open(filepath, 'r', encoding='utf-8') as f:
                data = json.load(f)
        except Exception as e:
            from kivy.logger import Logger
            Logger.error(f'GradedReading: Failed to load {filepath}: {e}')
            return

        try:
            fname = str(filepath).rsplit('\\', 1)[-1].rsplit('/', 1)[-1]
            title_ja = data.get('title_ja', '')
            title_en = data.get('title_en', '')
            lesson_num = data.get('lesson_number', '?')
            is_supp = fname.startswith('S')

            # Compute suffix letter by scanning sibling readings at the same lesson
            import glob as _og_glob
            _reading_dir = str(filepath).rsplit('\\', 1)[0] if '\\' in str(filepath) else str(filepath).rsplit('/', 1)[0]
            _siblings_g = []
            _siblings_s = []
            for _sfp in sorted(_og_glob.glob(f'{_reading_dir}/[GS]*.json')):
                try:
                    with open(_sfp, 'r', encoding='utf-8') as _sf:
                        _sd = json.load(_sf)
                    if not isinstance(_sd, dict):
                        continue
                    if _sd.get('lesson_number') == lesson_num:
                        _sfn = str(_sfp).rsplit('\\', 1)[-1].rsplit('/', 1)[-1]
                        if _sfn.startswith('G'):
                            _siblings_g.append(_sfn)
                        else:
                            _siblings_s.append(_sfn)
                except Exception:
                    continue
            _ordered = sorted(_siblings_g) + sorted(_siblings_s)
            _sfx_idx = _ordered.index(fname) if fname in _ordered else 0
            _suffix = chr(ord('a') + _sfx_idx)
            _label = '(Extra Reading)' if is_supp else '(Reading)'
            title = f'Lesson {lesson_num}{_suffix}. {_label} {title_ja} ({title_en})'

            # Build plain Japanese text from lines (paragraphs separated by newlines)
            lines = data.get('lines', [])
            parts = []
            for ln in lines:
                speaker = ln.get('speaker', '')
                ja = ln.get('ja', '')
                if speaker:
                    parts.append(f'{speaker}\uff1a{ja}')
                else:
                    parts.append(ja)
            full_text = '\n'.join(parts)

            # Check if already imported — mapping stored in JSON file
            material_id = self._get_graded_material_id(fname)

            if material_id is None:
                # Import via ReadingProcessor
                from reading.processor import ReadingProcessor
                processor = ReadingProcessor(get_db_path())
                material_id = processor.process_text(title, full_text)
                self._set_graded_material_id(fname, material_id)

            # Invalidate mat stats cache so back-nav refreshes with latest progress
            self._graded_mat_stats_cache.clear()

            # Remember current level for back-navigation
            current_level = getattr(self, '_view_payload', {}).get('level', 'n5')

            # Open with the standard custom reading viewer (no rename button)
            self.open_reading_material(material_id, record_nav=record_nav, hide_rename=True)

            # Override view state so back-navigation knows this is a graded reading
            self._current_lessons_view = 'graded_reading_view'
            self._view_payload = {'filepath': filepath, 'level': current_level}

        except Exception as e:
            from kivy.logger import Logger
            import traceback
            Logger.error(f'GradedReading: Error opening reading: {e}')
            Logger.error(traceback.format_exc())

    def _get_graded_material_id(self, filename: str) -> int | None:
        """Get the custom reading material_id for an imported graded reading."""
        import json
        from pathlib import Path
        mapping_file = Path('dictionary/graded_reading_map.json')
        if mapping_file.exists():
            try:
                with open(mapping_file, 'r', encoding='utf-8') as f:
                    mapping = json.load(f)
                mid = mapping.get(filename)
                if mid is not None:
                    # Verify material still exists in DB
                    from reading.db_schema import get_reading_material
                    mat = get_reading_material(get_db_path(), mid)
                    if mat:
                        return mid
            except Exception:
                pass
        return None

    def _set_graded_material_id(self, filename: str, material_id: int):
        """Store the mapping from graded reading filename to material_id."""
        import json
        from pathlib import Path
        mapping_file = Path('dictionary/graded_reading_map.json')
        mapping = {}
        if mapping_file.exists():
            try:
                with open(mapping_file, 'r', encoding='utf-8') as f:
                    mapping = json.load(f)
            except Exception:
                pass
        mapping[filename] = material_id
        try:
            with open(mapping_file, 'w', encoding='utf-8') as f:
                json.dump(mapping, f, indent=2, ensure_ascii=False)
        except Exception:
            pass

