            content.add_widget(separator)
            content.add_widget(Widget(size_hint_y=None, height=dp(12)))
            
            # Add "Found in" section showing words with this kanji
            Logger.info(f'EntryDetailScreen: Calling _create_found_in_words for: {kanji}')
