    def _update_bg(self, *args):
        """Update background rectangle."""
        if hasattr(self, '_bg_rect'):
            self._bg_rect.pos = self.pos
            self._bg_rect.size = self.size
    
    def _draw_separator(self, widget, dark_mode):
        """Draw a separator line on the widget's canvas."""
        from kivy.graphics import Color, Rectangle
        with widget.canvas:
            Color(0.4, 0.4, 0.4, 0.5) if dark_mode else Color(0.6, 0.6, 0.6, 0.5)
            Rectangle(pos=widget.pos, size=widget.size)
    
    def _build_tatoeba_section(self, entry, app):
        """Build the Tatoeba example sentences section.
        
        Shows 1-3 sentences initially with speaker buttons.
        Has "(show more)" button to expand full list.
        """
        from kivy.uix.boxlayout import BoxLayout
        from kivy.uix.label import Label
        from kivy.uix.button import Button
        from kivy.metrics import dp
        
        try:
            conn = dict_db.init_db(get_db_path())
            total_count = dict_db.count_tatoeba_sentences(conn, entry_id=self.entry_id)
            
            if total_count == 0:
                conn.close()
                return None
            
            # Get initial sentences (up to 3)
            sentences = dict_db.get_tatoeba_sentences(conn, entry_id=self.entry_id, limit=10)
            conn.close()
            
            if not sentences:
                return None
            
        except Exception as e:
            Logger.error(f'EntryDetailScreen: Error loading Tatoeba sentences: {e}')
            return None
        
        # Create container
        container = BoxLayout(orientation='vertical', size_hint_y=None, spacing=dp(6),
                              padding=[dp(8), 0, dp(8), 0])
        container.bind(minimum_height=container.setter('height'))
        
        # Header
        header = Label(
            text='Example Sentences:',
            size_hint_y=None,
            height=dp(24),
            font_size='13sp',
            font_name='fonts/NotoSansJP-Regular.ttf',
            color=(0.7, 0.7, 0.7, 1) if app.dark_mode else (0.3, 0.3, 0.3, 1),
            halign='left',
            valign='middle'
        )
        header.bind(size=header.setter('text_size'))
        container.add_widget(header)
        
        # Sentences container (will hold visible sentences)
        sentences_box = BoxLayout(orientation='vertical', size_hint_y=None, spacing=dp(16))
        sentences_box.bind(minimum_height=sentences_box.setter('height'))
        
        # Track state
        self._tatoeba_sentences = sentences
        self._tatoeba_showing_all = False
        self._tatoeba_sentences_box = sentences_box
        
        # Show initial 3 sentences
        for i, sent in enumerate(sentences[:3]):
            row = self._create_tatoeba_row(i + 1, sent, app)
            sentences_box.add_widget(row)
        
        container.add_widget(sentences_box)
        
        # Show more/hide button (only if more than 3 sentences)
        if len(sentences) > 3:
            toggle_btn = Button(
                text=f'(show {len(sentences) - 3} more)',
                size_hint_y=None,
                height=dp(44),
                font_size='13sp',
                background_normal='',
                background_color=(0, 0, 0, 0),
                color=(0.4, 0.7, 1, 1) if app.dark_mode else (0.2, 0.5, 0.9, 1)
            )
            
            def toggle_sentences(instance):
                self._tatoeba_showing_all = not self._tatoeba_showing_all
                sentences_box.clear_widgets()
                
                if self._tatoeba_showing_all:
                    # Show all
                    for i, sent in enumerate(self._tatoeba_sentences):
                        row = self._create_tatoeba_row(i + 1, sent, app)
                        sentences_box.add_widget(row)
                    instance.text = '(hide)'
                else:
                    # Show only first 3
                    for i, sent in enumerate(self._tatoeba_sentences[:3]):
                        row = self._create_tatoeba_row(i + 1, sent, app)
                        sentences_box.add_widget(row)
                    instance.text = f'(show {len(self._tatoeba_sentences) - 3} more)'
            
            toggle_btn.bind(on_release=toggle_sentences)
            container.add_widget(toggle_btn)
        
        return container
    
    def _build_grammar_exercises_section(self, entry, app):
        """Build grammar exercises section showing example sentences grouped by category.
        
        Each category shows 3 sentences initially with a per-category toggle.
        Category explanations are shown above each group.
        """
        from kivy.uix.boxlayout import BoxLayout
        from kivy.uix.label import Label
        from kivy.uix.button import Button
        from kivy.metrics import dp

        # Category explanations
        CATEGORY_EXPLANATIONS = {
            'noun_predicate': 'State what something is using a noun as the predicate.',
            'na_adj_predicate': 'Describe something using a な-adjective as the predicate.',
            'topic': 'Mark the topic of a sentence — what you are talking about.',
            'contrast': 'Highlight a contrast or distinction between two things.',
            'ru_verb': 'Conjugate 一段 (ichidan / ru-verbs) into polite form.',
            'u_verb': 'Conjugate 五段 (godan / u-verbs) into polite form.',
            'irregular': 'Conjugate する and 来る into polite form.',
            'direct_object': 'Mark the direct object — what the action is done to.',
            'movement_through': 'Mark the place you move through or along.',
            'departure_point': 'Mark the point of departure or detachment.',
        }

        try:
            conn = dict_db.init_db(get_db_path())
            cur = conn.cursor()
            cur.execute("""
                SELECT category, category_label, japanese, english, notes, position
                FROM grammar_exercises
                WHERE entry_id = ?
                ORDER BY category, position
            """, (self.entry_id,))
            rows = cur.fetchall()
            conn.close()

            if not rows:
                return None
        except Exception as e:
            Logger.error(f'EntryDetailScreen: Error loading grammar exercises: {e}')
            return None

        # Group by category preserving insertion order
        categories = {}
        for row in rows:
            cat_id = row[0]
            if cat_id not in categories:
                categories[cat_id] = {'label': row[1], 'sentences': []}
            categories[cat_id]['sentences'].append({
                'japanese': row[2],
                'english': row[3],
                'notes': row[4],
            })

        # Build container
        container = BoxLayout(orientation='vertical', size_hint_y=None, spacing=dp(6),
                              padding=[dp(8), 0, dp(8), 0])
        container.bind(minimum_height=container.setter('height'))

        # Section header
        header = Label(
            text='Grammar Examples:',
            size_hint_y=None,
            height=dp(24),
            font_size='13sp',
            font_name='fonts/NotoSansJP-Regular.ttf',
            color=(0.7, 0.7, 0.7, 1) if app.dark_mode else (0.3, 0.3, 0.3, 1),
            halign='left',
            valign='middle'
        )
        header.bind(size=header.setter('text_size'))
        container.add_widget(header)

        INITIAL_SHOW = 3

        # Build each category group
        for cat_id, cat_data in categories.items():
            sentences = cat_data['sentences']
            cat_label_text = cat_data['label']
            explanation = CATEGORY_EXPLANATIONS.get(cat_id, '')

            # Category header
            cat_header = Label(
                text=cat_label_text,
                size_hint_y=None,
                height=dp(26),
                font_size='13sp',
                bold=True,
                font_name='fonts/NotoSansJP-Regular.ttf',
                color=(0.5, 0.8, 1, 1) if app.dark_mode else (0.2, 0.4, 0.7, 1),
                halign='left',
                valign='middle',
                padding=[dp(4), 0]
            )
            cat_header.bind(size=cat_header.setter('text_size'))
            container.add_widget(Widget(size_hint_y=None, height=dp(6)))
            container.add_widget(cat_header)

            # Category explanation
            if explanation:
                expl_label = Label(
                    text=explanation,
                    size_hint_y=None,
                    font_size='12sp',
                    font_name='fonts/NotoSansJP-Regular.ttf',
                    color=(0.55, 0.55, 0.55, 1) if app.dark_mode else (0.45, 0.45, 0.45, 1),
                    halign='left',
                    valign='top',
                    text_size=(None, None),
                    padding=[dp(4), 0]
                )
                expl_label.bind(width=lambda w, width: setattr(w, 'text_size', (width - dp(8), None)))
                expl_label.bind(texture_size=lambda w, ts: setattr(w, 'height', ts[1] + dp(4)))
                container.add_widget(expl_label)

            # Sentences box for this category
            cat_box = BoxLayout(orientation='vertical', size_hint_y=None, spacing=dp(4))
            cat_box.bind(minimum_height=cat_box.setter('height'))

            for i, sent in enumerate(sentences[:INITIAL_SHOW]):
                row = self._create_grammar_exercise_row(i + 1, sent, app)
                cat_box.add_widget(row)

            container.add_widget(cat_box)

            # Per-category show more toggle
            if len(sentences) > INITIAL_SHOW:
                remaining = len(sentences) - INITIAL_SHOW
                toggle_btn = Button(
                    text=f'(show {remaining} more)',
                    size_hint_y=None,
                    height=dp(36),
                    font_size='12sp',
                    background_normal='',
                    background_color=(0, 0, 0, 0),
                    color=(0.4, 0.7, 1, 1) if app.dark_mode else (0.2, 0.5, 0.9, 1)
                )

                def make_toggle(box, sents, btn, init_count):
                    expanded = [False]
                    def toggle(instance):
                        expanded[0] = not expanded[0]
                        box.clear_widgets()
                        show = sents if expanded[0] else sents[:init_count]
                        for j, s in enumerate(show):
                            row = self._create_grammar_exercise_row(j + 1, s, app)
                            box.add_widget(row)
                        if expanded[0]:
                            btn.text = '(show less)'
                        else:
                            btn.text = f'(show {len(sents) - init_count} more)'
                    return toggle

                toggle_btn.bind(on_release=make_toggle(cat_box, sentences, toggle_btn, INITIAL_SHOW))
                container.add_widget(toggle_btn)

        return container

    def _create_grammar_exercise_row(self, num, sentence, app):
        """Create a single grammar exercise sentence row."""
        from kivy.uix.boxlayout import BoxLayout
        from kivy.uix.label import Label
        from kivy.metrics import dp

        row = BoxLayout(orientation='vertical', size_hint_y=None, spacing=dp(2),
                        padding=[dp(4), dp(4), dp(4), dp(4)])
        row.bind(minimum_height=row.setter('height'))

        # Japanese sentence
        jp_label = Label(
            text=f'{num}. {sentence["japanese"]}',
            size_hint_y=None,
            height=dp(28),
            font_size='15sp',
            font_name='fonts/NotoSansJP-Regular.ttf',
            color=(0.95, 0.93, 0.90, 1) if app.dark_mode else (0.1, 0.1, 0.1, 1),
            halign='left',
            valign='middle',
            padding=[dp(4), 0],
            markup=True
        )
        jp_label.bind(size=jp_label.setter('text_size'))
        row.add_widget(jp_label)

        # English translation (toggleable — hidden by default)
        eng_label = Label(
            text=sentence['english'],
            size_hint_y=None,
            height=dp(0),
            opacity=0,
            font_size='13sp',
            font_name='fonts/NotoSansJP-Regular.ttf',
            color=(0.6, 0.6, 0.6, 1) if app.dark_mode else (0.4, 0.4, 0.4, 1),
            halign='left',
            valign='middle',
            padding=[dp(20), 0]
        )
        eng_label.bind(size=eng_label.setter('text_size'))
        row.add_widget(eng_label)

        # Tap to toggle English
        def toggle_english(instance, touch):
            if not instance.collide_point(*touch.pos):
                return False
            if eng_label.opacity == 0:
                eng_label.opacity = 1
                eng_label.height = dp(22)
            else:
                eng_label.opacity = 0
                eng_label.height = dp(0)
            return True

        jp_label.bind(on_touch_down=toggle_english)

        return row
    
    def _create_tatoeba_row(self, num, sentence, app):
        """Create a single Tatoeba sentence row with clickable words, speaker button, and hidden translation."""
        from kivy.uix.boxlayout import BoxLayout
        from kivy.uix.label import Label
        from kivy.uix.button import Button
        from kivy.uix.widget import Widget
        from kivy.metrics import dp
        
        row = BoxLayout(orientation='vertical', size_hint_y=None, spacing=dp(2))
        row.bind(minimum_height=row.setter('height'))
        
        # Japanese sentence (clickable words, full width — no TTS inline)
        japanese_text = sentence["japanese"]
        clickable_sentence = self._create_clickable_tatoeba_sentence(f'{num}. {japanese_text}', app)
        row.add_widget(clickable_sentence)
        
        # Translation container (hidden initially)
        english_text = sentence.get("english", "")
        translation_container = BoxLayout(orientation='vertical', size_hint_y=None, height=0, opacity=0)
        
        if english_text:
            eng_label = Label(
                text=english_text,
                size_hint_y=None,
                font_size='13sp',
                color=(0.6, 0.6, 0.6, 1) if app.dark_mode else (0.4, 0.4, 0.4, 1),
                halign='left',
                valign='top'
            )
            eng_label.bind(
                width=lambda inst, w: setattr(inst, 'text_size', (w, None)),
                texture_size=lambda inst, ts: setattr(inst, 'height', ts[1])
            )
            translation_container.add_widget(eng_label)
        
        # Centered action row: [spacer] [translate btn] [tts btn] [spacer]
        action_row = BoxLayout(size_hint_y=None, height=dp(36), spacing=dp(8))
        action_row.add_widget(Widget(size_hint_x=1))
        
        # Translate icon button
        translate_btn = Button(
            text='\ue8e2',  # translate icon
            font_name='fonts/MaterialSymbolsOutlined.ttf',
            font_size='18sp',
            size_hint=(None, None),
            size=(dp(36), dp(36)),
            background_normal='',
            background_color=(0.20, 0.30, 0.50, 1),
            color=(1, 1, 1, 1)
        )
        
        def toggle_translation(instance, container=translation_container,
                               eng_lbl=eng_label if english_text else None):
            if container.opacity == 0:
                container.opacity = 1
                if eng_lbl:
                    eng_lbl.texture_update()
                    container.height = eng_lbl.texture_size[1] + dp(4)
                instance.background_color = (0.15, 0.50, 0.30, 1)  # green = shown
            else:
                container.opacity = 0
                container.height = 0
                instance.background_color = (0.20, 0.30, 0.50, 1)  # blue = hidden
        
        translate_btn.bind(on_release=toggle_translation)
        action_row.add_widget(translate_btn)
        
        # TTS speaker button
        speaker_btn = Button(
            text='\ue050',  # volume_up icon
            font_name='fonts/MaterialSymbolsOutlined.ttf',
            font_size='18sp',
            size_hint=(None, None),
            size=(dp(36), dp(36)),
            background_normal='',
            background_color=(0.3, 0.5, 0.3, 1) if app.dark_mode else (0.4, 0.7, 0.4, 1),
            color=(1, 1, 1, 1)
        )
        
        def speak_sentence(instance, text=japanese_text):
            try:
                app_instance = App.get_running_app()
                if hasattr(app_instance, 'speak_text'):
                    app_instance.speak_text(text, btn=instance)
            except Exception as e:
                Logger.error(f'TTS error: {e}')
        
        speaker_btn.bind(on_release=speak_sentence)
        action_row.add_widget(speaker_btn)
        action_row.add_widget(Widget(size_hint_x=1))
        
        row.add_widget(translation_container)
        row.add_widget(action_row)
        
        return row
    
    def _create_clickable_tatoeba_sentence(self, text, app):
        """Create a label with clickable parsed words for Tatoeba sentences."""
        from kivy.uix.label import Label
        from kivy.metrics import dp
        
        text_color = (0.95, 0.95, 0.95, 1) if app.dark_mode else (0.1, 0.1, 0.1, 1)
        link_color = '6495ed' if app.dark_mode else '2060a0'  # Blue for clickable words
        
        # Extract just the Japanese text (remove the number prefix for parsing)
        import re
        match = re.match(r'^(\d+\.\s*)(.*)', text)
        if match:
            prefix = match.group(1)
            japanese = match.group(2)
        else:
            prefix = ''
            japanese = text
        
        # Try to parse and match tokens to dictionary
        markup_text = text
        matched_tokens = []
        
        try:
            from reading.processor import ReadingProcessor
            processor = ReadingProcessor(get_db_path())
            tokens = processor.tokenize(japanese)
            matched_tokens = processor.match_tokens_to_db(tokens)
            
            # Build markup text with clickable words
            markup_parts = [prefix]  # Keep the number prefix
            for i, token in enumerate(matched_tokens):
                if token.get('entry_id'):
                    # Clickable word (vocab match)
                    markup_parts.append(f'[ref={i}][color={link_color}]{token["surface"]}[/color][/ref]')
                else:
                    # Normal text (particles, punctuation, etc.)
                    markup_parts.append(token['surface'])
            markup_text = ''.join(markup_parts)
            
        except Exception as e:
            Logger.error(f'EntryDetailScreen: Error parsing Tatoeba sentence: {e}')
            # Fallback to plain text
            markup_text = text
            matched_tokens = []
        
        # Create a wrapping label with markup
        sentence_label = Label(
            text=markup_text,
            size_hint=(1, None),
            halign='left',
            valign='middle',
            font_name='fonts/NotoSansJP-Regular.ttf',
            font_size='18sp',
            color=text_color,
            markup=True
        )
        sentence_label.bind(
            width=lambda instance, value: setattr(instance, 'text_size', (value, None)),
            texture_size=lambda instance, value: setattr(instance, 'height', max(dp(40), value[1] + dp(8)))
        )
        
        # Store tokens for click handling
        sentence_label._matched_tokens = matched_tokens
        
        # Handle clicks on words
        def on_word_click(instance, ref):
            try:
                token_idx = int(ref)
                token = instance._matched_tokens[token_idx]
                # always copy and flash regardless of entry_id
                text = token.get('surface','')
                try:
                    from kivy.core.clipboard import Clipboard
                    Clipboard.copy(text)
                except Exception:
                    pass
                try:
                    app = App.get_running_app()
                    if hasattr(app, '_flash_opacity'):
                        app._flash_opacity(instance)
                except Exception:
                    pass
                # Always show popup, fallback to general lookup if no entry_id
                if token.get('entry_id'):
                    self._show_parsed_word_popup(token, source_widget=instance)
                else:
                    self._show_word_popup(text, source_widget=instance)
            except Exception as e:
                Logger.error(f'EntryDetailScreen: Error on Tatoeba word click: {e}')
        
        sentence_label.bind(on_ref_press=on_word_click)
        
        return sentence_label

    def _make_pitch_accent_widget(self, kana: str, accent_num: int, dark_mode: bool = True):
        """Create a pitch accent widget with the line running through the mora characters.

        The line is drawn at the TOP of the character cell for HIGH morae and
        at the BOTTOM for LOW morae, with a vertical drop/rise at transitions —
        matching traditional Japanese pitch accent notation.

        This widget replaces the plain kana reading row entirely.
        Returns a BoxLayout (size_hint_y=None) or None.
        """
        from kivy.uix.widget import Widget as _W
        from kivy.graphics import Color as _C, Line as _L
        from kivy.metrics import dp as _dp
        from dictionary.pitch_accent import split_morae, get_pitch_pattern

        morae = split_morae(kana)
        n = len(morae)
        if n == 0:
            return None
        accent_num = max(0, min(accent_num, n))
        pattern = get_pitch_pattern(n, accent_num)

        CHAR_H = _dp(38)   # character row height
        LINE_W = 2.2
        mora_widths = [_dp(36) if len(m) > 1 else _dp(26) for m in morae]
        TOTAL_W = sum(mora_widths)

        if accent_num == 0:
            line_color = (0.35, 0.70, 1.00, 1) if dark_mode else (0.15, 0.45, 0.80, 1)
        elif accent_num == 1:
            line_color = (1.00, 0.42, 0.32, 1) if dark_mode else (0.85, 0.20, 0.15, 1)
        else:
            line_color = (0.40, 0.85, 0.50, 1) if dark_mode else (0.15, 0.60, 0.30, 1)

        char_color = (0.90, 0.90, 0.90, 1) if dark_mode else (0.12, 0.12, 0.12, 1)

        # ── Character row ────────────────────────────────────────────────────
        char_row = BoxLayout(
            orientation='horizontal',
            size_hint=(None, None), size=(TOTAL_W, CHAR_H),
        )

        for mora, mw in zip(morae, mora_widths):
            lbl = Label(
                text=mora,
                size_hint=(None, None),
                size=(mw, CHAR_H),
                font_size='20sp',
                halign='center',
                valign='middle',
                color=char_color,
            )
            try:
                lbl.font_name = 'fonts/NotoSansJP-Regular.ttf'
            except Exception:
                pass
            char_row.add_widget(lbl)

        # Draw pitch line: horizontal segments at top (HIGH) or bottom (LOW)
        # with vertical connectors at transitions, drawn at cell boundaries
        def _draw_pitch(inst, *_args):
            inst.canvas.after.clear()
            PAD = _dp(4)
            y_h = inst.y + inst.height - PAD   # HIGH level
            y_l = inst.y + PAD                 # LOW level
            # Cumulative x positions for cell boundaries
            xs = [inst.x]
            for mw in mora_widths:
                xs.append(xs[-1] + mw)
            with inst.canvas.after:
                _C(*line_color)
                for i, high in enumerate(pattern):
                    y = y_h if high else y_l
                    _L(points=[xs[i], y, xs[i + 1], y], width=LINE_W)
                    if i > 0 and pattern[i] != pattern[i - 1]:
                        prev_y = y_h if pattern[i - 1] else y_l
                        _L(points=[xs[i], prev_y, xs[i], y], width=LINE_W)

        char_row.bind(pos=_draw_pitch, size=_draw_pitch)

        outer = BoxLayout(orientation='horizontal', size_hint=(1, None), height=CHAR_H)
        outer.add_widget(char_row)
        outer.add_widget(_W())  # spacer keeps diagram left-aligned
        return outer

    def _create_found_in_words(self, kanji_char):
        """Create 'Found in:' section showing words containing this kanji."""
        try:
            Logger.info(f'EntryDetailScreen: Creating found_in_words for kanji: {kanji_char}')
            # Get words containing this kanji
            conn = dict_db.init_db(get_db_path())
            cur = conn.cursor()
            
            # Query for vocab entries containing this kanji, ordered by JLPT level
            cur.execute('''
                SELECT e.id, e.kanji, e.kana, e.gloss, e.jlpt_level
                FROM entries e
                WHERE e.kind = 'vocab' AND (e.kanji LIKE ? OR e.kana LIKE ?)
                ORDER BY 
                    CASE 
                        WHEN e.jlpt_level = 'N5' THEN 1
                        WHEN e.jlpt_level = 'N4' THEN 2
                        WHEN e.jlpt_level = 'N3' THEN 3
                        WHEN e.jlpt_level = 'N2' THEN 4
                        WHEN e.jlpt_level = 'N1' THEN 5
                        WHEN e.jlpt_level IS NULL THEN 6
                        ELSE 7
                    END,
                    e.id
                LIMIT 50
            ''', (f'%{kanji_char}%', f'%{kanji_char}%'))
            
            words = cur.fetchall()
            conn.close()
            
            Logger.info(f'EntryDetailScreen: Found {len(words)} words containing {kanji_char}')
            
            if not words:
                Logger.info(f'EntryDetailScreen: No words found for {kanji_char}, returning None')
                return None
            
            app = App.get_running_app()
            container = BoxLayout(orientation='vertical', size_hint_y=None, spacing=dp(6), padding=(0, dp(8), 0, 0))
            container.bind(minimum_height=container.setter('height'))
            
            # "Found in:" label
            found_label = Label(
                text='Found in:',
                size_hint_y=None,
                height=dp(24),
                halign='left',
                valign='middle',
                font_size='14sp',
                color=(0.7, 0.7, 0.7, 1) if app.dark_mode else (0.3, 0.3, 0.3, 1),
                bold=True
            )
            found_label.bind(width=lambda instance, value: setattr(instance, 'text_size', (value, None)))
            container.add_widget(found_label)
            
            # Words list container
            words_container = BoxLayout(orientation='vertical', size_hint_y=None, spacing=dp(4))
            words_container.bind(minimum_height=words_container.setter('height'))
            
            # Store for show more functionality
            self._found_in_words = words
            self._found_in_words_container = words_container
            self._found_in_show_more_btn = None
            
            # Initially show 5 words
            self._show_found_in_words(words_container, words[:5])
            container.add_widget(words_container)
            
            # Show more button if there are more than 5 words
            if len(words) > 5:
                show_more_btn = Button(
                    text='Show More',
                    size_hint_y=None,
                    height=dp(32),
                    background_normal='',
                    background_color=(0.25, 0.35, 0.50, 1),
                    color=(1, 1, 1, 1),
                    font_name='fonts/NotoSansJP-Regular.ttf',
                    font_size='12sp'
                )
                show_more_btn.bind(on_release=lambda *_: self._show_all_found_in_words())
                self._found_in_show_more_btn = show_more_btn
                container.add_widget(show_more_btn)
            
            return container
            
        except Exception as e:
            Logger.error(f'Error creating found in words: {e}')
            import traceback
            Logger.error(traceback.format_exc())
            return None
    
    def _show_found_in_words(self, container, words):
        """Display a list of words in the container."""
        app = App.get_running_app()
        
        for i, (word_id, kanji, kana, gloss_json, jlpt) in enumerate(words, 1):
            # Parse first definition
            try:
                import json
                glosses = json.loads(gloss_json)
                first_def = glosses[0] if glosses else ''
            except:
                first_def = gloss_json or ''
            
            # Truncate definition if too long
            if len(first_def) > 40:
                first_def = first_def[:37] + '...'
            
            # Word display text
            display_text = kanji or kana
            if kanji and kana and kanji != kana:
                word_text = f'{i}. {kanji} ({kana})'
            else:
                word_text = f'{i}. {display_text}'
            
            # Add JLPT level tag (jlpt is already in 'N5' format)
            if jlpt:
                word_text += f' [{jlpt}]'
            
            # Word button (clickable)
            word_btn = Button(
                text=word_text,
                size_hint_y=None,
                height=dp(32),
                halign='left',
                valign='middle',
                background_normal='',
                background_color=(0.18, 0.18, 0.20, 1) if app.dark_mode else (0.93, 0.90, 0.83, 1),
                color=(0.9, 0.9, 0.9, 1) if app.dark_mode else (0.1, 0.1, 0.1, 1),
                font_name='fonts/NotoSansJP-Regular.ttf',
                font_size='13sp'
            )
            word_btn.bind(
                width=lambda instance, value: setattr(instance, 'text_size', (value - dp(16), None)),
                on_release=lambda btn, wid=word_id, surface=display_text: self._show_found_in_word_popup(wid, surface)
            )
            container.add_widget(word_btn)
            
            # Definition label
            if first_def:
                def_label = Label(
                    text=f'   {first_def}',
                    size_hint_y=None,
                    halign='left',
                    valign='top',
                    font_size='11sp',
                    color=(0.6, 0.6, 0.6, 1) if app.dark_mode else (0.4, 0.4, 0.4, 1),
                    italic=True
                )
                def_label.bind(
                    width=lambda instance, value: setattr(instance, 'text_size', (value, None)),
                    texture_size=lambda instance, value: setattr(instance, 'height', value[1])
                )
                container.add_widget(def_label)
    
    def _show_all_found_in_words(self):
        """Show all found in words (remove show more button)."""
        # Clear current words
        self._found_in_words_container.clear_widgets()
        
        # Show all words
        self._show_found_in_words(self._found_in_words_container, self._found_in_words)
        
        # Remove show more button
        if self._found_in_show_more_btn and self._found_in_show_more_btn.parent:
            self._found_in_show_more_btn.parent.remove_widget(self._found_in_show_more_btn)
    
