    def _show_stroke_order(self, kanji):
        """Show stroke order diagram for a kanji character."""
        try:
            from app.widgets.stroke_order_widget import StrokeOrderWidget
            from kivy.uix.popup import Popup
            from kivy.uix.button import Button
            from kivy.uix.boxlayout import BoxLayout
            from kivy.uix.label import Label
            from kivy.uix.floatlayout import FloatLayout
            from kivy.uix.anchorlayout import AnchorLayout
            
            Logger.info(f'Opening stroke order for kanji: {kanji}')
            
            # Create popup content
            content = BoxLayout(orientation='vertical', padding=dp(10), spacing=dp(8))
            
            # Container for square stroke widget
            widget_container = AnchorLayout(size_hint=(1, 1))
            
            # Stroke order widget - make it square by constraining to minimum dimension
            stroke_widget = StrokeOrderWidget(
                size_hint=(None, None)
            )
            # Calculate square size based on container
            def update_widget_size(container, *args):
                # Make it square, sized to fit the smaller dimension
                size = min(container.width * 0.95, container.height * 0.95)
                stroke_widget.size = (size, size)
            
            widget_container.bind(size=update_widget_size)
            
            # Set kanji after widget is created
            stroke_widget.kanji = kanji
            widget_container.add_widget(stroke_widget)
            content.add_widget(widget_container)
            
            # Info label
            info_label = Label(
                text='',
                size_hint_y=None,
                height=dp(25),
                font_size='14sp'
            )
            
            def update_info(*args):
                info = stroke_widget.get_stroke_info()
                info_label.text = f"Stroke {info['shown']}/{info['total']}"
            
            # Connect callback for animation updates
            stroke_widget.on_stroke_changed = update_info
            
            update_info()
            content.add_widget(info_label)
            
            # Control buttons
            controls = BoxLayout(size_hint_y=None, height=dp(40), spacing=dp(5))
            
            btn_prev = Button(text='Prev', size_hint_x=0.2)
            btn_prev.bind(on_release=lambda x: (stroke_widget.previous_stroke(), update_info()))
            
            btn_next = Button(text='Next', size_hint_x=0.2)
            btn_next.bind(on_release=lambda x: (stroke_widget.next_stroke(), update_info()))
            
            def play_animation(instance):
                stroke_widget.clear()  # Reset to beginning
                stroke_widget.animate_strokes(0.44)  # 0.44s per stroke for smooth animation
            
            btn_animate = Button(text='Play', size_hint_x=0.25, 
                               background_color=(0.2, 0.7, 0.3, 1))  # Green color
            btn_animate.bind(on_release=play_animation)
            
            btn_clear = Button(text='Clear', size_hint_x=0.2)
            btn_clear.bind(on_release=lambda x: (stroke_widget.clear(), update_info()))
            
            btn_all = Button(text='All', size_hint_x=0.15)
            btn_all.bind(on_release=lambda x: (stroke_widget.show_all_strokes(), update_info()))
            
            controls.add_widget(btn_prev)
            controls.add_widget(btn_next)
            controls.add_widget(btn_animate)
            controls.add_widget(btn_clear)
            controls.add_widget(btn_all)
            
            content.add_widget(controls)
            
            # Close button row
            close_row = BoxLayout(size_hint_y=None, height=dp(40), spacing=dp(5))
            btn_close = Button(text='Close', size_hint_x=1,
                             background_color=(0.8, 0.2, 0.2, 1))  # Red color
            close_row.add_widget(btn_close)
            content.add_widget(close_row)
            
            # Create popup
            popup = Popup(
                title='Stroke Order',  # Removed kanji to avoid tofu text
                content=content,
                size_hint=(0.7, 0.7),  # More compact size
                auto_dismiss=True,
                separator_height=dp(2)
            )
            
            # Bind close button to dismiss popup
            btn_close.bind(on_release=popup.dismiss)
            popup.open()
            
        except Exception as e:
            Logger.error(f'Error showing stroke order: {e}')
            import traceback
            Logger.error(traceback.format_exc())
    
