    def _apply_known_to_vectors(self, entry_id, entry, selected_vector_types, popup):
        """Mark selected vectors as Known."""
        if not selected_vector_types:
            # Show error toast
            toast_content = Label(text='No vectors selected!', halign='center', valign='middle')
            toast = Popup(title='', content=toast_content, size_hint=(None, None), 
                         size=(dp(200), dp(80)), auto_dismiss=True, separator_height=0)
            toast.open()
            Clock.schedule_once(lambda dt: toast.dismiss(), 1.5)
            return
        
        Logger.info(f'EntryDetailScreen: Add to Known for vectors: {selected_vector_types}')
        
        try:
            conn = dict_db.init_db(get_db_path())
            entry_kind = entry.get('kind') or 'vocab'
            
            from datetime import datetime, timedelta
            now = datetime.utcnow()
            far_future = (now + timedelta(days=365 * 10)).isoformat()
            
            for vector_type in selected_vector_types:
                dict_db.update_srs_vector(conn, entry_id, entry_kind, {
                    'interval': 365,
                    'ease': 2.5,
                    'reps': 10,
                    'due_at': far_future,
                    'last_seen': now.isoformat(),
                    'streak': 10,
                }, vector_type)
            
            conn.close()
            Logger.info(f'EntryDetailScreen: Marked {len(selected_vector_types)} vectors as Known')

            # Immediately remove from queue if all vectors for this entry are
            # now learned.  This fires before the user sees the toast, so by
            # the time they tap "Start Lesson" the word is already gone.
            try:
                _app = App.get_running_app()
                if _app:
                    _app._clean_fully_done_queue_items()
            except Exception:
                pass

            popup.dismiss()
            
            # Check if we're in a study session and should skip the current entry
            session_type = getattr(self, '_current_session_type', None)
            session_entry_id = getattr(self, '_current_session_entry_id', None)
            
            if session_type and session_entry_id == entry_id:
                Logger.info(f'EntryDetailScreen: Skipping entry {entry_id} in {session_type} session')
                
                # Skip to next card based on session type
                if session_type == 'review':
                    self._skip_current_review()
                elif session_type == 'drill':
                    self._skip_current_drill()
                
                # Clear session markers
                self._current_session_type = None
                self._current_session_entry_id = None
            
            # Show confirmation
            toast_content = Label(
                text=f'Added {len(selected_vector_types)} vector(s) to Known!',
                halign='center',
                valign='middle'
            )
            toast = Popup(
                title='',
                content=toast_content,
                size_hint=(None, None),
                size=(dp(240), dp(80)),
                auto_dismiss=True,
                separator_height=0
            )
            toast.open()
            Clock.schedule_once(lambda dt: toast.dismiss(), 1.2)
            
            # Refresh UI
            try:
                self._refresh_srs_status()
            except Exception:
                pass
            
        except Exception as e:
            Logger.error(f'EntryDetailScreen: Error adding vectors to Known: {e}')
            import traceback
            Logger.error(traceback.format_exc())
            popup.dismiss()
    
    def _apply_reset_to_vectors(self, entry_id, entry, selected_vector_types, popup):
        """Reset selected vectors to Unknown."""
        if not selected_vector_types:
            # Show error toast
            toast_content = Label(text='No vectors selected!', halign='center', valign='middle')
            toast = Popup(title='', content=toast_content, size_hint=(None, None), 
                         size=(dp(200), dp(80)), auto_dismiss=True, separator_height=0)
            toast.open()
            Clock.schedule_once(lambda dt: toast.dismiss(), 1.5)
            return
        
        Logger.info(f'EntryDetailScreen: Reset vectors to Unknown: {selected_vector_types}')
        
        try:
            conn = dict_db.init_db(get_db_path())
            entry_kind = entry.get('kind') or 'vocab'
            cur = conn.cursor()
            
            # Get the SRS row
            srs_row = dict_db.get_srs_row(conn, entry_id)
            if srs_row:
                data = srs_row.get('data') or {}
                per_vector = data.get('per_vector', {})
                
                # Remove selected vectors from per_vector
                for vector_type in selected_vector_types:
                    if vector_type in per_vector:
                        del per_vector[vector_type]
                
                # Update or delete the SRS row
                if not per_vector:
                    # No vectors left, delete the entire SRS row
                    cur.execute('DELETE FROM srs WHERE entry_id = ?', (entry_id,))
                else:
                    # Update with remaining vectors
                    data['per_vector'] = per_vector
                    import json
                    cur.execute('UPDATE srs SET data = ? WHERE entry_id = ?', 
                               (json.dumps(data), entry_id))
                
                conn.commit()
            
            conn.close()
            Logger.info(f'EntryDetailScreen: Reset {len(selected_vector_types)} vectors to Unknown')
            
            popup.dismiss()
            
            # Show confirmation
            toast_content = Label(
                text=f'Reset {len(selected_vector_types)} vector(s) to Unknown!',
                halign='center',
                valign='middle'
            )
            toast = Popup(
                title='',
                content=toast_content,
                size_hint=(None, None),
                size=(dp(260), dp(80)),
                auto_dismiss=True,
                separator_height=0
            )
            toast.open()
            Clock.schedule_once(lambda dt: toast.dismiss(), 1.2)
            
            # Refresh UI
            try:
                self._refresh_srs_status()
            except Exception:
                pass
            
        except Exception as e:
            Logger.error(f'EntryDetailScreen: Error resetting vectors: {e}')
            import traceback
            Logger.error(traceback.format_exc())
            popup.dismiss()
    
    def _confirm_reset_status(self, entry_id, entry, parent_popup, current_status):
        """Show confirmation dialog before resetting SRS status."""
        confirm_layout = BoxLayout(orientation='vertical', padding=dp(16), spacing=dp(12))
        
        msg = Label(
            text=f'This word is currently "{current_status}".\n\nThis will reset this item\'s status to Unknown.\n\nAre you sure?',
            size_hint_y=None,
            halign='center',
            valign='middle'
        )
        msg.bind(
            width=lambda instance, value: setattr(instance, 'text_size', (value, None)),
            texture_size=lambda instance, value: setattr(instance, 'height', value[1])
        )
        confirm_layout.add_widget(msg)
        
        btn_box = BoxLayout(size_hint_y=None, height=dp(48), spacing=dp(8))
        
        cancel_btn = Button(text='Cancel')
        cancel_btn.background_normal = ''
        cancel_btn.background_color = (0.5, 0.5, 0.5, 1)
        cancel_btn.color = (1, 1, 1, 1)
        
        confirm_btn = Button(text='Reset to Unknown')
        confirm_btn.background_normal = ''
        confirm_btn.background_color = (0.6, 0.2, 0.2, 1)
        confirm_btn.color = (1, 1, 1, 1)
        
        confirm_popup = Popup(
            title='Confirm Reset',
            content=confirm_layout,
            size_hint=(None, None),
            size=(min(dp(360), Window.width*0.85), min(dp(250), Window.height*0.4)),
            auto_dismiss=False
        )
        
        cancel_btn.bind(on_release=lambda *_: confirm_popup.dismiss())
        confirm_btn.bind(on_release=lambda *_: (self._reset_entry_to_unknown(entry_id, entry, parent_popup, current_status), confirm_popup.dismiss()))
        
        btn_box.add_widget(cancel_btn)
        btn_box.add_widget(confirm_btn)
        confirm_layout.add_widget(btn_box)
        
        confirm_popup.open()
    
    def _add_entry_to_known(self, entry_id, entry, popup, previous_status='Unknown'):
        """Mark entry as Known (highest SRS level - will never appear in reviews)."""
        Logger.info(f'EntryDetailScreen: Add to Known requested for entry_id={entry_id} (was {previous_status})')
        
        try:
            conn = dict_db.init_db(get_db_path())
            entry_data = dict_db.get_entry_by_id(conn, entry_id)
            if not entry_data:
                Logger.error(f'EntryDetailScreen: Entry {entry_id} not found')
                conn.close()
                popup.dismiss()
                return
            
            entry_kind = entry_data.get('kind') or 'vocab'
            
            # Get or create SRS row
            from dictionary import learning as _learning
            
            # Get all vectors for this entry
            vectors = _learning.make_vectors_for_entries(conn, [entry_id], entry_kind)
            
            # Mark all vectors as "Known" with interval >= 180 days
            from datetime import datetime, timedelta
            now = datetime.utcnow()
            far_future = (now + timedelta(days=365 * 10)).isoformat()  # 10 years in future
            
            for vec in vectors:
                vector_type = vec.get('vector_type')
                dict_db.update_srs_vector(conn, entry_id, entry_kind, {
                    'interval': 365,  # 1 year interval (well above 180 threshold)
                    'ease': 2.5,
                    'reps': 10,  # Mark as well-practiced
                    'due_at': far_future,  # Far future so never due
                    'last_seen': now.isoformat(),
                    'streak': 10,
                }, vector_type)
            
            conn.close()
            Logger.info(f'EntryDetailScreen: Marked entry {entry_id} as Known ({len(vectors)} vectors)')
            
            popup.dismiss()
            
            # Show brief confirmation
            toast_content = Label(
                text='Added to Known!',
                halign='center',
                valign='middle'
            )
            toast = Popup(
                title='',
                content=toast_content,
                size_hint=(None, None),
                size=(dp(180), dp(80)),
                auto_dismiss=True,
                separator_height=0
            )
            toast.open()
            Clock.schedule_once(lambda dt: toast.dismiss(), 1.2)
            
            # Refresh SRS status display if on entry detail screen
            try:
                self._refresh_srs_status()
            except Exception:
                pass
            
        except Exception as e:
            Logger.error(f'EntryDetailScreen: Error adding to Known: {e}')
            import traceback
            Logger.error(traceback.format_exc())
            popup.dismiss()
    
    def _reset_entry_to_unknown(self, entry_id, entry, popup, previous_status):
        """Reset entry to Unknown status (remove from SRS completely)."""
        Logger.info(f'EntryDetailScreen: Reset to Unknown requested for entry_id={entry_id} (was {previous_status})')
        
        try:
            conn = dict_db.init_db(get_db_path())
            
            # Delete the SRS row completely to reset to Unknown
            cur = conn.cursor()
            cur.execute('DELETE FROM srs WHERE entry_id = ?', (entry_id,))
            conn.commit()
            conn.close()
            
            Logger.info(f'EntryDetailScreen: Reset entry {entry_id} to Unknown')
            
            popup.dismiss()
            
            # Show brief confirmation
            toast_content = Label(
                text='Reset to Unknown!',
                halign='center',
                valign='middle'
            )
            toast = Popup(
                title='',
                content=toast_content,
                size_hint=(None, None),
                size=(dp(200), dp(80)),
                auto_dismiss=True,
                separator_height=0
            )
            toast.open()
            Clock.schedule_once(lambda dt: toast.dismiss(), 1.2)
            
            # Refresh SRS status display if on entry detail screen
            try:
                self._refresh_srs_status()
            except Exception:
                pass
            
        except Exception as e:
            Logger.error(f'EntryDetailScreen: Error resetting to Unknown: {e}')
            import traceback
            Logger.error(traceback.format_exc())
            popup.dismiss()
    
    def _refresh_srs_status(self):
        """Refresh the SRS status display after changes."""
        if not self.entry_id:
            return
        # Reload the entry to refresh UI
        self.load_entry(self.entry_id)
    
    def _add_entry_to_queue(self, entry_id, entry, popup):
        """Add entry to queue."""
        Logger.info(f'EntryDetailScreen: Add to queue requested for entry_id={entry_id}')
        
        app = App.get_running_app()
        if not app:
            Logger.error('EntryDetailScreen: Could not get app instance')
            popup.dismiss()
            return
        
        # Check if already in queue
        if hasattr(app, '_lesson_queue') and entry_id in app._lesson_queue:
            # Show "Already in Queue" message
            from kivy.uix.label import Label
            message_content = BoxLayout(orientation='vertical', padding=dp(12), spacing=dp(8))
            
            message_label = Label(
                text='Already in SRS/Queue',
                size_hint_y=None,
                height=dp(40),
                halign='center',
                valign='middle',
                font_size='16sp'
            )
            message_label.bind(size=message_label.setter('text_size'))
            message_content.add_widget(message_label)
            
            ok_btn = Button(text='OK', size_hint_y=None, height=dp(40))
            ok_btn.background_normal = ''
            ok_btn.background_color = (0.5, 0.5, 0.5, 1)
            ok_btn.color = (1, 1, 1, 1)
            
            message_popup = Popup(
                title='Already in Queue',
                content=message_content,
                size_hint=(0.7, 0.3)
            )
            
            ok_btn.bind(on_release=lambda *_: message_popup.dismiss())
            message_content.add_widget(ok_btn)
            message_popup.open()
            popup.dismiss()
            return
        
        # Check if entry already has SRS data
        try:
            conn = dict_db.init_db(get_db_path())
            cursor = conn.cursor()
            
            cursor.execute('SELECT DISTINCT entry_id FROM srs')
            entry_ids = [r[0] for r in cursor.fetchall()]
            conn.close()
            
            if entry_id in entry_ids:
                # Show "Already in SRS" message - don't allow adding
                from kivy.uix.label import Label
                message_content = BoxLayout(orientation='vertical', padding=dp(12), spacing=dp(8))
                
                message_label = Label(
                    text='Already in SRS/Queue',
                    size_hint_y=None,
                    height=dp(40),
                    halign='center',
                    valign='middle',
                    font_size='16sp'
                )
                message_label.bind(size=message_label.setter('text_size'))
                message_content.add_widget(message_label)
                
                ok_btn = Button(text='OK', size_hint_y=None, height=dp(40))
                ok_btn.background_normal = ''
                ok_btn.background_color = (0.5, 0.5, 0.5, 1)
                ok_btn.color = (1, 1, 1, 1)
                
                message_popup = Popup(
                    title='Already in SRS',
                    content=message_content,
                    size_hint=(0.7, 0.3)
                )
                
                ok_btn.bind(on_release=lambda *_: message_popup.dismiss())
                message_content.add_widget(ok_btn)
                message_popup.open()
                popup.dismiss()
                return
        except Exception as e:
            Logger.error(f'EntryDetailScreen: Error checking SRS: {e}')
        
        # Add to queue
        if not hasattr(app, '_lesson_queue'):
            app._lesson_queue = []
        
        if entry_id not in app._lesson_queue:
            def _do_add(position):
                if entry_id not in app._lesson_queue:
                    if position == 'front':
                        app._lesson_queue.insert(0, entry_id)
                    else:
                        app._lesson_queue.append(entry_id)
                    app._save_lesson_queue()
                    Logger.info(f'EntryDetailScreen: Added entry {entry_id} to queue')
                popup.dismiss()
                try:
                    sm = app._get_screen_manager()
                    if sm and sm.current == 'lessons':
                        ls = app.root.ids.get('lessons_screen') if getattr(app, 'root', None) else None
                        if ls and getattr(ls, '_current_lessons_view', None) == 'queue':
                            Clock.schedule_once(lambda dt: app.show_my_queue(getattr(ls, '_queue_filter', 'all'), record_nav=False), 0.1)
                except Exception as e:
                    Logger.error(f'EntryDetailScreen: Error refreshing queue: {e}')
            app._show_queue_position_popup(_do_add)

