    def on_settings_search_change(self, search_text):
        """Filter tools/settings items based on search text."""
        try:
            sm = self._get_screen_manager()
            if not sm:
                return
            
            current_screen = sm.current
            search_lower = search_text.lower().strip()
            
            # Define searchable items for each screen
            # Tools screen has: Drill, Translator
            tools_items = {
                'tools_drill_btn': ['drill', 'practice', 'exercise'],
                'tools_translator_btn': ['translator', 'translate', 'translation']
            }
            
            # Settings screen has all settings buttons
            settings_items = {
                'settings_my_stats_btn': ['my stats', 'stats', 'statistics', 'progress', 'words known', 'cards done', 'reading stats'],
                'settings_study_settings_btn': ['study settings', 'study', 'settings', 'tts', 'voice', 'weak items', 'stats', 'counter'],
                'settings_sync_btn': ['sign in', 'sync', 'account', 'login', 'sign out'],
                'settings_download_data_btn': ['download', 'data', 'database', 'update'],
                'settings_licenses_btn': ['licenses', 'credits', 'attribution', 'open source'],
                'settings_report_btn': ['report', 'problem', 'bug', 'issue', 'feedback'],
                'settings_full_version_btn': ['full version', 'upgrade', 'premium', 'subscribe', 'handwriting']
            }
            
            # Choose which items to filter based on current screen
            if current_screen == 'tools':
                # Tools screen
                items = tools_items
            elif current_screen == 'settings':
                # Settings screen
                items = settings_items
            else:
                return
            
            # Show/hide items based on search
            for item_id, keywords in items.items():
                widget = self.root.ids.get(item_id)
                if widget:
                    if not search_text:
                        # No search - show all
                        widget.opacity = 1
                        widget.disabled = False
                        widget.size_hint_y = None
                        widget.height = dp(56)
                    else:
                        # Check if any keyword matches
                        matches = any(search_lower in keyword for keyword in keywords)
                        if matches:
                            widget.opacity = 1
                            widget.disabled = False
                            widget.size_hint_y = None
                            widget.height = dp(56)
                        else:
                            widget.opacity = 0
                            widget.disabled = True
                            widget.size_hint_y = None
                            widget.height = 0
                            
        except Exception as e:
            Logger.error(f'Settings search error: {e}')
            import traceback
            Logger.error(traceback.format_exc())

    def _get_reviews_due_count(self) -> int:
        """Count how many review vectors are due now."""
        conn = None
        try:
            conn = dict_db.init_db(get_db_path())
            vectors = dict_db.get_due_review_vectors(conn)
            
            # Filter OUT handwriting vectors if handwriting mode is disabled
            if not self.handwriting_mode:
                vectors = [v for v in vectors if v.get('vector_type') != 'handwriting']
            
            # Filter for handwriting-only mode if enabled
            if self.handwriting_only_mode:
                vectors = [v for v in vectors if v.get('vector_type') == 'handwriting']
            
            return len(vectors)
        except Exception as e:
            Logger.warning(f'Study: Error getting reviews due count: {e}')
            return 0
        finally:
            if conn:
                try:
                    conn.close()
                except Exception as e:
                    Logger.warning(f'Study: Error closing connection: {e}')

    def _get_lessons_count(self) -> int:
        """Count how many new items are available (limited by daily_new_items_limit)."""
        try:
            lesson_queue = getattr(self, '_lesson_queue', [])
            if not lesson_queue:
                return 0
            
            # Get the daily limit
            daily_limit = int(getattr(self, 'daily_new_items_limit', 8))
            
            # Helper to check if entry has new vectors (not in SRS)
            def has_new_vectors(conn, entry_id):
                """Check if entry has any vectors not yet in SRS."""
                import json
                cursor = conn.cursor()
                
                # Get entry kind (+ kanji/kana for kana detection)
                cursor.execute('SELECT kind, kanji, kana FROM entries WHERE id = ?', (entry_id,))
                row = cursor.fetchone()
                if not row:
                    return False
                entry_kind = self._effective_entry_kind(row[0], row[1], row[2])
                
                # Check if this entry+kind has SRS data
                cursor.execute('SELECT data FROM srs WHERE entry_id = ?', (entry_id,))
                srs_row = cursor.fetchone()
                
                if not srs_row:
                    return True  # No SRS = new entry
                
                srs_data = json.loads(srs_row[0])
                per_kind = srs_data.get('per_kind', {})
                
                # If entry+kind not in SRS, it has new vectors
                return entry_kind not in per_kind
            
            # Count entries with new vectors
            conn = None
            try:
                conn = dict_db.init_db(get_db_path())
                new_entry_count = 0
                
                for item in lesson_queue:
                    # Stop counting if we've reached the limit
                    if new_entry_count >= daily_limit:
                        break
                    
                    if isinstance(item, str) and item.startswith('reading:'):
                        # Reading materials count as 1 session item
                        new_entry_count += 1
                    elif isinstance(item, str) and item.startswith('graded:'):
                        # Graded readings count as 1 session item
                        new_entry_count += 1
                    elif isinstance(item, int):
                        if has_new_vectors(conn, item):
                            new_entry_count += 1
                    elif isinstance(item, str) and item.startswith('custom_lesson:'):
                        # Custom lesson - count entries with new vectors
                        try:
                            lesson_id = int(item.split(':')[1])
                            entry_ids = dict_db.get_custom_lesson_entry_ids(conn, lesson_id)
                            for eid in entry_ids:
                                if new_entry_count >= daily_limit:
                                    break
                                if has_new_vectors(conn, eid):
                                    new_entry_count += 1
                        except Exception:
                            pass
                    else:
                        # Lesson file - estimate ~5 items, check actual
                        try:
                            import json
                            from pathlib import Path
                            lesson_path = Path(item)
                            if lesson_path.exists():
                                with open(lesson_path, 'r', encoding='utf-8') as f:
                                    lesson_data = json.load(f)
                                
                                if lesson_data.get('lesson_type') == 'grammar':
                                    eid = lesson_data.get('entry_id')
                                    if not eid:
                                        items = lesson_data.get('items', [])
                                        if items:
                                            eid = items[0].get('entry_id')
                                    if eid and has_new_vectors(conn, eid):
                                        new_entry_count += 1
                                else:
                                    items = lesson_data.get('items', [])
                                    for lesson_item in items:
                                        if new_entry_count >= daily_limit:
                                            break
                                        entry_id = lesson_item.get('entry_id')
                                        if entry_id and has_new_vectors(conn, entry_id):
                                            new_entry_count += 1
                        except Exception:
                            # Fallback: estimate 5 new items if can't read file
                            new_entry_count += min(5, daily_limit - new_entry_count)
                
                return new_entry_count
            finally:
                if conn:
                    try:
                        conn.close()
                    except Exception:
                        pass
                        
        except Exception as e:
            Logger.error(f'Study: Error counting lessons: {e}')
            return 0

    @staticmethod
    def _effective_entry_kind(db_kind, kanji, kana):
        """Return the effective kind, accounting for kana chars stored as kind='kanji'.

        Kana characters (あ, ア, etc.) are stored in the DB with kind='kanji'
        but ``make_vectors_from_row`` overrides them to kind='kana' so that
        ``show_kana``/``show_romaji`` vectors are created.  SRS data is keyed by
        the effective kind, so any code comparing the DB kind against per_kind
        must apply the same normalisation.
        """
        if db_kind == 'kanji' and kanji and kana and kanji == kana and len(kanji) <= 2:
            ch = kanji[0]
            if ('\u3040' <= ch <= '\u309F') or ('\u30A0' <= ch <= '\u30FF'):
                return 'kana'
        return db_kind

    def _clean_fully_done_queue_items(self):
        """Remove queue items whose study vectors are all already learned.

        Handles every queue item type: direct entry IDs (int), lesson file
        paths, custom_lesson:ID, reading:ID, and graded:path.  An entry is
        considered *done* when every applicable vector type (filtered by the
        current handwriting mode) is either drill-promoted (in per_kind) or
        manually marked known (per_vector with interval >= 180).

        A lesson-file / custom-lesson queue item is removed only when ALL
        entries inside it are done.
        """
        try:
            lesson_queue = getattr(self, '_lesson_queue', [])
            if not lesson_queue:
                return
            import json as _json
            from pathlib import Path as _Path
            from dictionary.learning import make_vectors_from_row as _make_vr

            conn = dict_db.init_db(get_db_path())
            cursor = conn.cursor()
            items_to_remove = []

            def _entry_is_done(entry_id):
                """Return True if *entry_id*'s applicable vectors are all learned."""
                cursor.execute(
                    'SELECT kind, kanji, kana, study_vectors FROM entries WHERE id = ?',
                    (entry_id,))
                erow = cursor.fetchone()
                if not erow:
                    return False
                db_kind, kanji, kana, study_vectors_str = erow
                eff_kind = self._effective_entry_kind(db_kind, kanji, kana)

                cursor.execute('SELECT data FROM srs WHERE entry_id = ?', (entry_id,))
                srs_row = cursor.fetchone()
                if not srs_row:
                    return False  # No SRS yet → still new

                srs_data = _json.loads(srs_row[0])

                # Build expected vector types, filtered by handwriting mode
                expected_vecs = _make_vr(entry_id, db_kind, kanji, kana, '', study_vectors_str)
                filtered_types = {v['vector_type'] for v in expected_vecs}
                if self.handwriting_only_mode:
                    filtered_types = {vt for vt in filtered_types if vt == 'handwriting'}
                elif not self.handwriting_mode:
                    filtered_types = {vt for vt in filtered_types if vt != 'handwriting'}
                if not filtered_types:
                    return True  # Nothing expected → consider done

                # Drill promotion path
                pk = srs_data.get('per_kind', {}).get(eff_kind, {})
                if pk and filtered_types:
                    promoted_set = set(pk.get('promoted_vectors', []))
                    is_done = False
                    if eff_kind == 'grammar':
                        from dictionary.learning import GRAMMAR_EXERCISES_PER_ENTRY as _GEPE
                        gc = [p for p in promoted_set if p.startswith('grammar-cat:')]
                        gs = [p for p in promoted_set if p.startswith('grammar-scramble:')]
                        gt = [p for p in promoted_set if p.startswith('grammar-translate:')]
                        gd = [p for p in promoted_set if p.startswith('grammar-dictation:')]
                        if (len(gc) >= _GEPE and len(gs) >= _GEPE
                                and len(gt) >= _GEPE and len(gd) >= _GEPE):
                            is_done = True
                    elif filtered_types.issubset(promoted_set):
                        is_done = True
                    if is_done:
                        return True

                # Manual "Mark as Known" path: per-vector with interval >= 180
                per_vector = srs_data.get('per_vector', {})
                if per_vector and filtered_types and all(
                    (per_vector.get(vt, {}).get('interval', 0) or 0) >= 180
                    for vt in filtered_types
                ):
                    return True

                return False

            try:
                for qitem in lesson_queue[:]:
                    # ── reading material ──
                    if isinstance(qitem, str) and qitem.startswith('reading:'):
                        try:
                            rmid = int(qitem.split(':')[1])
                            from reading.db_schema import get_reading_material, get_read_ranges
                            mat = get_reading_material(get_db_path(), rmid)
                            if mat is None:
                                items_to_remove.append(qitem)
                                continue
                            tokens = mat.get('tokens', [])
                            ranges = get_read_ranges(get_db_path(), rmid)
                            if tokens and ranges:
                                ls_screen = self.root.ids.get('lessons_screen')
                                if ls_screen and hasattr(ls_screen, '_is_reading_fully_read'):
                                    if ls_screen._is_reading_fully_read(tokens, ranges):
                                        items_to_remove.append(qitem)
                        except Exception:
                            pass
                        continue

                    # ── graded reading ──
                    if isinstance(qitem, str) and qitem.startswith('graded:'):
                        try:
                            _grfp = qitem[len('graded:'):]
                            _grfn = str(_grfp).rsplit('\\', 1)[-1].rsplit('/', 1)[-1]
                            ls_screen = self.root.ids.get('lessons_screen')
                            if ls_screen and hasattr(ls_screen, '_get_graded_material_id'):
                                _mid = ls_screen._get_graded_material_id(_grfn)
                                if _mid is not None:
                                    from reading.db_schema import get_reading_material, get_read_ranges
                                    mat = get_reading_material(get_db_path(), _mid)
                                    if mat:
                                        tokens = mat.get('tokens', [])
                                        ranges = get_read_ranges(get_db_path(), _mid)
                                        if tokens and ranges:
                                            if ls_screen._is_reading_fully_read(tokens, ranges):
                                                items_to_remove.append(qitem)
                        except Exception:
                            pass
                        continue

                    # ── direct entry ID ──
                    if isinstance(qitem, int):
                        if _entry_is_done(qitem):
                            items_to_remove.append(qitem)
                        continue

                    # ── custom lesson ──
                    if isinstance(qitem, str) and qitem.startswith('custom_lesson:'):
                        try:
                            lesson_id = int(qitem.split(':')[1])
                            entry_ids = dict_db.get_custom_lesson_entry_ids(conn, lesson_id)
                            if entry_ids and all(_entry_is_done(eid) for eid in entry_ids):
                                items_to_remove.append(qitem)
                        except Exception:
                            pass
                        continue

                    # ── lesson file path ──
                    if isinstance(qitem, str):
                        try:
                            lesson_path = _Path(qitem)
                            if not lesson_path.exists():
                                continue
                            with open(lesson_path, 'r', encoding='utf-8') as f:
                                lesson_data = _json.load(f)
                            if lesson_data.get('lesson_type') == 'grammar':
                                eid = lesson_data.get('entry_id')
                                if not eid:
                                    items = lesson_data.get('items', [])
                                    if items:
                                        eid = items[0].get('entry_id')
                                if eid and _entry_is_done(eid):
                                    items_to_remove.append(qitem)
                            else:
                                items = lesson_data.get('items', [])
                                entry_ids = [it.get('entry_id') for it in items if it.get('entry_id')]
                                if entry_ids and all(_entry_is_done(eid) for eid in entry_ids):
                                    items_to_remove.append(qitem)
                        except Exception:
                            pass
                        continue
            finally:
                conn.close()

            if items_to_remove:
                for it in items_to_remove:
                    if it in self._lesson_queue:
                        self._lesson_queue.remove(it)
                        Logger.info(f'Study: Passive cleanup removed fully-done item from queue: {it}')
                self._save_lesson_queue()
        except Exception as e:
            Logger.warning(f'Study: Queue passive cleanup error: {e}')

    def on_study_settings_search_change(self, search_text):
        """Filter study settings based on search text."""
        try:
            app_root = getattr(self, 'root', None)
            if app_root is None:
                return
            
            search_lower = search_text.lower().strip()
            
            # Define searchable settings with keywords
            settings_items = {
                'study_settings_home_screen': ['home', 'screen', 'start', 'default', 'dictionary', 'study', 'launch'],
                # 'study_settings_tts_voice': ['tts', 'voice', 'speech', 'audio', 'sound', 'female', 'male'],  # hidden until implemented
                'study_settings_remember_position': ['remember', 'my stuff', 'position', 'tab', 'keep'],
                'study_settings_hide_stats': ['hide', 'stats', 'statistics', 'counter', 'review counter', 'during study'],
                'study_settings_max_weak': ['max', 'weak', 'items', 'unstable', 'low stability'],
                'study_settings_erase_srs': ['erase', 'reset', 'srs', 'data', 'delete', 'clear', 'wipe'],
            }
            
            # If search is empty, show all
            if not search_lower:
                for item_id in settings_items.keys():
                    item = app_root.ids.get(item_id)
                    if item:
                        item.opacity = 1
                        item.height = dp(56)
                        item.disabled = False
                return
            
            # Filter items based on keyword matching
            for item_id, keywords in settings_items.items():
                item = app_root.ids.get(item_id)
                if item:
                    # Check if search text is in any keyword
                    matches = any(search_lower in keyword for keyword in keywords)
                    
                    if matches:
                        # Show item
                        item.opacity = 1
                        item.height = dp(56)
                        item.disabled = False
                    else:
                        # Hide item
                        item.opacity = 0
                        item.height = 0
                        item.disabled = True
        
        except Exception as e:
            Logger.warning(f'Study settings search error: {e}')

    def _update_study_stats(self):
        """Update the Study screen stats labels."""
        try:
            Logger.info('Study: _update_study_stats called')
            if not getattr(self, 'root', None):
                Logger.info('Study: No root widget')
                return
            
            # Check for daily reset
            self._check_daily_reset()
            
            # Update reviews count
            reviews_count = self._get_reviews_due_count()
            Logger.info(f'Study: Reviews count = {reviews_count}')
            
            # Update weak words count
            try:
                conn = dict_db.init_db(get_db_path())
                weak_vectors = dict_db.get_weak_vectors_for_drill(
                    conn, 
                    threshold=3, 
                    limit=9999,
                    exclude_vector_ids=self._drilled_today
                )
                
                # Filter OUT handwriting vectors if handwriting mode is disabled
                if not self.handwriting_mode:
                    weak_vectors = [v for v in weak_vectors if v.get('vector_type') != 'handwriting']
                
                # Filter for handwriting-only mode if enabled
                if self.handwriting_only_mode:
                    weak_vectors = [v for v in weak_vectors if v.get('vector_type') == 'handwriting']
                
                weak_count = len(weak_vectors)
                conn.close()
                Logger.info(f'Study: Weak words count = {weak_count} (handwriting_only={self.handwriting_only_mode})')
            except Exception as e:
                Logger.error(f'Study: Error counting weak words: {e}')
                weak_count = 0
            
            # Passive queue cleanup: remove entries that are fully in SRS already
            self._clean_fully_done_queue_items()

            # Update lessons count
            lessons_count = self._get_lessons_count()
            Logger.info(f'Study: Lessons count = {lessons_count}')
            
            # Access labels using root.ids (which contains all ids from KV file)
            reviews_label = self.root.ids.get('study_reviews_count')
            if reviews_label:
                reviews_label.text = str(reviews_count)
                Logger.info(f'Study: Updated reviews label to {reviews_count}')
            else:
                Logger.info('Study: No reviews label found')
            
            # Weak words count used for action button logic (label removed from UI)
            Logger.info(f'Study: Weak words count for button logic = {weak_count}')
            
            # Update lessons label
            lessons_label = self.root.ids.get('study_lessons_count')
            if lessons_label:
                lessons_label.text = str(lessons_count)
                Logger.info(f'Study: Updated lessons label to {lessons_count}')
            
            # Update action button
            self._update_study_action_button(reviews_count, weak_count, lessons_count)
            
        except Exception as e:
            Logger.error(f'Study: Error updating stats: {e}')

    def _update_study_action_button(self, reviews_count, weak_count, lessons_count):
        """Update the Study action button text and handler based on what's available."""
        try:
            button = self.root.ids.get('study_action_button')
            if not button:
                return
            
            # Unbind existing handlers
            button.unbind(on_release=self.on_study_action_button)
            button.unbind(on_press=self._study_button_press)
            button.unbind(on_release=self._study_button_release)
            
            # Priority logic: Reviews are always highest priority
            if reviews_count > 0:
                button.text = 'Start Review'
                button.disabled = False
                self._set_study_button_color(button, 'blue')
                button.bind(on_press=self._study_button_press)
                button.bind(on_release=lambda x: (self._study_button_release(x), self._start_session_with_loading(self.start_review_session, 'Loading Reviews...')))
                Logger.info('Study: Button set to Start Review')
                
            # Check for incomplete drill session to resume (only if no reviews due)
            elif hasattr(self, '_incomplete_drill') and self._incomplete_drill:
                incomplete = self._incomplete_drill
                mode = incomplete.get('mode')
                
                if mode == 'weak_words':
                    button.text = 'Resume Weak Words'
                    button.disabled = False
                    self._set_study_button_color(button, 'yellow')
                    button.bind(on_press=self._study_button_press)
                    button.bind(on_release=lambda x: (self._study_button_release(x), self._start_session_with_loading(self._resume_incomplete_drill, 'Resuming...')))
                    Logger.info('Study: Button set to Resume Weak Words')
                    return
                elif mode == 'lesson':
                    button.text = 'Resume Lesson'
                    button.disabled = False
                    self._set_study_button_color(button, 'green')
                    button.bind(on_press=self._study_button_press)
                    button.bind(on_release=lambda x: (self._study_button_release(x), self._start_session_with_loading(self._resume_incomplete_drill, 'Resuming...')))
                    Logger.info('Study: Button set to Resume Lesson')
                    return
                
            elif self._reviews_completed_this_session and weak_count > 0 and not self._weak_words_completed_this_session:
                button.text = 'Drill Weak Words'
                button.disabled = False
                self._set_study_button_color(button, 'yellow')
                button.bind(on_press=self._study_button_press)
                button.bind(on_release=lambda x: (self._study_button_release(x), self._start_session_with_loading(self.start_weak_words_drill, 'Loading Weak Words...')))
                Logger.info('Study: Button set to Drill Weak Words')
                
            elif lessons_count > 0:
                # Check if first queue item is a reading
                _first_q = self._lesson_queue[0] if hasattr(self, '_lesson_queue') and self._lesson_queue else None
                _is_reading = isinstance(_first_q, str) and (_first_q.startswith('reading:') or _first_q.startswith('graded:'))
                button.text = 'Start Reading' if _is_reading else 'Start Next Lesson'
                button.disabled = False
                self._set_study_button_color(button, 'green')
                button.bind(on_press=self._study_button_press)
                _loading_text = 'Opening Reading...' if _is_reading else 'Loading Lesson...'
                button.bind(on_release=lambda x, lt=_loading_text: (self._study_button_release(x), self._start_session_with_loading(self.start_lesson_drill, lt)))
                Logger.info(f'Study: Button set to {"Start Reading" if _is_reading else "Start Next Lesson"}')
                
            else:
                button.text = 'Nothing to Study'
                button.disabled = True
                button.background_color = (0.30, 0.30, 0.32, 1)
                Logger.info('Study: Button set to Nothing to Study')
                
        except Exception as e:
            Logger.error(f'Study: Error updating action button: {e}')
    
    def _set_study_button_color(self, button, color_name):
        """Set study button base color and store for press effects."""
        colors = {
            'blue': (0.25, 0.35, 0.50, 1),
            'yellow': (0.85, 0.45, 0.15, 1),
            'green': (0.20, 0.55, 0.30, 1)
        }
        button.background_color = colors.get(color_name, colors['blue'])
        button._base_color = colors.get(color_name, colors['blue'])
    
    def _study_button_press(self, button):
        """Darken button by 25% on press."""
        if hasattr(button, '_base_color'):
            r, g, b, a = button._base_color
            button.background_color = (r * 0.75, g * 0.75, b * 0.75, a)
    
    def _study_button_release(self, button):
        """Restore button to base color on release."""
        if hasattr(button, '_base_color'):
            button.background_color = button._base_color

    def _show_study_loading(self, text='Loading...'):
        """Show a full-screen loading overlay on the study screen."""
        try:
            sm = self._get_screen_manager()
            if not sm:
                return
            study_screen = sm.get_screen('study')
            if not study_screen:
                return
            # Avoid duplicates
            self._hide_study_loading()
            from kivy.uix.floatlayout import FloatLayout
            from kivy.uix.label import Label
            from kivy.graphics import Color, Rectangle
            overlay = FloatLayout(size_hint=(1, 1))
            with overlay.canvas.before:
                Color(0, 0, 0, 0.55)
                bg = Rectangle(pos=overlay.pos, size=overlay.size)
            overlay.bind(pos=lambda o, v: setattr(bg, 'pos', v))
            overlay.bind(size=lambda o, v: setattr(bg, 'size', v))
            label = Label(
                text=text,
                font_name='fonts/NotoSansJP-Regular.ttf',
                font_size='20sp',
                color=(0.90, 0.88, 0.85, 1),
                pos_hint={'center_x': 0.5, 'center_y': 0.5}
            )
            overlay.add_widget(label)
            study_screen.add_widget(overlay)
            self._study_loading_overlay = overlay
        except Exception as e:
            Logger.error(f'Study: Error showing loading overlay: {e}')

    def _hide_study_loading(self):
        """Remove the study loading overlay if present."""
        try:
            if hasattr(self, '_study_loading_overlay') and self._study_loading_overlay:
                parent = self._study_loading_overlay.parent
                if parent:
                    parent.remove_widget(self._study_loading_overlay)
                self._study_loading_overlay = None
        except Exception as e:
            Logger.error(f'Study: Error hiding loading overlay: {e}')

    def _start_session_with_loading(self, start_fn, loading_text='Loading...'):
        """Show loading overlay then defer session start by one frame."""
        self._show_study_loading(loading_text)
        from kivy.clock import Clock
        Clock.schedule_once(lambda dt: start_fn(), 0.05)

    def _resume_incomplete_drill(self):
        """Resume an incomplete drill session."""
        try:
            if not hasattr(self, '_incomplete_drill') or not self._incomplete_drill:
                Logger.warning('Resume: No incomplete drill to resume')
                self._hide_study_loading()
                return
            
            incomplete = self._incomplete_drill
            mode = incomplete.get('mode')
            session_id = incomplete.get('session_id')
            
            Logger.info(f'Resume: Resuming {mode} drill session {session_id}')
            
            # Restore session state
            self._current_drill_session_id = session_id
            self._drill_mode = mode
            
            # Clear incomplete drill flag
            self._incomplete_drill = None
            
            # Navigate to drill screen
            sm = self._get_screen_manager()
            if sm:
                sm.current = 'drill'
                self._hide_study_loading()
                # Load the session and update UI
                Clock.schedule_once(lambda dt: self._load_and_resume_drill_session(), 0.1)
            
        except Exception as e:
            Logger.error(f'Resume: Error resuming incomplete drill: {e}')
            self._hide_study_loading()
    
    def _load_and_resume_drill_session(self):
        """Load the incomplete drill session and update UI."""
        try:
            conn = dict_db.init_db(get_db_path())
            session = dict_db.get_learning_session(conn, self._current_drill_session_id)

            if not session:
                Logger.error('Resume: Session not found')
                conn.close()
                return

            # Restore _drill_completed_count from session history
            # (count promoted non-filler, non-already_in_srs vectors)
            history = session.get('data', {}).get('history', [])
            promoted = sum(
                1 for h in history
                if h.get('result', {}).get('status') == 'promoted'
            )
            self._drill_completed_count = promoted
            Logger.info(f'Resume: Restored drill_completed_count = {promoted}')

            # Restore grammar exercise pools for grammar entries still in session
            data = session.get('data', {})
            all_vecs = data.get('in_progress', []) + data.get('pending', []) + data.get('remaining_vectors', [])
            grammar_eids = {v['entry_id'] for v in all_vecs if v.get('kind') == 'grammar'}
            if grammar_eids:
                import dictionary.learning as learning
                pools = {}
                for eid in grammar_eids:
                    pool = learning.load_grammar_exercise_pool(conn, eid)
                    if pool:
                        pools[eid] = pool
                if pools:
                    self._grammar_exercise_pools = pools
                    Logger.info(f'Resume: Restored grammar pools for {len(pools)} entries')

            conn.close()

            # Use the standard drill loader which handles lesson sessions
            # (pending/in_progress/remaining_vectors, info cards, progressive
            # unlock, batched flow, etc.) correctly.
            self._load_current_drill()

        except Exception as e:
            Logger.error(f'Resume: Error loading session: {e}')

    def on_study_action_button(self):
        """Handle Study screen action button press (legacy - now handled dynamically)."""
        try:
            Logger.info('Study: Action button pressed')
            # Start review session
            self.start_review_session()
        except Exception as e:
            Logger.error(f'Study: Error handling action button: {e}')
    
    def start_review_session(self):
        """Start a review session with due vectors."""
        # NOTE: _hide_study_loading() is called AFTER sm.current = 'review' below
        # to avoid a brief flash of the study screen between overlay removal and
        # screen switch.
        # Silently warm up the handwriting recognizer in the background so the
        # first handwriting question loads without a blocking overlay.
        if getattr(self, 'handwriting_mode', False) or getattr(self, 'handwriting_only_mode', False):
            self._prewarm_recognizer_silent()
        conn = None
        review_vectors = []
        try:
            # Reset session flags for new review
            self._reviews_completed_this_session = False
            self._weak_words_completed_this_session = False
            
            conn = dict_db.init_db(get_db_path())
            review_vectors = dict_db.get_due_review_vectors(conn)
        except Exception as e:
            Logger.error(f'Review: Error starting session: {e}')
            self._hide_study_loading()
            return
        finally:
            if conn:
                try:
                    conn.close()
                except Exception as e:
                    Logger.warning(f'Review: Error closing connection: {e}')
        
        if not review_vectors:
            Logger.info('Review: No vectors due for review')
            self._hide_study_loading()
            return
        
        # Filter OUT handwriting vectors if handwriting mode is disabled
        if not self.handwriting_mode:
            review_vectors = [v for v in review_vectors if v.get('vector_type') != 'handwriting']
            Logger.info(f'Review: Excluded handwriting - {len(review_vectors)} vectors remain')
            if not review_vectors:
                Logger.info('Review: No non-handwriting vectors due')
                self._hide_study_loading()
                return
        
        # Filter for handwriting-only mode if enabled
        if self.handwriting_only_mode:
            review_vectors = [v for v in review_vectors if v.get('vector_type') == 'handwriting']
            Logger.info(f'Review: Filtered to {len(review_vectors)} handwriting vectors')
            if not review_vectors:
                Logger.info('Review: No handwriting vectors due')
                self._hide_study_loading()
                return
        
        Logger.info(f'Review: Starting session with {len(review_vectors)} vectors')
        self._review_queue = list(review_vectors)  # List of vector dicts
        self._review_index = 0
        self._review_history = []  # Track completed reviews for undo
        self._undo_confirm = False  # Track undo confirmation state
        self._review_wrong_counts = {}  # Track consecutive wrong answers per vector
        self._review_graded_vectors = set()  # Track which vectors have been graded already
        
        # Navigate to review screen
        sm = self._get_screen_manager()
        if sm:
            sm.current = 'review'
            self._hide_study_loading()
            self._load_current_review()
    
    def _load_current_review(self):
        """Load the current review vector into the UI."""
        try:
            if self._review_index >= len(self._review_queue):
                self._finish_review_session()
                return
            
            vector = self._review_queue[self._review_index]
            entry_id = vector['entry_id']
            vector_type = vector['vector_type']
            prompt = vector['prompt']
            answer = vector['answer']
            
            Logger.info(f'Review: Loading vector {vector_type} for entry {entry_id}')
            
            # Handle handwriting vectors
            if vector_type == 'handwriting':
                # Clear cached canvas height so each new word re-measures fresh.
                self._review_hw_capped_height = None
                self._load_handwriting_review(vector)
                return
            
            # --- Restore normal UI after handwriting mode ---
            from kivy.metrics import dp
            # Hide handwriting canvas
            hw_container = self.root.ids.get('review_handwriting_container')
            if hw_container:
                hw_container.height = 0
                hw_container.opacity = 0
            # Hide handwriting button rows
            hw_btn_row = self.root.ids.get('review_hw_button_row')
            if hw_btn_row:
                hw_btn_row.height = 0
                hw_btn_row.opacity = 0
            hw_check_row = self.root.ids.get('review_hw_check_row')
            if hw_check_row:
                hw_check_row.height = 0
                hw_check_row.opacity = 0
            # Restore normal button row
            normal_btn_row = self.root.ids.get('review_normal_button_row')
            if normal_btn_row:
                normal_btn_row.height = dp(56)
                normal_btn_row.opacity = 1
            # Restore text input (get ID directly)
            text_input_restore = self.root.ids.get('review_input')
            if text_input_restore:
                text_input_restore.opacity = 1
                text_input_restore.height = dp(50)
                text_input_restore.size_hint_y = None
            # Restore normal buttons (get IDs directly)
            submit_btn_restore = self.root.ids.get('review_submit_btn')
            if submit_btn_restore:
                submit_btn_restore.opacity = 1
                submit_btn_restore.disabled = False
            reveal_btn_restore = self.root.ids.get('review_reveal_btn')
            if reveal_btn_restore:
                reveal_btn_restore.opacity = 1
                reveal_btn_restore.disabled = False
            undo_btn_restore = self.root.ids.get('review_undo_btn')
            if undo_btn_restore:
                undo_btn_restore.opacity = 1
                undo_btn_restore.disabled = False
            # Restore counter row
            counter_row = self.root.ids.get('review_counter_row')
            if counter_row:
                counter_row.height = dp(40)
                counter_row.opacity = 1
            
            # Restore spacers for normal review mode
            # External spacer stays at 0; internal review_inner_spacer handles layout.
            top_spacer = self.root.ids.get('review_top_spacer')
            if top_spacer:
                top_spacer.size_hint_y = None
                top_spacer.height = 0
            bottom_section = self.root.ids.get('review_bottom_section')
            if bottom_section:
                bottom_section.size_hint_y = 1
                bottom_section.size_hint_x = 0.85
                bottom_section.pos_hint = {'center_x': 0.5}
            # Restore inner spacer and collapse hw centering spacers
            inner_sp = self.root.ids.get('review_inner_spacer')
            if inner_sp:
                inner_sp.size_hint_y = 1
            hw_top_sp = self.root.ids.get('review_hw_top_spacer')
            if hw_top_sp:
                hw_top_sp.size_hint_y = None
                hw_top_sp.height = 0
            hw_bot_sp = self.root.ids.get('review_hw_bottom_spacer')
            if hw_bot_sp:
                hw_bot_sp.size_hint_y = None
                hw_bot_sp.height = 0
            # Hide streak label for normal mode
            streak_label = self.root.ids.get('review_streak_label')
            if streak_label:
                streak_label.opacity = 0
                streak_label.height = 0
            
            # Handle grammar vectors differently
            is_grammar = vector.get('kind') == 'grammar'
            
            # Ensure grammar review vectors have exercise data loaded.
            # Review vectors from get_due_review_vectors() lack grammar_category
            # and exercise_data — load the pool by entry_id and pick an exercise.
            if is_grammar and not vector.get('exercise_data'):
                self._ensure_grammar_exercise_loaded(vector)
            
            if is_grammar and vector_type == 'fill-blank':
                # Grammar fill-in-the-blank — rotate exercise from pool
                pools = getattr(self, '_grammar_exercise_pools', {})
                eid = vector.get('entry_id')
                eid_pool = pools.get(eid)
                # Lazy-load pool if not already cached (e.g. SRS review drills)
                if not eid_pool and eid and vector.get('grammar_category'):
                    try:
                        with dict_db.get_db(get_db_path()) as conn:
                            eid_pool = learning.load_grammar_exercise_pool(conn, eid)
                        if eid_pool:
                            if not hasattr(self, '_grammar_exercise_pools'):
                                self._grammar_exercise_pools = {}
                            self._grammar_exercise_pools[eid] = eid_pool
                    except Exception:
                        pass
                if eid_pool and vector.get('grammar_category'):
                    learning.pick_fresh_grammar_exercise(vector, eid_pool)

                exercise_data = vector.get('exercise_data', {})
                
                # If exercise_data is missing, load it from the grammar lesson file
                if not exercise_data.get('sentence_with_blank'):
                    exercise_data = self._load_grammar_exercise_for_entry(vector.get('entry_id'))
                    if exercise_data:
                        # Store back into vector for future use
                        vector['exercise_data'] = exercise_data
                
                grammar_point = exercise_data.get('grammar_point', '')
                translation = exercise_data.get('translation', '')
                notes = exercise_data.get('notes', '')
                
                # Extract hint from the grammar point's meaning or notes
                hint = self._extract_grammar_hint(grammar_point, notes)
                
                # Keep the blank as underscores (for aesthetics)
                sentence_with_hint = exercise_data.get('sentence_with_blank', '')
                
                # Add formality indicator to the end of translation (e.g., "(casual)" or "(formal polite)")
                # Extract just the formality part from the hint (everything after the dash)
                if ' - ' in hint:
                    formality = hint.split(' - ', 1)[1]  # Get the part after " - "
                    translation_with_hint = f"{translation} ({formality})"
                else:
                    translation_with_hint = translation
                
                # Format translation with bold text on the key word
                formatted_translation = self._format_translation_with_bold(translation_with_hint, grammar_point)
                prompt_text = formatted_translation
                prompt = sentence_with_hint
                
                # Store exercise data for answer validation
                self._current_grammar_exercise = exercise_data
                
            elif is_grammar and vector_type == 'scramble':
                # Grammar scramble — rotate exercise from pool, shuffle blocks
                pools = getattr(self, '_grammar_exercise_pools', {})
                eid = vector.get('entry_id')
                eid_pool = pools.get(eid)
                if not eid_pool and eid and vector.get('grammar_category'):
                    try:
                        with dict_db.get_db(get_db_path()) as conn:
                            eid_pool = learning.load_grammar_exercise_pool(conn, eid)
                        if eid_pool:
                            if not hasattr(self, '_grammar_exercise_pools'):
                                self._grammar_exercise_pools = {}
                            self._grammar_exercise_pools[eid] = eid_pool
                    except Exception:
                        pass
                if eid_pool and vector.get('grammar_category'):
                    learning.pick_fresh_grammar_exercise(vector, eid_pool)

                exercise_data = vector.get('exercise_data', {})
                grammar_point = exercise_data.get('grammar_point', '')
                translation = exercise_data.get('translation', '')

                # Parse scramble_blocks
                blocks_raw = exercise_data.get('scramble_blocks', '[]')
                if isinstance(blocks_raw, str):
                    try:
                        blocks = json.loads(blocks_raw)
                    except (json.JSONDecodeError, TypeError):
                        blocks = []
                else:
                    blocks = list(blocks_raw)

                # Correct sentence for answer validation
                correct_sentence = ''.join(blocks) if blocks else exercise_data.get('audio_text', '')
                self._current_scramble_correct = correct_sentence.rstrip('。、！？…')

                # Shuffle blocks (guaranteed different from original order)
                shuffled = learning._shuffle_blocks(blocks)

                # Format as spaced-out labels
                prompt = ' '.join(f'「{b}」' for b in shuffled) if shuffled else ''

                # Build translation with hint
                hint = self._extract_grammar_hint(grammar_point, exercise_data.get('notes', ''))
                if ' - ' in hint:
                    formality = hint.split(' - ', 1)[1]
                    translation_with_hint = f"{translation} ({formality})"
                else:
                    translation_with_hint = translation

                formatted_translation = self._format_translation_with_bold(translation_with_hint, grammar_point)
                prompt_text = formatted_translation

                self._current_grammar_exercise = exercise_data

            elif is_grammar and vector_type == 'translate':
                # Grammar translate — show English, user types Japanese sentence
                pools = getattr(self, '_grammar_exercise_pools', {})
                eid = vector.get('entry_id')
                eid_pool = pools.get(eid)
                if not eid_pool and eid and vector.get('grammar_category'):
                    try:
                        with dict_db.get_db(get_db_path()) as conn:
                            eid_pool = learning.load_grammar_exercise_pool(conn, eid)
                        if eid_pool:
                            if not hasattr(self, '_grammar_exercise_pools'):
                                self._grammar_exercise_pools = {}
                            self._grammar_exercise_pools[eid] = eid_pool
                    except Exception:
                        pass
                if eid_pool and vector.get('grammar_category'):
                    learning.pick_fresh_grammar_exercise(vector, eid_pool)

                exercise_data = vector.get('exercise_data', {})
                grammar_point = exercise_data.get('grammar_point', '')
                translation = exercise_data.get('translation', '')

                # Build translation with hint
                hint = self._extract_grammar_hint(grammar_point, exercise_data.get('notes', ''))
                if ' - ' in hint:
                    formality = hint.split(' - ', 1)[1]
                    translation_with_hint = f"{translation} ({formality})"
                else:
                    translation_with_hint = translation

                formatted_translation = self._format_translation_with_bold(translation_with_hint, grammar_point)
                prompt_text = 'Translate to Japanese:'
                prompt = formatted_translation

                self._current_grammar_exercise = exercise_data

            elif is_grammar and vector_type == 'dictation':
                # Grammar dictation — user hears Japanese via TTS, types what they hear
                pools = getattr(self, '_grammar_exercise_pools', {})
                eid = vector.get('entry_id')
                eid_pool = pools.get(eid)
                if not eid_pool and eid and vector.get('grammar_category'):
                    try:
                        with dict_db.get_db(get_db_path()) as conn:
                            eid_pool = learning.load_grammar_exercise_pool(conn, eid)
                        if eid_pool:
                            if not hasattr(self, '_grammar_exercise_pools'):
                                self._grammar_exercise_pools = {}
                            self._grammar_exercise_pools[eid] = eid_pool
                    except Exception:
                        pass
                if eid_pool and vector.get('grammar_category'):
                    learning.pick_fresh_grammar_exercise(vector, eid_pool)

                exercise_data = vector.get('exercise_data', {})
                self._current_grammar_exercise = exercise_data

                # The sentence to speak
                dictation_sentence = vector.get('answer', '') or exercise_data.get('audio_text', '')
                self._dictation_audio_text = dictation_sentence

                # Speaker icon in question label — user taps to replay
                prompt = '\ue050'  # Material Symbols volume_up icon
                prompt_text = 'Write what you hear:'

                # Auto-play TTS on load
                Clock.schedule_once(lambda dt: self.play_audio(dictation_sentence), 0.3)

            # Determine prompt text based on vector type
            elif vector_type == 'show_kana':
                prompt_text = 'Type the reading:'
            elif vector_type == 'show_romaji':
                # Determine if answer is hiragana or katakana
                answer_char = (vector.get('answer', '') or '')[0:1]
                if '\u30A0' <= answer_char <= '\u30FF':  # Katakana range
                    prompt_text = 'Type the katakana:'
                else:  # Hiragana (or other)
                    prompt_text = 'Type the hiragana:'
            elif vector_type == 'orthography_to_reading':
                prompt_text = 'Type the reading:'
            elif vector_type in ('orthography_to_meaning', 'kana_to_meaning'):
                prompt_text = 'Type the meaning:'
                # Extract parenthetical hint from first meaning if present
                import re as _re_hint
                _answer_text = vector.get('answer', '') or ''
                _first_meaning = _answer_text.split(';')[0].strip()
                _hint_match = _re_hint.search(r'\(([^)]+)\)', _first_meaning)
                if _hint_match:
                    prompt_text = f'Type the meaning: ({_hint_match.group(1)})'
                elif vector_type == 'kana_to_meaning':
                    # Add (katakana) hint if the prompt word is katakana
                    kana_prompt = vector.get('prompt', '')
                    if kana_prompt and all('\u30A0' <= c <= '\u30FF' or not c.strip() for c in kana_prompt):
                        prompt_text = 'Type the meaning: (katakana)'
            else:
                prompt_text = 'Type the answer:'
            
            # Update UI
            prompt_label = self.root.ids.get('review_prompt')
            question_label = self.root.ids.get('review_question')
            text_input = self.root.ids.get('review_input')
            undo_btn = self.root.ids.get('review_undo_btn')
            submit_btn = self.root.ids.get('review_submit_btn')
            reveal_btn = self.root.ids.get('review_reveal_btn')
            
            if prompt_label:
                # Bind ref press handler for clickable grammar hints (only bind once)
                if not hasattr(prompt_label, '_grammar_hint_bound'):
                    prompt_label.bind(on_ref_press=self._on_grammar_hint_ref_press)
                    prompt_label._grammar_hint_bound = True
                prompt_label.text = prompt_text
                # Ensure visibility (handwriting mode may have hidden it)
                prompt_label.opacity = 1
                prompt_label.height = dp(26)
            
            if question_label:
                # For grammar, use the local prompt variable; otherwise use vector's prompt
                question_text = prompt if is_grammar else vector.get('prompt', '')
                
                # For kanji entries with readings, format to show only on'yomi and kun'yomi
                if vector_type == 'orthography_to_reading' and vector.get('kind') == 'kanji':
                    question_text = self._format_kanji_readings(question_text)
                
                # Truncate meanings if this is a meaning-type question and has multiple meanings
                if vector_type in ('orthography_to_meaning', 'kana_to_meaning', 'meaning_to_kana', 'show_kana', 'show_romaji'):
                    question_text = self._format_meanings_truncated(question_text)
                    # Bind click handler if truncated
                    if getattr(self, '_meanings_truncated', False):
                        question_label.unbind(on_touch_down=self._toggle_meanings)
                        question_label.bind(on_touch_down=self._toggle_meanings)
                elif vector_type == 'orthography_to_reading' and vector.get('kind') == 'kanji':
                    # Kanji readings already have click handler
                    if getattr(self, '_kanji_readings_truncated', False):
                        question_label.unbind(on_touch_down=self._toggle_kanji_readings)
                        question_label.bind(on_touch_down=self._toggle_kanji_readings)
                
                question_label.text = question_text
                # Adjust font size and font for special vector types
                if is_grammar and vector_type == 'dictation':
                    from kivy.metrics import sp
                    question_label.font_name = 'fonts/MaterialSymbolsOutlined.ttf'
                    question_label.font_size = sp(48)
                    # Bind tap to replay TTS
                    question_label.unbind(on_touch_down=self._on_dictation_speaker_tap)
                    question_label.bind(on_touch_down=self._on_dictation_speaker_tap)
                elif is_grammar and vector_type == 'scramble':
                    from kivy.metrics import sp
                    question_label.font_size = sp(26)
                    question_label.font_name = 'fonts/NotoSansJP-Regular.ttf'
                else:
                    from kivy.metrics import sp
                    question_label.font_size = sp(28)
                    question_label.font_name = 'fonts/NotoSansJP-Regular.ttf'
                # Unbind dictation tap handler if not dictation
                if not (is_grammar and vector_type == 'dictation'):
                    question_label.unbind(on_touch_down=self._on_dictation_speaker_tap)
            
            if text_input:
                text_input.text = ''
                text_input.readonly = False
                
                # Enable IME mode based on prompt type
                if is_grammar and vector_type in ('fill-blank', 'scramble', 'translate', 'dictation'):
                    # Grammar IME: show kanji as user types when answer has kanji
                    if vector_type == 'scramble':
                        grammar_answer = getattr(self, '_current_scramble_correct', '')
                    elif vector_type in ('translate', 'dictation'):
                        grammar_answer = vector.get('answer', '')
                    else:
                        grammar_answer = getattr(self, '_current_grammar_exercise', {}).get('correct_answer', '') or vector.get('answer', '')
                    self._grammar_expected_answer = grammar_answer
                    if grammar_answer and any(0x4e00 <= ord(ch) <= 0x9fff for ch in grammar_answer):
                        self._review_ime_mode = 'grammar_kanji'
                        self._grammar_kanji_segments = self._build_grammar_kanji_segments(grammar_answer)
                    else:
                        self._review_ime_mode = 'hiragana'
                        self._grammar_kanji_segments = []
                elif vector_type == 'show_kana':
                    # show_kana: answer is plain romaji, no IME conversion
                    self._review_ime_mode = None
                    self._grammar_expected_answer = ''
                elif prompt_text == 'Type the hiragana:':
                    self._review_ime_mode = 'hiragana'
                elif prompt_text == 'Type the katakana:':
                    self._review_ime_mode = 'katakana'
                elif prompt_text == 'Type the reading:':
                    # Check if the prompt is katakana - if so, use katakana IME
                    question_text = prompt if is_grammar else vector.get('prompt', '')
                    if question_text and any('\u30A0' <= c <= '\u30FF' for c in question_text):
                        self._review_ime_mode = 'katakana'
                    else:
                        self._review_ime_mode = 'hiragana'
                elif vector_type in ('meaning_to_kana', 'kana_to_meaning'):
                    # For meaning<->kana vectors, check the expected answer to determine IME mode
                    expected_answer = vector.get('answer', '')
                    if expected_answer and any('\u30A0' <= c <= '\u30FF' for c in expected_answer):
                        self._review_ime_mode = 'katakana'
                    elif expected_answer and any('\u3040' <= c <= '\u309F' for c in expected_answer):
                        self._review_ime_mode = 'hiragana'
                    else:
                        self._review_ime_mode = None
                else:
                    self._review_ime_mode = None
                
                # Schedule focus with a short delay; on Android the keyboard
                # may still be closing from the button press that triggered
                # _load_current_review.  A second attempt at 0.3s covers the
                # case where the first fires too early.
                def _focus_input(dt, ti=text_input):
                    if ti and not ti.focus and not ti.readonly:
                        ti.focus = True
                Clock.schedule_once(_focus_input, 0.05)
                Clock.schedule_once(_focus_input, 0.3)
            
            # Reset Submit button
            if submit_btn:
                submit_btn.text = 'Submit'
            
            # Reset Reveal button
            if reveal_btn:
                reveal_btn.text = 'Reveal'
                reveal_btn.background_color = (0.60, 0.15, 0.20, 1)
                reveal_btn.disabled = False
                reveal_btn.opacity = 1.0
            
            # Reset undo button state
            if undo_btn:
                undo_btn.text = 'Undo'
                undo_btn.background_color = (0.30, 0.30, 0.32, 1)
                undo_btn.disabled = len(self._review_history) == 0
            
            # Update review counter
            counter_row = self.root.ids.get('review_counter_row')
            counter_label = self.root.ids.get('review_counter')
            if counter_row:
                if self.hide_review_counter:
                    counter_row.opacity = 0
                    counter_row.height = 0
                else:
                    counter_row.opacity = 1
                    from kivy.metrics import dp
                    counter_row.height = dp(40)
                    if counter_label:
                        counter_label.text = f'{self._review_index + 1} / {len(self._review_queue)}'
            
            # Reset attempt counter text after a delay to let flash complete
            # The text was set to show result (1/1 or 0/1) in submit handler
            attempt_counter = self.root.ids.get('review_attempt_counter')
            if attempt_counter and not self.hide_review_counter:
                attempt_counter.opacity = 1
                # Delay resetting text to match color flash duration
                Clock.schedule_once(lambda dt: setattr(attempt_counter, 'text', '0 / 1'), 0.5)
            
            # Clear feedback
            feedback_label = self.root.ids.get('review_feedback')
            if feedback_label:
                feedback_label.text = ''
            
            self._undo_confirm = False
            self._reveal_confirm = False
            self._review_revealed = False
            self._review_waiting_continue = False  # Reset waiting flag after undo
            
        except Exception as e:
            Logger.error(f'Review: Error loading item: {e}')
    
    def _build_grammar_kanji_segments(self, answer_text):
        """Build cumulative reading-to-original mapping for grammar kanji IME.
        Returns list of (cumulative_hiragana_reading, cumulative_original_text) tuples.
        Splits pykakasi segments at character level so kanji boundaries appear early."""
        if not answer_text:
            return []
        try:
            import pykakasi
            if not hasattr(self, '_kakasi_instance'):
                self._kakasi_instance = pykakasi.kakasi()
            word_segments = self._kakasi_instance.convert(answer_text)

            def _is_kana(c):
                o = ord(c)
                return (0x3040 <= o <= 0x309F) or (0x30A0 <= o <= 0x30FF)

            def _norm_kana(c):
                o = ord(c)
                return chr(o - 0x60) if 0x30A0 <= o <= 0x30FF else c

            cum_reading = ''
            cum_original = ''
            result = []

            for seg in word_segments:
                orig = seg.get('orig', '')
                hira = seg.get('hira', seg.get('orig', ''))
                hira_norm = ''.join(_norm_kana(ch) for ch in hira)
                chars = list(orig)

                if len(chars) <= 1:
                    cum_reading += hira_norm
                    cum_original += orig
                    result.append((cum_reading, cum_original))
                    continue

                # Count leading kana characters
                leading = 0
                for c in chars:
                    if _is_kana(c):
                        leading += 1
                    else:
                        break

                # Count trailing kana characters (after the leading kana)
                trailing = 0
                for c in reversed(chars[leading:]):
                    if _is_kana(c):
                        trailing += 1
                    else:
                        break

                mid_end = len(chars) - trailing if trailing else len(chars)

                # Leading kana: 1 reading char each
                for i in range(leading):
                    cum_reading += _norm_kana(chars[i])
                    cum_original += chars[i]
                    result.append((cum_reading, cum_original))

                # Middle (kanji run): gets remaining reading as a block
                if leading < mid_end:
                    end_idx = len(hira_norm) - trailing if trailing else len(hira_norm)
                    mid_reading = hira_norm[leading:end_idx]
                    cum_reading += mid_reading
                    for i in range(leading, mid_end):
                        cum_original += chars[i]
                    result.append((cum_reading, cum_original))

                # Trailing kana: 1 reading char each
                for i in range(mid_end, len(chars)):
                    cum_reading += _norm_kana(chars[i])
                    cum_original += chars[i]
                    result.append((cum_reading, cum_original))

            return result
        except Exception as e:
            Logger.error(f'Grammar IME: Error building kanji segments: {e}')
            return []

    def _text_to_hiragana(self, text):
        """Convert any Japanese text (including kanji) to hiragana reading.
        Uses pykakasi if available, falls back to DB-based kanji→kana lookup."""
        if not text:
            return ''
        try:
            import pykakasi
            if not hasattr(self, '_kakasi_instance'):
                self._kakasi_instance = pykakasi.kakasi()
            result = self._kakasi_instance.convert(text)
            hiragana = ''.join(item.get('hira', item.get('orig', '')) for item in result)
            return self._kata_to_hira(hiragana)
        except Exception:
            # Fallback: use DB kanji→kana mapping
            return self._text_to_hiragana_db(text)

    def _kata_to_hira(self, text):
        """Convert katakana to hiragana. Preserves ー (long vowel mark)."""
        out = []
        for ch in text:
            code = ord(ch)
            if 0x30A1 <= code <= 0x30F6:  # ァ-ヶ (standard katakana letters)
                out.append(chr(code - 0x60))
            else:
                out.append(ch)
        return ''.join(out)

    def _promote_grammar_katakana(self, text, correct_answer):
        """Auto-promote hiragana to katakana where correct_answer has katakana.
        Walks character-by-character; if the correct answer has a katakana char
        and the user typed its hiragana equivalent, replace with katakana.
        Also promotes '-' to 'ー' where the correct answer has 'ー'."""
        if not correct_answer or not text:
            return text
        result = list(text)
        for i in range(min(len(result), len(correct_answer))):
            c_ch = correct_answer[i]
            c_code = ord(c_ch)
            if c_ch == '\u30fc' and result[i] == '-':
                # Promote ASCII hyphen to long vowel mark
                result[i] = '\u30fc'
            elif 0x30A1 <= c_code <= 0x30F6:
                hira_equiv = chr(c_code - 0x60)
                if result[i] == hira_equiv:
                    result[i] = c_ch
        return ''.join(result)

    def _get_kanji_to_kana_map(self):
        """Lazy-load a kanji→kana lookup dict from the DB entries table.
        Prioritizes vocab entries over kanji entries (which have on/kun reading strings)."""
        if not hasattr(self, '_kanji_kana_map'):
            self._kanji_kana_map = {}
            try:
                import dictionary.db as dict_db
                conn = dict_db.init_db(get_db_path())
                cur = conn.cursor()
                # Load kanji-kind entries first (lower priority)
                cur.execute('SELECT kanji, kana FROM entries WHERE kanji IS NOT NULL AND kanji != "" AND kind = "kanji"')
                for kanji, kana in cur.fetchall():
                    # Extract kun reading (most useful for word lookup)
                    if 'kun:' in kana:
                        parts = kana.split('kun:')[1].split('|')[0].strip()
                        first_reading = parts.split()[0].replace('.', '') if parts else kana
                        self._kanji_kana_map[kanji] = first_reading
                    else:
                        self._kanji_kana_map[kanji] = kana
                # Overwrite with vocab entries (higher priority, simpler kana)
                # Prefer entries actually in curriculum (study_order > 0) over unassigned ones (study_order = 0)
                cur.execute('SELECT kanji, kana FROM entries WHERE kanji IS NOT NULL AND kanji != "" AND kind = "vocab" ORDER BY CASE WHEN study_order > 0 THEN 0 ELSE 1 END, study_order')
                vocab_seen = set()
                for kanji, kana in cur.fetchall():
                    if kanji not in vocab_seen:
                        self._kanji_kana_map[kanji] = kana
                        vocab_seen.add(kanji)
                conn.close()
            except Exception as e:
                Logger.warning(f'Failed to build kanji→kana map: {e}')
        return self._kanji_kana_map

    def _text_to_hiragana_db(self, text):
        """Convert Japanese text to hiragana using DB-based word lookup.
        Greedily matches the longest known kanji word at each position."""
        if not text:
            return ''
        kmap = self._get_kanji_to_kana_map()
        result = []
        i = 0
        while i < len(text):
            best_len = 0
            best_kana = None
            # Try longest match first (up to 10 chars)
            for length in range(min(10, len(text) - i), 0, -1):
                substr = text[i:i + length]
                if substr in kmap:
                    best_len = length
                    best_kana = kmap[substr]
                    break
            if best_kana:
                result.append(self._kata_to_hira(best_kana))
                i += best_len
            else:
                # Pass through as-is (kana, punctuation, etc.)
                ch = text[i]
                result.append(self._kata_to_hira(ch))
                i += 1
        return ''.join(result)

    def _flexible_sentence_match(self, user_text, correct_text):
        """Compare user input against correct sentence with flexible matching.
        Handles: exact match, katakana↔hiragana, kanji→kana via DB, romaji→kana.
        Completely ignores punctuation. Handles mixed kana+romaji input.
        Returns True if the answers should be considered equivalent."""
        import re as _re
        _punct = _re.compile(r'[\s。、！？…!?,.\u3000「」『』（）〜・]+')
        user_clean = _punct.sub('', user_text).replace('-', '\u30fc')
        correct_clean = _punct.sub('', correct_text)

        if user_clean == correct_clean:
            return True

        # Normalize katakana→hiragana in both
        user_hira = self._kata_to_hira(user_clean)
        correct_hira = self._kata_to_hira(correct_clean)
        if user_hira == correct_hira:
            return True

        # Convert any ASCII romaji runs in user input to hiragana
        # Handles pure romaji, mixed kana+romaji, and trailing 'n' → ん
        if any(c.isascii() and c.isalpha() for c in user_hira):
            from dictionary.learning import convert_greedy_romaji
            def _convert_run(m):
                r = m.group(0).lower()
                converted, remainder = convert_greedy_romaji(r)
                if remainder == 'n':
                    converted += '\u3093'
                    remainder = ''
                return converted + remainder
            user_hira = _re.sub(r'[a-zA-Z]+', _convert_run, user_hira)

        # Convert correct answer to full hiragana (handles kanji)
        correct_hira = self._text_to_hiragana(correct_clean)
        if user_hira == correct_hira:
            return True

        return False

    def _reading_to_kanji_display(self, full_reading, segments):
        """Map hiragana reading back to kanji display using pre-computed segments."""
        if not segments or not full_reading:
            return full_reading
        best_orig = ''
        best_len = 0
        for cum_reading, cum_orig in segments:
            if full_reading.startswith(cum_reading) and len(cum_reading) > best_len:
                best_orig = cum_orig
                best_len = len(cum_reading)
        if best_len > 0:
            return best_orig + full_reading[best_len:]
        return full_reading

    def _display_to_reading(self, display_text, segments):
        """Convert displayed text (may contain kanji) back to hiragana reading
        using pre-computed segments (avoids pykakasi context-loss issues)."""
        if not display_text:
            return ''
        if not segments:
            return display_text
        best_reading = ''
        best_orig_len = 0
        for cum_reading, cum_original in segments:
            if display_text.startswith(cum_original) and len(cum_original) > best_orig_len:
                best_reading = cum_reading
                best_orig_len = len(cum_original)
        remainder = display_text[best_orig_len:] if best_orig_len else display_text
        # Remainder should be kana — normalize katakana to hiragana
        norm = []
        for ch in remainder:
            code = ord(ch)
            if 0x30A0 <= code <= 0x30FF:
                norm.append(chr(code - 0x60))
            else:
                norm.append(ch)
        return best_reading + ''.join(norm)

    def on_review_input_text(self, instance, value):
        """Handle text input changes for IME conversion during reviews."""
        try:
            # Only convert if IME mode is active
            ime_mode = getattr(self, '_review_ime_mode', None)
            if not ime_mode or instance.readonly:
                return
            
            # Grammar kanji IME: convert romaji and show kanji from expected answer
            if ime_mode == 'grammar_kanji':
                if getattr(self, '_grammar_ime_updating', False):
                    return
                import re
                segments = getattr(self, '_grammar_kanji_segments', [])
                match = re.search(r'[a-zA-Z]+$', value)
                if match:
                    romaji_suffix = match.group()
                    prefix = value[:match.start()]
                    converted_suffix = dict_db._romaji_to_hiragana(romaji_suffix)
                    if not converted_suffix:
                        return
                    prefix_reading = self._display_to_reading(prefix, segments)
                    full_reading = prefix_reading + converted_suffix
                else:
                    if not value:
                        return
                    full_reading = self._display_to_reading(value, segments)
                display = self._reading_to_kanji_display(full_reading, segments)
                if display != value:
                    self._grammar_ime_updating = True
                    instance.text = display
                    try:
                        instance.cursor = (len(display), 0)
                    except:
                        pass
                    self._grammar_ime_updating = False
                return
            
            # Get current cursor position
            cursor_pos = instance.cursor_index()
            
            # For katakana mode, convert "-" to "ー" (long vowel mark)
            if ime_mode == 'katakana' and '-' in value:
                new_text = value.replace('-', 'ー')
                if new_text != value:
                    instance.text = new_text
                    try:
                        instance.cursor = (len(new_text), 0)
                    except:
                        pass
                    return
            
            # Find the romaji suffix (contiguous ASCII letters at the end)
            import re
            match = re.search(r'[a-zA-Z]+$', value)
            if not match:
                # No romaji to convert, but still promote hyphen→ー for grammar
                grammar_answer = getattr(self, '_grammar_expected_answer', '')
                if grammar_answer and '-' in value:
                    promoted = self._promote_grammar_katakana(value, grammar_answer)
                    if promoted != value:
                        instance.text = promoted
                        try:
                            instance.cursor = (len(promoted), 0)
                        except:
                            pass
                return
            
            romaji_suffix = match.group()
            suffix_start = match.start()
            prefix = value[:suffix_start]
            
            # Convert romaji suffix to kana
            if ime_mode == 'hiragana':
                converted_suffix = dict_db._romaji_to_hiragana(romaji_suffix)
            elif ime_mode == 'katakana':
                hira = dict_db._romaji_to_hiragana(romaji_suffix)
                converted_suffix = dict_db._hiragana_to_katakana(hira) if hira else None
            else:
                return
            
            # Update text if conversion succeeded
            if converted_suffix:
                new_text = prefix + converted_suffix
                # Auto-promote hiragana to katakana for grammar exercises
                grammar_answer = getattr(self, '_grammar_expected_answer', '')
                if grammar_answer:
                    new_text = self._promote_grammar_katakana(new_text, grammar_answer)
                instance.text = new_text
                # Move cursor to end
                try:
                    instance.cursor = (len(new_text), 0)
                except:
                    pass
        except Exception as e:
            Logger.error(f'Review: Error in IME conversion: {e}')
    
    def _load_handwriting_review(self, vector):
        """Load a handwriting review vector into the UI."""
        try:
            # Fix old vectors missing characters/reading/prompt data
            if not vector.get('characters') or vector.get('reading') is None or not vector.get('prompt'):
                Logger.info(f'Review HW: Regenerating missing handwriting data for entry {vector.get("entry_id")}')
                # Query entry from database
                conn = dict_db.init_db(get_db_path())
                c = conn.cursor()
                c.execute('SELECT kanji, kana, gloss, kind FROM entries WHERE id = ?', (vector.get('entry_id'),))
                row = c.fetchone()
                if row:
                    kanji, kana, gloss, kind = row
                    # Regenerate handwriting data
                    import dictionary.handwriting_drill as handwriting_drill
                    entry_dict = {'id': vector.get('entry_id'), 'kind': kind, 'kanji': kanji, 'kana': kana, 'gloss': gloss}
                    hw_vector = handwriting_drill.create_handwriting_vector(entry_dict)
                    # Update vector with missing fields (including kind for old vectors)
                    vector['characters'] = hw_vector.get('characters', [])
                    vector['reading'] = hw_vector.get('reading', '')
                    vector['kind'] = hw_vector.get('kind', kind)  # Update kind from entry
                    if hw_vector.get('prompt'):
                        vector['prompt'] = hw_vector.get('prompt', '')
                    Logger.info(f'Review HW: Regenerated - kind={vector["kind"]}, characters={vector["characters"]}, prompt={repr(vector.get("prompt", "")[:60])}')
                conn.close()
            
            # Also fix old vectors that have wrong kind (e.g., 'vocab' instead of 'kanji')
            # This handles vectors that weren't regenerated above
            if vector.get('kind') != 'kanji':
                entry_id = vector.get('entry_id')
                if entry_id:
                    conn = dict_db.init_db(get_db_path())
                    c = conn.cursor()
                    c.execute('SELECT kind FROM entries WHERE id = ?', (entry_id,))
                    row = c.fetchone()
                    if row and row[0] == 'kanji':
                        vector['kind'] = 'kanji'
                        Logger.info(f'Review HW: Fixed kind field for entry {entry_id} to kanji')
                    conn.close()
            
            # Initialize character tracking if not present
            if 'current_char_index' not in vector:
                vector['current_char_index'] = 0
            if 'char_results' not in vector:
                vector['char_results'] = []
            
            # Get UI elements (review screen IDs)
            prompt_label = self.root.ids.get('review_prompt')
            question_label = self.root.ids.get('review_question')
            text_input = self.root.ids.get('review_input')
            handwriting_container = self.root.ids.get('review_handwriting_container')
            
            # Get normal buttons (hide these)
            submit_btn = self.root.ids.get('review_submit_btn')
            reveal_btn = self.root.ids.get('review_reveal_btn')
            undo_btn = self.root.ids.get('review_undo_btn')
            
            # Get handwriting button rows
            hw_button_row = self.root.ids.get('review_hw_button_row')
            hw_check_row = self.root.ids.get('review_hw_check_row')
            
            counter_label = self.root.ids.get('review_counter')
            
            # Build fill-in-the-blank display
            characters = vector.get('characters', [])
            current_idx = vector.get('current_char_index', 0)
            char_results = vector.get('char_results', [])
            
            Logger.info(f'Review HW: characters={characters}, current_idx={current_idx}, char_results={char_results}')
            Logger.info(f'Review HW: prompt={vector.get("prompt")}, reading={vector.get("reading")}, answer={vector.get("answer")}')
            
            # Create display: [見][_] for 見る where first is done, second is current
            blanks = []
            for i, char in enumerate(characters):
                if i < len(char_results):
                    # Already filled in
                    blanks.append(f'[color=60ff60]{char}[/color]' if char_results[i] else f'[color=ff6060]{char}[/color]')
                elif i == current_idx:
                    # Current blank to fill
                    blanks.append('[b]_[/b]')
                else:
                    # Future blank
                    blanks.append('_')
            
            display_text = ' '.join(blanks)
            
            # Set question (fill-in-the-blank display) - blanks at top
            if question_label:
                question_label.text = display_text
                question_label.markup = True
            
            # Set prompt text (pronunciation) - middle
            # For kana-only entries, hide reading (would reveal answer)
            if prompt_label:
                reading = vector.get('reading', '')
                answer = vector.get('answer', '')
                
                # Check if answer contains any kanji characters
                has_kanji = any('\u4e00' <= c <= '\u9fff' for c in answer)
                
                if not has_kanji:
                    # Hide reading for kana-only entries (would give away answer)
                    prompt_label.text = ''
                    prompt_label.height = 0
                    prompt_label.opacity = 0
                else:
                    # Show reading for entries with kanji
                    # Format kanji readings to show only on'yomi and kun'yomi
                    if vector.get('kind') == 'kanji':
                        original_reading = reading
                        reading = self._format_kanji_readings(reading)
                        Logger.info(f'Review HW: Formatted kanji reading - original={repr(original_reading[:80])}, formatted={repr(reading)}')
                        
                        # Make label clickable to toggle full/truncated view if truncated
                        if self._kanji_readings_truncated:
                            # Unbind any existing handlers first
                            prompt_label.unbind(on_touch_down=self._toggle_kanji_readings)
                            prompt_label.bind(on_touch_down=self._toggle_kanji_readings)
                    
                    prompt_label.text = reading
                    prompt_label.markup = True
                    prompt_label.font_size = '16sp'
                    prompt_label.opacity = 1
                    # Enable text wrapping to prevent bleeding off screen
                    from kivy.metrics import dp
                    prompt_label.size_hint_y = None
                    prompt_label.height = dp(36)  # Min height, will expand if needed
                    prompt_label.text_size = (prompt_label.width, None)
                    prompt_label.halign = 'center'
                    prompt_label.valign = 'middle'
                    # Bind width to update text_size for proper wrapping
                    prompt_label.bind(width=lambda instance, value: setattr(instance, 'text_size', (value, None)))
            
            # Widen the bottom section for handwriting mode
            review_bottom = self.root.ids.get('review_bottom_section')
            if review_bottom:
                review_bottom.size_hint_x = 0.96
                review_bottom.pos_hint = {'center_x': 0.5}
            
            # Show definition in feedback area - bottom
            feedback_label = self.root.ids.get('review_feedback')
            if feedback_label:
                definition = vector.get('prompt', '')
                # Fallback: fetch definition directly from DB if still empty
                if not definition and vector.get('entry_id'):
                    try:
                        _conn = dict_db.init_db(get_db_path())
                        _c = _conn.cursor()
                        _c.execute('SELECT gloss FROM entries WHERE id = ?', (vector.get('entry_id'),))
                        _row = _c.fetchone()
                        _conn.close()
                        if _row and _row[0]:
                            definition = _row[0].split(';')[0].strip()
                            vector['prompt'] = definition  # cache it
                    except Exception:
                        pass
                feedback_label.text = definition
                feedback_label.color = (0.60, 0.58, 0.55, 1)
                feedback_label.markup = False
                # Use larger font when definition is the only clue (kana entries with no reading shown)
                reading_visible = prompt_label and prompt_label.opacity > 0 and prompt_label.text
                if not reading_visible:
                    feedback_label.font_size = '18sp'
                else:
                    feedback_label.font_size = '14sp'
            
            # Hide text input and dismiss keyboard for handwriting mode
            if text_input:
                text_input.focus = False
                text_input.opacity = 0
                text_input.height = 0
                text_input.size_hint_y = None
            
            # Hide normal button row container
            normal_btn_row = self.root.ids.get('review_normal_button_row')
            if normal_btn_row:
                normal_btn_row.height = 0
                normal_btn_row.opacity = 0
            
            # Hide normal buttons
            if submit_btn:
                submit_btn.opacity = 0
                submit_btn.disabled = True
            if reveal_btn:
                reveal_btn.opacity = 0
                reveal_btn.disabled = True
            if undo_btn:
                undo_btn.opacity = 0
                undo_btn.disabled = True
            
            # Show handwriting button rows
            if hw_button_row:
                from kivy.metrics import dp
                hw_button_row.height = dp(40)
                hw_button_row.opacity = 1
            
            if hw_check_row:
                from kivy.metrics import dp
                hw_check_row.height = dp(40)
                hw_check_row.opacity = 1
            
            # Reset submit button text and revealed flag
            submit_btn_hw = self.root.ids.get('review_hw_submit')
            if submit_btn_hw:
                submit_btn_hw.text = 'Check'
                submit_btn_hw.background_color = (0.25, 0.35, 0.50, 1)
            vector['_hw_revealed'] = False
            
            # Clean up stroke order widget if it was active
            self._cleanup_review_stroke_order()
            # Reset reveal confirm state
            self._review_hw_reveal_confirm = False
            
            # Shrink top spacer and center content for handwriting
            from kivy.metrics import dp
            top_spacer = self.root.ids.get('review_top_spacer')
            if top_spacer:
                top_spacer.size_hint_y = None
                top_spacer.height = 0
            bottom_section = self.root.ids.get('review_bottom_section')
            if bottom_section:
                bottom_section.size_hint_y = 1
                bottom_section.spacing = dp(2)
                bottom_section.padding = [0, 0, 0, dp(56)]
            # Collapse inner spacer so review_hw_top_spacer can center the canvas
            inner_sp = self.root.ids.get('review_inner_spacer')
            if inner_sp:
                inner_sp.size_hint_y = None
                inner_sp.height = 0
            
            # Activate centering spacers
            hw_top_sp = self.root.ids.get('review_hw_top_spacer')
            if hw_top_sp:
                hw_top_sp.size_hint_y = 1
                hw_top_sp.height = 0
            hw_bot_sp = self.root.ids.get('review_hw_bottom_spacer')
            if hw_bot_sp:
                hw_bot_sp.size_hint_y = 1
                hw_bot_sp.height = 0
            
            # Update counter to show character progress
            counter_row = self.root.ids.get('review_counter_row')
            if counter_row and counter_label:
                # Show character progress: "0 / 2" for first of 2 characters
                char_num = current_idx
                total_chars = len(characters)
                counter_label.text = f'{char_num} / {total_chars}'
                counter_row.opacity = 1
                from kivy.metrics import dp
                counter_row.height = dp(40)
            
            # Hide attempt counter (not used in handwriting mode)
            attempt_counter = self.root.ids.get('review_attempt_counter')
            if attempt_counter:
                attempt_counter.opacity = 0
                attempt_counter.height = 0
            
            # Hide streak label (reviews don't use streaks, only drills)
            streak_label = self.root.ids.get('review_streak_label')
            if streak_label:
                streak_label.opacity = 0
                streak_label.height = 0
            
            if handwriting_container:
                from kivy.metrics import dp
                from kivy.clock import Clock

                cached_h = getattr(self, '_review_hw_capped_height', None)
                if cached_h is not None:
                    # Reuse previously measured height — no deferred reflow needed.
                    handwriting_container.size_hint_y = None
                    handwriting_container.height = cached_h
                else:
                    # First character: measure after one layout frame then cache.
                    def set_square_canvas_review(dt):
                        if bottom_section and handwriting_container:
                            canvas_width = bottom_section.width
                            handwriting_container.size_hint_y = None
                            handwriting_container.height = canvas_width
                            self._review_hw_capped_height = canvas_width
                    Clock.schedule_once(set_square_canvas_review, 0)
                handwriting_container.opacity = 1
                
                # Create or get handwriting canvas
                if not hasattr(self, '_review_handwriting_canvas'):
                    from handwriting_canvas import HandwritingCanvas
                    self._review_handwriting_canvas = HandwritingCanvas(
                        size_hint=(1, 1)
                    )
                    handwriting_container.clear_widgets()
                    handwriting_container.add_widget(self._review_handwriting_canvas)
                else:
                    # Clear existing canvas
                    self._review_handwriting_canvas.clear_canvas()
                    # Re-enable canvas (in case it was disabled after a reveal)
                    self._review_handwriting_canvas.disabled = False
                    # Make sure it's added to the container
                    if self._review_handwriting_canvas.parent != handwriting_container:
                        handwriting_container.clear_widgets()
                        handwriting_container.add_widget(self._review_handwriting_canvas)
                
                # Warm up recognizer in background (non-blocking)
                self._prewarm_recognizer_silent()
            
        except Exception as e:
            Logger.error(f'Review: Error loading handwriting review: {e}')
            import traceback
            traceback.print_exc()
    
    def on_review_handwriting_submit(self):
        """Handle handwriting review submission - character by character."""
        try:
            Logger.info('Review: Handwriting Check button clicked')
            
            if self._review_index >= len(self._review_queue):
                return
            
            vector = self._review_queue[self._review_index]
            
            # Check if we're waiting for continue (after completing all characters with Auto)
            if getattr(self, '_review_waiting_continue', False):
                Logger.info('Review: Continue clicked - advancing to next review')
                self._review_waiting_continue = False
                
                # Reset button
                submit_btn = self.root.ids.get('review_hw_submit')
                if submit_btn:
                    submit_btn.text = 'Check'
                    submit_btn.background_color = (0.25, 0.35, 0.50, 1)
                
                # Clear feedback
                feedback_label = self.root.ids.get('review_feedback')
                if feedback_label:
                    feedback_label.text = ''
                
                # Advance to next review
                self._review_index += 1
                self._load_current_review()
                return
            
            # Check if this is Continue mode (after reveal)
            if vector.get('_hw_revealed', False):
                # Clean up stroke order widget if active
                self._cleanup_review_stroke_order()
                
                # Mark as wrong and continue to next character
                if 'char_results' not in vector:
                    vector['char_results'] = []
                vector['char_results'].append(False)
                
                # Clear canvas
                if hasattr(self, '_review_handwriting_canvas'):
                    self._review_handwriting_canvas.clear_canvas()
                
                # Move to next character
                vector['current_char_index'] = vector.get('current_char_index', 0) + 1
                vector['_hw_revealed'] = False
                
                # Check if all characters are done
                if vector['current_char_index'] >= len(vector.get('characters', [])):
                    # All done
                    all_correct = all(vector['char_results'])
                    Logger.info(f'Review: All characters done (after reveal). Results: {vector["char_results"]}, Overall: {all_correct}')
                    
                    entry_id = vector['entry_id']
                    kind = vector['kind']
                    vector_type = vector['vector_type']
                    grade = 3 if all_correct else 1
                    self._apply_review_grade(entry_id, kind, vector_type, grade, grammar_category=vector.get('grammar_category'))
                    
                    # Show final feedback
                    feedback_label = self.root.ids.get('review_feedback')
                    if feedback_label:
                        answer = vector.get('answer', '')
                        if all_correct:
                            feedback_label.text = f'✓ Correct! {answer}'
                            feedback_label.color = (0.20, 0.65, 0.30, 1)
                        else:
                            feedback_label.text = f'Answer: {answer}'
                            feedback_label.color = (0.85, 0.40, 0.35, 1)
                    
                    # Advance index then load next
                    self._review_index += 1
                    self._auto_tts_after_answer(vector)
                    from kivy.clock import Clock
                    Clock.schedule_once(lambda dt: self._load_current_review(), 1.2)
                else:
                    # More characters
                    Logger.info(f'Review: Continuing to next character after reveal')
                    self._load_handwriting_review(vector)
                
                return
            
            # Get current character info
            characters = vector.get('characters', [])
            current_idx = vector.get('current_char_index', 0)
            
            if current_idx >= len(characters):
                Logger.error('Review: Character index out of bounds')
                return
            
            expected_char = characters[current_idx]
            
            # Get strokes from canvas
            if not hasattr(self, '_review_handwriting_canvas'):
                Logger.error('Review: No handwriting canvas found')
                return
            
            strokes = self._review_handwriting_canvas.get_strokes()
            if not strokes:
                Logger.info('Review: No strokes drawn')
                return
            
            # Use async recognition with loading overlay for first init
            def handle_recognition_result(candidates):
                self._process_review_handwriting_recognition(candidates, expected_char, characters, current_idx)
            
            self._recognize_with_loading(strokes, 40, handle_recognition_result)
            
        except Exception as e:
            Logger.error(f'Review: Error in handwriting submission: {e}')
            import traceback
            traceback.print_exc()
    
    def _process_review_handwriting_recognition(self, candidates, expected_char, characters, current_idx):
        """Process recognition results for review handwriting (called after recognition completes)."""
        try:
            vector = self._review_queue[self._review_index]
            
            if not candidates:
                Logger.info('Review: Could not recognize drawing')
                feedback_label = self.root.ids.get('review_feedback')
                if feedback_label:
                    feedback_label.text = 'Could not recognize. Try again.'
                    feedback_label.color = (0.85, 0.40, 0.35, 1)
                self._review_handwriting_canvas.clear_canvas()
                return
            
            # Get top match
            drawn_char, confidence = candidates[0]
            
            # Grade the attempt - pass all candidates for lenient matching
            import dictionary.handwriting_drill as handwriting_drill
            is_correct_char, feedback_msg = handwriting_drill.grade_handwriting_attempt(
                drawn_char, expected_char, confidence, all_candidates=candidates
            )
            
            Logger.info(f'Review: Character {current_idx+1}/{len(characters)}: drew={drawn_char}, expected={expected_char}, conf={confidence:.2f}, correct={is_correct_char}')
            
            # Record result for this character
            if 'char_results' not in vector:
                vector['char_results'] = []
            vector['char_results'].append(is_correct_char)
            
            # Update the vector in the queue to persist changes
            self._review_queue[self._review_index] = vector
            
            # Clear canvas for next character
            self._review_handwriting_canvas.clear_canvas()
            
            # Move to next character
            vector['current_char_index'] = current_idx + 1
            
            # Check if all characters are done
            if vector['current_char_index'] >= len(characters):
                # All characters tested - determine overall result
                all_correct = all(vector['char_results'])
                
                Logger.info(f'Review: All characters tested. Results: {vector["char_results"]}, Overall: {all_correct}')
                
                # Update question display to show all completed characters
                question_label = self.root.ids.get('review_question')
                if question_label:
                    completed_chars = []
                    for i, char in enumerate(characters):
                        if vector['char_results'][i]:
                            completed_chars.append(f'[color=60ff60]{char}[/color]')
                        else:
                            completed_chars.append(f'[color=ff6060]{char}[/color]')
                    question_label.text = ' '.join(completed_chars)
                    question_label.markup = True
                
                # Submit to SRS
                entry_id = vector['entry_id']
                kind = vector['kind']
                vector_type = vector['vector_type']
                
                # Grade: 1=Again (any wrong), 3=Good (all correct)
                grade = 3 if all_correct else 1
                self._apply_review_grade(entry_id, kind, vector_type, grade, grammar_category=vector.get('grammar_category'))
                
                # Show final feedback
                feedback_label = self.root.ids.get('review_feedback')
                answer = vector.get('answer', '')
                if all_correct:
                    Logger.info('Review: All characters correct')
                    if feedback_label:
                        feedback_label.text = f'✓ Correct! {answer}'
                        feedback_label.color = (0.20, 0.65, 0.30, 1)
                else:
                    Logger.info('Review: Some characters wrong')
                    wrong_chars = [char for i, char in enumerate(characters) if not vector['char_results'][i]]
                    if feedback_label:
                        feedback_label.text = f'Wrong: {", ".join(wrong_chars)}. Answer: {answer}'
                        feedback_label.color = (0.85, 0.40, 0.35, 1)
                
                # Change button to Continue with appropriate color
                submit_btn = self.root.ids.get('review_hw_submit')
                if submit_btn:
                    submit_btn.text = 'Continue'
                    if all_correct:
                        submit_btn.background_color = (0.20, 0.65, 0.30, 1)  # Green
                    else:
                        submit_btn.background_color = (0.85, 0.40, 0.35, 1)  # Red
                
                # Set flag to advance on next click
                self._review_waiting_continue = True
                
                # Auto TTS after completing handwriting review
                self._auto_tts_after_answer(vector)
            else:
                # More characters to test - reload with next character
                Logger.info(f'Review: Character correct, moving to next ({vector["current_char_index"]}/{len(characters)})')
                self._load_handwriting_review(vector)
            
        except Exception as e:
            Logger.error(f'Review: Error processing handwriting recognition: {e}')
        try:
            # If stroke order is showing, switch to free-draw canvas
            if getattr(self, '_review_stroke_order_active', False):
                self._switch_to_review_free_draw()
                return
            
            # If free-draw canvas is active, clear it
            if getattr(self, '_review_free_draw_active', False):
                if hasattr(self, '_review_free_draw_canvas'):
                    self._review_free_draw_canvas.clear_canvas()
                    Logger.info('Review: Cleared free-draw canvas')
                return
            
            if hasattr(self, '_review_handwriting_canvas'):
                self._review_handwriting_canvas.undo_stroke()
                Logger.info('Review: Undid last stroke')
        except Exception as e:
            Logger.error(f'Review: Error in handwriting undo: {e}')
    
    def on_review_handwriting_reveal(self):
        """Reveal the current character with stroke order animation, or replay."""
        try:
            # If free-draw canvas is showing, reshow stroke order animation on Play
            if getattr(self, '_review_free_draw_active', False):
                handwriting_container = self.root.ids.get('review_handwriting_container')
                if handwriting_container and hasattr(self, '_review_stroke_order_widget'):
                    handwriting_container.clear_widgets()
                    handwriting_container.add_widget(self._review_stroke_order_widget)
                    self._review_free_draw_active = False
                    self._review_stroke_order_active = True
                    self._review_stroke_order_widget.clear()
                    self._review_stroke_order_widget.animate_strokes(0.44)
                    Logger.info('Review: Reshowing stroke order from free-draw mode')
                return
            
            # If stroke order is already showing, act as "Play" button (replay)
            if getattr(self, '_review_stroke_order_active', False):
                if hasattr(self, '_review_stroke_order_widget'):
                    self._review_stroke_order_widget.clear()
                    self._review_stroke_order_widget.animate_strokes(0.44)
                    Logger.info('Review: Replaying stroke order animation')
                return
            
            if self._review_index >= len(self._review_queue):
                return
            
            vector = self._review_queue[self._review_index]
            characters = vector.get('characters', [])
            current_idx = vector.get('current_char_index', 0)
            
            if current_idx >= len(characters):
                return
            
            # Two-click confirmation: first click turns button yellow
            reveal_btn = self.root.ids.get('review_hw_reveal')
            if not getattr(self, '_review_hw_reveal_confirm', False):
                self._review_hw_reveal_confirm = True
                if reveal_btn:
                    reveal_btn.text = 'Reveal?'
                    reveal_btn.background_color = (0.68, 0.56, 0.15, 1)
                Logger.info('Review HW: Reveal confirmation requested')
                return
            
            # Second click: perform the reveal
            self._review_hw_reveal_confirm = False
            self._perform_review_reveal()
            
        except Exception as e:
            Logger.error(f'Review: Error in handwriting reveal: {e}')
    
    def _perform_review_reveal(self):
        """Actually perform the reveal with stroke order animation."""
        try:
            if self._review_index >= len(self._review_queue):
                return
            
            vector = self._review_queue[self._review_index]
            characters = vector.get('characters', [])
            current_idx = vector.get('current_char_index', 0)
            
            if current_idx >= len(characters):
                return
            
            expected_char = characters[current_idx]
            
            # Mark as revealed (counts as wrong)
            vector['_hw_revealed'] = True
            
            # Update the display to show the character in red (wrong)
            question_label = self.root.ids.get('review_question')
            if question_label:
                char_results = vector.get('char_results', [])
                blanks = []
                for i, char in enumerate(characters):
                    if i < len(char_results):
                        blanks.append(f'[color=60ff60]{char}[/color]' if char_results[i] else f'[color=ff6060]{char}[/color]')
                    elif i == current_idx:
                        blanks.append(f'[color=ff6060][b]{char}[/b][/color]')
                    else:
                        blanks.append('_')
                display_text = ' '.join(blanks)
                question_label.text = display_text
                question_label.markup = True
            
            # Replace handwriting canvas with stroke order widget
            handwriting_container = self.root.ids.get('review_handwriting_container')
            if handwriting_container:
                from app.widgets.stroke_order_widget import StrokeOrderWidget
                
                # Remove canvas from container
                if hasattr(self, '_review_handwriting_canvas') and self._review_handwriting_canvas.parent == handwriting_container:
                    handwriting_container.remove_widget(self._review_handwriting_canvas)
                
                # Create stroke order widget
                stroke_widget = StrokeOrderWidget(
                    size_hint=(1, 1),
                    show_numbers=True
                )
                handwriting_container.clear_widgets()
                handwriting_container.add_widget(stroke_widget)
                
                # Store reference and set kanji (triggers load)
                self._review_stroke_order_widget = stroke_widget
                stroke_widget.kanji = expected_char
                
                # Show all strokes immediately (user can animate via Play)
                from kivy.clock import Clock
                Clock.schedule_once(lambda dt: stroke_widget.show_all_strokes(), 0.1)
                
                self._review_stroke_order_active = True
            
            # Change button text: Reveal -> Play, Undo -> Erase
            reveal_btn = self.root.ids.get('review_hw_reveal')
            if reveal_btn:
                reveal_btn.text = 'Play'
                reveal_btn.background_color = (0.25, 0.35, 0.50, 1)
            
            undo_btn = self.root.ids.get('review_hw_undo')
            if undo_btn:
                undo_btn.text = 'Erase'
            
            # Update feedback
            feedback_label = self.root.ids.get('review_feedback')
            if feedback_label:
                answer = vector.get('answer', '')
                feedback_label.text = f'Revealed: {expected_char} (from {answer})'
                feedback_label.color = (0.85, 0.70, 0.30, 1)
            
            # Change Check button to Continue
            submit_btn = self.root.ids.get('review_hw_submit')
            if submit_btn:
                submit_btn.text = 'Continue'
                submit_btn.background_color = (0.20, 0.45, 0.25, 1)
            
            Logger.info(f'Review: Revealed character with stroke order: {expected_char}')
        except Exception as e:
            Logger.error(f'Review: Error performing reveal: {e}')
            import traceback
            traceback.print_exc()
    
    def _cleanup_review_stroke_order(self):
        """Clean up stroke order widget after reveal, restoring button text."""
        # Reset confirm flag
        self._review_hw_reveal_confirm = False
        if getattr(self, '_review_stroke_order_active', False):
            # Stop animation
            if hasattr(self, '_review_stroke_order_widget'):
                self._review_stroke_order_widget.stop_animation()
            
            # Reset button text
            undo_btn = self.root.ids.get('review_hw_undo')
            if undo_btn:
                undo_btn.text = 'Undo'
            reveal_btn = self.root.ids.get('review_hw_reveal')
            if reveal_btn:
                reveal_btn.text = 'Reveal'
                reveal_btn.background_color = (0.60, 0.15, 0.20, 1)
            
            self._review_stroke_order_active = False
            self._review_free_draw_active = False
            self._review_free_draw_canvas = None
            Logger.info('Review: Cleaned up stroke order widget')
    
    def _switch_to_review_free_draw(self):
        """Replace stroke order display with a free-draw canvas (Erase was clicked)."""
        from app.widgets.handwriting_canvas import HandwritingCanvas
        handwriting_container = self.root.ids.get('review_handwriting_container')
        if not handwriting_container:
            return
        if hasattr(self, '_review_stroke_order_widget'):
            self._review_stroke_order_widget.stop_animation()
        handwriting_container.clear_widgets()
        canvas = HandwritingCanvas(size_hint=(1, 1))
        handwriting_container.add_widget(canvas)
        self._review_free_draw_canvas = canvas
        self._review_stroke_order_active = False
        self._review_free_draw_active = True
        Logger.info('Review: Switched to free-draw mode')

    def on_review_handwriting_undo(self):
        """Handle undo button in handwriting mode - remove last stroke."""
        try:
            if hasattr(self, '_review_handwriting_canvas'):
                self._review_handwriting_canvas.undo_stroke()
                Logger.info('Review: Undid last handwriting stroke')
        except Exception as e:
            Logger.error(f'Review: Error in handwriting undo: {e}')

    def on_review_handwriting_back(self):
        """Handle back button - go to previous character with confirmation."""
        try:
            if self._review_index >= len(self._review_queue):
                return
            
            vector = self._review_queue[self._review_index]
            
            # If stroke order or free-draw mode is showing, back cancels the reveal and restores drawing
            if getattr(self, '_review_stroke_order_active', False) or getattr(self, '_review_free_draw_active', False):
                self._cleanup_review_stroke_order()
                vector['_hw_revealed'] = False
                # Restore handwriting canvas
                handwriting_container = self.root.ids.get('review_handwriting_container')
                if handwriting_container and hasattr(self, '_review_handwriting_canvas'):
                    handwriting_container.clear_widgets()
                    handwriting_container.add_widget(self._review_handwriting_canvas)
                    self._review_handwriting_canvas.clear_canvas()
                    self._review_handwriting_canvas.disabled = False
                # Reset submit button
                submit_btn = self.root.ids.get('review_hw_submit')
                if submit_btn:
                    submit_btn.text = 'Check'
                    submit_btn.background_color = (0.25, 0.35, 0.50, 1)
                # Restore feedback to definition
                feedback_label = self.root.ids.get('review_feedback')
                if feedback_label:
                    feedback_label.text = vector.get('prompt', '')
                    feedback_label.color = (0.60, 0.58, 0.55, 1)
                    feedback_label.markup = False
                # Restore question blanks display
                question_label = self.root.ids.get('review_question')
                if question_label:
                    characters = vector.get('characters', [])
                    current_idx = vector.get('current_char_index', 0)
                    char_results = vector.get('char_results', [])
                    blanks = []
                    for i, char in enumerate(characters):
                        if i < len(char_results):
                            blanks.append(f'[color=60ff60]{char}[/color]' if char_results[i] else f'[color=ff6060]{char}[/color]')
                        elif i == current_idx:
                            blanks.append('[b]_[/b]')
                        else:
                            blanks.append('_')
                    question_label.text = ' '.join(blanks)
                    question_label.markup = True
                Logger.info('Review: Cancelled reveal, restored drawing mode')
                return
            
            current_idx = vector.get('current_char_index', 0)
            
            # If we're at the first character, can't go back
            if current_idx == 0:
                Logger.info('Review: Already at first character')
                return
            
            # Show confirmation popup
            from kivy.uix.popup import Popup
            from kivy.uix.boxlayout import BoxLayout
            from kivy.uix.label import Label
            from kivy.uix.button import Button
            from kivy.metrics import dp
            
            content = BoxLayout(orientation='vertical', spacing=dp(12), padding=dp(12))
            
            msg_label = Label(
                text="Really go back? This will undo this character's progress.",
                font_name='fonts/NotoSansJP-Regular.ttf',
                color=(0.90, 0.88, 0.85, 1),
                size_hint_y=None,
                height=dp(60),
                halign='center',
                valign='middle'
            )
            msg_label.bind(size=lambda instance, value: setattr(instance, 'text_size', value))
            content.add_widget(msg_label)
            
            btn_box = BoxLayout(orientation='horizontal', spacing=dp(8), size_hint_y=None, height=dp(48))
            
            cancel_btn = Button(
                text='Cancel',
                background_normal='',
                background_color=(0.35, 0.33, 0.30, 1),
                color=(0.90, 0.88, 0.85, 1),
                font_name='fonts/NotoSansJP-Regular.ttf'
            )
            
            confirm_btn = Button(
                text='Go Back',
                background_normal='',
                background_color=(0.70, 0.65, 0.20, 1),
                color=(0.90, 0.88, 0.85, 1),
                font_name='fonts/NotoSansJP-Regular.ttf'
            )
            
            btn_box.add_widget(cancel_btn)
            btn_box.add_widget(confirm_btn)
            content.add_widget(btn_box)
            
            popup = Popup(
                title='Confirm Go Back',
                content=content,
                size_hint=(0.8, 0.35),
                background_color=(0.18, 0.18, 0.20, 1)
            )
            
            cancel_btn.bind(on_release=lambda *_: popup.dismiss())
            confirm_btn.bind(on_release=lambda *_: self._do_handwriting_back(popup, vector))
            
            popup.open()
            
        except Exception as e:
            Logger.error(f'Review: Error in handwriting back: {e}')
    
    def _do_handwriting_back(self, popup, vector):
        """Actually go back to previous character."""
        try:
            popup.dismiss()
            
            # Move back one character
            current_idx = vector.get('current_char_index', 0)
            if current_idx > 0:
                vector['current_char_index'] = current_idx - 1
                # Remove the last result
                if 'char_results' in vector and vector['char_results']:
                    vector['char_results'].pop()
                
                # Reload the review with previous character
                self._load_handwriting_review(vector)
                Logger.info(f'Review: Went back to character {vector["current_char_index"]}')
        except Exception as e:
            Logger.error(f'Review: Error in _do_handwriting_back: {e}')
    
    def on_review_handwriting_auto(self):
        """Handle auto button - mark current character as correct automatically."""
        try:
            if self._review_index >= len(self._review_queue):
                return
            
            vector = self._review_queue[self._review_index]
            characters = vector.get('characters', [])
            current_idx = vector.get('current_char_index', 0)
            
            if current_idx >= len(characters):
                Logger.info('Review: Already at last character')
                return
            
            # Mark current character as correct (auto)
            if 'char_results' not in vector:
                vector['char_results'] = []
            vector['char_results'].append(True)
            
            # Update display to show character in green before moving to next
            question_label = self.root.ids.get('review_question')
            if question_label:
                answer = vector.get('answer', '')
                blanks = []
                for i, char in enumerate(characters):
                    if i < len(vector['char_results']):
                        # Character completed - show in green or red
                        color = '60ff60' if vector['char_results'][i] else 'ff6060'
                        blanks.append(f'[color={color}]{char}[/color]')
                    elif i == current_idx + 1:
                        # Next character (after current) - show blank
                        blanks.append('＿')
                    else:
                        blanks.append('＿')
                question_label.text = ''.join(blanks)
            
            # Clear canvas
            if hasattr(self, '_review_handwriting_canvas'):
                self._review_handwriting_canvas.clear_canvas()
            
            # Move to next character
            vector['current_char_index'] = current_idx + 1
            
            # Check if all characters are done
            if vector['current_char_index'] >= len(characters):
                # All characters tested
                all_correct = all(vector['char_results'])
                Logger.info(f'Review: Auto-marked to end. Results: {vector["char_results"]}, Overall: {all_correct}')
                
                # Submit to SRS
                entry_id = vector['entry_id']
                kind = vector['kind']
                vector_type = vector['vector_type']
                
                grade = 3 if all_correct else 1
                self._apply_review_grade(entry_id, kind, vector_type, grade, grammar_category=vector.get('grammar_category'))
                
                # Show feedback
                feedback_label = self.root.ids.get('review_feedback')
                answer = vector.get('answer', '')
                if feedback_label:
                    if all_correct:
                        feedback_label.text = f'✓ Correct! {answer}'
                        feedback_label.color = (0.20, 0.65, 0.30, 1)
                    else:
                        feedback_label.text = f'Answer: {answer}'
                        feedback_label.color = (0.85, 0.40, 0.35, 1)
                
                # Set waiting flag and change button to Continue
                self._review_waiting_continue = True
                submit_btn = self.root.ids.get('review_hw_submit')
                if submit_btn:
                    submit_btn.text = 'Continue'
                    submit_btn.background_color = (0.15, 0.65, 0.15, 1)  # Green
            else:
                # More characters - move to next character after brief delay
                Logger.info(f'Review: Auto-marked, moving to next character ({vector["current_char_index"]}/{len(characters)})')
                from kivy.clock import Clock
                Clock.schedule_once(lambda dt: self._load_handwriting_review(vector), 0.1)
            
        except Exception as e:
            Logger.error(f'Review: Error in handwriting auto: {e}')
    
    def on_review_submit(self):
        """Handle submit button press - check answer and grade."""
        try:
            Logger.info('Review: Submit button pressed')
            
            if self._review_index >= len(self._review_queue):
                return
            
            # Check if this is a handwriting review — must happen BEFORE any
            # focus manipulation so the keyboard stays closed for handwriting.
            vector = self._review_queue[self._review_index]
            Logger.info(f'Review: Vector type = {vector.get("vector_type")}')
            if vector.get('vector_type') == 'handwriting':
                return self.on_review_handwriting_submit()

            # Keep the keyboard alive between TYPING questions by refocusing
            # the input before Android's IME dismiss animation completes.
            if not getattr(self, '_review_waiting_continue', False):
                _ri = self.root.ids.get('review_input')
                if _ri and not _ri.readonly:
                    _ri.focus = True
            
            # Check if we're waiting for continue after showing feedback
            if getattr(self, '_review_waiting_continue', False):
                # User clicked Continue, proceed to next card
                self._review_waiting_continue = False
                
                # Reset submit button
                submit_btn = self.root.ids.get('review_submit_btn')
                if submit_btn:
                    submit_btn.text = 'Submit'
                    submit_btn.background_color = (0.15, 0.45, 0.65, 1)  # Blue
                
                # Reset attempt counter color (in case color flash is still active)
                attempt_counter = self.root.ids.get('review_attempt_counter')
                if attempt_counter and not self.hide_review_counter:
                    attempt_counter.color = (0.15, 0.45, 0.65, 1)
                
                # Clear feedback
                feedback_label = self.root.ids.get('review_feedback')
                if feedback_label:
                    feedback_label.text = ''
                
                # Move to next
                self._review_index += 1
                self._load_current_review()
                return
            
            # If answer was revealed, just continue to next card
            if getattr(self, '_review_revealed', False):
                self._review_index += 1
                self._load_current_review()
                return
            
            vector = self._review_queue[self._review_index]
            entry_id = vector['entry_id']
            vector_type = vector['vector_type']
            kind = vector['kind']
            
            # Get correct answer - different for grammar vs regular vectors
            is_grammar = vector.get('kind') == 'grammar'
            if is_grammar and vector_type in ('translate', 'dictation'):
                correct_answer = vector['answer']
            elif is_grammar and hasattr(self, '_current_grammar_exercise'):
                correct_answer = self._current_grammar_exercise.get('correct_answer', '')
            else:
                correct_answer = vector['answer']
            
            text_input = self.root.ids.get('review_input')
            
            if not text_input:
                return
            
            user_answer = text_input.text.strip()
            
            if not user_answer:
                Logger.info('Review: Empty answer, ignoring')
                return
            
            # Import check_answer_match upfront so it's available for wrong-vector check later
            from dictionary.learning import check_answer_match

            # Check answer - special handling for grammar types
            if is_grammar and vector_type == 'fill-blank':
                is_correct = user_answer == correct_answer
                # Also accept kana/romaji if correct answer contains kanji
                if not is_correct:
                    is_correct = self._flexible_sentence_match(user_answer, correct_answer)
            elif is_grammar and vector_type == 'scramble':
                correct_sentence = getattr(self, '_current_scramble_correct', '') or self._current_review_vector.get('answer', '')
                is_correct = self._flexible_sentence_match(user_answer, correct_sentence)
                correct_answer = correct_sentence
                Logger.info(f'Review Scramble: user="{user_answer}" correct="{correct_sentence}" match={is_correct}')
            elif is_grammar and vector_type == 'translate':
                correct_sentence = vector.get('answer', '')
                is_correct = self._flexible_sentence_match(user_answer, correct_sentence)
                correct_answer = correct_sentence
                Logger.info(f'Review Translate: user="{user_answer}" correct="{correct_sentence}" match={is_correct}')
            elif is_grammar and vector_type == 'dictation':
                correct_sentence = vector.get('answer', '')
                is_correct = self._flexible_sentence_match(user_answer, correct_sentence)
                correct_answer = correct_sentence
                Logger.info(f'Review Dictation: user="{user_answer}" correct="{correct_sentence}" match={is_correct}')
            else:
                # Regular vocab/kanji answer validation
                is_correct = check_answer_match(user_answer, correct_answer, vector_type)
            
            Logger.info(f'Review: Answer "{user_answer}" vs "{correct_answer}" (vector_type={vector_type}) = {is_correct}')

            # If wrong, check if user answered a different vector for same entry
            if not is_correct:
                # Get all vectors for this entry
                conn = None
                all_vectors = []
                try:
                    conn = dict_db.init_db(get_db_path())
                    import dictionary.learning as learning
                    all_vectors = learning.make_vectors_for_entries(conn, [entry_id], kind)
                except Exception as e:
                    Logger.error(f'Review: Error getting vectors: {e}')
                finally:
                    if conn:
                        try:
                            conn.close()
                        except Exception as e:
                            Logger.warning(f'Review: Error closing connection: {e}')
                
                # Check if answer matches any other vector using check_answer_match
                for other_vec in all_vectors:
                    if other_vec['vector_type'] == vector_type:
                        continue  # Skip current vector
                    
                    other_answer = other_vec.get('answer', '')
                    other_vector_type = other_vec.get('vector_type', '')
                    
                    # Use check_answer_match for consistent validation
                    matches_other = check_answer_match(user_answer, other_answer, other_vector_type)
                    
                    if matches_other:
                        # User answered the wrong vector type
                        feedback_label = self.root.ids.get('review_feedback')
                        if feedback_label:
                            # Determine what they typed vs what's asked
                            other_type_name = 'reading' if 'reading' in other_vec['vector_type'] or other_vec['vector_type'] in ('show_kana', 'show_romaji') else 'meaning'
                            current_type_name = 'reading' if 'reading' in vector_type or vector_type in ('show_kana', 'show_romaji') else 'meaning'
                            
                            feedback_label.text = f"That's the {other_type_name}, this asks for the {current_type_name}"
                            feedback_label.color = (0.9, 0.6, 0.1, 1)  # Orange/warning color
                        
                        # Clear input and keep focus so user can try again immediately
                        if text_input:
                            text_input.text = ''
                            Clock.schedule_once(lambda dt: setattr(text_input, 'focus', True), 0.05)
                        
                        # Don't submit, let them try again
                        return
                
                # Check for synonym confusion (e.g. なぜ vs どうして)
                if vector_type == 'meaning_to_kana':
                    _synonym_hints = {
                        'なぜ': 2,
                        'どうして': 4,
                    }
                    expected_kana = correct_answer.strip()
                    user_kana = user_answer.strip()
                    if expected_kana in _synonym_hints and user_kana in _synonym_hints and user_kana != expected_kana:
                        char_count = _synonym_hints[expected_kana]
                        feedback_label = self.root.ids.get('review_feedback')
                        if feedback_label:
                            feedback_label.text = f"Hint: {char_count} characters"
                            feedback_label.color = (0.9, 0.6, 0.1, 1)
                        if text_input:
                            text_input.text = ''
                            Clock.schedule_once(lambda dt: setattr(text_input, 'focus', True), 0.05)
                        return

                # Check for homonym confusion (e.g. やさしい easy vs kind)
                if vector_type in ('kana_to_meaning', 'orthography_to_meaning'):
                    _homonym_map = {
                        'やさしい': [
                            {'gloss': 'easy; plain; simple', 'kanji': '易しい'},
                            {'gloss': 'tender; kind; gentle; graceful; affectionate; amiable', 'kanji': '優しい'},
                        ],
                    }
                    kana_key = vector.get('prompt', '').strip()
                    if kana_key in _homonym_map:
                        for other in _homonym_map[kana_key]:
                            if check_answer_match(user_answer, other['gloss'], vector_type):
                                # User answered with the other homonym's meaning
                                if check_answer_match(user_answer, correct_answer, vector_type):
                                    break  # Actually correct, don't intercept
                                feedback_label = self.root.ids.get('review_feedback')
                                if feedback_label:
                                    feedback_label.text = f"That's {other['kanji']} — this one means something else"
                                    feedback_label.color = (0.9, 0.6, 0.1, 1)
                                if text_input:
                                    text_input.text = ''
                                    Clock.schedule_once(lambda dt: setattr(text_input, 'focus', True), 0.05)
                                return

            # Update attempt counter based on correctness
            attempt_counter = self.root.ids.get('review_attempt_counter')
            if attempt_counter and not self.hide_review_counter:
                if is_correct:
                    attempt_counter.text = '1 / 1'
                    attempt_counter.color = (0.20, 0.70, 0.20, 1)  # Green
                    Logger.info('Review: Attempt counter flashing GREEN')
                else:
                    attempt_counter.text = '0 / 1'
                    attempt_counter.color = (0.85, 0.20, 0.20, 1)  # Red
                    Logger.info('Review: Attempt counter flashing RED')
                # Reset to default color after 0.5 seconds
                Clock.schedule_once(lambda dt: setattr(attempt_counter, 'color', (0.15, 0.45, 0.65, 1)), 0.5)
            elif not attempt_counter:
                Logger.warning('Review: attempt_counter not found in UI')
            
            # Show feedback
            feedback_label = self.root.ids.get('review_feedback')
            if feedback_label:
                if is_correct:
                    feedback_label.text = '✓ Correct!'
                    feedback_label.color = (0.15, 0.65, 0.15, 1)
                else:
                    feedback_label.text = f'✗ Incorrect - Answer: {correct_answer}'
                    feedback_label.color = (0.85, 0.20, 0.20, 1)
            
            # Flash counter color based on correctness
            counter_label = self.root.ids.get('review_counter')
            if counter_label and not self.hide_review_counter:
                if is_correct:
                    counter_label.color = (0.20, 0.70, 0.20, 1)  # Green
                else:
                    counter_label.color = (0.85, 0.20, 0.20, 1)  # Red
                # Reset color after 0.5 seconds
                Clock.schedule_once(lambda dt: setattr(counter_label, 'color', (0.40, 0.40, 0.40, 1)), 0.5)
            
            # Auto-grade: correct = Good (3), incorrect = Again (1)
            grade = 3 if is_correct else 1
            
            # Build vector key for tracking
            vector_key = f"{entry_id}:{vector_type}"
            
            # Check if this is the first attempt at this vector
            graded_vectors = getattr(self, '_review_graded_vectors', set())
            is_first_attempt = vector_key not in graded_vectors
            
            # Handle wrong answers: track count and re-add to queue
            if not is_correct:
                # Increment wrong count for this vector
                wrong_counts = getattr(self, '_review_wrong_counts', {})
                wrong_counts[vector_key] = wrong_counts.get(vector_key, 0) + 1
                self._review_wrong_counts = wrong_counts
                
                attempt_info = "(first attempt)" if is_first_attempt else "(retry)"
                Logger.info(f'Review: Vector {vector_key} wrong {wrong_counts[vector_key]} time(s) {attempt_info}')
                
                # If failed 3 times, mark for drill
                if wrong_counts[vector_key] >= 3:
                    Logger.info(f'Review: Vector {vector_key} failed 3+ times, marking for drill')
                    self._mark_for_drill(entry_id, vector_type)
                else:
                    # Add back to end of queue
                    self._review_queue.append(vector)
                    Logger.info(f'Review: Re-added vector {vector_key} to end of queue')
            else:
                # Reset wrong count on correct answer
                wrong_counts = getattr(self, '_review_wrong_counts', {})
                if vector_key in wrong_counts:
                    wrong_counts[vector_key] = 0
            
            # Save to history for undo
            self._review_history.append({
                'entry_id': entry_id,
                'vector_type': vector_type,
                'grade': grade,
                'index': self._review_index,
                'is_first_attempt': is_first_attempt,
                'vector_key': vector_key,
                'was_in_queue': not is_correct  # Track if we added it back to queue
            })
            
            # Only apply SRS grade on first attempt
            if is_first_attempt:
                # Save previous SRS state before updating for undo
                conn = dict_db.init_db(get_db_path())
                prev_srs = dict_db.get_srs_vector(conn, entry_id, kind, vector_type)
                conn.close()
                self._review_history[-1]['prev_srs'] = prev_srs.copy()
                
                self._apply_review_grade(entry_id, kind, vector_type, grade, grammar_category=vector.get('grammar_category'))
                graded_vectors.add(vector_key)
                self._review_graded_vectors = graded_vectors
                Logger.info(f'Review: Applied SRS grade {grade} to vector {vector_key}')
            else:
                Logger.info(f'Review: Skipped SRS update for retry attempt on vector {vector_key}')
            
            # Enable undo button now that we have history
            undo_btn = self.root.ids.get('review_undo_btn')
            if undo_btn:
                undo_btn.disabled = False
            
            # Auto TTS after answering
            self._auto_tts_after_answer(vector)
            
            if is_correct:
                # Correct - move to next card immediately (color flash delay is independent)
                self._review_index += 1
                self._load_current_review()
            else:
                # Incorrect - pause to show feedback
                self._review_waiting_continue = True
                submit_btn = self.root.ids.get('review_submit_btn')
                if submit_btn:
                    submit_btn.text = 'Continue'
                    submit_btn.background_color = (0.15, 0.65, 0.15, 1)  # Green
            
        except Exception as e:
            Logger.error(f'Review: Error submitting answer: {e}')
    
    def on_review_reveal(self):
        """Handle reveal button press - show answer and mark as wrong."""
        try:
            Logger.info('Review: Reveal button pressed')
            reveal_btn = self.root.ids.get('review_reveal_btn')
            
            if not reveal_btn:
                return
            
            # Check if we need confirmation
            reveal_confirm = getattr(self, '_reveal_confirm', False)
            
            if not reveal_confirm:
                # First click: show confirmation (yellow, warns it counts as wrong)
                reveal_btn.text = 'Reveal?'
                reveal_btn.background_color = (0.68, 0.56, 0.15, 1)
                self._reveal_confirm = True
                Logger.info('Review: Reveal confirmation requested')
                return
            
            # Second click: actually reveal
            if self._review_index >= len(self._review_queue):
                return
            
            vector = self._review_queue[self._review_index]
            entry_id = vector['entry_id']
            vector_type = vector['vector_type']
            kind = vector['kind']
            
            # Get correct answer - different for grammar vs regular vectors
            is_grammar = vector.get('kind') == 'grammar'
            if is_grammar and vector_type == 'scramble':
                correct_answer = getattr(self, '_current_scramble_correct', '') or vector.get('answer', '')
            elif is_grammar and vector_type in ('translate', 'dictation'):
                correct_answer = vector.get('answer', '')
            elif is_grammar and hasattr(self, '_current_grammar_exercise'):
                correct_answer = self._current_grammar_exercise.get('correct_answer', '')
            else:
                correct_answer = vector['answer']
            
            vector_key = f"{entry_id}:{vector_type}"
            
            # Show answer in feedback label (red text below)
            text_input = self.root.ids.get('review_input')
            submit_btn = self.root.ids.get('review_submit_btn')
            reveal_btn = self.root.ids.get('review_reveal_btn')
            feedback_label = self.root.ids.get('review_feedback')
            
            # Show feedback (don't set text_input readonly — keeps keyboard
            # alive on Android so the layout doesn't shift and user can
            # tap Continue without being "stuck").
            if feedback_label:
                # Truncate long answers for display
                max_length = 60
                display_answer = correct_answer
                if len(correct_answer) > max_length:
                    display_answer = correct_answer[:max_length] + '...'
                
                feedback_label.text = f'Answer: {display_answer}'
                feedback_label.color = (0.85, 0.20, 0.20, 1)
            
            # Change Submit button to "Continue"
            if submit_btn:
                submit_btn.text = 'Continue'
                submit_btn.background_color = (0.15, 0.65, 0.15, 1)
            
            # Disable Reveal button
            if reveal_btn:
                reveal_btn.disabled = True
                reveal_btn.opacity = 0.5
            
            # Use waiting_continue so Submit/Continue works the same as
            # the wrong-answer flow (consistent UX).
            self._review_waiting_continue = True
            
            Logger.info(f'Review: Revealed answer "{correct_answer}" for vector {vector_key}')
            
            # Check if this is the first attempt at this vector
            graded_vectors = getattr(self, '_review_graded_vectors', set())
            is_first_attempt = vector_key not in graded_vectors
            
            # Track wrong count for revealed answers
            wrong_counts = getattr(self, '_review_wrong_counts', {})
            wrong_counts[vector_key] = wrong_counts.get(vector_key, 0) + 1
            self._review_wrong_counts = wrong_counts
            
            Logger.info(f'Review: Vector {vector_key} revealed (wrong {wrong_counts[vector_key]} time(s)) {"(first attempt)" if is_first_attempt else "(retry)"}')
            
            # If failed 3 times, mark for drill
            if wrong_counts[vector_key] >= 3:
                Logger.info(f'Review: Vector {vector_key} failed 3+ times, marking entry {entry_id} for drill')
                self._mark_for_drill(entry_id, vector_type)
            else:
                # Add back to end of queue
                self._review_queue.append(vector)
                Logger.info(f'Review: Re-added vector {vector_key} to end of queue')
            
            # Grade as wrong (1 = Again)
            grade = 1
            
            # Save to history for undo (include all fields for consistency with submit)
            self._review_history.append({
                'entry_id': entry_id,
                'vector_type': vector_type,
                'grade': grade,
                'index': self._review_index,
                'is_first_attempt': is_first_attempt,
                'vector_key': vector_key,
                'was_in_queue': True  # Revealed answers are always added back to queue
            })
            
            # Only apply SRS grade on first attempt
            if is_first_attempt:
                # Save previous SRS state before updating for undo
                conn = None
                try:
                    conn = dict_db.init_db(get_db_path())
                    prev_srs = dict_db.get_srs_vector(conn, entry_id, kind, vector_type)
                    if prev_srs:
                        self._review_history[-1]['prev_srs'] = prev_srs.copy()
                except Exception as e:
                    Logger.error(f'Review: Error saving SRS state in reveal: {e}')
                finally:
                    if conn:
                        try:
                            conn.close()
                        except Exception as e:
                            Logger.warning(f'Review: Error closing connection: {e}')
                
                self._apply_review_grade(entry_id, kind, vector_type, grade, grammar_category=vector.get('grammar_category'))
                graded_vectors.add(vector_key)
                self._review_graded_vectors = graded_vectors
                Logger.info(f'Review: Applied SRS grade {grade} to vector {vector_key}')
            else:
                Logger.info(f'Review: Skipped SRS update for retry attempt on vector {vector_key}')
            
            # Enable undo button now that we have history
            undo_btn = self.root.ids.get('review_undo_btn')
            if undo_btn:
                undo_btn.disabled = False
            
            # Auto TTS after reveal
            self._auto_tts_after_answer(vector)
            
            # Set flag that answer was revealed (so Submit continues instead of checking)
            self._review_revealed = True
            
        except Exception as e:
            Logger.error(f'Review: Error revealing answer: {e}')
    
    def on_review_undo(self):
        """Handle undo button press."""
        try:
            Logger.info('Review: Undo button pressed')
            
            # Check if this is a handwriting review - undo should remove last stroke
            if self._review_index < len(self._review_queue):
                vector = self._review_queue[self._review_index]
                if vector.get('vector_type') == 'handwriting':
                    if hasattr(self, '_review_handwriting_canvas'):
                        self._review_handwriting_canvas.undo_stroke()
                        Logger.info('Review: Undid last stroke')
                    return
            
            undo_btn = self.root.ids.get('review_undo_btn')
            
            if not undo_btn:
                return
            
            if not self._review_history:
                Logger.info('Review: No history to undo')
                return
            
            # First click: show confirmation (yellow)
            if not self._undo_confirm:
                undo_btn.text = 'Undo? (Reset)'
                undo_btn.background_color = (0.68, 0.56, 0.15, 1)
                self._undo_confirm = True
                Logger.info('Review: Undo confirmation requested')
            else:
                # Second click: actually undo
                last_action = self._review_history.pop()
                entry_id = last_action['entry_id']
                vector_type = last_action['vector_type']
                vector_key = last_action['vector_key']
                is_first_attempt = last_action['is_first_attempt']
                
                Logger.info(f'Review: Undoing entry {entry_id} vector {vector_type}')
                
                # If this was a first attempt, revert the SRS changes
                if is_first_attempt and 'prev_srs' in last_action:
                    conn = dict_db.init_db(get_db_path())
                    prev_srs = last_action['prev_srs']
                    
                    # Get the kind
                    cursor = conn.cursor()
                    cursor.execute('SELECT kind FROM entries WHERE id = ?', (entry_id,))
                    kind_row = cursor.fetchone()
                    kind = kind_row[0] if kind_row else 'vocab'
                    
                    # Restore previous SRS state
                    dict_db.update_srs_vector(conn, entry_id, kind, prev_srs, vector_type)

                    # Undo daily activity tracking
                    try:
                        was_first = (prev_srs.get('reps', 0) == 0)
                        if was_first:
                            dict_db.record_daily_activity(conn, reviewed=0, learned=-1)
                        else:
                            dict_db.record_daily_activity(conn, reviewed=-1, learned=0)
                    except Exception:
                        pass

                    conn.close()
                    
                    # Remove from graded vectors set
                    graded_vectors = getattr(self, '_review_graded_vectors', set())
                    if vector_key in graded_vectors:
                        graded_vectors.discard(vector_key)
                        self._review_graded_vectors = graded_vectors
                    
                    Logger.info(f'Review: Reverted SRS changes for vector {vector_key}')
                
                # If it was added back to queue (wrong answer), remove it
                if last_action.get('was_in_queue'):
                    # Find and remove the vector from the end of the queue
                    for i in range(len(self._review_queue) - 1, -1, -1):
                        v = self._review_queue[i]
                        if v.get('entry_id') == entry_id and v.get('vector_type') == vector_type:
                            self._review_queue.pop(i)
                            Logger.info(f'Review: Removed vector {vector_key} from queue')
                            break
                    
                    # Decrement wrong count
                    wrong_counts = getattr(self, '_review_wrong_counts', {})
                    if vector_key in wrong_counts and wrong_counts[vector_key] > 0:
                        wrong_counts[vector_key] -= 1
                        Logger.info(f'Review: Decremented wrong count for {vector_key}')
                
                # Reset reveal/continue state before reloading so the card
                # comes back in a fully interactive state (keyboard + input).
                self._review_index = last_action['index']
                self._undo_confirm = False
                self._review_revealed = False
                self._review_waiting_continue = False
                # Force text input back to editable before _load_current_review
                # so Android doesn't keep a stale readonly/unfocused state.
                _undo_ti = self.root.ids.get('review_input')
                if _undo_ti:
                    _undo_ti.readonly = False
                    _undo_ti.disabled = False
                self._load_current_review()
                
                # Extra aggressive focus recovery for Android:
                # after undo the keyboard may have dismissed; schedule
                # repeated focus attempts so the user can type immediately.
                def _force_focus_after_undo(dt):
                    ti = self.root.ids.get('review_input')
                    if ti and not ti.readonly and not ti.disabled:
                        ti.focus = True
                        Logger.info('Review: Undo force-focus fired')
                from kivy.clock import Clock
                Clock.schedule_once(_force_focus_after_undo, 0.1)
                Clock.schedule_once(_force_focus_after_undo, 0.4)
                
        except Exception as e:
            Logger.error(f'Review: Error in undo: {e}')
    
    def on_review_add_button(self):
        """Handle + button press during review."""
        try:
            if not hasattr(self, '_review_queue') or not hasattr(self, '_review_index'):
                return
            if self._review_index >= len(self._review_queue):
                return
            
            vector = self._review_queue[self._review_index]
            entry_id = vector.get('entry_id')
            
            # Fetch the entry
            conn = dict_db.init_db(get_db_path())
            cursor = conn.cursor()
            cursor.execute('SELECT * FROM entries WHERE id = ?', (entry_id,))
            row = cursor.fetchone()
            conn.close()
            
            if not row:
                return
            
            entry = dict(zip([col[0] for col in cursor.description], row))
            
            # Show the actions popup (same as dictionary entry)
            self._show_actions_popup_during_session(entry_id, entry, 'review')
            
        except Exception as e:
            Logger.error(f'Review: Error showing add button popup: {e}')
    
    def _show_info_card_action_popup(self, entry_id):
        """Show entry action popup when + is tapped on an info card (same style as dictionary popup).

        Includes Queue / Lesson / Known / Dictionary actions.
        Marking as Known also skips the entry from the current lesson session.
        """
        import sqlite3 as _sq
        try:
            conn = _sq.connect(get_db_path())
            conn.row_factory = _sq.Row
            cursor = conn.cursor()
            cursor.execute('SELECT id, kanji, kana, gloss, pos, kind FROM entries WHERE id = ?', (entry_id,))
            entry = cursor.fetchone()
            conn.close()
            if not entry:
                return

            from kivy.uix.popup import Popup
            from kivy.uix.gridlayout import GridLayout

            entry_kind = entry['kind'] or 'vocab'
            is_in_queue = entry_id in getattr(self, '_lesson_queue', [])

            # Check if all vectors known (interval >= 180)
            all_vectors_known = False
            try:
                _tc = _sq.connect(get_db_path())
                import dictionary.learning as _lc
                _vecs = _lc.make_vectors_for_entries(_tc, [entry_id], entry_kind)
                if _vecs:
                    _ok = True
                    for _v in _vecs:
                        _sv = dict_db.get_srs_vector(_tc, entry_id, entry_kind, _v.get('vector_type'))
                        if (_sv.get('interval', 0) or 0) < 180:
                            _ok = False
                            break
                    all_vectors_known = _ok
                _tc.close()
            except Exception:
                pass

            word_text = entry['kanji'] or entry['kana']
            has_reading = bool(entry['kanji'] and entry['kana'] and entry['kanji'] != entry['kana'])

            content = BoxLayout(orientation='vertical', spacing=4,
                                padding=[dp(10), dp(12), dp(10), dp(6)])

            if has_reading:
                rl = Label(text=entry['kana'], font_size='12sp', size_hint_y=None,
                           height=dp(18), color=(0.7, 0.7, 0.7, 1))
                rl.font_name = 'fonts/NotoSansJP-Regular.ttf'
                content.add_widget(rl)

            wl = Label(text=word_text, font_size='20sp', size_hint_y=None,
                       height=dp(28), bold=True)
            wl.font_name = 'fonts/NotoSansJP-Regular.ttf'
            content.add_widget(wl)

            gloss_text = entry['gloss'] or ''
            if len(gloss_text) > 100:
                gloss_text = gloss_text[:100] + '...'
            dl = Label(text=gloss_text, size_hint_y=None, height=dp(44),
                       halign='center', valign='middle', font_size='13sp')
            dl.bind(width=lambda inst, val: setattr(inst, 'text_size', (val - dp(8), None)))
            content.add_widget(dl)

            btn_grid = GridLayout(cols=2, size_hint_y=None, height=dp(76), spacing=4)
            popup_ref = [None]

            # Queue
            queue_btn = Button(
                text='- Queue' if is_in_queue else '+ Queue',
                background_normal='',
                background_color=(0.65, 0.25, 0.20, 1) if is_in_queue else (0.20, 0.45, 0.25, 1)
            )
            def _on_ic_queue(*a, _eid=entry_id, _inq=is_in_queue):
                if not hasattr(self, '_lesson_queue'):
                    self._lesson_queue = []
                if _inq:
                    if _eid in self._lesson_queue:
                        self._lesson_queue.remove(_eid)
                        self._save_lesson_queue()
                    if popup_ref[0]:
                        popup_ref[0].dismiss()
                else:
                    def _do_add(position):
                        if _eid not in self._lesson_queue:
                            if position == 'front':
                                self._lesson_queue.insert(0, _eid)
                            else:
                                self._lesson_queue.append(_eid)
                            self._save_lesson_queue()
                        if popup_ref[0]:
                            popup_ref[0].dismiss()
                    self._show_queue_position_popup(_do_add)
            queue_btn.bind(on_release=_on_ic_queue)

            # Lesson
            lesson_btn = Button(text='+ Lesson', background_normal='',
                                background_color=(0.20, 0.45, 0.25, 1))
            def _on_ic_lesson(*a, _eid=entry_id):
                eds = self.root.ids.get('entry_detail_screen')
                if eds:
                    eds._show_custom_lesson_picker_detail(_eid, popup_ref[0])
            lesson_btn.bind(on_release=_on_ic_lesson)

            # Known
            known_btn = Button(
                text='\u2713 Known' if all_vectors_known else '+ Known',
                background_normal='',
                background_color=(0.545, 0.459, 0.125, 1) if all_vectors_known else (0.22, 0.22, 0.25, 1)
            )
            known_btn.font_name = 'fonts/NotoSansJP-Regular.ttf'
            def _on_ic_known(*a, _eid=entry_id):
                if popup_ref[0]:
                    popup_ref[0].dismiss()
                # Mark all vectors as known directly, then skip to next card
                self._mark_entry_known_and_skip(_eid)
            known_btn.bind(on_release=_on_ic_known)

            # Dictionary
            dict_btn = Button(text='Dictionary', background_normal='',
                              background_color=(0.22, 0.22, 0.25, 1))
            def _on_ic_dict(*a, _eid=entry_id):
                if popup_ref[0]:
                    popup_ref[0].dismiss()
                self.show_entry_detail(_eid)
            dict_btn.bind(on_release=_on_ic_dict)

            btn_grid.add_widget(queue_btn)
            btn_grid.add_widget(lesson_btn)
            btn_grid.add_widget(known_btn)
            btn_grid.add_widget(dict_btn)
            content.add_widget(btn_grid)

            close_btn = Button(text='Close', size_hint_y=None, height=dp(34),
                               background_normal='', background_color=(0.30, 0.30, 0.35, 1))
            close_btn.bind(on_release=lambda *_: popup_ref[0].dismiss())
            content.add_widget(close_btn)

            popup = Popup(
                title='', content=content,
                size_hint=(0.75, None),
                height=dp(250) if has_reading else dp(235),
                separator_height=0,
                background_color=(0.18, 0.18, 0.20, 1)
            )
            popup_ref[0] = popup
            popup.open()
        except Exception as e:
            Logger.error(f'InfoCard: Error showing action popup: {e}')
            import traceback
            traceback.print_exc()

    def _mark_entry_known_and_skip(self, entry_id):
        """Mark all SRS vectors for entry_id as Known (interval=365) then skip in lesson."""
        try:
            conn = dict_db.init_db(get_db_path())
            entry_data = dict_db.get_entry_by_id(conn, entry_id)
            entry_kind = (entry_data.get('kind') or 'vocab') if entry_data else 'vocab'

            from dictionary import learning as _learning
            vectors = _learning.make_vectors_for_entries(conn, [entry_id], entry_kind)

            from datetime import datetime, timedelta
            now = datetime.utcnow()
            far_future = (now + timedelta(days=365 * 10)).isoformat()

            for vec in vectors:
                dict_db.update_srs_vector(conn, entry_id, entry_kind, {
                    'interval': 365,
                    'ease': 2.5,
                    'reps': 10,
                    'due_at': far_future,
                    'last_seen': now.isoformat(),
                    'streak': 10,
                }, vec.get('vector_type'))

            conn.close()
            Logger.info(f'InfoCard: Marked entry {entry_id} as Known ({len(vectors)} vectors)')
        except Exception as e:
            Logger.error(f'InfoCard: Error marking entry {entry_id} as known: {e}')
            import traceback; traceback.print_exc()

        # Remove from session and advance immediately
        self._skip_lesson_entry_from_session(entry_id)

    def _skip_lesson_entry_from_session(self, entry_id):
        """Remove an entry's vectors from the current lesson session (mark as known/skipped).

        Called when the user marks an entry as Known from the info card popup.
        Removes vectors from all queues, updates total_vectors for the counter,
        and advances past the current info card for that entry.
        """
        try:
            if not hasattr(self, '_current_drill_session_id'):
                return
            conn = dict_db.init_db(get_db_path())
            session = dict_db.get_learning_session(conn, self._current_drill_session_id)
            if not session:
                conn.close()
                return
            data = session['data']
            removed_real = 0

            # Strip entry vectors from all queues
            for key in ('in_progress', 'pending', 'remaining_vectors'):
                lst = data.get(key, [])
                before = len(lst)
                kept = []
                for v in lst:
                    if v.get('entry_id') == entry_id:
                        if not v.get('is_filler') and not v.get('already_in_srs'):
                            removed_real += 1
                    else:
                        kept.append(v)
                data[key] = kept

            # Strip from batched_vectors
            if data.get('batched_vectors'):
                for bi, batch in enumerate(data['batched_vectors']):
                    kept = []
                    for v in batch:
                        if v.get('entry_id') == entry_id:
                            if not v.get('is_filler') and not v.get('already_in_srs'):
                                removed_real += 1
                        else:
                            kept.append(v)
                    data['batched_vectors'][bi] = kept

            # Strip from remaining_info
            if data.get('remaining_info'):
                data['remaining_info'] = [
                    c for c in data['remaining_info']
                    if c.get('entry_id') != entry_id
                ]

            # Clear pending_info_card if it belongs to this entry
            pic = data.get('pending_info_card')
            if pic:
                if isinstance(pic, list):
                    if any(c.get('entry_id') == entry_id for c in pic):
                        data['pending_info_card'] = None
                elif isinstance(pic, dict) and pic.get('entry_id') == entry_id:
                    data['pending_info_card'] = None

            # Strip the entry's info cards from batched_info so they don't replay
            current_info_index = data.get('info_index', 0)
            batch_idx = data.get('batch_index', 0)
            if data.get('batched_info'):
                for bi, batch in enumerate(data['batched_info']):
                    before = len(batch)
                    batch[:] = [c for c in batch if c.get('entry_id') != entry_id]
                    removed_cards = before - len(batch)
                    if removed_cards > 0:
                        Logger.info(f'InfoCard: Removed {removed_cards} info cards for entry {entry_id} from batched_info[{bi}]')
                    # If this is the current batch, adjust info_index
                    if bi == batch_idx and removed_cards > 0:
                        # Cards at or before info_index were removed — pull index back
                        data['info_index'] = max(0, min(current_info_index, len(batch) - 1))
                        if not batch:
                            data['info_index'] = 0

            # Also strip from flat info list
            if data.get('info'):
                before_info = len(data['info'])
                data['info'] = [c for c in data['info'] if c.get('entry_id') != entry_id]
                after_info = len(data['info'])
                # Adjust info_index for flat info list too
                if after_info < before_info:
                    data['info_index'] = max(0, min(current_info_index, after_info - 1))
                    if after_info == 0:
                        data['info_index'] = 0

            # Reduce total_vectors so the progress counter stays accurate
            meta = data.get('meta', {})
            old_total = meta.get('total_vectors', 0)
            meta['total_vectors'] = max(0, old_total - removed_real)
            data['meta'] = meta

            dict_db.update_learning_session(conn, self._current_drill_session_id, data)
            conn.close()
            Logger.info(f'InfoCard: Skipped entry {entry_id} from lesson session '
                        f'(removed {removed_real} real vectors, total {old_total}->{meta["total_vectors"]})')

            # Hide writing practice overlay if active (user may have been practicing)
            if getattr(self, 'writing_practice_active', False):
                self._hide_writing_practice()

            # Clear progressive unlock mode if active (user saw an unlock card
            # for this entry and marked it known from there).
            if getattr(self, '_progressive_unlock_mode', False):
                self._progressive_unlock_mode = False
                self._progressive_unlock_cards = []

            # Clear stale info card reference so the next + press uses the
            # correct entry (the next card shown by _load_current_drill).
            self._current_info_card = None

            # Instead of _advance_info_card_index (which blindly increments),
            # go straight to _load_current_drill which will pick up the cleaned
            # session data and show the correct next card or switch to drill phase.
            self._hide_info_card_overlay()
            self._load_current_drill()
        except Exception as e:
            Logger.error(f'InfoCard: Error skipping entry {entry_id}: {e}')
            import traceback
            traceback.print_exc()

    def on_drill_add_button(self):
        """Handle + button press during drill."""
        try:
            # Dismiss the keyboard first so the popup opens at full window height.
            # adjustResize shrinks the window while the keyboard is visible; if the
            # popup opens during that shrunken state it will be mis-positioned once
            # the window restores to full height when the keyboard dismisses.
            text_input = self.root.ids.get('drill_input')
            if text_input and text_input.focus:
                text_input.focus = False

            # During info card phase OR progressive unlock, show the compact entry popup
            # for the currently displayed info card (NOT the stale _current_drill_vector).
            if getattr(self, '_drill_mode', '') == 'lesson':
                card = getattr(self, '_current_info_card', None)
                if card:
                    # Check if an info card is actually visible: phase=='info', or
                    # progressive unlock mode, or writing practice for an info card.
                    info_visible = False
                    if getattr(self, '_progressive_unlock_mode', False):
                        info_visible = True
                    elif getattr(self, 'writing_practice_active', False):
                        info_visible = True
                    else:
                        overlay = self.root.ids.get('info_card_overlay')
                        if overlay and not overlay.disabled and overlay.opacity > 0:
                            info_visible = True
                        else:
                            try:
                                conn = dict_db.init_db(get_db_path())
                                session = dict_db.get_learning_session(conn, self._current_drill_session_id)
                                conn.close()
                                if session and session['data'].get('phase') == 'info':
                                    info_visible = True
                            except Exception:
                                pass
                    if info_visible:
                        _eid = card.get('entry_id')
                        if _eid:
                            Clock.schedule_once(
                                lambda dt, eid=_eid: self._show_info_card_action_popup(eid), 0.25)
                            return
                        pass

            if not hasattr(self, '_current_drill_vector') or not self._current_drill_vector:
                return

            vector = self._current_drill_vector
            entry_id = vector.get('entry_id')

            # Fetch the entry synchronously (fast) before the popup delay
            conn = dict_db.init_db(get_db_path())
            cursor = conn.cursor()
            cursor.execute('SELECT * FROM entries WHERE id = ?', (entry_id,))
            row = cursor.fetchone()
            conn.close()

            if not row:
                return

            entry = dict(zip([col[0] for col in cursor.description], row))

            # Delay 250 ms so the keyboard can finish dismissing and the window
            # can restore to full height before the popup sizes itself.
            Clock.schedule_once(
                lambda dt, eid=entry_id, e=entry:
                    self._show_actions_popup_during_session(eid, e, 'drill'),
                0.25)

        except Exception as e:
            Logger.error(f'Drill: Error showing add button popup: {e}')
    
