    def _get_vector_status(self, entry_id, entry_kind, vector_type):
        """Get the SRS status for a specific vector.
        
        Returns:
            Tuple of (status_name, status_color, percentage)
        """
        try:
            conn = dict_db.init_db(get_db_path())
            srs_vec = dict_db.get_srs_vector(conn, entry_id, entry_kind, vector_type)
            conn.close()
            
            interval = srs_vec.get('interval', 0) or 0
            
            # Calculate percentage toward Known (180 days = 100%)
            if interval >= 180:
                percentage = 100
                return ('Known', (0.545, 0.459, 0.125, 1), percentage)  # Gold #8B7520
            elif interval >= 120:
                # Mastered: 120-180 days = 50-99%
                percentage = min(99, int((interval - 120) / 60 * 49 + 50))
                return ('Mastered', (0.35, 0.50, 0.35, 1), percentage)
            elif interval >= 8:
                # Studying: 8-120 days = 25-49%
                percentage = min(49, int((interval - 8) / 112 * 24 + 25))
                return ('Studying', (0.30, 0.40, 0.55, 1), percentage)
            elif interval >= 1:
                # Fresh: 1-7 days = 5-24%
                percentage = min(24, int((interval - 1) / 6 * 19 + 5))
                return ('Fresh', (0.85, 0.45, 0.15, 1), percentage)
            else:
                return ('Unknown', (0.5, 0.5, 0.5, 1), 0)
        except Exception as e:
            Logger.error(f'SpoonfedApp: Error getting vector status: {e}')
            return ('Unknown', (0.5, 0.5, 0.5, 1), 0)
    
    def _get_vector_display_name(self, vector_type, kind):
        """Get a user-friendly name for a vector type."""
        names = {
            'show_kana': 'Kana -> Romaji',
            'show_romaji': 'Romaji -> Kana',
            'orthography_to_reading': 'Kanji -> Reading',
            'orthography_to_meaning': 'Kanji -> Meaning',
            'kana_to_meaning': 'Kana -> Meaning',
            'meaning_to_kana': 'Meaning -> Kana',
            'fill-blank': 'Fill in the Blank',
            'scramble': 'Word Scramble',
            'translate': 'Translate',
            'dictation': 'Listening Dictation',
            'handwriting': 'Handwriting',
            'default': 'Default'
        }
        return names.get(vector_type, vector_type)
    
    def _show_vector_management_popup(self, entry_id, entry):
        """Show popup to manage individual vector statuses with checkboxes."""
        from kivy.uix.checkbox import CheckBox
        
        entry_kind = entry.get('kind') or 'vocab'
        
        # Get all vectors for this entry
        try:
            conn = dict_db.init_db(get_db_path())
            from dictionary import learning as _learning
            vectors = _learning.make_vectors_for_entries(conn, [entry_id], entry_kind)
            conn.close()
        except Exception as e:
            Logger.error(f'SpoonfedApp: Error getting vectors: {e}')
            return
        
        if not vectors:
            Logger.warning(f'SpoonfedApp: No vectors found for entry {entry_id}')
            return
        
        # Main layout
        main_layout = BoxLayout(orientation='vertical', spacing=dp(8), padding=dp(12))
        
        # Title
        title_label = Label(
            text='Select Study Vectors',
            size_hint_y=None,
            height=dp(30),
            font_size='16sp',
            bold=True,
            halign='left',
            valign='middle'
        )
        title_label.bind(width=lambda instance, value: setattr(instance, 'text_size', (value, None)))
        main_layout.add_widget(title_label)
        
        # Scroll view for vectors
        scroll = ScrollView(size_hint=(1, 1), do_scroll_x=False)
        vectors_container = BoxLayout(orientation='vertical', size_hint_y=None, spacing=dp(4))
        vectors_container.bind(minimum_height=vectors_container.setter('height'))
        
        # Store checkboxes and vector info
        checkboxes = {}
        
        for vec in vectors:
            vector_type = vec.get('vector_type')
            status_name, status_color, percentage = self._get_vector_status(entry_id, entry_kind, vector_type)
            display_name = self._get_vector_display_name(vector_type, entry_kind)
            
            # Row for this vector
            row = BoxLayout(size_hint_y=None, height=dp(44), spacing=dp(8))
            
            # Checkbox
            cb = CheckBox(size_hint=(None, None), size=(dp(32), dp(32)), active=True)
            checkboxes[vector_type] = cb
            row.add_widget(cb)
            
            # Vector name and status
            info_box = BoxLayout(orientation='vertical', spacing=dp(2))
            
            name_label = Label(
                text=display_name,
                size_hint_y=None,
                height=dp(20),
                font_size='13sp',
                halign='left',
                valign='middle',
                color=(0.9, 0.9, 0.9, 1) if self.dark_mode else (0.1, 0.1, 0.1, 1)
            )
            name_label.bind(width=lambda instance, value: setattr(instance, 'text_size', (value, None)))
            
            status_label = Label(
                text=f'Status: {status_name} ({percentage}%)',
                size_hint_y=None,
                height=dp(18),
                font_size='11sp',
                halign='left',
                valign='middle',
                color=status_color
            )
            status_label.bind(width=lambda instance, value: setattr(instance, 'text_size', (value, None)))
            
            info_box.add_widget(name_label)
            info_box.add_widget(status_label)
            row.add_widget(info_box)
            
            vectors_container.add_widget(row)
        
        scroll.add_widget(vectors_container)
        main_layout.add_widget(scroll)
        
        # Action buttons
        btn_row = BoxLayout(size_hint_y=None, height=dp(48), spacing=dp(8))
        
        # Reset Status button
        reset_btn = Button(text='Reset Status')
        reset_btn.background_normal = ''
        reset_btn.background_color = (0.6, 0.2, 0.2, 1)
        reset_btn.color = (1, 1, 1, 1)
        
        # Add to Known button
        known_btn = Button(text='Add to Known')
        known_btn.background_normal = ''
        known_btn.background_color = (0.545, 0.459, 0.125, 1)  # Gold #8B7520
        known_btn.color = (1, 1, 1, 1)
        
        popup = Popup(
            title='Manage Study Vectors',
            content=main_layout,
            size_hint=(None, None),
            size=(min(dp(400), Window.width*0.9), min(dp(500), Window.height*0.7)),
            auto_dismiss=True
        )
        
        def get_selected_vectors():
            return [vtype for vtype, cb in checkboxes.items() if cb.active]
        
        known_btn.bind(on_release=lambda *_: self._apply_known_to_vectors(entry_id, entry, get_selected_vectors(), popup))
        reset_btn.bind(on_release=lambda *_: self._apply_reset_to_vectors(entry_id, entry, get_selected_vectors(), popup))
        
        btn_row.add_widget(reset_btn)
        btn_row.add_widget(known_btn)
        main_layout.add_widget(btn_row)
        
        # Close button
        close_btn = Button(text='Cancel', size_hint_y=None, height=dp(40))
        close_btn.background_normal = ''
        close_btn.background_color = (0.5, 0.5, 0.5, 1)
        close_btn.color = (1, 1, 1, 1)
        close_btn.bind(on_release=lambda *_: popup.dismiss())
        main_layout.add_widget(close_btn)
        
        popup.open()
    
    def _apply_known_to_vectors(self, entry_id, entry, selected_vector_types, popup):
        """Mark selected vectors as Known."""
        if not selected_vector_types:
            # Show error toast
            toast_content = Label(text='No vectors selected!', halign='center', valign='middle')
            toast = Popup(title='', content=toast_content, size_hint=(None, None), 
                         size=(dp(200), dp(80)), auto_dismiss=True, separator_height=0)
            toast.open()
            Clock.schedule_once(lambda dt: toast.dismiss(), 1.5)
            return
        
        Logger.info(f'SpoonfedApp: Add to Known for vectors: {selected_vector_types}')
        
        try:
            conn = dict_db.init_db(get_db_path())
            entry_kind = entry.get('kind') or 'vocab'
            
            from datetime import datetime, timedelta
            now = datetime.utcnow()
            far_future = (now + timedelta(days=365 * 10)).isoformat()
            
            for vector_type in selected_vector_types:
                dict_db.update_srs_vector(conn, entry_id, entry_kind, {
                    'interval': 365,
                    'ease': 2.5,
                    'reps': 10,
                    'due_at': far_future,
                    'last_seen': now.isoformat(),
                    'streak': 10,
                }, vector_type)
            
            conn.close()
            Logger.info(f'SpoonfedApp: Marked {len(selected_vector_types)} vectors as Known')
            
            popup.dismiss()
            
            # Check if we're in a study session and should skip the current entry
            session_type = getattr(self, '_current_session_type', None)
            session_entry_id = getattr(self, '_current_session_entry_id', None)
            
            # Show confirmation toast first
            toast_content = Label(
                text=f'Added {len(selected_vector_types)} vector(s) to Known!',
                halign='center',
                valign='middle'
            )
            toast = Popup(
                title='',
                content=toast_content,
                size_hint=(None, None),
                size=(dp(240), dp(80)),
                auto_dismiss=True,
                separator_height=0
            )
            toast.open()
            Clock.schedule_once(lambda dt: toast.dismiss(), 1.2)
            
            # Defer the skip to ensure UI is ready
            if session_type and session_entry_id == entry_id:
                Logger.info(f'SpoonfedApp: Skipping entry {entry_id} in {session_type} session')
                
                def do_skip(dt):
                    # Skip to next card based on session type
                    if session_type == 'review':
                        self._skip_current_review()
                    elif session_type == 'drill':
                        self._skip_current_drill()
                    
                    # Clear session markers
                    self._current_session_type = None
                    self._current_session_entry_id = None
                
                # Schedule skip after a brief delay to ensure popup is dismissed
                Clock.schedule_once(do_skip, 0.2)
            
        except Exception as e:
            Logger.error(f'SpoonfedApp: Error adding vectors to Known: {e}')
            import traceback
            Logger.error(traceback.format_exc())
            popup.dismiss()
    
    def _apply_reset_to_vectors(self, entry_id, entry, selected_vector_types, popup):
        """Reset selected vectors to Unknown."""
        if not selected_vector_types:
            # Show error toast
            toast_content = Label(text='No vectors selected!', halign='center', valign='middle')
            toast = Popup(title='', content=toast_content, size_hint=(None, None), 
                         size=(dp(200), dp(80)), auto_dismiss=True, separator_height=0)
            toast.open()
            Clock.schedule_once(lambda dt: toast.dismiss(), 1.5)
            return
        
        Logger.info(f'SpoonfedApp: Reset vectors to Unknown: {selected_vector_types}')
        
        try:
            conn = dict_db.init_db(get_db_path())
            entry_kind = entry.get('kind') or 'vocab'
            cur = conn.cursor()
            
            # Get the SRS row
            srs_row = dict_db.get_srs_row(conn, entry_id)
            if srs_row:
                data = srs_row.get('data') or {}
                per_vector = data.get('per_vector', {})
                
                # Remove selected vectors from per_vector
                for vector_type in selected_vector_types:
                    if vector_type in per_vector:
                        del per_vector[vector_type]
                
                # Update or delete the SRS row
                if not per_vector:
                    # No vectors left, delete the entire SRS row
                    cur.execute('DELETE FROM srs WHERE entry_id = ?', (entry_id,))
                else:
                    # Update with remaining vectors
                    data['per_vector'] = per_vector
                    import json
                    cur.execute('UPDATE srs SET data = ? WHERE entry_id = ?', 
                               (json.dumps(data), entry_id))
                
                conn.commit()
            
            conn.close()
            Logger.info(f'SpoonfedApp: Reset {len(selected_vector_types)} vectors to Unknown')
            
            popup.dismiss()
            
            # Show confirmation
            toast_content = Label(
                text=f'Reset {len(selected_vector_types)} vector(s) to Unknown!',
                halign='center',
                valign='middle'
            )
            toast = Popup(
                title='',
                content=toast_content,
                size_hint=(None, None),
                size=(dp(260), dp(80)),
                auto_dismiss=True,
                separator_height=0
            )
            toast.open()
            Clock.schedule_once(lambda dt: toast.dismiss(), 1.2)
            
        except Exception as e:
            Logger.error(f'SpoonfedApp: Error resetting vectors: {e}')
            import traceback
            Logger.error(traceback.format_exc())
            popup.dismiss()
    
    def _show_vector_management_popup_during_session(self, entry_id, entry, session_type):
        """Show vector management popup during a session with skip-on-known functionality."""
        # Store session type for use in _apply_known_to_vectors
        self._current_session_type = session_type
        self._current_session_entry_id = entry_id
        
        # Call the regular vector management popup
        self._show_vector_management_popup(entry_id, entry)
    
    def _skip_current_review(self):
        """Skip the current review card and remove all vectors for this entry from the queue."""
        try:
            if not hasattr(self, '_review_queue') or not hasattr(self, '_review_index'):
                return
            
            # Get the entry_id of the current card
            current = self._review_queue[self._review_index] if self._review_index < len(self._review_queue) else None
            entry_id = current.get('entry_id') if current else None
            
            if entry_id:
                # Remove ALL remaining vectors for this entry_id from the queue
                # (vectors at indexes > current that share the same entry_id)
                before = len(self._review_queue)
                remaining = self._review_queue[self._review_index + 1:]
                filtered = [v for v in remaining if v.get('entry_id') != entry_id]
                self._review_queue = self._review_queue[:self._review_index] + filtered
                removed = before - len(self._review_queue) - 1  # -1 for current card
                if removed > 0:
                    Logger.info(f'Review: Removed {removed} additional vectors for entry {entry_id}')
            
            # Load the next review (index now points to the next non-removed card)
            if self._review_index < len(self._review_queue):
                self._load_current_review()
            else:
                self._finish_review_session()
            
            Logger.info(f'Review: Skipped entry {entry_id} after marking as known')
            
        except Exception as e:
            Logger.error(f'Review: Error skipping current entry: {e}')
    
    def _skip_current_drill(self):
        """Skip the current drill and remove ALL vectors for this entry from the session.

        Instead of submitting 3 correct answers (which triggers progressive-unlock
        side effects), we directly strip every vector for the entry from all queues,
        reduce total_vectors so the progress counter is accurate, and clear any
        pending info cards that belong to this entry.
        """
        try:
            if not hasattr(self, '_current_drill_session_id'):
                Logger.error('Drill: No active drill session to skip')
                return

            entry_id = None

            if hasattr(self, '_current_drill_vector') and self._current_drill_vector:
                entry_id = self._current_drill_vector.get('entry_id')
                Logger.info(f'Drill: Skipping ALL vectors for entry {entry_id} after marking as known')

                try:
                    conn = dict_db.init_db(get_db_path())
                    session = dict_db.get_learning_session(conn, self._current_drill_session_id)
                    if session and entry_id:
                        data = session.get('data', {})
                        removed_real = 0  # count of real (non-filler) vectors removed

                        # Remove from in_progress, pending, remaining_vectors
                        for key in ('in_progress', 'pending', 'remaining_vectors'):
                            lst = data.get(key, [])
                            before = len(lst)
                            kept = []
                            for v in lst:
                                if v.get('entry_id') == entry_id:
                                    if not v.get('is_filler') and not v.get('already_in_srs'):
                                        removed_real += 1
                                else:
                                    kept.append(v)
                            data[key] = kept
                            removed = before - len(kept)
                            if removed > 0:
                                Logger.info(f'Drill: Removed {removed} vectors for entry {entry_id} from {key}')

                        # Remove from batched_vectors
                        if data.get('batched_vectors'):
                            for bi, batch in enumerate(data['batched_vectors']):
                                before = len(batch)
                                kept = []
                                for v in batch:
                                    if v.get('entry_id') == entry_id:
                                        if not v.get('is_filler') and not v.get('already_in_srs'):
                                            removed_real += 1
                                    else:
                                        kept.append(v)
                                data['batched_vectors'][bi] = kept

                        # Remove from remaining_info (un-unlocked info cards)
                        if data.get('remaining_info'):
                            data['remaining_info'] = [
                                c for c in data['remaining_info']
                                if c.get('entry_id') != entry_id
                            ]

                        # Clear pending_info_card if it belongs to this entry
                        pic = data.get('pending_info_card')
                        if pic:
                            if isinstance(pic, list):
                                if any(c.get('entry_id') == entry_id for c in pic):
                                    data['pending_info_card'] = None
                            elif isinstance(pic, dict) and pic.get('entry_id') == entry_id:
                                data['pending_info_card'] = None

                        # Reduce total_vectors so the progress counter stays accurate
                        meta = data.get('meta', {})
                        old_total = meta.get('total_vectors', 0)
                        meta['total_vectors'] = max(0, old_total - removed_real)
                        data['meta'] = meta
                        Logger.info(f'Drill: total_vectors {old_total} -> {meta["total_vectors"]} (removed {removed_real} real vectors)')

                        dict_db.update_learning_session(conn, self._current_drill_session_id, data)

                    conn.close()

                    # Update completed count (we're effectively "completing" these vectors)
                    # Don't increment — just reduce the total so the ratio is correct.
                    # The counter shows completed/total and we reduced total.

                except Exception as e:
                    Logger.error(f'Drill: Error removing vectors: {e}')

            # Clear UI state before loading next drill
            text_input = self.root.ids.get('drill_input')
            if text_input:
                text_input.text = ''
                text_input.focus = False

            feedback_label = self.root.ids.get('drill_feedback')
            if feedback_label:
                feedback_label.text = ''
            
            submit_btn = self.root.ids.get('drill_submit_btn')
            if submit_btn:
                submit_btn.text = 'Submit'
                submit_btn.background_color = (0.15, 0.45, 0.65, 1)  # Blue
            
            # Reset waiting_continue flag if set
            self._drill_waiting_continue = False
            
            # Move to next drill (schedule it to avoid UI conflicts)
            Clock.schedule_once(lambda dt: self._load_current_drill(), 0.1)
            
        except Exception as e:
            Logger.error(f'Drill: Error skipping current entry: {e}')
            import traceback
            Logger.error(traceback.format_exc())
    
    def _apply_review_grade(self, entry_id: int, kind: str, vector_type: str, grade: int, grammar_category: str = None):
        """Apply FSRS grade to a specific vector.
        
        If grammar_category is provided, it is saved as last_review_category
        in the SRS per-vector data so the next review round-robins to the
        next category.
        """
        conn = None
        try:
            import json
            from datetime import datetime, timedelta
            
            # Load current SRS vector data
            conn = dict_db.init_db(get_db_path())
            vec = dict_db.get_srs_vector(conn, entry_id, kind, vector_type)
            
            ease = vec.get('ease', 2.5)
            reps = vec.get('reps', 0)
            interval = vec.get('interval', 0)
            
            # Simple FSRS-like update
            if grade == 1:  # Again
                new_interval = 1
                new_ease = max(1.3, ease - 0.2)
                new_reps = 0
            elif grade == 2:  # Hard
                new_interval = max(1, int(interval * 1.2))
                new_ease = max(1.3, ease - 0.15)
                new_reps = reps + 1
            elif grade == 3:  # Good
                new_interval = max(1, int(interval * ease))
                new_ease = ease
                new_reps = reps + 1
            else:  # Easy (4)
                new_interval = max(1, int(interval * ease * 1.3))
                new_ease = min(2.5, ease + 0.15)
                new_reps = reps + 1
            
            # Calculate new due date
            new_due_at = (datetime.utcnow() + timedelta(days=new_interval)).isoformat()
            
            # Update per-vector SRS data
            updates = {
                'ease': new_ease,
                'reps': new_reps,
                'interval': new_interval,
                'due_at': new_due_at,
                'last_seen': datetime.utcnow().isoformat()
            }
            # Save which grammar category was reviewed for round-robin
            if grammar_category:
                updates['last_review_category'] = grammar_category
            dict_db.update_srs_vector(conn, entry_id, kind, updates, vector_type)

            # Record daily activity: first-time review = learned, subsequent = reviewed
            try:
                if reps == 0 and grade > 1:
                    dict_db.record_daily_activity(conn, reviewed=0, learned=1)
                else:
                    dict_db.record_daily_activity(conn, reviewed=1, learned=0)
            except Exception:
                pass

            Logger.info(f'Review: Updated vector {vector_type} for entry {entry_id} - grade={grade}, interval={new_interval}')
            
        except Exception as e:
            Logger.error(f'Review: Error applying grade: {e}')
        finally:
            if conn:
                try:
                    conn.close()
                except Exception as e:
                    Logger.warning(f'Review: Error closing connection: {e}')
    
    def _mark_for_drill(self, entry_id: int, vector_type: str):
        """Mark a specific vector for drill practice after repeated failures."""
        try:
            import json
            from datetime import datetime
            
            conn = dict_db.init_db(get_db_path())
            cur = conn.cursor()
            
            # Update SRS record with a drill flag in the per_vector data
            cur.execute('SELECT data FROM srs WHERE entry_id=?', (entry_id,))
            row = cur.fetchone()
            
            if row:
                data = json.loads(row[0]) if row[0] else {}
                per_vector = data.get('per_vector') or {}
                vec_data = per_vector.get(vector_type) or {}
                vec_data['needs_drill'] = True
                vec_data['drill_marked_at'] = datetime.utcnow().isoformat()
                per_vector[vector_type] = vec_data
                data['per_vector'] = per_vector
                
                cur.execute(
                    'UPDATE srs SET data=? WHERE entry_id=?',
                    (json.dumps(data), entry_id)
                )
                conn.commit()
                Logger.info(f'Review: Marked vector {vector_type} for entry {entry_id} for drill practice')
            
        except Exception as e:
            Logger.error(f'Review: Error marking for drill: {e}')
        finally:
            if conn:
                try:
                    conn.close()
                except Exception as e:
                    Logger.warning(f'Review: Error closing connection: {e}')
    
    def _finish_review_session(self):
        """Finish the review session and return to Study screen."""
        try:
            Logger.info('Review: Session complete')
            self._review_queue = []
            self._review_index = 0
            self._review_answered = False
            
            # Mark reviews as completed for this session
            self._reviews_completed_this_session = True
            
            # Navigate back to study screen
            sm = self._get_screen_manager()
            if sm:
                sm.current = 'study'
                # Update stats to show new counts (including weak words drill option)
                Clock.schedule_once(lambda dt: self._update_study_stats(), 0.1)
            
            # Background sync after review session
            try:
                from sync import supabase_client as sb
                if sb.is_logged_in() and sb.is_configured():
                    import threading
                    from sync.sync import run_full_sync
                    def _bg():
                        ok, msg = run_full_sync()
                        Logger.info(f'Sync: post-review sync: {msg}')
                    threading.Thread(target=_bg, daemon=True).start()
            except Exception as e:
                Logger.warning(f'Sync: post-review sync skipped: {e}')
        except Exception as e:
            Logger.error(f'Review: Error finishing session: {e}')

    def start_weak_words_drill(self):
        """Start drilling weak words (uses drill UI, no SRS updates)."""
        # Keep loading overlay visible during DB work; it will be hidden after
        # the screen switch below so there's no frozen-study-screen flash.
        # Silently warm up the handwriting recognizer in the background.
        if getattr(self, 'handwriting_mode', False) or getattr(self, 'handwriting_only_mode', False):
            self._prewarm_recognizer_silent()
        conn = None
        try:
            Logger.info('WeakDrill: Starting weak words drill')
            
            conn = dict_db.init_db(get_db_path())
            weak_vectors = dict_db.get_weak_vectors_for_drill(
                conn, 
                threshold=3, 
                limit=14, 
                exclude_vector_ids=self._drilled_today
            )
            
            if not weak_vectors:
                Logger.info('WeakDrill: No weak vectors available')
                return
            
            Logger.info(f'WeakDrill: Found {len(weak_vectors)} weak vectors')
            
            # Filter OUT handwriting vectors if handwriting mode is disabled
            if not self.handwriting_mode:
                weak_vectors = [v for v in weak_vectors if v.get('vector_type') != 'handwriting']
                Logger.info(f'WeakDrill: Excluded handwriting - {len(weak_vectors)} vectors remain')
                if not weak_vectors:
                    Logger.info('WeakDrill: No non-handwriting vectors available')
                    return
            
            # Filter for handwriting-only mode if enabled
            if self.handwriting_only_mode:
                weak_vectors = [v for v in weak_vectors if v.get('vector_type') == 'handwriting']
                Logger.info(f'WeakDrill: Filtered to {len(weak_vectors)} handwriting vectors')
                if not weak_vectors:
                    Logger.info('WeakDrill: No handwriting vectors available')
                    return
            
            # Create a learning session directly with the weak vectors we already have
            # (don't use create_session as that regenerates vectors assuming all entries are the same kind)
            import dictionary.learning as learning
            import random
            from datetime import datetime
            dict_db.ensure_learning_table(conn)
            
            # Use the weak_vectors list directly as the pending vectors
            in_progress = weak_vectors[:learning.DEFAULT_SLOTS]
            pending = weak_vectors[learning.DEFAULT_SLOTS:]
            
            # Add fillers if needed (but since kinds are mixed, skip fillers for now)
            # Fillers would need to be kind-aware
            
            # Shuffle in_progress to randomize initial order
            random.shuffle(in_progress)
            
            data = {
                'info': [],  # No info cards for weak words drill
                'info_index': 0,
                'phase': 'drill',  # Start directly in drill phase
                'pending': pending,
                'in_progress': in_progress,
                'meta': {
                    'created_by': 'weak_drill',
                    'num_slots': learning.DEFAULT_SLOTS,
                    'created_at': datetime.utcnow().isoformat(),
                    'drill_type': 'weak_words',
                    'weak_vectors_count': len(weak_vectors),
                    'total_vectors': len(weak_vectors),
                    'filter_vector_type': 'handwriting' if self.handwriting_only_mode else None,
                    'exclude_vector_type': 'handwriting' if not self.handwriting_mode else None
                },
                'history': []
            }
            
            # Create the session with kind='mixed' since we have multiple kinds
            session_id = dict_db.create_learning_session(conn, kind='mixed', data=data)
            dict_db.update_learning_session(conn, session_id, data)
            
            conn.close()
            
            # Store session info
            self._current_drill_session_id = session_id
            self._drill_mode = 'weak_words'
            self._drill_completed_count = 0
            self._drill_waiting_continue = False
            
            # Clean up any time attack state
            self._cleanup_time_attack_state()
            
            # Navigate to drill screen
            sm = self._get_screen_manager()
            if sm:
                sm.current = 'drill'
                self._hide_study_loading()
                # Ensure overlay state is reset (in case a prior lesson drill left it disabled)
                self._hide_info_card_overlay()
                self._load_current_drill()
        
        except Exception as e:
            Logger.error(f'WeakDrill: Error starting drill: {e}')
            import traceback
            traceback.print_exc()
        finally:
            if conn:
                try:
                    conn.close()
                except Exception as e:
                    Logger.warning(f'WeakDrill: Error closing connection: {e}')

    def start_lesson_drill(self):
        """Start drilling lesson items (uses drill UI, completed items go to SRS)."""
        # Keep loading overlay visible during DB work; it will be hidden after
        # the screen switch below so there's no frozen-study-screen flash.
        # Silently warm up the handwriting recognizer in the background.
        if getattr(self, 'handwriting_mode', False) or getattr(self, 'handwriting_only_mode', False):
            self._prewarm_recognizer_silent()
        conn = None
        try:
            Logger.info('LessonDrill: Starting lesson drill')
            
            if not hasattr(self, '_lesson_queue') or not self._lesson_queue:
                Logger.info('LessonDrill: No lessons queued')
                return
            
            # Intercept reading items — open reading view instead of drill
            _first = self._lesson_queue[0]
            if isinstance(_first, str) and _first.startswith('reading:'):
                try:
                    _rmid = int(_first.split(':')[1])
                    ls = self.root.ids.get('lessons_screen') if getattr(self, 'root', None) else None
                    if ls and hasattr(ls, 'open_reading_material'):
                        sm = self._get_screen_manager()
                        if sm:
                            sm.current = 'lessons'
                        ls.open_reading_material(_rmid, from_queue=True)
                        return
                except Exception as e:
                    Logger.error(f'LessonDrill: Error opening reading from queue: {e}')
                    return
            if isinstance(_first, str) and _first.startswith('graded:'):
                try:
                    _grfp = _first[len('graded:'):]
                    ls = self.root.ids.get('lessons_screen') if getattr(self, 'root', None) else None
                    if ls and hasattr(ls, 'open_graded_reading'):
                        sm = self._get_screen_manager()
                        if sm:
                            sm.current = 'lessons'
                        ls.open_graded_reading(_grfp)
                        return
                except Exception as e:
                    Logger.error(f'LessonDrill: Error opening graded reading from queue: {e}')
                    return
            
            conn = dict_db.init_db(get_db_path())
            
            # Get daily limit
            daily_limit = int(getattr(self, 'daily_new_items_limit', 8))
            Logger.info(f'LessonDrill: Daily new items limit = {daily_limit}')
            
            # Helper function to check if entry has any new (not in SRS) vectors
            def has_new_vectors(entry_id):
                """Return True if the entry has at least one vector not yet learned."""
                import json
                from dictionary.learning import make_vectors_from_row as _make_vr
                cursor = conn.cursor()

                # Fetch kind + fields needed to determine canonical vector types
                cursor.execute(
                    'SELECT kind, kanji, kana, study_vectors FROM entries WHERE id = ?',
                    (entry_id,))
                row = cursor.fetchone()
                if not row:
                    return False
                entry_kind, kanji, kana, study_vectors_str = row
                entry_kind = self._effective_entry_kind(entry_kind, kanji, kana)

                # Build the set of vector types this entry should have
                expected_vecs = _make_vr(entry_id, entry_kind, kanji, kana, '', study_vectors_str)
                expected_types = {v['vector_type'] for v in expected_vecs}
                if not expected_types:
                    return False

                # Check SRS data
                cursor.execute('SELECT data FROM srs WHERE entry_id = ?', (entry_id,))
                srs_row = cursor.fetchone()

                if not srs_row:
                    # No SRS at all — definitely new
                    return True

                srs_data = json.loads(srs_row[0])

                # Filter expected vector types by current handwriting settings
                filtered_types = expected_types.copy()
                if self.handwriting_only_mode:
                    filtered_types = {vt for vt in filtered_types if vt == 'handwriting'}
                elif not self.handwriting_mode:
                    filtered_types = {vt for vt in filtered_types if vt != 'handwriting'}
                if not filtered_types:
                    return False

                # Check per_kind: only consider done when ALL expected vectors promoted
                pk = srs_data.get('per_kind', {}).get(entry_kind, {})
                if pk:
                    promoted_set = set(pk.get('promoted_vectors', []))
                    if entry_kind == 'grammar':
                        # Grammar stores full vector IDs (grammar-cat:..., grammar-scramble:..., grammar-translate:..., grammar-dictation:...)
                        from dictionary.learning import GRAMMAR_EXERCISES_PER_ENTRY as _GEPE
                        cloze_promoted = [p for p in promoted_set if p.startswith('grammar-cat:')]
                        scramble_promoted = [p for p in promoted_set if p.startswith('grammar-scramble:')]
                        translate_promoted = [p for p in promoted_set if p.startswith('grammar-translate:')]
                        dictation_promoted = [p for p in promoted_set if p.startswith('grammar-dictation:')]
                        if len(cloze_promoted) >= _GEPE and len(scramble_promoted) >= _GEPE and len(translate_promoted) >= _GEPE and len(dictation_promoted) >= _GEPE:
                            return False
                    elif filtered_types.issubset(promoted_set):
                        return False

                # Manual "Mark as Known" stores per-vector entries.
                # Every expected vector type must be present with interval >= 180.
                per_vector = srs_data.get('per_vector', {})
                for vt in expected_types:
                    vec = per_vector.get(vt, {})
                    if (vec.get('interval', 0) or 0) < 180:
                        return True  # This type is still unlearned

                return False  # All expected vector types are learned
            
            # Expand queue items to get entry IDs with new vectors (up to daily limit)
            all_entry_ids = []
            intro_cards_by_entry = {}  # entry_id -> [teaching cards] from lesson files
            skipped_count = 0
            fully_done_items = []  # queue items where every entry is already in SRS
            
            for item in self._lesson_queue:
                # Stop if we've reached the daily limit
                if len(all_entry_ids) >= daily_limit:
                    Logger.info(f'LessonDrill: Reached daily limit of {daily_limit} items')
                    break
                
                if isinstance(item, int):
                    # Direct entry ID - check if it has new vectors
                    if has_new_vectors(item):
                        all_entry_ids.append(item)
                    else:
                        skipped_count += 1
                        fully_done_items.append(item)  # single entry, fully checked, already known
                elif isinstance(item, str) and item.startswith('custom_lesson:'):
                    # Custom lesson from database
                    try:
                        lesson_id = int(item.split(':')[1])
                        entry_ids = dict_db.get_custom_lesson_entry_ids(conn, lesson_id)
                        # Only add entries with new vectors, up to the daily limit
                        added = 0
                        all_checked = True
                        for eid in entry_ids:
                            if len(all_entry_ids) >= daily_limit:
                                all_checked = False  # hit limit mid-item; don't mark done
                                break
                            if has_new_vectors(eid):
                                all_entry_ids.append(eid)
                                added += 1
                            else:
                                skipped_count += 1
                        Logger.info(f'LessonDrill: Expanded custom lesson {lesson_id} to {len(entry_ids)} entries (added {added}, skipped {len(entry_ids)-added})')
                        if all_checked and added == 0 and entry_ids:
                            fully_done_items.append(item)
                    except Exception as e:
                        Logger.error(f'LessonDrill: Error loading custom lesson {item}: {e}')
                else:
                    # Lesson file path - load entries from JSON
                    try:
                        import json
                        lesson_path = Path(item)
                        if lesson_path.exists():
                            with open(lesson_path, 'r', encoding='utf-8') as f:
                                lesson_data = json.load(f)
                            
                            # Grammar lessons: entry_id at top level or in items
                            if lesson_data.get('lesson_type') == 'grammar':
                                eid = lesson_data.get('entry_id')
                                # If not at top level, try to get from items[0]
                                if not eid:
                                    items = lesson_data.get('items', [])
                                    if items and len(items) > 0:
                                        eid = items[0].get('entry_id')
                                if eid and len(all_entry_ids) < daily_limit:
                                    if has_new_vectors(eid):
                                        all_entry_ids.append(eid)
                                        intro_cards = lesson_data.get('intro_cards', [])
                                        if intro_cards:
                                            intro_cards_by_entry.setdefault(eid, []).extend(intro_cards)
                                        Logger.info(f'LessonDrill: Grammar lesson {lesson_path.name} entry_id={eid}')
                                    else:
                                        skipped_count += 1
                                        fully_done_items.append(item)
                            else:
                                items = lesson_data.get('items', [])
                                added = 0
                                first_added_eid = None
                                lesson_skipped = 0
                                all_checked = True
                                for lesson_item in items:
                                    # Stop if we've reached the limit
                                    if len(all_entry_ids) >= daily_limit:
                                        all_checked = False
                                        break
                                    entry_id = lesson_item.get('entry_id')
                                    if entry_id:
                                        if has_new_vectors(entry_id):
                                            all_entry_ids.append(entry_id)
                                            if first_added_eid is None:
                                                first_added_eid = entry_id
                                            added += 1
                                        else:
                                            lesson_skipped += 1
                                Logger.info(f'LessonDrill: Loaded {lesson_path.name} (added {added}, skipped {lesson_skipped})')
                                if added > 0 and first_added_eid is not None:
                                    intro_cards = lesson_data.get('intro_cards', [])
                                    if intro_cards:
                                        intro_cards_by_entry.setdefault(first_added_eid, []).extend(intro_cards)
                                if all_checked and added == 0 and items:
                                    fully_done_items.append(item)
                    except Exception as e:
                        Logger.error(f'LessonDrill: Error loading lesson file {item}: {e}')
            
            # Remove queue items where every entry is already learned
            if fully_done_items:
                for done_item in fully_done_items:
                    if done_item in self._lesson_queue:
                        self._lesson_queue.remove(done_item)
                        Logger.info(f'LessonDrill: Auto-removed fully-learned item from queue: {done_item}')
                self._save_lesson_queue()
            
            if skipped_count > 0:
                Logger.info(f'LessonDrill: Skipped {skipped_count} entries already in SRS')
            
            if not all_entry_ids:
                Logger.info('LessonDrill: No entries with new vectors found in queue')
                conn.close()
                return
            
            Logger.info(f'LessonDrill: Processing {len(all_entry_ids)} total entries from queue')
            
            # Determine predominant kind from all entries (handles mixed vocab/grammar sessions)
            cursor = conn.cursor()
            cursor.execute(f'''
                SELECT kind, COUNT(*) as count 
                FROM entries 
                WHERE id IN ({','.join('?' * len(all_entry_ids))})
                GROUP BY kind
                ORDER BY count DESC
                LIMIT 1
            ''', all_entry_ids)
            kind_row = cursor.fetchone()
            entry_kind = kind_row[0] if kind_row else 'vocab'
            Logger.info(f'LessonDrill: Primary entry kind is {entry_kind} for this session')
            
            # Detect ALL grammar entries in the session (regardless of how they
            # entered the queue: direct ID, custom lesson, or lesson file).
            cursor.execute(f'''
                SELECT id FROM entries
                WHERE id IN ({','.join('?' * len(all_entry_ids))})
                  AND kind = 'grammar'
            ''', all_entry_ids)
            self._grammar_entry_ids_in_session = {r[0] for r in cursor.fetchall()}
            if self._grammar_entry_ids_in_session:
                Logger.info(f'LessonDrill: {len(self._grammar_entry_ids_in_session)} grammar entries detected')
            
            import dictionary.learning as learning
            dict_db.ensure_learning_table(conn)
            
            # Create session - treat grammar like vocab since we have pre-made exercises
            # Use batched info card flow for lesson drills (teach-then-drill in groups of 4)
            session_id = learning.create_session(
                conn, 
                all_entry_ids,
                entry_kind,
                filter_vector_type='handwriting' if self.handwriting_only_mode else None,
                exclude_vector_type='handwriting' if not self.handwriting_mode else None,
                enable_batched_info=True
            )
            
            # Get the session data and mark vectors that already have SRS
            session = dict_db.get_learning_session(conn, session_id)
            data = session['data']
            
            # Prepend teaching concept cards before their entry's info card
            if intro_cards_by_entry:
                # Tag teaching cards with entry_id so progressive unlock can group them
                for eid, cards in intro_cards_by_entry.items():
                    for card in cards:
                        card['entry_id'] = eid
                
                # Interleave into initial info cards
                new_info = []
                for card in data.get('info', []):
                    eid = card.get('entry_id')
                    if eid in intro_cards_by_entry:
                        new_info.extend(intro_cards_by_entry.pop(eid))
                    new_info.append(card)
                data['info'] = new_info
                
                # Interleave into remaining info cards (for progressive unlock)
                if 'remaining_info' in data and intro_cards_by_entry:
                    new_remaining = []
                    for card in data['remaining_info']:
                        eid = card.get('entry_id')
                        if eid in intro_cards_by_entry:
                            new_remaining.extend(intro_cards_by_entry.pop(eid))
                        new_remaining.append(card)
                    data['remaining_info'] = new_remaining
            
            # Replace standard grammar vectors with DB exercise vectors
            grammar_eids = getattr(self, '_grammar_entry_ids_in_session', set())
            if grammar_eids:
                # Pre-load exercise pools and grammar_point name for each entry
                grammar_vectors_map = {}  # eid -> list of fill-blank vectors
                grammar_scramble_map = {}  # eid -> list of scramble vectors
                grammar_translate_map = {}  # eid -> list of translate vectors
                grammar_dictation_map = {}  # eid -> list of dictation vectors
                grammar_pools = {}  # eid -> {category: [exercise_dict, ...]}
                for eid in grammar_eids:
                    pool = learning.load_grammar_exercise_pool(conn, eid)
                    if pool:
                        # Fetch grammar_point name from entries table
                        cursor.execute('SELECT kanji, kana FROM entries WHERE id = ?', (eid,))
                        gp_row = cursor.fetchone()
                        gp_name = (gp_row[0] or gp_row[1] or '') if gp_row else ''
                        grammar_vectors_map[eid] = learning.make_grammar_cloze_vectors(eid, gp_name, pool)
                        grammar_scramble_map[eid] = learning.make_grammar_scramble_vectors(eid, gp_name, pool)
                        grammar_translate_map[eid] = learning.make_grammar_translate_vectors(eid, gp_name, pool)
                        grammar_dictation_map[eid] = learning.make_grammar_dictation_vectors(eid, gp_name, pool)
                        grammar_pools[eid] = pool
                    else:
                        Logger.warning(f'LessonDrill: No DB exercises for grammar entry {eid}')
                # Store pools on app so _load_current_drill can rotate exercises
                self._grammar_exercise_pools = grammar_pools

                def _replace_grammar_vectors(vector_list):
                    """Replace placeholder grammar vectors with DB-based cloze vectors.
                    
                    Scramble, translate, and dictation vectors are NOT added here — they are
                    deferred to remaining_vectors and injected progressively as
                    earlier vector types are promoted."""
                    new_list = []
                    deferred = []
                    seen = set()
                    for v in vector_list:
                        eid = v.get('entry_id')
                        if eid in grammar_eids and eid not in seen:
                            new_vecs = grammar_vectors_map.get(eid, [v])
                            new_list.extend(new_vecs)
                            scramble_vecs = grammar_scramble_map.get(eid, [])
                            deferred.extend(scramble_vecs)
                            translate_vecs = grammar_translate_map.get(eid, [])
                            deferred.extend(translate_vecs)
                            dictation_vecs = grammar_dictation_map.get(eid, [])
                            deferred.extend(dictation_vecs)
                            seen.add(eid)
                        elif eid in grammar_eids:
                            pass  # skip duplicate placeholder
                        else:
                            new_list.append(v)
                    return new_list, deferred, len(seen)

                # Replace vectors in pending, in_progress, AND remaining_vectors
                # Scramble and translate vectors are deferred into remaining_vectors
                # for progressive introduction as earlier types are promoted.
                total_replaced = 0
                all_deferred = []
                for list_name in ('pending', 'in_progress', 'remaining_vectors'):
                    replaced_list, deferred, count = _replace_grammar_vectors(data.get(list_name, []))
                    data[list_name] = replaced_list
                    all_deferred.extend(deferred)
                    total_replaced += count

                # Also replace grammar vectors in queued batches
                if data.get('batched_vectors'):
                    new_batches = []
                    for batch_vecs in data['batched_vectors']:
                        replaced_batch, deferred, count = _replace_grammar_vectors(batch_vecs)
                        new_batches.append(replaced_batch)
                        all_deferred.extend(deferred)
                        total_replaced += count
                    data['batched_vectors'] = new_batches

                # Store deferred scramble/translate vectors in remaining_vectors
                if all_deferred:
                    data.setdefault('remaining_vectors', []).extend(all_deferred)
                    Logger.info(f'LessonDrill: Deferred {len(all_deferred)} scramble+translate+dictation vectors for progressive introduction')

                Logger.info(f'LessonDrill: Injected DB exercise vectors for {total_replaced} grammar entries')
                # Clean up
                self._grammar_entry_ids_in_session = set()
            
            # Helper to mark SRS vectors in a list
            def _mark_srs_vectors(vector_list):
                for vector in vector_list:
                    entry_id = vector.get('entry_id')
                    vector_type = vector.get('vector_type')
                    cursor.execute('SELECT data FROM srs WHERE entry_id = ?', (entry_id,))
                    srs_row = cursor.fetchone()
                    if srs_row:
                        srs_data = json.loads(srs_row[0])
                        per_vector = srs_data.get('per_vector', {})
                        per_kind = srs_data.get('per_kind', {})
                        entry_kind_from_vector = vector.get('kind')
                        vector_in_srs = False
                        if vector_type in per_vector:
                            vector_in_srs = True
                        elif entry_kind_from_vector in per_kind:
                            kind_data = per_kind[entry_kind_from_vector]
                            if not per_vector and vector_type in kind_data:
                                vector_in_srs = True
                        if vector_in_srs:
                            vector['already_in_srs'] = True
                            Logger.info(f'LessonDrill: Vector {vector_type} for entry {entry_id} already in SRS, will skip')

            # Check each vector in pending, in_progress, batched_vectors, and remaining_vectors for existing SRS
            import json
            _mark_srs_vectors(data.get('pending', []))
            _mark_srs_vectors(data.get('in_progress', []))
            for batch_vecs in data.get('batched_vectors', []):
                _mark_srs_vectors(batch_vecs)
            _mark_srs_vectors(data.get('remaining_vectors', []))
            
            # Set metadata to mark this as a lesson drill (enables SRS promotion for new vectors)
            data['meta']['drill_type'] = 'lesson'
            # Count non-SRS and non-filler vectors as the total (only new vectors to learn)
            # Include vectors in batched_vectors and remaining_vectors (deferred scramble)
            all_session_vectors = data.get('pending', []) + data.get('in_progress', [])
            for batch_vecs in data.get('batched_vectors', []):
                all_session_vectors.extend(batch_vecs)
            all_session_vectors.extend(data.get('remaining_vectors', []))
            total_new_vectors = sum(1 for v in all_session_vectors
                                   if not v.get('already_in_srs', False) and not v.get('is_filler', False))
            data['meta']['total_vectors'] = total_new_vectors
            dict_db.update_learning_session(conn, session_id, data)
            
            conn.close()
            
            # Store session info
            self._current_drill_session_id = session_id
            self._drill_mode = 'lesson'
            self._drill_completed_count = 0
            self._drill_waiting_continue = False
            
            # Clean up any time attack state
            self._cleanup_time_attack_state()
            
            # Navigate to drill screen
            sm = self._get_screen_manager()
            if sm:
                sm.current = 'drill'
                self._hide_study_loading()
                self._load_current_drill()
            
        except Exception as e:
            Logger.error(f'LessonDrill: Error starting drill: {e}')
            import traceback
            traceback.print_exc()
        finally:
            if conn:
                try:
                    conn.close()
                except Exception as e:
                    Logger.warning(f'LessonDrill: Error closing connection: {e}')

    def _format_kanji_readings(self, readings_text):
        """Format kanji readings to show only on'yomi and kun'yomi with truncation.
        
        Args:
            readings_text: Raw readings string like "on: オン | kun: くん | nanori: なのり"
        
        Returns:
            Formatted string with readings on single line (no labels), truncated with colored ... if needed
        """
        if not readings_text:
            return readings_text
        
        # Reset expansion state for new readings
        self._kanji_readings_expanded = False
        
        max_length = 50  # Maximum total characters before truncating
        
        # Parse readings by type
        on_readings = []
        kun_readings = []
        
        # Split on | first to handle different sections
        sections = readings_text.split('|')
        current_type = None
        
        for section in sections:
            section = section.strip()
            parts = section.split()
            
            for part in parts:
                if part == 'on:':
                    current_type = 'on'
                elif part == 'kun:':
                    current_type = 'kun'
                elif part == 'nanori:':
                    current_type = None  # Ignore nanori
                elif current_type == 'on':
                    on_readings.append(part)
                elif current_type == 'kun':
                    kun_readings.append(part)
        
        # Combine all readings (on first, then kun) without labels
        all_readings = on_readings + kun_readings
        result = ', '.join(all_readings) if all_readings else readings_text
        
        # Store full text for expansion
        self._kanji_readings_full = result
        
        # Truncate if too long, with colored ellipsis
        if len(result) > max_length:
            truncated = result[:max_length].rstrip(', ')
            # Use markup for colored ellipsis - dark navy blue
            result = truncated + '[color=3b5998]...[/color]'
            self._kanji_readings_truncated = True
        else:
            self._kanji_readings_truncated = False
        
        return result

    def _toggle_kanji_readings(self, instance, touch):
        """Toggle between truncated and full kanji readings display on touch."""
        # Check if touch is within the label bounds
        if not instance.collide_point(*touch.pos):
            return False
        
        # Only toggle if readings are actually truncated
        if not hasattr(self, '_kanji_readings_truncated') or not self._kanji_readings_truncated:
            return False
        
        # Toggle between full and truncated view
        if not hasattr(self, '_kanji_readings_expanded'):
            self._kanji_readings_expanded = False
        
        self._kanji_readings_expanded = not self._kanji_readings_expanded
        
        if self._kanji_readings_expanded:
            # Show full text
            instance.text = self._kanji_readings_full
        else:
            # Show truncated with ellipsis
            max_length = 50
            truncated = self._kanji_readings_full[:max_length].rstrip(', ')
            instance.text = truncated + '[color=3b5998]...[/color]'
        
        return True
    
    def _format_meanings_truncated(self, meanings_text):
        """Truncate meanings to first 3 entries with clickable ... to expand.
        
        Args:
            meanings_text: String with meanings separated by semicolons like "yes; that is correct; right; um; errr"
        
        Returns:
            Formatted string with first 3 meanings, plus blue "..." if more exist
        """
        if not meanings_text:
            return meanings_text
        
        # Reset expansion state for new meanings
        self._meanings_expanded = False
        
        # Split by semicolon and clean up
        meanings = [m.strip() for m in meanings_text.split(';') if m.strip()]
        
        if len(meanings) <= 3:
            # No truncation needed
            self._meanings_truncated = False
            return meanings_text
        
        # Store full text for expansion
        self._meanings_full = meanings_text
        self._meanings_truncated = True
        
        # Show first 3 meanings with blue clickable ellipsis
        truncated_meanings = meanings[:3]
        result = '; '.join(truncated_meanings) + '; [color=4a90e2]...[/color]'
        
        return result
    
    def _toggle_meanings(self, instance, touch):
        """Toggle between truncated and full meanings display on touch."""
        # Check if touch is within the label bounds
        if not instance.collide_point(*touch.pos):
            return False
        
        # Only toggle if meanings were truncated
        if not getattr(self, '_meanings_truncated', False):
            return False
        
        # Check if we're currently in truncated state and "..." is visible
        # If expanded, allow clicking anywhere to collapse
        # If truncated, only trigger if clicking in bottom half (where ... likely is)
        if not getattr(self, '_meanings_expanded', False):
            # In truncated mode - check if touch is in bottom 60% of label
            # This helps avoid accidental clicks on the upper part
            label_bottom = instance.y
            label_top = instance.y + instance.height
            click_threshold = label_bottom + (instance.height * 0.4)
            
            if touch.pos[1] > click_threshold:
                return False  # Click in upper area, ignore
        
        # Toggle expansion state
        self._meanings_expanded = not getattr(self, '_meanings_expanded', False)
        
        if self._meanings_expanded:
            # Show full meanings
            instance.text = self._meanings_full
        else:
            # Show truncated (first 3)
            meanings = [m.strip() for m in self._meanings_full.split(';') if m.strip()]
            truncated_meanings = meanings[:3]
            instance.text = '; '.join(truncated_meanings) + '; [color=4a90e2]...[/color]'
        
        return True  # Event consumed

    def _load_current_drill(self):
        """Load the current drill vector into the UI."""
        conn = None
        try:
            if not hasattr(self, '_current_drill_session_id'):
                Logger.error('Drill: No active drill session')
                return
            
            conn = dict_db.init_db(get_db_path())
            import dictionary.learning as learning
            
            # ── For non-lesson drills, always ensure drill_main_container is visible ──
            # This guards against stale disabled/opacity state from a previous lesson drill
            if getattr(self, '_drill_mode', '') != 'lesson':
                self._hide_info_card_overlay()

            # Hide drill content immediately so no stale question text / partially-
            # restored layout is ever visible to the user.  Each code path below is
            # responsible for restoring opacity=1 once content is fully set up.
            _drill_main = self.root.ids.get('drill_main_container')
            if _drill_main:
                _drill_main.opacity = 0
                _drill_main.disabled = False  # always re-enable; info-card/writing-practice sets disabled=True
            # Also hide the global top bar (back + plus buttons) so they don't
            # float over the black drill area during the load transition.
            _top_bar_hide = self.root.ids.get('global_top_bar')
            if _top_bar_hide:
                _top_bar_hide.opacity = 0
            
            # ── Single session read for all checks below ──
            session = dict_db.get_learning_session(conn, self._current_drill_session_id)
            if not session:
                Logger.error('Drill: Session not found')
                if conn: conn.close()
                return
            sdata = session['data']
            
            # ── Check for info card phase (batched lesson flow) ──
            if self._drill_mode == 'lesson':
                if sdata.get('phase') == 'info':
                    # Determine which info cards to show
                    batch_idx = sdata.get('batch_index', 0)
                    batched_info = sdata.get('batched_info', [])
                    info_index = sdata.get('info_index', 0)
                    
                    if batched_info and batch_idx < len(batched_info):
                        current_batch_cards = batched_info[batch_idx]
                    else:
                        # Fallback: use the flat info list
                        current_batch_cards = sdata.get('info', [])
                    

                    
                    if info_index < len(current_batch_cards):
                        # Show info card
                        card = current_batch_cards[info_index]
                        conn.close()
                        self._show_lesson_info_card(card, info_index, len(current_batch_cards), batch_idx)
                        return
                    else:
                        # All info cards for this batch shown → switch to drill phase
                        learning.set_session_phase(conn, self._current_drill_session_id, 'drill')
                        self._hide_info_card_overlay()
            
            # Get next vector directly from already-loaded session data
            in_progress = sdata.get('in_progress') or []
            vector = in_progress[0] if in_progress else None
            
            # For weak words, lesson, and tools drills, check if all non-filler vectors are completed
            if self._drill_mode in ('weak_words', 'lesson', 'tools_drill'):
                data = sdata
                meta = data.get('meta', {})
                total_vectors = meta.get('total_vectors', 0)
                completed = self._drill_completed_count
                
                # For progressive unlock lessons: check if lesson is complete
                if meta.get('progressive_unlock'):
                    # Check if all vectors are done (including remaining)
                    active_real = [v for v in data.get('in_progress', [])
                                   if not v.get('is_filler') and not v.get('already_in_srs')]
                    pending_real = [v for v in data.get('pending', [])
                                    if not v.get('is_filler') and not v.get('already_in_srs')]
                    remaining_vectors = data.get('remaining_vectors', [])
                    
                    if not active_real and not pending_real and not remaining_vectors:
                        # All vectors done - lesson complete
                        self._finish_drill_session()
                        return
                    
                    # Safety net: if there's a pending info card that was never
                    # shown (e.g. drain recovery fired but user got filler wrong),
                    # show it now before continuing.
                    if data.get('pending_info_card'):
                        conn.close()
                        self._show_progressive_unlock_card()
                        return
                
                # For old batched lessons: when current batch is drained, advance to next batch
                elif meta.get('batched_lesson') and not meta.get('final_drill'):
                    # Check if all non-filler vectors in current in_progress/pending are done
                    active_real = [v for v in data.get('in_progress', [])
                                   if not v.get('is_filler') and not v.get('already_in_srs')]
                    pending_real = [v for v in data.get('pending', [])
                                    if not v.get('is_filler') and not v.get('already_in_srs')]
                    if not active_real and not pending_real:
                        # Current batch exhausted — advance to next
                        result = learning.advance_to_next_batch(conn, self._current_drill_session_id)
                        Logger.info(f'LessonDrill: Batch advance result: {result}')
                        if result.get('status') == 'advanced':
                            # Next batch has info cards to show
                            conn.close()
                            self._load_current_drill()  # re-enter, will hit info phase
                            return
                        elif result.get('status') == 'final_drill':
                            # All batches done, entering final drill with everything
                            conn.close()
                            self._load_current_drill()
                            return
                
                # If all non-filler vectors are done, end the drill (or recycle if unlimited)
                if completed >= total_vectors:
                    if getattr(self, '_drill_config_unlimited', False) and self._drill_mode == 'tools_drill':
                        # Unlimited mode: recycle all vectors back into the session
                        self._recycle_drill_vectors(conn, session)
                    else:
                        self._finish_drill_session()
                        return
            
            # For time_attack unlimited, recycle content when entries run out
            if (self._drill_mode == 'time_attack'
                    and getattr(self, '_drill_config_unlimited', False)
                    and not vector):
                session = dict_db.get_learning_session(conn, self._current_drill_session_id)
                self._recycle_drill_vectors(conn, session)
                conn.close()
                return

            conn.close()

            if not vector:
                # Session complete
                self._finish_drill_session()
                return
            
            # Store current vector
            self._current_drill_vector = vector
            
            # Update UI
            prompt_label = self.root.ids.get('drill_prompt')
            question_label = self.root.ids.get('drill_question')
            text_input = self.root.ids.get('drill_input')
            streak_label = self.root.ids.get('drill_streak_label')
            feedback_label = self.root.ids.get('drill_feedback')
            counter_label = self.root.ids.get('drill_counter')
            progress_label = self.root.ids.get('drill_progress_text')
            submit_btn = self.root.ids.get('drill_submit_btn')
            reveal_btn = self.root.ids.get('drill_reveal_btn')
            undo_btn = self.root.ids.get('drill_undo_btn')
            
            # Determine prompt based on vector type
            vector_type = vector.get('vector_type', '')
            prompt = vector.get('prompt', '')
            
            # Handle handwriting vectors
            if vector_type == 'handwriting':
                # Explicitly dismiss soft keyboard before switching to handwriting UI
                # so it doesn't linger and block the drawing canvas.
                if text_input:
                    text_input.focus = False
                # Track that the last drill was handwriting so _load_current_drill
                # can defer focus correctly on the next typing question.
                self._last_drill_vector_type = 'handwriting'
                # Clear the cached canvas height so each new word re-caps fresh.
                # Within-word character advances bypass _load_current_drill so they
                # keep the cache and skip the deferred reflow.
                self._drill_hw_capped_height = None
                self._load_handwriting_drill(vector)
                return
            
            # --- Restore normal UI after handwriting mode ---
            from kivy.metrics import dp
            # Hide handwriting canvas
            hw_container = self.root.ids.get('drill_handwriting_container')
            if hw_container:
                hw_container.size_hint_y = None
                hw_container.height = 0
                hw_container.opacity = 0
            # Hide handwriting button rows
            hw_btn_row = self.root.ids.get('drill_hw_button_row')
            if hw_btn_row:
                hw_btn_row.height = 0
                hw_btn_row.opacity = 0
            hw_check_row = self.root.ids.get('drill_hw_check_row')
            if hw_check_row:
                hw_check_row.height = 0
                hw_check_row.opacity = 0
            # Restore normal button row
            normal_btn_row = self.root.ids.get('drill_normal_button_row')
            if normal_btn_row:
                normal_btn_row.height = dp(56)
                normal_btn_row.opacity = 1
            # Restore top spacer / bottom section to typing layout
            top_spacer = self.root.ids.get('drill_top_spacer')
            if top_spacer:
                top_spacer.size_hint_y = None
                top_spacer.height = 0
            bottom_section = self.root.ids.get('drill_bottom_section')
            if bottom_section:
                bottom_section.size_hint_y = 1
                bottom_section.spacing = dp(4)
                bottom_section.padding = [dp(4), dp(4), dp(4), dp(56)]
                bottom_section.size_hint_x = 0.92
                bottom_section.pos_hint = {'center_x': 0.5}
            # Restore inner spacer so it can absorb unused vertical space
            inner_sp = self.root.ids.get('drill_inner_spacer')
            if inner_sp:
                inner_sp.size_hint_y = 1
                inner_sp.height = 0
            # Deactivate centering spacers
            hw_top_sp = self.root.ids.get('drill_hw_top_spacer')
            if hw_top_sp:
                hw_top_sp.size_hint_y = None
                hw_top_sp.height = 0
            hw_bot_sp = self.root.ids.get('drill_hw_bottom_spacer')
            if hw_bot_sp:
                hw_bot_sp.size_hint_y = None
                hw_bot_sp.height = 0
            # Hide handwriting definition label
            hw_def_label = self.root.ids.get('drill_hw_definition')
            if hw_def_label:
                hw_def_label.height = 0
                hw_def_label.opacity = 0
                hw_def_label.text = ''
            # Restore prompt font size, markup, and visibility
            # (handwriting mode may have set opacity=0 / height=0)
            if prompt_label:
                prompt_label.font_size = '14sp'
                prompt_label.markup = True
                prompt_label.opacity = 1
                prompt_label.size_hint_y = None
                prompt_label.height = dp(26)
            # Restore question label visibility
            if question_label:
                question_label.height = dp(50)
                question_label.opacity = 1
                question_label.markup = True
            # Restore text input
            if text_input:
                text_input.opacity = 1
                text_input.height = dp(50)
                text_input.size_hint_y = None
            # Restore normal buttons
            if submit_btn:
                submit_btn.opacity = 1
                submit_btn.disabled = False
            if reveal_btn:
                reveal_btn.opacity = 1
                reveal_btn.disabled = False
            if undo_btn:
                undo_btn.opacity = 1
                undo_btn.disabled = False
            # Restore counters
            drill_counter_row_fix = self.root.ids.get('drill_counter_row')
            if drill_counter_row_fix:
                drill_counter_row_fix.size_hint_y = None
                drill_counter_row_fix.height = dp(44)
                drill_counter_row_fix.opacity = 1
            drill_counter_fix = self.root.ids.get('drill_counter')
            if drill_counter_fix:
                drill_counter_fix.height = dp(18)
                drill_counter_fix.opacity = 1
            drill_progress_fix = self.root.ids.get('drill_progress_text')
            if drill_progress_fix:
                drill_progress_fix.height = dp(16)
                drill_progress_fix.opacity = 1
            if streak_label:
                streak_label.height = dp(20)
                streak_label.opacity = 1
            
            # Handle grammar vectors differently
            is_grammar = vector.get('kind') == 'grammar'
            
            # Ensure grammar vectors have exercise data loaded (weak words drill
            # vectors may also lack grammar_category).
            if is_grammar and not vector.get('exercise_data'):
                self._ensure_grammar_exercise_loaded(vector)
            
            if is_grammar and vector_type == 'fill-blank':
                # Grammar fill-in-the-blank — rotate exercise from pool
                pools = getattr(self, '_grammar_exercise_pools', {})
                eid = vector.get('entry_id')
                eid_pool = pools.get(eid)
                # Lazy-load pool if not already cached (e.g. SRS review drills)
                if not eid_pool and eid and vector.get('grammar_category'):
                    try:
                        with dict_db.get_db(get_db_path()) as conn:
                            eid_pool = learning.load_grammar_exercise_pool(conn, eid)
                        if eid_pool:
                            if not hasattr(self, '_grammar_exercise_pools'):
                                self._grammar_exercise_pools = {}
                            self._grammar_exercise_pools[eid] = eid_pool
                    except Exception:
                        pass
                if eid_pool and vector.get('grammar_category'):
                    learning.pick_fresh_grammar_exercise(vector, eid_pool)

                exercise_data = vector.get('exercise_data', {})
                
                # If exercise_data is missing, load it from the grammar lesson file
                if not exercise_data.get('sentence_with_blank'):
                    exercise_data = self._load_grammar_exercise_for_entry(vector.get('entry_id'))
                    if exercise_data:
                        # Store back into vector for future use
                        vector['exercise_data'] = exercise_data
                
                grammar_point = exercise_data.get('grammar_point', '')
                translation = exercise_data.get('translation', '')
                notes = exercise_data.get('notes', '')
                form_being_tested = exercise_data.get('form_being_tested', '')
                
                # Debug log
                Logger.info(f'Grammar drill: grammar_point={grammar_point}, translation={translation}, form_being_tested={form_being_tested}')
                
                # Use DB-level hint if available, otherwise fall back to extraction
                db_hint = exercise_data.get('hint', '')
                if db_hint:
                    # DB hint is ready to use as the parenthetical (e.g. "Polite", "Casual copula")
                    translation_with_hint = f"{translation} ({db_hint})"
                else:
                    # Legacy path: extract hint from grammar point name
                    hint = self._extract_grammar_hint(grammar_point, notes)
                    if ' - ' in hint:
                        formality = hint.split(' - ', 1)[1]
                        translation_with_hint = f"{translation} ({formality})"
                    else:
                        translation_with_hint = translation
                
                # Keep the blank as underscores (for aesthetics)
                sentence_with_hint = exercise_data.get('sentence_with_blank', '')
                
                # Format translation with bold text on the key word
                formatted_translation = self._format_translation_with_bold(translation_with_hint, grammar_point)
                prompt_text = formatted_translation
                prompt = sentence_with_hint
                
                # Store exercise data for answer validation
                self._current_grammar_exercise = exercise_data
                
            elif is_grammar and vector_type == 'scramble':
                # Grammar scramble — rotate exercise from pool, shuffle blocks
                pools = getattr(self, '_grammar_exercise_pools', {})
                eid = vector.get('entry_id')
                eid_pool = pools.get(eid)
                if not eid_pool and eid and vector.get('grammar_category'):
                    try:
                        with dict_db.get_db(get_db_path()) as conn:
                            eid_pool = learning.load_grammar_exercise_pool(conn, eid)
                        if eid_pool:
                            if not hasattr(self, '_grammar_exercise_pools'):
                                self._grammar_exercise_pools = {}
                            self._grammar_exercise_pools[eid] = eid_pool
                    except Exception:
                        pass
                if eid_pool and vector.get('grammar_category'):
                    learning.pick_fresh_grammar_exercise(vector, eid_pool)

                exercise_data = vector.get('exercise_data', {})
                grammar_point = exercise_data.get('grammar_point', '')
                translation = exercise_data.get('translation', '')

                # Parse scramble_blocks
                blocks_raw = exercise_data.get('scramble_blocks', '[]')
                if isinstance(blocks_raw, str):
                    try:
                        blocks = json.loads(blocks_raw)
                    except (json.JSONDecodeError, TypeError):
                        blocks = []
                else:
                    blocks = list(blocks_raw)

                # Correct sentence for answer validation
                correct_sentence = ''.join(blocks) if blocks else exercise_data.get('audio_text', '')
                self._current_scramble_correct = correct_sentence.rstrip('。、！？…')

                # Shuffle blocks (guaranteed different from original order)
                shuffled = learning._shuffle_blocks(blocks)

                # Format as spaced-out labels
                prompt = ' '.join(f'「{b}」' for b in shuffled) if shuffled else ''

                # Build translation with hint
                db_hint = exercise_data.get('hint', '')
                if db_hint:
                    translation_with_hint = f"{translation} ({db_hint})"
                else:
                    hint = self._extract_grammar_hint(grammar_point, exercise_data.get('notes', ''))
                    if ' - ' in hint:
                        formality = hint.split(' - ', 1)[1]
                        translation_with_hint = f"{translation} ({formality})"
                    else:
                        translation_with_hint = translation

                formatted_translation = self._format_translation_with_bold(translation_with_hint, grammar_point)
                prompt_text = formatted_translation

                self._current_grammar_exercise = exercise_data

            elif is_grammar and vector_type == 'translate':
                # Grammar translate — show English, user types Japanese sentence
                pools = getattr(self, '_grammar_exercise_pools', {})
                eid = vector.get('entry_id')
                eid_pool = pools.get(eid)
                if not eid_pool and eid and vector.get('grammar_category'):
                    try:
                        with dict_db.get_db(get_db_path()) as conn:
                            eid_pool = learning.load_grammar_exercise_pool(conn, eid)
                        if eid_pool:
                            if not hasattr(self, '_grammar_exercise_pools'):
                                self._grammar_exercise_pools = {}
                            self._grammar_exercise_pools[eid] = eid_pool
                    except Exception:
                        pass
                if eid_pool and vector.get('grammar_category'):
                    learning.pick_fresh_grammar_exercise(vector, eid_pool)

                exercise_data = vector.get('exercise_data', {})
                grammar_point = exercise_data.get('grammar_point', '')
                translation = exercise_data.get('translation', '')

                # Build translation with hint
                db_hint = exercise_data.get('hint', '')
                if db_hint:
                    translation_with_hint = f"{translation} ({db_hint})"
                else:
                    hint = self._extract_grammar_hint(grammar_point, exercise_data.get('notes', ''))
                    if ' - ' in hint:
                        formality = hint.split(' - ', 1)[1]
                        translation_with_hint = f"{translation} ({formality})"
                    else:
                        translation_with_hint = translation

                formatted_translation = self._format_translation_with_bold(translation_with_hint, grammar_point)
                prompt_text = 'Translate to Japanese:'
                prompt = formatted_translation

                self._current_grammar_exercise = exercise_data

            elif is_grammar and vector_type == 'dictation':
                # Grammar dictation — user hears Japanese via TTS, types what they hear
                pools = getattr(self, '_grammar_exercise_pools', {})
                eid = vector.get('entry_id')
                eid_pool = pools.get(eid)
                if not eid_pool and eid and vector.get('grammar_category'):
                    try:
                        with dict_db.get_db(get_db_path()) as conn:
                            eid_pool = learning.load_grammar_exercise_pool(conn, eid)
                        if eid_pool:
                            if not hasattr(self, '_grammar_exercise_pools'):
                                self._grammar_exercise_pools = {}
                            self._grammar_exercise_pools[eid] = eid_pool
                    except Exception:
                        pass
                if eid_pool and vector.get('grammar_category'):
                    learning.pick_fresh_grammar_exercise(vector, eid_pool)

                exercise_data = vector.get('exercise_data', {})
                self._current_grammar_exercise = exercise_data

                # The sentence to speak (stored in vector['prompt'] / answer)
                dictation_sentence = vector.get('answer', '') or exercise_data.get('audio_text', '')
                self._dictation_audio_text = dictation_sentence

                # Speaker icon in question label — user taps to replay
                prompt = '\ue050'  # Material Symbols volume_up icon
                prompt_text = 'Write what you hear:'

                # Auto-play TTS on load
                Clock.schedule_once(lambda dt: self.play_audio(dictation_sentence), 0.3)

            elif vector_type == 'show_kana':
                prompt_text = 'Type the reading:'
            elif vector_type == 'show_romaji':
                # Determine if answer is hiragana or katakana
                answer_char = (vector.get('answer', '') or '')[0:1]
                if '\u30A0' <= answer_char <= '\u30FF':  # Katakana range
                    prompt_text = 'Type the katakana:'
                else:  # Hiragana (or other)
                    prompt_text = 'Type the hiragana:'
            elif vector_type == 'orthography_to_reading':
                prompt_text = 'Type the reading:'
            elif vector_type in ('orthography_to_meaning', 'kana_to_meaning'):
                prompt_text = 'Type the meaning:'
                # Extract parenthetical hint from first meaning if present
                import re as _re_hint
                _answer_text = vector.get('answer', '') or ''
                _first_meaning = _answer_text.split(';')[0].strip()
                _hint_match = _re_hint.search(r'\(([^)]+)\)', _first_meaning)
                if _hint_match:
                    prompt_text = f'Type the meaning: ({_hint_match.group(1)})'
                elif vector_type == 'kana_to_meaning':
                    # Add (katakana) hint if the prompt word is katakana
                    kana_prompt = vector.get('prompt', '')
                    if kana_prompt and all('\u30A0' <= c <= '\u30FF' or not c.strip() for c in kana_prompt):
                        prompt_text = 'Type the meaning: (katakana)'
            else:
                prompt_text = 'Type the answer:'
            
            if prompt_label:
                # Bind ref press handler for clickable grammar hints (only bind once)
                if not hasattr(prompt_label, '_grammar_hint_bound'):
                    prompt_label.bind(on_ref_press=self._on_grammar_hint_ref_press)
                    prompt_label._grammar_hint_bound = True
                prompt_label.text = prompt_text
                # Ensure visibility (handwriting mode may have hidden it)
                prompt_label.opacity = 1
                prompt_label.height = dp(26)
            
            if question_label:
                # For grammar, use the local prompt variable; otherwise use vector's prompt
                question_text = prompt if is_grammar else vector.get('prompt', '')
                
                # For kanji entries with readings, format to show only on'yomi and kun'yomi
                if vector_type == 'orthography_to_reading' and vector.get('kind') == 'kanji':
                    question_text = self._format_kanji_readings(question_text)
                
                # Truncate meanings if this is a meaning-type question and has multiple meanings
                if vector_type in ('orthography_to_meaning', 'kana_to_meaning', 'meaning_to_kana', 'show_kana', 'show_romaji'):
                    question_text = self._format_meanings_truncated(question_text)
                    # Bind click handler if truncated
                    if getattr(self, '_meanings_truncated', False):
                        question_label.unbind(on_touch_down=self._toggle_meanings)
                        question_label.bind(on_touch_down=self._toggle_meanings)
                elif vector_type == 'orthography_to_reading' and vector.get('kind') == 'kanji':
                    # Kanji readings already have click handler
                    if getattr(self, '_kanji_readings_truncated', False):
                        question_label.unbind(on_touch_down=self._toggle_kanji_readings)
                        question_label.bind(on_touch_down=self._toggle_kanji_readings)
                
                question_label.text = question_text
                Logger.info(f'Drill: question_label.text = {repr(question_text)}, vector_type={vector_type}, prompt={repr(prompt)}')
                # Adjust font size and font for special vector types
                if is_grammar and vector_type == 'dictation':
                    from kivy.metrics import sp
                    question_label.font_name = 'fonts/MaterialSymbolsOutlined.ttf'
                    question_label.font_size = sp(48)
                    # Bind tap to replay TTS
                    _audio = getattr(self, '_dictation_audio_text', '')
                    question_label.unbind(on_touch_down=self._on_dictation_speaker_tap)
                    question_label.bind(on_touch_down=self._on_dictation_speaker_tap)
                elif is_grammar and vector_type == 'scramble':
                    from kivy.metrics import sp
                    question_label.font_size = sp(26)
                    question_label.font_name = 'fonts/NotoSansJP-Regular.ttf'
                else:
                    from kivy.metrics import sp
                    question_label.font_size = sp(26)
                    question_label.font_name = 'fonts/NotoSansJP-Regular.ttf'
                # Unbind dictation tap handler if not dictation
                if not (is_grammar and vector_type == 'dictation'):
                    question_label.unbind(on_touch_down=self._on_dictation_speaker_tap)
            
            if text_input:
                text_input.text = ''
                text_input.readonly = False
                # Clear any stale selection / cursor state left by reveal
                text_input.cancel_selection()
                try:
                    text_input.cursor = (0, 0)
                except Exception:
                    pass
                
                # Enable IME mode based on prompt type
                if is_grammar and vector_type in ('fill-blank', 'scramble', 'translate', 'dictation'):
                    # Grammar IME: show kanji as user types when answer has kanji
                    if vector_type == 'scramble':
                        grammar_answer = getattr(self, '_current_scramble_correct', '')
                    elif vector_type in ('translate', 'dictation'):
                        grammar_answer = vector.get('answer', '')
                    else:
                        grammar_answer = getattr(self, '_current_grammar_exercise', {}).get('correct_answer', '') or vector.get('answer', '')
                    self._grammar_expected_answer = grammar_answer
                    if grammar_answer and any(0x4e00 <= ord(ch) <= 0x9fff for ch in grammar_answer):
                        self._drill_ime_mode = 'grammar_kanji'
                        self._grammar_kanji_segments = self._build_grammar_kanji_segments(grammar_answer)
                    else:
                        self._drill_ime_mode = 'hiragana'
                        self._grammar_kanji_segments = []
                elif vector_type == 'show_kana':
                    # show_kana: answer is plain romaji, no IME conversion
                    self._drill_ime_mode = None
                    self._grammar_expected_answer = ''
                elif prompt_text == 'Type the hiragana:':
                    self._drill_ime_mode = 'hiragana'
                elif prompt_text == 'Type the katakana:':
                    self._drill_ime_mode = 'katakana'
                elif prompt_text == 'Type the reading:':
                    # Check if the prompt is katakana - if so, use katakana IME
                    question_text = prompt if is_grammar else vector.get('prompt', '')
                    if question_text and any('\u30A0' <= c <= '\u30FF' for c in question_text):
                        self._drill_ime_mode = 'katakana'
                    else:
                        self._drill_ime_mode = 'hiragana'
                elif vector_type in ('meaning_to_kana', 'kana_to_meaning'):
                    # For meaning<->kana vectors, check the expected answer to determine IME mode
                    expected_answer = vector.get('answer', '')
                    if expected_answer and any('\u30A0' <= c <= '\u30FF' for c in expected_answer):
                        self._drill_ime_mode = 'katakana'
                    elif expected_answer and any('\u3040' <= c <= '\u309F' for c in expected_answer):
                        self._drill_ime_mode = 'hiragana'
                    else:
                        self._drill_ime_mode = None
                else:
                    self._drill_ime_mode = None
                
                # Restore container visibility and set focus.
                #
                # Bottom-spacer layout: content sits at the top of the screen
                # and the soft keyboard covers only the empty spacer below the
                # buttons.  Opening the keyboard therefore causes no visible
                # reflow, so we focus the input and show content immediately.
                _dm = self.root.ids.get('drill_main_container')
                if _dm:
                    _dm.opacity = 1
                    _dm.disabled = False
                _tb = self.root.ids.get('global_top_bar')
                if _tb:
                    _tb.opacity = 1
                # Force-hide overlays to prevent invisible touch interception
                for _ovl_id in ('info_card_overlay', 'writing_practice_overlay'):
                    _ovl = self.root.ids.get(_ovl_id)
                    if _ovl and (not _ovl.disabled or _ovl.opacity > 0):
                        _ovl.opacity = 0
                        _ovl.disabled = True
                        _ovl.size_hint = (0, 0)
                text_input.disabled = False
                # Diagnostic: log widget states before focus
                _ico = self.root.ids.get('info_card_overlay')
                _wpo = self.root.ids.get('writing_practice_overlay')
                Logger.info(f'DrillFocus: dm.disabled={_dm.disabled if _dm else "?"}, '
                            f'ti.disabled={text_input.disabled}, ti.readonly={text_input.readonly}, '
                            f'ti.opacity={text_input.opacity}, ti.height={text_input.height}, '
                            f'ico.disabled={_ico.disabled if _ico else "?"}, ico.size_hint={_ico.size_hint if _ico else "?"}, '
                            f'wpo.disabled={_wpo.disabled if _wpo else "?"}, wpo.size_hint={_wpo.size_hint if _wpo else "?"}')
                if not text_input.focus:
                    Clock.schedule_once(
                        lambda dt, _ti=text_input: setattr(_ti, 'focus', True), 0)
                self._last_drill_vector_type = vector_type
            
            if streak_label:
                # Hide streak counter for filler words OR if hide_review_counter is enabled
                is_filler = vector.get('is_filler', False)
                if is_filler or self.hide_review_counter:
                    streak_label.opacity = 0
                else:
                    streak_label.opacity = 1
                    # Delay resetting streak to let flash complete (0.5s)
                    streak = vector.get('streak', 0)
                    # Check if session is still active before resetting (to avoid errors after finishing)
                    def reset_streak(dt):
                        if hasattr(self, '_current_drill_session_id') and self._current_drill_session_id:
                            streak_label.text = f'Streak: {streak}/3'
                            streak_label.color = (0.15, 0.45, 0.65, 1)
                    Clock.schedule_once(reset_streak, 0.5)
            
            if feedback_label:
                feedback_label.text = ''
            
            # Reset buttons
            submit_btn = self.root.ids.get('drill_submit_btn')
            reveal_btn = self.root.ids.get('drill_reveal_btn')
            undo_btn = self.root.ids.get('drill_undo_btn')
            
            if submit_btn:
                submit_btn.text = 'Submit'
                submit_btn.background_color = (0.25, 0.35, 0.50, 1)
            
            if reveal_btn:
                reveal_btn.text = 'Reveal'
                reveal_btn.background_color = (0.60, 0.15, 0.20, 1)
                reveal_btn.disabled = False
                reveal_btn.opacity = 1.0
            
            if undo_btn:
                undo_btn.text = 'Undo'
                undo_btn.background_color = (0.30, 0.30, 0.32, 1)
            
            # Reset flags
            self._drill_reveal_confirm = False
            self._drill_undo_confirm = False
            self._drill_revealed = False
            self._drill_waiting_continue = False  # Reset waiting flag after undo
            
            # Update counter and progress based on mode
            if hasattr(self, '_drill_mode') and self._drill_mode == 'time_attack':
                # Time attack mode - update display separately
                self._update_time_attack_display()
            else:
                # Regular drill mode - show counter and progress
                if counter_label:
                    if self.hide_review_counter:
                        counter_label.opacity = 0
                    else:
                        counter_label.opacity = 1
                        completed = getattr(self, '_drill_completed_count', 0)
                        conn2 = None
                        try:
                            conn2 = dict_db.init_db(get_db_path())
                            session = dict_db.get_learning_session(conn2, self._current_drill_session_id)
                            total = session['data']['meta'].get('total_vectors', 0)
                            counter_label.text = f'{completed} / {total}'
                        except Exception as e:
                            Logger.error(f'Drill: Error updating counter: {e}')
                        finally:
                            if conn2:
                                try:
                                    conn2.close()
                                except Exception:
                                    pass
                
                # Update progress (active vectors)
                if progress_label:
                    if self.hide_review_counter:
                        progress_label.opacity = 0
                    else:
                        progress_label.opacity = 1
                        conn3 = None
                        try:
                            conn3 = dict_db.init_db(get_db_path())
                            session = dict_db.get_learning_session(conn3, self._current_drill_session_id)
                            active = len(session['data'].get('in_progress', []))
                            progress_label.text = f'{active} active'
                        except Exception as e:
                            Logger.error(f'Drill: Error updating progress: {e}')
                        finally:
                            if conn3:
                                try:
                                    conn3.close()
                                except Exception:
                                    pass
                
                # Update streak label for regular mode
                if streak_label:
                    is_filler = vector.get('is_filler', False)
                    if not is_filler:
                        streak = vector.get('streak', 0)
                        streak_label.text = f'Streak: {streak}/3'
                        streak_label.color = (0.15, 0.45, 0.65, 1)
            
        except Exception as e:
            Logger.error(f'Drill: Error loading vector: {e}')
            import traceback
            traceback.print_exc()
        finally:
            if conn:
                try:
                    conn.close()
                except Exception as e:
                    Logger.warning(f'Drill: Error closing connection: {e}')

    # ────────────────────────────────────────────────────────────
    # Info Card Display (Lesson teach-then-drill flow)
    # ────────────────────────────────────────────────────────────

    def _show_lesson_info_card(self, card, info_index, total_in_batch, batch_index):
        """Display a single info card in the drill screen overlay.

        Args:
            card: dict with kanji, kana, gloss, pos, examples, entry_id, etc.
            info_index: 0-based index within the current batch
            total_in_batch: total info cards in this batch
            batch_index: which batch (0-based)
        """
        from kivy.metrics import dp
        Logger.info(f'InfoCard: Showing card {info_index+1}/{total_in_batch} batch={batch_index} entry={card.get("entry_id")}')

        # Teaching concept cards (title + body, no entry data)
        if card.get('card_type') == 'teaching':
            self._show_teaching_info_card(card, info_index, total_in_batch, batch_index)
            return

        # Store current card data for TTS and writing practice
        self._current_info_card = card
        self._current_info_index = info_index
        self._current_info_total = total_in_batch
        self._current_info_batch = batch_index

        # ── Hide drill UI, show info card overlay ──
        drill_main = self.root.ids.get('drill_main_container')
        if drill_main:
            drill_main.opacity = 0
            drill_main.disabled = True

        overlay = self.root.ids.get('info_card_overlay')
        if overlay:
            overlay.opacity = 1
            overlay.disabled = False
            overlay.size_hint = (1, 1)

        # Restore global top bar (back + plus buttons) — _load_current_drill hid
        # it at the top; info cards are a valid visible state so reveal it now.
        _tb_info = self.root.ids.get('global_top_bar')
        if _tb_info:
            _tb_info.opacity = 1

        # Hide writing practice overlay in case it's visible
        # Set size_hint to (0,0) so it doesn't intercept touches
        wp_overlay = self.root.ids.get('writing_practice_overlay')
        if wp_overlay:
            wp_overlay.opacity = 0
            wp_overlay.disabled = True
            wp_overlay.size_hint = (0, 0)

        # Explicitly force-enable all interactive info card widgets.
        # Kivy's disabled propagation can sometimes leave children stuck;
        # this brute-force pass guarantees buttons are clickable.
        for _btn_id in ['info_card_tts_btn', 'info_card_skip_all_btn',
                        'info_card_skip_btn', 'info_card_next_btn', 'info_card_prev_btn']:
            _btn = self.root.ids.get(_btn_id)
            if _btn:
                _btn.disabled = False

        # Disable Prev on the first card in the batch
        prev_btn = self.root.ids.get('info_card_prev_btn')
        if prev_btn:
            is_first = (info_index == 0)
            prev_btn.disabled = is_first
            prev_btn.opacity = 0.35 if is_first else 1.0

        # ── Populate info card content ──
        progress_label = self.root.ids.get('info_card_progress')
        if progress_label:
            batch_label = f'  (Batch {batch_index + 1})' if batch_index > 0 else ''
            progress_label.text = f'Learning {info_index + 1}/{total_in_batch}{batch_label}'

        word_label = self.root.ids.get('info_card_word')
        if word_label:
            word_label.font_size = '36sp'  # Restore default (teaching cards use 24sp)
            kanji = card.get('kanji', '')
            kana = card.get('kana', '')
            Logger.info(f'InfoCard: word display entry={card.get("entry_id")} kanji="{kanji}" kana="{kana}"')
            # Show kanji if available, otherwise kana
            if kanji:
                word_label.text = kanji
            else:
                word_label.text = kana

        reading_label = self.root.ids.get('info_card_reading')
        if reading_label:
            kanji = card.get('kanji', '')
            kana = card.get('kana', '')
            if kanji and kana:
                reading_label.text = kana
                reading_label.height = reading_label.texture_size[1] + dp(6)
            elif not kanji:
                # Kana-only word, reading is redundant
                reading_label.text = ''
                reading_label.height = 0
            else:
                reading_label.text = ''
                reading_label.height = 0

        # ── Card type badge ──
        type_lbl = self.root.ids.get('info_card_type_label')
        if type_lbl:
            kind = card.get('kind', 'vocab')
            if kind == 'kanji':
                type_lbl.text = 'Kanji'
            elif kind == 'grammar':
                type_lbl.text = 'Grammar'
            elif kind == 'kana':
                kana_text = card.get('kana', '') or card.get('kanji', '')
                first_ch = kana_text[0] if kana_text else ''
                if '\u3041' <= first_ch <= '\u3096':
                    type_lbl.text = 'Hiragana'
                elif '\u30A0' <= first_ch <= '\u30FF':
                    type_lbl.text = 'Katakana'
                else:
                    type_lbl.text = 'Kana'
            else:
                type_lbl.text = 'Vocabulary'
            type_lbl.height = dp(18)

        pos_label = self.root.ids.get('info_card_pos')
        if pos_label:
            pos_text = card.get('pos', '')
            jlpt = card.get('jlpt_level', '')
            parts = []
            if pos_text:
                # Truncate long POS: show first entry + "..." if more
                pos_entries = [p.strip() for p in pos_text.split(';') if p.strip()]
                if len(pos_entries) > 1:
                    truncated_pos = pos_entries[0] + '...'
                else:
                    truncated_pos = pos_entries[0] if pos_entries else pos_text
                parts.append(truncated_pos)
                # Store full POS for tap-to-reveal
                pos_label._full_pos_text = pos_text
            else:
                pos_label._full_pos_text = ''
            if jlpt:
                parts.append(jlpt)
            pos_label.text = '  ·  '.join(parts)
            # Bind tap to expand/collapse POS if truncated
            if not hasattr(pos_label, '_pos_tap_bound'):
                def _on_pos_touch(instance, touch):
                    if instance.collide_point(*touch.pos) and getattr(instance, '_full_pos_text', ''):
                        full = instance._full_pos_text
                        jlpt_part = getattr(instance, '_jlpt_text', '')
                        # Toggle between truncated and full
                        if '...' in instance.text:
                            p = [full]
                            if jlpt_part:
                                p.append(jlpt_part)
                            instance.text = '  ·  '.join(p)
                        else:
                            pos_entries = [e.strip() for e in full.split(';') if e.strip()]
                            if len(pos_entries) > 1:
                                p = [pos_entries[0] + '...']
                            else:
                                p = [full]
                            if jlpt_part:
                                p.append(jlpt_part)
                            instance.text = '  ·  '.join(p)
                pos_label.bind(on_touch_down=_on_pos_touch)
                pos_label._pos_tap_bound = True
            pos_label._jlpt_text = jlpt or ''

        definition_label = self.root.ids.get('info_card_definition')
        if definition_label:
            definition_label.halign = 'center'  # Restore default (teaching cards use left)
            definition_label.font_size = '16sp'  # Restore default
            gloss = card.get('gloss', '')
            # Format multiple definitions with numbered list
            meanings = [m.strip() for m in gloss.split(';') if m.strip()]
            if len(meanings) > 1:
                numbered = '  '.join(f'{i+1}. {m}' for i, m in enumerate(meanings[:5]))
                definition_label.text = numbered
            else:
                definition_label.text = gloss

        # ── Restore TTS button visibility (teaching cards hide it) ──
        tts_btn = self.root.ids.get('info_card_tts_btn')
        if tts_btn:
            try:
                tts_box = tts_btn.parent.parent
                tts_box.height = dp(40)
                tts_box.opacity = 1
            except (AttributeError, TypeError):
                pass

        # ── Populate example sentences ──
        examples_box = self.root.ids.get('info_card_examples_box')
        examples_header = self.root.ids.get('info_card_examples_header')
        if examples_box:
            examples_box.clear_widgets()
            examples = card.get('examples', [])
            if examples:
                if examples_header:
                    examples_header.height = dp(22)
                    examples_header.opacity = 1
                for ex in examples[:3]:
                    jp = ex.get('japanese', '')
                    en = ex.get('english', '')
                    self._add_info_card_example(examples_box, jp, en)
            else:
                if examples_header:
                    examples_header.height = 0
                    examples_header.opacity = 0

        # ── Update Next button text ──
        next_btn = self.root.ids.get('info_card_next_btn')
        if next_btn:
            has_practice_char = bool(card.get('kanji') or card.get('kana'))
            at_last = (info_index >= total_in_batch - 1)
            if self.handwriting_mode and has_practice_char:
                next_btn.text = 'Practice'
            elif at_last:
                next_btn.text = 'Start Drill'
            else:
                next_btn.text = 'Next'

        # ── Reset scroll position ──
        scroll = self.root.ids.get('info_card_scroll')
        if scroll:
            scroll.scroll_y = 1

        # ── Auto TTS for vocab info cards ──
        if self.auto_tts:
            kana = card.get('kana') or ''
            tts_text = kana or card.get('kanji') or card.get('prompt', '')
            if tts_text:
                Clock.schedule_once(lambda dt, t=tts_text: self.speak_text(t), 0.4)

    def _show_teaching_info_card(self, card, info_index, total_in_batch, batch_index):
        """Display a teaching concept card (title + body text, no entry data)."""
        from kivy.metrics import dp

        self._current_info_card = card
        self._current_info_index = info_index
        self._current_info_total = total_in_batch
        self._current_info_batch = batch_index

        # ── Hide drill UI, show info card overlay ──
        drill_main = self.root.ids.get('drill_main_container')
        if drill_main:
            drill_main.opacity = 0
            drill_main.disabled = True

        overlay = self.root.ids.get('info_card_overlay')
        if overlay:
            overlay.opacity = 1
            overlay.disabled = False
            overlay.size_hint = (1, 1)

        _tb_info = self.root.ids.get('global_top_bar')
        if _tb_info:
            _tb_info.opacity = 1

        wp_overlay = self.root.ids.get('writing_practice_overlay')
        if wp_overlay:
            wp_overlay.opacity = 0
            wp_overlay.disabled = True
            wp_overlay.size_hint = (0, 0)

        for _btn_id in ['info_card_tts_btn', 'info_card_skip_all_btn',
                        'info_card_skip_btn', 'info_card_next_btn', 'info_card_prev_btn']:
            _btn = self.root.ids.get(_btn_id)
            if _btn:
                _btn.disabled = False

        prev_btn = self.root.ids.get('info_card_prev_btn')
        if prev_btn:
            is_first = (info_index == 0)
            prev_btn.disabled = is_first
            prev_btn.opacity = 0.35 if is_first else 1.0

        # ── Progress indicator ──
        progress_label = self.root.ids.get('info_card_progress')
        if progress_label:
            batch_label = f'  (Batch {batch_index + 1})' if batch_index > 0 else ''
            progress_label.text = f'Learning {info_index + 1}/{total_in_batch}{batch_label}'

        # ── Type badge ──
        type_lbl = self.root.ids.get('info_card_type_label')
        if type_lbl:
            type_lbl.text = 'Introduction'
            type_lbl.height = dp(18)

        # ── Title in the word slot ──
        word_label = self.root.ids.get('info_card_word')
        if word_label:
            word_label.text = card.get('title', '')
            word_label.font_size = '24sp'

        # ── Hide reading and POS ──
        reading_label = self.root.ids.get('info_card_reading')
        if reading_label:
            reading_label.text = ''
            reading_label.height = 0

        pos_label = self.root.ids.get('info_card_pos')
        if pos_label:
            pos_label.text = ''

        # ── Body text in definition slot ──
        definition_label = self.root.ids.get('info_card_definition')
        if definition_label:
            definition_label.text = card.get('body', '')
            definition_label.halign = 'left'
            definition_label.font_size = '15sp'

        # ── Hide TTS button ──
        tts_btn = self.root.ids.get('info_card_tts_btn')
        if tts_btn:
            try:
                tts_box = tts_btn.parent.parent
                tts_box.height = 0
                tts_box.opacity = 0
            except (AttributeError, TypeError):
                pass

        # ── Hide examples ──
        examples_header = self.root.ids.get('info_card_examples_header')
        if examples_header:
            examples_header.height = 0
            examples_header.opacity = 0

        examples_box = self.root.ids.get('info_card_examples_box')
        if examples_box:
            examples_box.clear_widgets()

        # ── Next button ──
        next_btn = self.root.ids.get('info_card_next_btn')
        if next_btn:
            at_last = (info_index >= total_in_batch - 1)
            next_btn.text = 'Start Drill' if at_last else 'Next'

        # Reset scroll position
        scroll = self.root.ids.get('info_card_scroll')
        if scroll:
            scroll.scroll_y = 1

    def _add_info_card_example(self, container, japanese, english):
        """Add a single example sentence row to the info card.

        The Japanese sentence is parsed into clickable tokens (matching the
        dictionary entry detail view).  Falls back to plain text on error.
        """
        from kivy.uix.boxlayout import BoxLayout
        from kivy.uix.label import Label
        from kivy.uix.button import Button
        from kivy.uix.widget import Widget
        from kivy.metrics import dp

        row = BoxLayout(orientation='vertical', size_hint_y=None, spacing=dp(2),
                        padding=[0, dp(4), 0, dp(4)])
        row.bind(minimum_height=row.setter('height'))

        # ── Japanese sentence (clickable words) ──
        try:
            from reading.processor import ReadingProcessor
            processor = ReadingProcessor(get_db_path())
            tokens = processor.tokenize(japanese)
            matched_tokens = processor.match_tokens_to_db(tokens)

            markup_parts = []
            for i, token in enumerate(matched_tokens):
                if token.get('entry_id'):
                    markup_parts.append(
                        f'[ref={i}][color=6495ed]{token["surface"]}[/color][/ref]'
                    )
                else:
                    markup_parts.append(token['surface'])
            markup_text = ''.join(markup_parts)

            jp_label = Label(
                text=markup_text, font_size='16sp',
                color=(0.88, 0.86, 0.83, 1),
                font_name='fonts/NotoSansJP-Regular.ttf',
                size_hint_y=None, halign='left', valign='top',
                markup=True
            )
            jp_label.bind(
                texture_size=lambda inst, ts: setattr(inst, 'height', ts[1] + dp(4)),
                width=lambda inst, w: setattr(inst, 'text_size', (w, None))
            )
            jp_label._matched_tokens = matched_tokens

            def _on_word_tap(instance, ref):
                try:
                    idx = int(ref)
                    token = instance._matched_tokens[idx]
                    if token.get('entry_id'):
                        # Delegate to EntryDetailScreen which owns _show_parsed_word_popup
                        eds = self.root.ids.get('entry_detail_screen')
                        if eds:
                            eds._show_parsed_word_popup(token)
                except Exception as exc:
                    Logger.error(f'InfoCard: word tap error: {exc}')
                    import traceback; traceback.print_exc()

            jp_label.bind(on_ref_press=_on_word_tap)

        except Exception as e:
            Logger.warning(f'InfoCard: clickable parse failed, using plain text: {e}')
            jp_label = Label(
                text=japanese, font_size='16sp',
                color=(0.88, 0.86, 0.83, 1),
                font_name='fonts/NotoSansJP-Regular.ttf',
                size_hint_y=None, halign='left', valign='top',
                markup=False
            )
            jp_label.bind(
                texture_size=lambda inst, ts: setattr(inst, 'height', ts[1] + dp(4)),
                width=lambda inst, w: setattr(inst, 'text_size', (w, None))
            )

        row.add_widget(jp_label)

        # ── English translation ──
        if english:
            en_label = Label(
                text=english, font_size='14sp',
                color=(0.55, 0.55, 0.58, 1),
                font_name='fonts/NotoSansJP-Regular.ttf',
                size_hint_y=None, halign='left', valign='top',
                italic=True
            )
            en_label.bind(
                texture_size=lambda inst, ts: setattr(inst, 'height', ts[1] + dp(2)),
                width=lambda inst, w: setattr(inst, 'text_size', (w, None))
            )
            row.add_widget(en_label)

        # ── TTS button for example ──
        tts_row = BoxLayout(size_hint_y=None, height=dp(30))
        tts_btn = Button(
            text='\ue050',
            font_name='fonts/MaterialSymbolsOutlined.ttf',
            size_hint=(None, None), size=(dp(36), dp(26)),
            background_normal='', background_down='',
            background_color=(0.22, 0.32, 0.48, 1),
            color=(0.90, 0.88, 0.85, 1), font_size='16sp',
        )
        tts_btn.bind(on_press=lambda inst: setattr(inst, 'background_color', (0.15, 0.22, 0.35, 1)))
        tts_btn.bind(on_release=lambda inst, t=japanese: (
            setattr(inst, 'background_color', (0.22, 0.32, 0.48, 1)),
            self.play_audio(t, btn=inst)
        ))
        tts_row.add_widget(tts_btn)
        tts_row.add_widget(Widget())
        row.add_widget(tts_row)

        container.add_widget(row)

    def _hide_info_card_overlay(self):
        """Hide info card overlay and show the normal drill UI."""
        overlay = self.root.ids.get('info_card_overlay')
        if overlay:
            overlay.opacity = 0
            overlay.disabled = True
            overlay.size_hint = (0, 0)

        wp_overlay = self.root.ids.get('writing_practice_overlay')
        if wp_overlay:
            wp_overlay.opacity = 0
            wp_overlay.disabled = True
            wp_overlay.size_hint = (0, 0)

        # NOTE: drill_main_container and global_top_bar opacity/disabled are
        # intentionally NOT restored here.  _load_current_drill (and
        # _load_handwriting_drill) own that lifecycle; restoring them here would
        # produce a flash frame on Android before _load_current_drill hides them
        # again.

    def _show_progressive_unlock_card(self):
        """Show the info card(s) unlocked by getting first correct on an entry.
        
        This is part of the progressive unlock flow where new entries are
        introduced one at a time as the user gets their first correct answer.
        Supports multiple cards per entry (e.g. teaching card + info card).
        """
        try:
            conn = dict_db.init_db(get_db_path())
            import dictionary.learning as learning
            
            # Get the pending info card(s)
            pending = learning.get_pending_info_card(conn, self._current_drill_session_id)
            if not pending:
                Logger.info('ProgressiveUnlock: No pending info card')
                conn.close()
                self._load_current_drill()
                return
            
            # Normalize to list
            if isinstance(pending, list):
                cards = pending
            else:
                cards = [pending]
            
            # Get session to determine total active entries for progress display
            session = dict_db.get_learning_session(conn, self._current_drill_session_id)
            data = session['data'] if session else {}
            active_entry_ids = data.get('active_entry_ids', [])
            remaining_info = data.get('remaining_info', [])
            total_entries = len(active_entry_ids) + len(remaining_info)
            current_idx = len(active_entry_ids)  # This new card makes us the Nth active
            
            conn.close()
            
            Logger.info(f'ProgressiveUnlock: Showing {len(cards)} unlocked card(s) for entry {cards[0].get("entry_id")} ({current_idx}/{total_entries})')
            
            # Mark that this is a progressive unlock card
            self._progressive_unlock_mode = True
            self._progressive_unlock_cards = cards
            self._progressive_unlock_idx = 0
            
            self._show_lesson_info_card(cards[0], 0, len(cards), -1)
            
        except Exception as e:
            Logger.error(f'ProgressiveUnlock: Error showing card: {e}')
            import traceback
            traceback.print_exc()
            self._load_current_drill()

    def on_info_card_tts(self):
        """Play TTS for the current info card entry."""
        Logger.info('InfoCard: TTS button pressed')
        card = getattr(self, '_current_info_card', None)
        if not card:
            return
        # For kanji, strip reading-type labels and just speak the readings
        kana = card.get('kana') or ''
        kind = card.get('kind', '')
        if kind == 'kanji' and kana and '|' in kana:
            text = _kanji_readings_for_tts(kana) or card.get('kanji') or card.get('prompt', '')
        else:
            text = kana or card.get('kanji') or card.get('prompt', '')
        if text:
            # Try to get the info card TTS button for loading indicator
            btn = None
            try:
                sm = self._get_screen_manager()
                if sm:
                    drill_screen = sm.get_screen('drill')
                    btn = drill_screen.ids.get('info_card_tts_btn')
            except Exception:
                pass
            self.play_audio(text, btn=btn)

    def on_info_card_prev(self):
        """Go back to the previous info card in the batch."""
        Logger.info('InfoCard: Prev button pressed')
        try:
            # Progressive unlock mode — navigate within unlock cards
            if getattr(self, '_progressive_unlock_mode', False):
                idx = getattr(self, '_progressive_unlock_idx', 0)
                if idx > 0:
                    idx -= 1
                    self._progressive_unlock_idx = idx
                    cards = self._progressive_unlock_cards
                    self._show_lesson_info_card(cards[idx], idx, len(cards), -1)
                return
            
            info_index = getattr(self, '_current_info_index', 0)
            if info_index <= 0:
                return  # Already on first card
            conn = dict_db.init_db(get_db_path())
            import dictionary.learning as learning
            session = dict_db.get_learning_session(conn, self._current_drill_session_id)
            if session:
                data = session['data']
                data['info_index'] = info_index - 1
                dict_db.update_learning_session(conn, self._current_drill_session_id, data)
            conn.close()
            self._load_current_drill()
        except Exception as e:
            Logger.error(f'InfoCard: Error in on_info_card_prev: {e}')
            import traceback
            traceback.print_exc()

    def on_info_card_next(self):
        """Advance to the next info card, or start writing practice / drill."""
        Logger.info('InfoCard: Next/Skip button pressed')
        try:
            card = getattr(self, '_current_info_card', None)
            info_index = getattr(self, '_current_info_index', 0)
            total = getattr(self, '_current_info_total', 0)
            batch_index = getattr(self, '_current_info_batch', 0)

            # Check if writing practice should be shown for this card.
            # Use kanji if present, else kana (covers hiragana/katakana cards).
            if self.handwriting_mode and card:
                practice_char = card.get('kanji') or card.get('kana') or ''
                if practice_char:
                    self._start_writing_practice_for_card(card, info_index, total, batch_index)
                    return

            self._advance_info_card_index()
        except Exception as e:
            Logger.error(f'InfoCard: Error in on_info_card_next: {e}')
            import traceback
            traceback.print_exc()

    def _advance_info_card_index(self):
        """Move to the next info card in the batch, or switch to drill phase."""
        try:
            # Check if this is a progressive unlock card (shown mid-drill)
            if getattr(self, '_progressive_unlock_mode', False):
                cards = getattr(self, '_progressive_unlock_cards', [])
                idx = getattr(self, '_progressive_unlock_idx', 0) + 1
                if idx < len(cards):
                    # More cards to show for this unlock
                    self._progressive_unlock_idx = idx
                    self._show_lesson_info_card(cards[idx], idx, len(cards), -1)
                    return
                # All unlock cards shown — clear and return to drilling
                self._progressive_unlock_mode = False
                self._progressive_unlock_cards = []
                conn = dict_db.init_db(get_db_path())
                import dictionary.learning as learning
                learning.clear_pending_info_card(conn, self._current_drill_session_id)
                conn.close()
                self._hide_info_card_overlay()
                self._load_current_drill()
                return
            
            info_index = getattr(self, '_current_info_index', 0)
            total = getattr(self, '_current_info_total', 0)

            next_index = info_index + 1
            if next_index < total:
                # Update session info_index and re-enter _load_current_drill
                conn = dict_db.init_db(get_db_path())
                import dictionary.learning as learning
                session = dict_db.get_learning_session(conn, self._current_drill_session_id)
                if session:
                    data = session['data']
                    data['info_index'] = next_index
                    dict_db.update_learning_session(conn, self._current_drill_session_id, data)
                conn.close()
                self._load_current_drill()
            else:
                # All info cards for this batch shown → switch to drill phase
                conn = dict_db.init_db(get_db_path())
                import dictionary.learning as learning
                learning.set_session_phase(conn, self._current_drill_session_id, 'drill')
                conn.close()
                self._hide_info_card_overlay()
                self._load_current_drill()
        except Exception as e:
            Logger.error(f'InfoCard: Error advancing index: {e}')
            import traceback
            traceback.print_exc()

    def on_info_card_skip_all(self):
        """Skip all remaining info cards for the current batch and go straight to drilling."""
        Logger.info('InfoCard: Skip All button pressed')
        try:
            conn = dict_db.init_db(get_db_path())
            import dictionary.learning as learning
            if getattr(self, '_progressive_unlock_mode', False):
                # Progressive unlock: clear pending cards, return to drill
                Logger.info('InfoCard: SkipAll in progressive unlock mode')
                self._progressive_unlock_mode = False
                self._progressive_unlock_cards = []
                learning.clear_pending_info_card(conn, self._current_drill_session_id)
            else:
                Logger.info('InfoCard: SkipAll setting phase to drill')
                learning.set_session_phase(conn, self._current_drill_session_id, 'drill')
            conn.close()
            self._hide_info_card_overlay()
            # Also clear the stored info card state to prevent stale re-display
            self._current_info_card = None
            self._current_info_index = 0
            self._current_info_total = 0
            self._load_current_drill()
        except Exception as e:
            Logger.error(f'InfoCard: Error skipping all: {e}')

    # ────────────────────────────────────────────────────────────
    # Writing Practice (Info Card → Character Practice)
    # ────────────────────────────────────────────────────────────

    def _start_writing_practice_for_card(self, card, info_index, total_in_batch, batch_index):
        # Clear cached canvas height — each new word gets a fresh measurement.
        self._wp_capped_height = None
        """Start character writing practice after viewing an info card."""
        # Use kanji if present, else kana (covers hiragana/katakana cards)
        char_source = card.get('kanji') or card.get('kana') or ''
        if not char_source:
            self._advance_info_card_index()
            return

        # Extract individual characters that have stroke data
        from dictionary.stroke_order import has_stroke_data
        characters = [ch for ch in char_source if has_stroke_data(ch)]
        if not characters:
            self._advance_info_card_index()
            return

        # Store writing practice state
        self._wp_characters = characters
        self._wp_char_index = 0
        self._wp_correct_count = 0
        self._wp_rounds_done = 0  # reset so each new card starts from round 1
        self._wp_required_rounds = 3  # user must write the full word 3 times
        self._wp_info_index = info_index
        self._wp_info_total = total_in_batch
        self._wp_batch_index = batch_index
        self._wp_card = card

        self._show_writing_practice()

    def _show_writing_practice(self):
        """Display the writing practice overlay for the current character.
        
        Layout mirrors the drill handwriting mode exactly:
        - Counter at top (character progress)
        - Streak counter (0/3 correct)
        - Character display (what to write)
        - Prompt (reading hint)
        - Square handwriting canvas
        - Buttons: ← | Undo | Reveal | Skip, then Check
        - Auto-play stroke order animation
        """
        from kivy.metrics import dp
        from kivy.clock import Clock

        characters = getattr(self, '_wp_characters', [])
        char_index = getattr(self, '_wp_char_index', 0)
        rounds_done = getattr(self, '_wp_rounds_done', 0)
        required_rounds = getattr(self, '_wp_required_rounds', 3)

        if char_index >= len(characters):
            # Done with all characters — advance to next info card
            self._hide_writing_practice()
            self._advance_info_card_index()
            return

        current_char = characters[char_index]

        # ── Hide info card overlay, show writing practice overlay ──
        info_overlay = self.root.ids.get('info_card_overlay')
        if info_overlay:
            info_overlay.opacity = 0
            info_overlay.disabled = True
            info_overlay.size_hint = (0, 0)

        drill_main = self.root.ids.get('drill_main_container')
        if drill_main:
            drill_main.opacity = 0
            drill_main.disabled = True

        wp_overlay = self.root.ids.get('writing_practice_overlay')
        if wp_overlay:
            wp_overlay.opacity = 1
            wp_overlay.disabled = False
            wp_overlay.size_hint = (1, 1)

        # Update top-bar practice counter
        self.writing_practice_counter_text = 'Practice'
        self.writing_practice_active = True

        # Show how many full-word rounds have been completed.
        streak_label = self.root.ids.get('wp_streak_label')
        if streak_label:
            streak_label.text = f'Write: {rounds_done + 1}/{required_rounds}'
            streak_label.color = (0.15, 0.45, 0.65, 1)

        # Update question: full word fill-in-blank display (like the HW drill).
        # e.g. for 日本語 at char_index=1: '[color=60ff60]日[/color] _ _'
        question = self.root.ids.get('wp_question')
        if question:
            blanks = []
            for i, ch in enumerate(characters):
                if i < char_index:
                    blanks.append(f'[color=60ff60]{ch}[/color]')
                elif i == char_index:
                    blanks.append('[b]_[/b]')
                else:
                    blanks.append('_')
            question.text = ' '.join(blanks)
            question.markup = True

        # Get reading from current info card for the prompt
        prompt = self.root.ids.get('wp_prompt')
        if prompt:
            # Try to get reading from the current info card data
            reading = ''
            if hasattr(self, '_current_drill_session_id') and self._current_drill_session_id:
                try:
                    conn = dict_db.init_db(get_db_path())
                    session = dict_db.get_learning_session(conn, self._current_drill_session_id)
                    if session:
                        info_cards = session['data'].get('info_cards', [])
                        info_index = session['data']['meta'].get('info_index', 0)
                        if 0 <= info_index < len(info_cards):
                            card = info_cards[info_index]
                            reading = card.get('reading', '')
                    conn.close()
                except Exception:
                    pass
            prompt.text = reading

        # Clear feedback
        feedback = self.root.ids.get('wp_feedback')
        if feedback:
            feedback.text = ''

        # Set up the container — reuse cached height between characters to avoid
        # the 120 ms deferred reflow that causes flickering on multi-char words.
        canvas_container = self.root.ids.get('wp_handwriting_container')
        if canvas_container:
            cached_h = getattr(self, '_wp_capped_height', None)
            if cached_h is not None:
                canvas_container.size_hint_y = None
                canvas_container.height = cached_h
            else:
                canvas_container.size_hint_y = 1
                def cap_wp_canvas(dt):
                    if not canvas_container:
                        return
                    parent = canvas_container.parent
                    max_h = parent.width if parent else canvas_container.width
                    if max_h > 0 and canvas_container.height > max_h:
                        canvas_container.size_hint_y = None
                        canvas_container.height = max_h
                    self._wp_capped_height = canvas_container.height
                Clock.schedule_once(cap_wp_canvas, 0.12)

            canvas_container.clear_widgets()
            
            # FIRST: Show stroke order widget with animation (like drill Reveal)
            self._wp_stroke_widget = None
            self._wp_stroke_hint = None
            self._wp_canvas = None
            
            try:
                from app.widgets.stroke_order_widget import StrokeOrderWidget
                from dictionary.stroke_order import has_stroke_data
                
                if has_stroke_data(current_char):
                    # ── Set up a RelativeLayout stack from the start ──
                    # The StrokeOrderWidget lives inside it during animation.
                    # After animation we dim it with opacity and layer the
                    # HandwritingCanvas on top — zero canvas.clear() calls.
                    from kivy.uix.relativelayout import RelativeLayout
                    stack = RelativeLayout(size_hint=(1, 1))
                    canvas_container.add_widget(stack)
                    self._wp_stack = stack
                    
                    # Create stroke order widget inside the stack
                    sow = StrokeOrderWidget(
                        size_hint=(1, 1),
                        show_numbers=True
                    )
                    self._wp_stroke_widget = sow
                    self._wp_anim_done = False
                    stack.add_widget(sow)
                    
                    # Set the kanji (triggers load)
                    sow.kanji = current_char
                    
                    # Calculate stroke count
                    stroke_count = len(sow.stroke_data['strokes']) if sow.stroke_data else 6
                    stroke_dur = 0.55
                    
                    # ── Completion callback ────────────────────────────
                    # Called by on_stroke_changed after the LAST stroke
                    # finishes.  This replaces the old timed schedule, so
                    # we never fire before the animation is really done.
                    def _on_animation_done():
                        """Convert sow to hint in-place after anim finishes."""
                        if self._wp_anim_done:
                            return
                        self._wp_anim_done = True
                        
                        _sow = self._wp_stroke_widget
                        _stk = getattr(self, '_wp_stack', None)
                        if not _sow or not _stk:
                            return
                        
                        # Freeze the widget: unbind size/pos so nothing can
                        # trigger canvas.clear() + redraw ever again.
                        _sow.unbind(size=_sow.redraw, pos=_sow.redraw)
                        _sow.on_stroke_changed = None
                        
                        # Dim to show as a subtle trace guide.
                        # This does NOT call canvas.clear() — it's a GPU
                        # opacity blend, so strokes can't go missing.
                        _sow.opacity = 0.40
                        
                        self._wp_stroke_hint = _sow
                        self._wp_stroke_widget = None
                        
                        # Layer HandwritingCanvas on top
                        try:
                            from handwriting_canvas import HandwritingCanvas
                            hw_canvas = HandwritingCanvas(
                                size_hint=(1, 1),
                                transparent_bg=True
                            )
                            _stk.add_widget(hw_canvas)
                            self._wp_canvas = hw_canvas
                        except Exception as e:
                            Logger.error(f'WritingPractice: canvas error: {e}')
                    
                    def _stroke_changed_cb():
                        """Fires after each stroke; trigger hint conversion
                        once all strokes are complete."""
                        _s = self._wp_stroke_widget
                        if _s and _s.stroke_data and \
                           _s.current_stroke >= len(_s.stroke_data['strokes']):
                            # Use schedule_once so we run outside the
                            # animation tick (avoids reentrancy issues).
                            Clock.schedule_once(lambda dt: _on_animation_done(), 0)
                    
                    sow.on_stroke_changed = _stroke_changed_cb
                    
                    # Show all strokes immediately, then animate
                    def start_animation(dt):
                        if self._wp_stroke_widget:
                            self._wp_stroke_widget.show_all_strokes()
                            def animate(dt2):
                                if self._wp_stroke_widget:
                                    self._wp_stroke_widget.clear()
                                    self._wp_stroke_widget.animate_strokes(stroke_dur)
                            Clock.schedule_once(animate, 0.3)
                    Clock.schedule_once(start_animation, 0.1)
                else:
                    # No stroke data - just show canvas immediately
                    from handwriting_canvas import HandwritingCanvas
                    hw_canvas = HandwritingCanvas(size_hint=(1, 1))
                    canvas_container.add_widget(hw_canvas)
                    self._wp_canvas = hw_canvas
                    
            except Exception as e:
                Logger.error(f'WritingPractice: Error setting up practice: {e}')
                import traceback
                traceback.print_exc()
                # Fallback: just show canvas
                try:
                    from handwriting_canvas import HandwritingCanvas
                    canvas_container.clear_widgets()
                    hw_canvas = HandwritingCanvas(size_hint=(1, 1))
                    canvas_container.add_widget(hw_canvas)
                    self._wp_canvas = hw_canvas
                except:
                    pass

        # Update check button text
        check_btn = self.root.ids.get('wp_check_btn')
        if check_btn:
            check_btn.text = 'Check'
            check_btn.background_color = (0.25, 0.35, 0.50, 1)

        # Reset reveal state
        self._wp_revealed = False

    def on_writing_practice_check(self):
        """Check the user's handwriting attempt."""
        # Check the handwriting
        canvas = getattr(self, '_wp_canvas', None)
        if not canvas:
            return

        strokes = canvas.get_strokes()
        if not strokes or len(strokes) == 0:
            feedback = self.root.ids.get('wp_feedback')
            if feedback:
                feedback.text = 'Please write something first!'
                feedback.color = (0.75, 0.55, 0.40, 1)
            return

        # Use async recognition with loading overlay for first init
        def handle_recognition_result(results):
            self._process_writing_practice_recognition(results)
        
        self._recognize_with_loading(strokes, 40, handle_recognition_result)
    
    def _process_writing_practice_recognition(self, results):
        """Process recognition results for writing practice (called after recognition completes)."""
        try:
            current_char = self._wp_characters[self._wp_char_index]
            required = getattr(self, '_wp_required_correct', 3)
            canvas = getattr(self, '_wp_canvas', None)

            # Handle no results
            if not results:
                feedback = self.root.ids.get('wp_feedback')
                if feedback:
                    feedback.text = 'Could not recognize. Try again.'
                    feedback.color = (0.75, 0.55, 0.40, 1)
                if canvas:
                    canvas.clear_canvas()
                return

            # Check if correct
            is_correct = False
            for candidate, score in results:
                if candidate == current_char:
                    is_correct = True
                    break

            feedback = self.root.ids.get('wp_feedback')
            if is_correct:
                # Update wp_question to show this character green BEFORE we
                # advance (fixes: last char stays as '_' instead of showing).
                _char_index = getattr(self, '_wp_char_index', 0)
                _characters = getattr(self, '_wp_characters', [])
                question = self.root.ids.get('wp_question')
                if question:
                    _blanks = []
                    for _i, _ch in enumerate(_characters):
                        if _i <= _char_index:
                            _blanks.append(f'[color=60ff60]{_ch}[/color]')
                        else:
                            _blanks.append('_')
                    question.text = ' '.join(_blanks)
                    question.markup = True

                _rounds_done = getattr(self, '_wp_rounds_done', 0)
                _req_rounds = getattr(self, '_wp_required_rounds', 3)
                if feedback:
                    feedback.text = f'Correct! (Round {_rounds_done + 1}/{_req_rounds})'
                    feedback.color = (0.40, 0.75, 0.40, 1)

                from kivy.clock import Clock

                # Play TTS when the last character of the word is correct
                if self.auto_tts and _char_index == len(_characters) - 1:
                    card = getattr(self, '_wp_card', None)
                    if card:
                        tts_text = card.get('kana') or card.get('kanji') or ''
                        if tts_text:
                            Clock.schedule_once(lambda dt, t=tts_text: self.speak_text(t), 0.15)

                Clock.schedule_once(lambda dt: self._advance_to_next_practice_char(), 0.5)
            else:
                top_guess = results[0][0] if results else '?'
                if feedback:
                    feedback.text = f'Try again (saw "{top_guess}")'
                    feedback.color = (0.75, 0.55, 0.40, 1)
                canvas.clear_canvas()

        except Exception as e:
            Logger.error(f'WritingPractice: Recognition error: {e}')
            feedback = self.root.ids.get('wp_feedback')
            if feedback:
                feedback.text = 'Error checking - try again'
                feedback.color = (0.75, 0.55, 0.40, 1)

    def on_writing_practice_undo(self):
        """Undo the last stroke on the handwriting canvas."""
        canvas = getattr(self, '_wp_canvas', None)
        if canvas and hasattr(canvas, 'undo_stroke'):
            canvas.undo_stroke()
        feedback = self.root.ids.get('wp_feedback')
        if feedback:
            feedback.text = ''

    def on_writing_practice_reveal(self):
        """Reveal the stroke order animation for the current character.
        
        Uses the same freeze-and-dim approach as the initial prompt:
        animate strokes, then freeze the widget at 40% opacity as a
        persistent trace guide with all strokes visible.
        """
        from kivy.clock import Clock
        
        characters = getattr(self, '_wp_characters', [])
        char_index = getattr(self, '_wp_char_index', 0)
        if char_index >= len(characters):
            return
        
        current_char = characters[char_index]
        canvas_container = self.root.ids.get('wp_handwriting_container')
        
        if not canvas_container:
            return
        
        # Clean up existing widgets
        canvas_container.clear_widgets()
        self._wp_canvas = None
        self._wp_stroke_hint = None
        self._wp_stroke_widget = None
        
        try:
            from app.widgets.stroke_order_widget import StrokeOrderWidget
            from dictionary.stroke_order import has_stroke_data
            
            if has_stroke_data(current_char):
                from kivy.uix.relativelayout import RelativeLayout
                stack = RelativeLayout(size_hint=(1, 1))
                canvas_container.add_widget(stack)
                self._wp_stack = stack
                
                sow = StrokeOrderWidget(
                    size_hint=(1, 1),
                    show_numbers=True
                )
                self._wp_stroke_widget = sow
                self._wp_anim_done = False
                stack.add_widget(sow)
                
                sow.kanji = current_char
                
                stroke_count = len(sow.stroke_data['strokes']) if sow.stroke_data else 6
                reveal_stroke_dur = 0.55
                
                def _on_reveal_anim_done():
                    """Freeze stroke widget as trace guide after animation."""
                    if self._wp_anim_done:
                        return
                    self._wp_anim_done = True
                    
                    _sow = self._wp_stroke_widget
                    _stk = getattr(self, '_wp_stack', None)
                    if not _sow or not _stk:
                        return
                    
                    _sow.unbind(size=_sow.redraw, pos=_sow.redraw)
                    _sow.on_stroke_changed = None
                    _sow.opacity = 0.40
                    
                    self._wp_stroke_hint = _sow
                    self._wp_stroke_widget = None
                    
                    try:
                        from handwriting_canvas import HandwritingCanvas
                        hw_canvas = HandwritingCanvas(
                            size_hint=(1, 1),
                            transparent_bg=True
                        )
                        _stk.add_widget(hw_canvas)
                        self._wp_canvas = hw_canvas
                    except Exception as e:
                        Logger.error(f'WritingPractice: reveal canvas error: {e}')
                
                def _reveal_stroke_changed_cb():
                    _s = self._wp_stroke_widget
                    if _s and _s.stroke_data and \
                       _s.current_stroke >= len(_s.stroke_data['strokes']):
                        Clock.schedule_once(lambda dt: _on_reveal_anim_done(), 0)
                
                sow.on_stroke_changed = _reveal_stroke_changed_cb
                
                def start_animation(dt):
                    if self._wp_stroke_widget:
                        self._wp_stroke_widget.show_all_strokes()
                        def animate(dt2):
                            if self._wp_stroke_widget:
                                self._wp_stroke_widget.clear()
                                self._wp_stroke_widget.animate_strokes(reveal_stroke_dur)
                        Clock.schedule_once(animate, 0.3)
                Clock.schedule_once(start_animation, 0.1)
                
        except Exception as e:
            Logger.error(f'WritingPractice: Error revealing strokes: {e}')
        
        feedback = self.root.ids.get('wp_feedback')
        if feedback:
            feedback.text = 'Showing stroke order...'
            feedback.color = (0.55, 0.55, 0.65, 1)

    def on_writing_practice_back(self):
        """Go back to the previous character or exit writing practice."""
        char_index = getattr(self, '_wp_char_index', 0)
        
        if char_index > 0:
            # Go back to previous character
            self._wp_char_index = char_index - 1
            self._wp_correct_count = 0
            self._show_writing_practice()
        else:
            # At first character — go back to info card
            self._hide_writing_practice()
            # Show info card overlay again
            info_overlay = self.root.ids.get('info_card_overlay')
            if info_overlay:
                info_overlay.opacity = 1
                info_overlay.disabled = False
                info_overlay.size_hint = (1, 1)

    def on_writing_practice_skip(self):
        """Skip this character and move to the next one."""
        self._advance_to_next_practice_char()

    def _advance_to_next_practice_char(self):
        """Move to the next character, or start the next round, or finish practice."""
        characters = getattr(self, '_wp_characters', [])
        char_index = getattr(self, '_wp_char_index', 0)

        self._wp_char_index = char_index + 1

        if self._wp_char_index >= len(characters):
            # Finished one full pass through all characters.
            rounds_done = getattr(self, '_wp_rounds_done', 0) + 1
            self._wp_rounds_done = rounds_done
            required_rounds = getattr(self, '_wp_required_rounds', 3)

            if rounds_done >= required_rounds:
                # All rounds complete — open keyboard behind overlay, then advance.
                self._pre_open_keyboard_then(self._hide_writing_practice,
                                             self._advance_info_card_index)
            else:
                # Start next round from character 0.
                self._wp_char_index = 0
                self._show_writing_practice()
        else:
            self._show_writing_practice()

    def on_writing_practice_move_on(self):
        """Skip remaining writing practice and move to next info card / drill."""
        # Same keyboard-pre-open strategy as _advance_to_next_practice_char.
        self._pre_open_keyboard_then(self._hide_writing_practice,
                                     self._advance_info_card_index)

    def _hide_writing_practice(self):
        """Hide the writing practice overlay and clean up."""
        # Clean up canvas
        if hasattr(self, '_wp_canvas'):
            self._wp_canvas = None
        
        # Clean up stroke hint (bindings already removed; just drop the ref)
        if hasattr(self, '_wp_stroke_hint'):
            self._wp_stroke_hint = None
        
        # Clean up stroke widget
        if hasattr(self, '_wp_stroke_widget'):
            if self._wp_stroke_widget:
                self._wp_stroke_widget.stop_animation()
            self._wp_stroke_widget = None

        wp_overlay = self.root.ids.get('writing_practice_overlay')
        if wp_overlay:
            wp_overlay.opacity = 0
            wp_overlay.disabled = True
            wp_overlay.size_hint = (0, 0)

        # Restore containers that _show_writing_practice hid.
        # Without this, leaving the drill while writing practice is active
        # leaves drill_main_container invisible/disabled, corrupting the UI.
        drill_main = self.root.ids.get('drill_main_container')
        if drill_main:
            drill_main.opacity = 1
            drill_main.disabled = False

        info_overlay = self.root.ids.get('info_card_overlay')
        if info_overlay:
            info_overlay.opacity = 0
            info_overlay.disabled = True
            info_overlay.size_hint = (0, 0)

        # Clear top-bar practice counter
        self.writing_practice_active = False
        self.writing_practice_counter_text = ''

        # Clear handwriting container
        canvas_container = self.root.ids.get('wp_handwriting_container')
        if canvas_container:
            canvas_container.clear_widgets()

    def _pre_open_keyboard_then(self, *callbacks, min_delay=0):
        """Open the drill keyboard while the current overlay is still visible.

        Peeks at the next drill vector.  If it's a typing vector AND the
        keyboard is currently closed, focus drill_input NOW (while the overlay
        is still covering the screen) so that adjustResize fires behind the
        opaque overlay — invisible to the user — then after 280 ms run the
        callbacks.  By the time _load_current_drill runs, focus is already
        True, so it takes the zero-delay immediate-reveal path.

        If the next vector is a handwriting drill (or we can't determine it),
        the keyboard must NOT be raised; just run callbacks immediately so the
        handwriting UI can appear without a stray keyboard opening.
        """
        from kivy.clock import Clock
        import dictionary.learning as learning

        # Peek at the next drill to decide whether we need the keyboard.
        next_is_typing = False
        try:
            if hasattr(self, '_current_drill_session_id'):
                conn = dict_db.init_db(get_db_path())
                next_vec = learning.get_next_vector(conn, self._current_drill_session_id)
                conn.close()
                if next_vec and next_vec.get('vector_type', '') != 'handwriting':
                    next_is_typing = True
        except Exception:
            pass  # Can't peek — don't open keyboard, safe fallback

        def _run_callbacks(dt):
            for cb in callbacks:
                cb()

        _ti = self.root.ids.get('drill_input')
        if next_is_typing and _ti and not _ti.focus:
            # Pre-open keyboard behind the overlay, reveal after it settles.
            # Use whichever is larger: the keyboard settle time or the caller's
            # requested minimum (e.g. to keep feedback visible long enough).
            _ti.focus = True
            Clock.schedule_once(_run_callbacks, max(0.28, min_delay))
        else:
            # Next drill is handwriting (or unknown) — don't open keyboard.
            # Still honour min_delay so feedback stays visible before advancing.
            if min_delay > 0:
                Clock.schedule_once(_run_callbacks, min_delay)
            else:
                _run_callbacks(0)

    def on_drill_input_text(self, instance, value):
        """Handle text input changes for IME conversion during drills."""
        try:
            # Only convert if IME mode is active
            ime_mode = getattr(self, '_drill_ime_mode', None)
            if not ime_mode or instance.readonly:
                return
            
            # Grammar kanji IME: convert romaji and show kanji from expected answer
            if ime_mode == 'grammar_kanji':
                if getattr(self, '_grammar_ime_updating', False):
                    return
                import re
                segments = getattr(self, '_grammar_kanji_segments', [])
                match = re.search(r'[a-zA-Z]+$', value)
                if match:
                    romaji_suffix = match.group()
                    prefix = value[:match.start()]
                    converted_suffix = dict_db._romaji_to_hiragana(romaji_suffix)
                    if not converted_suffix:
                        return
                    prefix_reading = self._display_to_reading(prefix, segments)
                    full_reading = prefix_reading + converted_suffix
                else:
                    if not value:
                        return
                    full_reading = self._display_to_reading(value, segments)
                display = self._reading_to_kanji_display(full_reading, segments)
                if display != value:
                    self._grammar_ime_updating = True
                    instance.text = display
                    try:
                        instance.cursor = (len(display), 0)
                    except:
                        pass
                    self._grammar_ime_updating = False
                return
            
            # Get current cursor position
            cursor_pos = instance.cursor_index()
            
            # For katakana mode, convert "-" to "ー" (long vowel mark)
            if ime_mode == 'katakana' and '-' in value:
                new_text = value.replace('-', 'ー')
                if new_text != value:
                    instance.text = new_text
                    try:
                        instance.cursor = (len(new_text), 0)
                    except:
                        pass
                    return
            
            # Find the romaji suffix (contiguous ASCII letters at the end)
            import re
            match = re.search(r'[a-zA-Z]+$', value)
            if not match:
                # No romaji to convert, but still promote hyphen→ー for grammar
                grammar_answer = getattr(self, '_grammar_expected_answer', '')
                if grammar_answer and '-' in value:
                    promoted = self._promote_grammar_katakana(value, grammar_answer)
                    if promoted != value:
                        instance.text = promoted
                        try:
                            instance.cursor = (len(promoted), 0)
                        except:
                            pass
                return
            
            romaji_suffix = match.group()
            suffix_start = match.start()
            prefix = value[:suffix_start]
            
            # Convert romaji suffix to kana
            if ime_mode == 'hiragana':
                converted_suffix = dict_db._romaji_to_hiragana(romaji_suffix)
            elif ime_mode == 'katakana':
                hira = dict_db._romaji_to_hiragana(romaji_suffix)
                converted_suffix = dict_db._hiragana_to_katakana(hira) if hira else None
            else:
                return
            
            # Update text if conversion succeeded
            if converted_suffix:
                new_text = prefix + converted_suffix
                # Auto-promote hiragana to katakana for grammar exercises
                grammar_answer = getattr(self, '_grammar_expected_answer', '')
                if grammar_answer:
                    new_text = self._promote_grammar_katakana(new_text, grammar_answer)
                instance.text = new_text
                # Move cursor to end
                try:
                    instance.cursor = (len(new_text), 0)
                except:
                    pass
        except Exception as e:
            Logger.error(f'Drill: Error in IME conversion: {e}')

    def _load_handwriting_drill(self, vector):
        """Load a handwriting drill vector into the UI."""
        try:
            # Fix old vectors missing characters/reading/prompt data
            if not vector.get('characters') or vector.get('reading') is None or not vector.get('prompt'):
                Logger.info(f'Drill HW: Regenerating missing handwriting data for entry {vector.get("entry_id")}')
                # Query entry from database
                conn = dict_db.init_db(get_db_path())
                c = conn.cursor()
                c.execute('SELECT kanji, kana, gloss, kind FROM entries WHERE id = ?', (vector.get('entry_id'),))
                row = c.fetchone()
                if row:
                    kanji, kana, gloss, kind = row
                    # Regenerate handwriting data
                    import dictionary.handwriting_drill as handwriting_drill
                    entry_dict = {'id': vector.get('entry_id'), 'kind': kind, 'kanji': kanji, 'kana': kana, 'gloss': gloss}
                    hw_vector = handwriting_drill.create_handwriting_vector(entry_dict)
                    # Update vector with missing fields (including kind for old vectors)
                    vector['characters'] = hw_vector.get('characters', [])
                    vector['reading'] = hw_vector.get('reading', '')
                    vector['kind'] = hw_vector.get('kind', kind)  # Update kind from entry
                    if hw_vector.get('prompt'):
                        vector['prompt'] = hw_vector.get('prompt', '')
                    Logger.info(f'Drill HW: Regenerated - kind={vector["kind"]}, characters={vector["characters"]}, prompt={repr(vector.get("prompt", "")[:60])}')
                conn.close()
            
            # Also fix old vectors that have wrong kind (e.g., 'vocab' instead of 'kanji')
            # This handles vectors that weren't regenerated above
            if vector.get('kind') != 'kanji':
                entry_id = vector.get('entry_id')
                if entry_id:
                    conn = dict_db.init_db(get_db_path())
                    c = conn.cursor()
                    c.execute('SELECT kind FROM entries WHERE id = ?', (entry_id,))
                    row = c.fetchone()
                    if row and row[0] == 'kanji':
                        vector['kind'] = 'kanji'
                        Logger.info(f'Drill HW: Fixed kind field for entry {entry_id} to kanji')
                    conn.close()
            
            # Initialize or reset character tracking only if needed
            characters = vector.get('characters', [])
            current_idx = vector.get('current_char_index', 0)
            char_results = vector.get('char_results', [])
            
            # Reset if this is a fresh attempt (not in progress)
            # Fresh = no char_results OR current_idx >= total characters (completed)
            if not char_results or current_idx >= len(characters):
                vector['current_char_index'] = 0
                vector['char_results'] = []
                Logger.info(f'Drill HW: Reset tracking for fresh attempt')
            else:
                Logger.info(f'Drill HW: Continuing in progress - char {current_idx}/{len(characters)}, results: {char_results}')
            
            # Get UI elements
            prompt_label = self.root.ids.get('drill_prompt')
            question_label = self.root.ids.get('drill_question')
            text_input = self.root.ids.get('drill_input')
            handwriting_container = self.root.ids.get('drill_handwriting_container')

            # Always dismiss the soft keyboard when entering handwriting mode,
            # regardless of call path (direct call for next char bypasses the
            # text_input.focus = False in _load_current_drill).
            if text_input and text_input.focus:
                text_input.focus = False
            
            # Get normal buttons (hide these)
            submit_btn = self.root.ids.get('drill_submit_btn')
            reveal_btn = self.root.ids.get('drill_reveal_btn')
            undo_btn = self.root.ids.get('drill_undo_btn')
            
            # Get handwriting submit button for text updates
            hw_submit = self.root.ids.get('drill_hw_submit')
            
            streak_label = self.root.ids.get('drill_streak_label')
            feedback_label = self.root.ids.get('drill_feedback')
            
            # Clear feedback from previous attempt
            if feedback_label:
                feedback_label.text = ''
            
            # Build fill-in-the-blank display
            characters = vector.get('characters', [])
            current_idx = vector.get('current_char_index', 0)
            char_results = vector.get('char_results', [])
            
            # Create display: [見][_] for 見る where first is done, second is current
            blanks = []
            for i, char in enumerate(characters):
                if i < len(char_results):
                    # Already filled in
                    blanks.append(f'[color=60ff60]{char}[/color]' if char_results[i] else f'[color=ff6060]{char}[/color]')
                elif i == current_idx:
                    # Current blank to fill
                    blanks.append('[b]_[/b]')
                else:
                    # Future blank
                    blanks.append('_')
            
            display_text = ' '.join(blanks)
            
            # Set question (fill-in-the-blank display) - blanks at top
            if question_label:
                question_label.text = display_text
                question_label.markup = True
            
            # Set prompt text (pronunciation) - middle, bigger for handwriting
            # For kana-only entries, hide reading (would reveal answer)
            if prompt_label:
                reading = vector.get('reading', '')
                answer = vector.get('answer', '')
                
                # Check if answer contains any kanji characters
                has_kanji = any('\u4e00' <= c <= '\u9fff' for c in answer)
                
                if not has_kanji:
                    # Hide reading for kana-only entries (would give away answer)
                    prompt_label.text = ''
                    prompt_label.height = 0
                    prompt_label.opacity = 0
                else:
                    # Show reading for entries with kanji
                    # Format kanji readings to show only on'yomi and kun'yomi
                    if vector.get('kind') == 'kanji':
                        original_reading = reading
                        reading = self._format_kanji_readings(reading)
                        Logger.info(f'Drill HW: Formatted kanji reading - original={repr(original_reading[:80])}, formatted={repr(reading)}')
                        
                        # Make label clickable to toggle full/truncated view if truncated
                        if self._kanji_readings_truncated:
                            # Unbind any existing handlers first
                            prompt_label.unbind(on_touch_down=self._toggle_kanji_readings)
                            prompt_label.bind(on_touch_down=self._toggle_kanji_readings)
                    
                    prompt_label.text = reading
                    prompt_label.markup = True
                    prompt_label.font_size = '16sp'
                    prompt_label.opacity = 1
                    # Enable text wrapping to prevent bleeding off screen
                    from kivy.metrics import dp
                    prompt_label.size_hint_y = None
                    prompt_label.height = dp(36)  # Min height, will expand if needed
                    prompt_label.text_size = (prompt_label.width, None)
                    prompt_label.halign = 'center'
                    prompt_label.valign = 'middle'
                    # Bind width to update text_size for proper wrapping
                    prompt_label.bind(width=lambda instance, value: setattr(instance, 'text_size', (value, None)))
            
            # Show definition below pronunciation (above canvas)
            from kivy.metrics import dp
            hw_def_label = self.root.ids.get('drill_hw_definition')
            if hw_def_label:
                definition = vector.get('prompt', '')
                # Fallback: fetch definition directly from DB if still empty
                if not definition and vector.get('entry_id'):
                    try:
                        _conn = dict_db.init_db(get_db_path())
                        _c = _conn.cursor()
                        _c.execute('SELECT gloss FROM entries WHERE id = ?', (vector.get('entry_id'),))
                        _row = _c.fetchone()
                        _conn.close()
                        if _row and _row[0]:
                            definition = _row[0].split(';')[0].strip()
                            vector['prompt'] = definition  # cache it
                    except Exception:
                        pass
                hw_def_label.text = definition
                # Use larger font when definition is the only clue (kana entries with no reading shown)
                reading_visible = prompt_label and prompt_label.opacity > 0 and prompt_label.text
                if not reading_visible:
                    hw_def_label.font_size = '16sp'
                    hw_def_label.height = dp(26)
                else:
                    hw_def_label.font_size = '13sp'
                    hw_def_label.height = dp(22)
                hw_def_label.opacity = 1
            
            # Hide text input, show handwriting canvas
            if text_input:
                text_input.opacity = 0
                text_input.height = 0
                text_input.size_hint_y = None
            
            # Hide normal button row
            normal_btn_row = self.root.ids.get('drill_normal_button_row')
            if normal_btn_row:
                normal_btn_row.height = 0
                normal_btn_row.opacity = 0
            
            # Show handwriting button rows
            hw_button_row = self.root.ids.get('drill_hw_button_row')
            if hw_button_row:
                from kivy.metrics import dp
                hw_button_row.height = dp(40)
                hw_button_row.opacity = 1
            
            hw_check_row = self.root.ids.get('drill_hw_check_row')
            if hw_check_row:
                from kivy.metrics import dp
                hw_check_row.height = dp(40)
                hw_check_row.opacity = 1
            
            # Reset submit button text and state
            if hw_submit:
                hw_submit.text = 'Check'
                hw_submit.background_color = (0.25, 0.35, 0.50, 1)
            
            # Reset revealed flag and waiting states
            vector['_hw_revealed'] = False
            self._drill_waiting_continue = False
            
            # Clean up stroke order widget if it was active
            self._cleanup_drill_stroke_order()
            # Reset reveal confirm state
            self._drill_hw_reveal_confirm = False
            
            # Shrink top spacer and center content for handwriting
            top_spacer = self.root.ids.get('drill_top_spacer')
            if top_spacer:
                top_spacer.size_hint_y = None
                top_spacer.height = 0
            # Collapse the inner spacer so the handwriting canvas fills from the top
            inner_sp = self.root.ids.get('drill_inner_spacer')
            if inner_sp:
                inner_sp.size_hint_y = None
                inner_sp.height = 0
            # Hide the counter row — its labels sit too close to drill_bottom_section
            # labels and cause visual overlap on small screens.
            counter_row = self.root.ids.get('drill_counter_row')
            if counter_row:
                counter_row.height = 0
                counter_row.opacity = 0
            bottom_section = self.root.ids.get('drill_bottom_section')
            if bottom_section:
                bottom_section.size_hint_y = 1
                bottom_section.spacing = dp(4)
                bottom_section.padding = [dp(4), dp(6), dp(4), dp(56)]
                bottom_section.size_hint_x = 0.92
                bottom_section.pos_hint = {'center_x': 0.5}
            # Keep centering spacers collapsed — canvas flex handles space
            hw_top_sp = self.root.ids.get('drill_hw_top_spacer')
            if hw_top_sp:
                hw_top_sp.size_hint_y = None
                hw_top_sp.height = 0
            hw_bot_sp = self.root.ids.get('drill_hw_bottom_spacer')
            if hw_bot_sp:
                hw_bot_sp.size_hint_y = None
                hw_bot_sp.height = 0
            
            # Show progress counter for handwriting mode (same as regular drills)
            drill_counter = self.root.ids.get('drill_counter')
            drill_progress = self.root.ids.get('drill_progress_text')
            if drill_counter and not self.hide_review_counter:
                drill_counter.opacity = 1
                drill_counter.height = dp(18)
                # Update counter values
                completed = getattr(self, '_drill_completed_count', 0)
                try:
                    conn_hw = dict_db.init_db(get_db_path())
                    session = dict_db.get_learning_session(conn_hw, self._current_drill_session_id)
                    total = session['data']['meta'].get('total_vectors', 0)
                    drill_counter.text = f'{completed} / {total}'
                    conn_hw.close()
                except Exception:
                    pass
            elif drill_counter and self.hide_review_counter:
                drill_counter.opacity = 0
                drill_counter.height = 0
            if drill_progress and not self.hide_review_counter:
                drill_progress.opacity = 1
                drill_progress.height = dp(16)
                try:
                    conn_hw2 = dict_db.init_db(get_db_path())
                    session2 = dict_db.get_learning_session(conn_hw2, self._current_drill_session_id)
                    active = len(session2['data'].get('in_progress', []))
                    drill_progress.text = f'{active} active'
                    conn_hw2.close()
                except Exception:
                    pass
            elif drill_progress and self.hide_review_counter:
                drill_progress.opacity = 0
                drill_progress.height = 0
            
            # Show streak counter (same as regular drill mode)
            if streak_label and not self.hide_review_counter:
                current_streak = vector.get('streak', 0)
                streak_label.text = f'Streak: {current_streak}/3'
                streak_label.color = (0.15, 0.45, 0.65, 1)
                streak_label.opacity = 1
                streak_label.height = dp(20)
            elif streak_label and self.hide_review_counter:
                # Hide streak counter if setting is enabled
                streak_label.opacity = 0
                streak_label.height = 0
            
            # Clear feedback text from previous vector
            if feedback_label:
                feedback_label.text = ''
            
            if handwriting_container:
                from kivy.metrics import dp
                from kivy.clock import Clock

                # If we already capped the canvas height for this word, reuse the
                # cached value immediately — avoids the 120 ms deferred reflow that
                # causes flickering when moving between characters in the same word.
                cached_h = getattr(self, '_drill_hw_capped_height', None)
                if cached_h is not None:
                    handwriting_container.size_hint_y = None
                    handwriting_container.height = cached_h
                else:
                    # First character: flex-fill then cap once layout has settled.
                    handwriting_container.size_hint_y = 1
                    def cap_canvas_height(dt):
                        if not handwriting_container or not bottom_section:
                            return
                        max_h = bottom_section.width
                        if handwriting_container.height > max_h:
                            handwriting_container.size_hint_y = None
                            handwriting_container.height = max_h
                        # Cache so subsequent characters skip this deferred step.
                        self._drill_hw_capped_height = handwriting_container.height
                    Clock.schedule_once(cap_canvas_height, 0.12)

                handwriting_container.opacity = 1

                # Create or get handwriting canvas
                if not hasattr(self, '_drill_handwriting_canvas'):
                    from handwriting_canvas import HandwritingCanvas
                    self._drill_handwriting_canvas = HandwritingCanvas(
                        size_hint=(1, 1)
                    )
                    handwriting_container.clear_widgets()
                    handwriting_container.add_widget(self._drill_handwriting_canvas)
                else:
                    # Clear existing canvas
                    self._drill_handwriting_canvas.clear_canvas()
                    # Re-enable canvas (in case it was disabled after incorrect answer)
                    self._drill_handwriting_canvas.disabled = False
                    # Make sure it's added to the container
                    if self._drill_handwriting_canvas.parent != handwriting_container:
                        handwriting_container.clear_widgets()
                        handwriting_container.add_widget(self._drill_handwriting_canvas)
                
                # Warm up recognizer in background (non-blocking)
                self._prewarm_recognizer_silent()
            
            # Reset flags
            self._drill_reveal_confirm = False
            self._drill_undo_confirm = False
            self._drill_revealed = False
            self._drill_waiting_continue = False
            
            # Re-enable back button (in case it was disabled after incorrect answer)
            back_btn = self.root.ids.get('drill_hw_back')
            if back_btn:
                back_btn.disabled = False
                back_btn.opacity = 1.0

            # Reveal the drill container now that all HW widgets are configured.
            # _load_current_drill hid it at the top to prevent stale-content flash.
            _dm_hw = self.root.ids.get('drill_main_container')
            if _dm_hw:
                _dm_hw.opacity = 1
            _tb_hw = self.root.ids.get('global_top_bar')
            if _tb_hw:
                _tb_hw.opacity = 1

            # Force layout update to ensure canvas is visible
            from kivy.clock import Clock
            def force_update(dt):
                if handwriting_container:
                    handwriting_container.do_layout()
            Clock.schedule_once(force_update, 0.1)
            
        except Exception as e:
            Logger.error(f'Drill: Error loading handwriting drill: {e}')
            import traceback
            traceback.print_exc()

    def on_drill_handwriting_submit(self):
        """Handle handwriting drill submission."""
        try:
            Logger.info('Drill: Handwriting submit called')
            
            if not hasattr(self, '_current_drill_vector') or not self._current_drill_vector:
                Logger.error('Drill: No current vector')
                return
            
            vector = self._current_drill_vector
            
            # Check if we're waiting for continue (after showing answer)
            if getattr(self, '_drill_waiting_continue', False):
                Logger.info('Drill: Continue clicked - advancing')
                self._drill_waiting_continue = False
                
                # Reset button
                submit_btn = self.root.ids.get('drill_hw_submit')
                if submit_btn:
                    submit_btn.text = 'Check'
                    submit_btn.background_color = (0.25, 0.35, 0.50, 1)
                
                # Clear feedback
                feedback_label = self.root.ids.get('drill_feedback')
                if feedback_label:
                    feedback_label.text = ''
                
                # Clear and advance
                if hasattr(self, '_drill_handwriting_canvas'):
                    self._drill_handwriting_canvas.clear_canvas()
                self._pre_open_keyboard_then(self._load_current_drill)
                return
            
            # Check if this is Continue mode (after reveal)
            if vector.get('_hw_revealed', False):
                # Clean up stroke order widget if active
                self._cleanup_drill_stroke_order()
                
                # Mark as wrong and continue to next character
                if 'char_results' not in vector:
                    vector['char_results'] = []
                vector['char_results'].append(False)
                
                # Clear canvas
                if hasattr(self, '_drill_handwriting_canvas'):
                    self._drill_handwriting_canvas.clear_canvas()
                
                # Move to next character
                vector['current_char_index'] = vector.get('current_char_index', 0) + 1
                vector['_hw_revealed'] = False
                
                # Check if all characters are done
                if vector['current_char_index'] >= len(vector.get('characters', [])):
                    # All done
                    all_correct = all(vector['char_results'])
                    Logger.info(f'Drill: All characters done (after reveal). Results: {vector["char_results"]}, Overall: {all_correct}')
                    
                    answer = vector.get('answer', '')
                    
                    # Submit to learning system
                    conn = None
                    try:
                        conn = dict_db.init_db(get_db_path())
                        import dictionary.learning as learning
                        
                        result = learning.submit_vector_result(
                            conn,
                            self._current_drill_session_id,
                            vector['id'],
                            all_correct
                        )
                        
                        Logger.info(f'Drill: Submit result (reveal): {result}')
                        
                        # Update completed count
                        if not vector.get('is_filler', False):
                            self._drill_completed_count = getattr(self, '_drill_completed_count', 0) + 1
                            
                    except Exception as e:
                        Logger.error(f'Drill: Error submitting: {e}')
                    finally:
                        if conn:
                            conn.close()
                    
                    # Show feedback
                    feedback_label = self.root.ids.get('drill_feedback')
                    if feedback_label:
                        if all_correct:
                            feedback_label.text = f'✓ Correct! {answer}'
                            feedback_label.color = (0.20, 0.65, 0.30, 1)
                        else:
                            feedback_label.text = f'Answer: {answer}'
                            feedback_label.color = (0.85, 0.40, 0.35, 1)
                    
                    # Pre-open keyboard behind the HW UI while feedback is
                    # visible, then load — avoids adjustResize flash.
                    self._auto_tts_after_answer(vector)
                    self._pre_open_keyboard_then(self._load_current_drill)
                else:
                    # More characters
                    Logger.info(f'Drill: Continuing to next character after reveal')
                    self._load_handwriting_drill(vector)
                
                return
            
            # Get current character info
            characters = vector.get('characters', [])
            current_idx = vector.get('current_char_index', 0)
            
            if current_idx >= len(characters):
                Logger.error('Drill: Character index out of bounds')
                return
            
            expected_char = characters[current_idx]
            
            # Get strokes from canvas
            if not hasattr(self, '_drill_handwriting_canvas'):
                Logger.error('Drill: No handwriting canvas found')
                return
            
            strokes = self._drill_handwriting_canvas.get_strokes()
            Logger.info(f'Drill: Got {len(strokes)} strokes')
            
            if not strokes:
                Logger.info('Drill: No strokes drawn')
                feedback_label = self.root.ids.get('drill_feedback')
                if feedback_label:
                    feedback_label.text = 'Please draw something first'
                    feedback_label.color = (0.85, 0.40, 0.35, 1)
                return
            
            # Use async recognition with loading overlay for first init
            def handle_recognition_result(candidates):
                self._process_drill_handwriting_recognition(candidates, expected_char, characters, current_idx)
            
            self._recognize_with_loading(strokes, 40, handle_recognition_result)
            
        except Exception as e:
            Logger.error(f'Drill: Error in handwriting submission: {e}')
            import traceback
            traceback.print_exc()
    
    def _process_drill_handwriting_recognition(self, candidates, expected_char, characters, current_idx):
        """Process recognition results for drill handwriting (called after recognition completes)."""
        try:
            vector = self._current_drill_vector
            
            if not candidates:
                feedback_label = self.root.ids.get('drill_feedback')
                if feedback_label:
                    feedback_label.text = 'Could not recognize drawing. Try again.'
                    feedback_label.color = (0.85, 0.40, 0.35, 1)
                self._drill_handwriting_canvas.clear_canvas()
                return
            
            # Get top match
            drawn_char, confidence = candidates[0]
            
            # Grade the attempt - pass all candidates for lenient matching
            is_correct_char, feedback_msg = handwriting_drill.grade_handwriting_attempt(
                drawn_char, expected_char, confidence, all_candidates=candidates
            )
            
            Logger.info(f'Drill: Character {current_idx+1}/{len(characters)}: drew={drawn_char}, expected={expected_char}, conf={confidence:.2f}, correct={is_correct_char}')
            
            # Record result for this character
            if 'char_results' not in vector:
                vector['char_results'] = []
            vector['char_results'].append(is_correct_char)
            
            # Clear canvas for next character
            self._drill_handwriting_canvas.clear_canvas()
            
            # Move to next character
            vector['current_char_index'] = current_idx + 1
            
            # Check if all characters are done
            if vector['current_char_index'] >= len(characters):
                # All characters tested - determine overall result
                all_correct = all(vector['char_results'])
                
                Logger.info(f'Drill: All characters tested. Results: {vector["char_results"]}, Overall: {all_correct}')
                
                # Update question display to show all completed characters
                question_label = self.root.ids.get('drill_question')
                if question_label:
                    completed_chars = []
                    for i, char in enumerate(characters):
                        if vector['char_results'][i]:
                            completed_chars.append(f'[color=60ff60]{char}[/color]')
                        else:
                            completed_chars.append(f'[color=ff6060]{char}[/color]')
                    question_label.text = ' '.join(completed_chars)
                    question_label.markup = True
                
                is_correct = all_correct
                answer = vector.get('answer', '')
                
                # Submit to learning system
                conn = None
                result = {}
                try:
                    conn = dict_db.init_db(get_db_path())
                    import dictionary.learning as learning
                    
                    result = learning.submit_vector_result(
                        conn,
                        self._current_drill_session_id,
                        self._current_drill_vector['id'],
                        is_correct
                    )
                    
                    Logger.info(f'Drill: Submit result: {result}')
                    
                    # Track completion only when vector is promoted (finished 3 correct)
                    if result.get('status') == 'promoted':
                        if not self._current_drill_vector.get('is_filler', False):
                            self._drill_completed_count = getattr(self, '_drill_completed_count', 0) + 1
                            
                            # Track drilled vector ID for weak words and lesson drills
                            if self._drill_mode != 'tools_drill':
                                vector_id = f"{self._current_drill_vector['entry_id']}:{self._current_drill_vector['vector_type']}"
                                self._drilled_today.add(vector_id)
                                Logger.info(f'Drill: Added {vector_id} to drilled_today set')
                    
                except Exception as e:
                    Logger.error(f'Drill: Error submitting handwriting answer: {e}')
                    import traceback
                    traceback.print_exc()
                finally:
                    if conn:
                        conn.close()
                
                # Update UI with feedback
                feedback_label = self.root.ids.get('drill_feedback')
                streak_label = self.root.ids.get('drill_streak_label')
                
                # Check if this is a filler or already in SRS (these pass immediately)
                is_filler_or_already = result.get('status') in ('filler_pass', 'already_in_srs')
                
                # Update streak counter (but not for fillers)
                if streak_label and not is_filler_or_already and not self.hide_review_counter:
                    current_streak = self._current_drill_vector.get('streak', 0)
                    if is_correct:
                        new_streak = current_streak + 1
                        streak_label.text = f'Streak: {new_streak}/3'
                        streak_label.color = (0.20, 0.65, 0.30, 1)
                    else:
                        streak_label.text = f'Streak: 0/3'
                        streak_label.color = (0.85, 0.40, 0.35, 1)
                    # Reset to default color after 0.5 seconds
                    from kivy.clock import Clock
                    Clock.schedule_once(lambda dt: setattr(streak_label, 'color', (0.25, 0.35, 0.50, 1)), 0.5)
                
                if is_correct:
                    # Correct answer - show feedback
                    if feedback_label:
                        feedback_label.text = '✓ Correct!'
                        feedback_label.color = (0.20, 0.65, 0.30, 1)
                    
                    # Check if we need to show a new info card (progressive unlock)
                    from kivy.clock import Clock
                    self._auto_tts_after_answer(vector)
                    if result.get('show_next_info') and self._drill_mode == 'lesson':
                        Clock.schedule_once(lambda dt: self._show_progressive_unlock_card(), 0.5)
                    else:
                        # Pre-open keyboard behind the HW UI while feedback is
                        # visible, then load — avoids adjustResize flash.
                        # min_delay=0.28 keeps feedback visible whether next
                        # drill is typing or another handwriting question.
                        self._pre_open_keyboard_then(self._load_current_drill, min_delay=0.28)
                else:
                    # Wrong answer - show feedback and wait for Continue
                    if feedback_label:
                        max_length = 60
                        display_answer = answer
                        if len(answer) > max_length:
                            display_answer = answer[:max_length] + '...'
                        feedback_label.text = f'✗ Incorrect - Answer: {display_answer}'
                        feedback_label.color = (0.85, 0.40, 0.35, 1)
                    
                    # Set waiting flag and change button
                    self._drill_waiting_continue = True
                    self._auto_tts_after_answer(vector)
                    submit_btn = self.root.ids.get('drill_hw_submit')
                    if submit_btn:
                        submit_btn.text = 'Continue'
                        submit_btn.background_color = (0.15, 0.65, 0.15, 1)  # Green
                    
                    # Don't disable back button - user should be able to go back and retry if recognition was wrong
            else:
                # More characters to test - reload with next character
                Logger.info(f'Drill: Character done, moving to next ({vector["current_char_index"]}/{len(characters)})')
                self._load_handwriting_drill(vector)
            
        except Exception as e:
            Logger.error(f'Drill: Error processing handwriting recognition: {e}')
            import traceback
            traceback.print_exc()

    def _on_handwriting_drill_reveal(self):
        """Handle reveal for handwriting drills - show stroke order animation."""
        try:
            # If free-draw canvas is showing, reshow stroke order animation on Play
            if getattr(self, '_drill_free_draw_active', False):
                handwriting_container = self.root.ids.get('drill_handwriting_container')
                if handwriting_container and hasattr(self, '_drill_stroke_order_widget'):
                    handwriting_container.clear_widgets()
                    handwriting_container.add_widget(self._drill_stroke_order_widget)
                    self._drill_free_draw_active = False
                    self._drill_stroke_order_active = True
                    self._drill_stroke_order_widget.clear()
                    self._drill_stroke_order_widget.animate_strokes(0.44)
                    Logger.info('Drill: Reshowing stroke order from free-draw mode')
                return
            
            # If stroke order is already showing, act as "Play" button (replay)
            if getattr(self, '_drill_stroke_order_active', False):
                if hasattr(self, '_drill_stroke_order_widget'):
                    self._drill_stroke_order_widget.clear()
                    self._drill_stroke_order_widget.animate_strokes(0.44)
                    Logger.info('Drill: Replaying stroke order animation')
                return
            
            vector = self._current_drill_vector
            characters = vector.get('characters', [])
            current_idx = vector.get('current_char_index', 0)
            
            if current_idx >= len(characters):
                return
            
            # Two-click confirmation: first click turns button yellow
            reveal_btn = self.root.ids.get('drill_hw_reveal')
            if not getattr(self, '_drill_hw_reveal_confirm', False):
                self._drill_hw_reveal_confirm = True
                if reveal_btn:
                    reveal_btn.text = 'Reveal?'
                    reveal_btn.background_color = (0.68, 0.56, 0.15, 1)
                Logger.info('Drill HW: Reveal confirmation requested')
                return
            
            # Second click: perform the reveal
            self._drill_hw_reveal_confirm = False
            self._perform_drill_reveal()
            
        except Exception as e:
            Logger.error(f'Drill: Error in handwriting reveal: {e}')
    
    def _perform_drill_reveal(self):
        """Actually perform the drill reveal with stroke order animation."""
        try:
            vector = self._current_drill_vector
            characters = vector.get('characters', [])
            current_idx = vector.get('current_char_index', 0)
            
            if current_idx >= len(characters):
                return
            
            expected_char = characters[current_idx]
            
            # Mark as revealed (counts as wrong)
            vector['_hw_revealed'] = True
            
            # Update the display to show the character in red (wrong)
            question_label = self.root.ids.get('drill_question')
            if question_label:
                char_results = vector.get('char_results', [])
                blanks = []
                for i, char in enumerate(characters):
                    if i < len(char_results):
                        blanks.append(f'[color=60ff60]{char}[/color]' if char_results[i] else f'[color=ff6060]{char}[/color]')
                    elif i == current_idx:
                        blanks.append(f'[color=ff6060][b]{char}[/b][/color]')
                    else:
                        blanks.append('_')
                display_text = ' '.join(blanks)
                question_label.text = display_text
                question_label.markup = True
            
            # Replace handwriting canvas with stroke order widget
            handwriting_container = self.root.ids.get('drill_handwriting_container')
            if handwriting_container:
                from app.widgets.stroke_order_widget import StrokeOrderWidget
                
                # Remove canvas from container
                if hasattr(self, '_drill_handwriting_canvas') and self._drill_handwriting_canvas.parent == handwriting_container:
                    handwriting_container.remove_widget(self._drill_handwriting_canvas)
                
                # Create stroke order widget
                stroke_widget = StrokeOrderWidget(
                    size_hint=(1, 1),
                    show_numbers=True
                )
                handwriting_container.clear_widgets()
                handwriting_container.add_widget(stroke_widget)
                
                # Store reference and set kanji (triggers load)
                self._drill_stroke_order_widget = stroke_widget
                stroke_widget.kanji = expected_char
                
                # Show all strokes immediately (user can animate via Play)
                from kivy.clock import Clock
                Clock.schedule_once(lambda dt: stroke_widget.show_all_strokes(), 0.1)
                
                self._drill_stroke_order_active = True
            
            # Change button text: Reveal -> Play, Undo -> Erase
            reveal_btn = self.root.ids.get('drill_hw_reveal')
            if reveal_btn:
                reveal_btn.text = 'Play'
                reveal_btn.background_color = (0.25, 0.35, 0.50, 1)
            
            undo_btn = self.root.ids.get('drill_hw_undo')
            if undo_btn:
                undo_btn.text = 'Erase'
            
            # Update feedback
            feedback_label = self.root.ids.get('drill_feedback')
            if feedback_label:
                answer = vector.get('answer', '')
                feedback_label.text = f'Revealed: {expected_char} (from {answer})'
                feedback_label.color = (0.85, 0.70, 0.30, 1)
            
            # Change Check button to Continue
            submit_btn = self.root.ids.get('drill_hw_submit')
            if submit_btn:
                submit_btn.text = 'Continue'
                submit_btn.background_color = (0.20, 0.45, 0.25, 1)
            
            Logger.info(f'Drill: Revealed character with stroke order: {expected_char}')
        except Exception as e:
            Logger.error(f'Drill: Error performing drill reveal: {e}')
            import traceback
            traceback.print_exc()
    
    def _cleanup_drill_stroke_order(self):
        """Clean up stroke order widget after drill reveal, restoring button text."""
        # Reset confirm flag
        self._drill_hw_reveal_confirm = False
        if getattr(self, '_drill_stroke_order_active', False):
            # Stop animation
            if hasattr(self, '_drill_stroke_order_widget'):
                self._drill_stroke_order_widget.stop_animation()
            
            # Reset button text
            undo_btn = self.root.ids.get('drill_hw_undo')
            if undo_btn:
                undo_btn.text = 'Undo'
            reveal_btn = self.root.ids.get('drill_hw_reveal')
            if reveal_btn:
                reveal_btn.text = 'Reveal'
                reveal_btn.background_color = (0.60, 0.15, 0.20, 1)
            
            self._drill_stroke_order_active = False
            self._drill_free_draw_active = False
            self._drill_free_draw_canvas = None
            Logger.info('Drill: Cleaned up stroke order widget')
    
    def _switch_to_drill_free_draw(self):
        """Replace stroke order display with a free-draw canvas (Erase was clicked)."""
        from app.widgets.handwriting_canvas import HandwritingCanvas
        handwriting_container = self.root.ids.get('drill_handwriting_container')
        if not handwriting_container:
            return
        if hasattr(self, '_drill_stroke_order_widget'):
            self._drill_stroke_order_widget.stop_animation()
        handwriting_container.clear_widgets()
        canvas = HandwritingCanvas(size_hint=(1, 1))
        handwriting_container.add_widget(canvas)
        self._drill_free_draw_canvas = canvas
        self._drill_stroke_order_active = False
        self._drill_free_draw_active = True
        Logger.info('Drill: Switched to free-draw mode')

    def on_drill_handwriting_back(self):
        """Handle back button for drill handwriting - go to previous character."""
        try:
            if not hasattr(self, '_current_drill_vector'):
                return
            
            vector = self._current_drill_vector
            
            # If stroke order or free-draw mode is showing, back cancels the reveal and restores drawing
            if getattr(self, '_drill_stroke_order_active', False) or getattr(self, '_drill_free_draw_active', False):
                self._cleanup_drill_stroke_order()
                vector['_hw_revealed'] = False
                # Restore handwriting canvas
                handwriting_container = self.root.ids.get('drill_handwriting_container')
                if handwriting_container and hasattr(self, '_drill_handwriting_canvas'):
                    handwriting_container.clear_widgets()
                    handwriting_container.add_widget(self._drill_handwriting_canvas)
                    self._drill_handwriting_canvas.clear_canvas()
                    self._drill_handwriting_canvas.disabled = False
                # Reset submit button
                submit_btn = self.root.ids.get('drill_hw_submit')
                if submit_btn:
                    submit_btn.text = 'Check'
                    submit_btn.background_color = (0.25, 0.35, 0.50, 1)
                # Restore feedback to definition
                feedback_label = self.root.ids.get('drill_feedback')
                if feedback_label:
                    feedback_label.text = ''
                # Restore question blanks display
                question_label = self.root.ids.get('drill_question')
                if question_label:
                    characters = vector.get('characters', [])
                    current_idx = vector.get('current_char_index', 0)
                    char_results = vector.get('char_results', [])
                    blanks = []
                    for i, char in enumerate(characters):
                        if i < len(char_results):
                            blanks.append(f'[color=60ff60]{char}[/color]' if char_results[i] else f'[color=ff6060]{char}[/color]')
                        elif i == current_idx:
                            blanks.append('[b]_[/b]')
                        else:
                            blanks.append('_')
                    question_label.text = ' '.join(blanks)
                    question_label.markup = True
                Logger.info('Drill: Cancelled reveal, restored drawing mode')
                return
            
            current_idx = vector.get('current_char_index', 0)
            
            if current_idx == 0:
                Logger.info('Drill: Already at first character')
                return
            
            # Show confirmation popup
            from kivy.uix.popup import Popup
            from kivy.uix.boxlayout import BoxLayout
            from kivy.uix.label import Label
            from kivy.uix.button import Button
            from kivy.metrics import dp
            
            content = BoxLayout(orientation='vertical', spacing=dp(12), padding=dp(12))
            
            msg_label = Label(
                text="Really go back? This will undo this character's progress.",
                font_name='fonts/NotoSansJP-Regular.ttf',
                color=(0.90, 0.88, 0.85, 1),
                size_hint_y=None,
                height=dp(60),
                halign='center',
                valign='middle'
            )
            msg_label.bind(size=lambda instance, value: setattr(instance, 'text_size', value))
            content.add_widget(msg_label)
            
            btn_box = BoxLayout(orientation='horizontal', spacing=dp(8), size_hint_y=None, height=dp(48))
            
            cancel_btn = Button(
                text='Cancel',
                background_normal='',
                background_color=(0.35, 0.33, 0.30, 1),
                color=(0.90, 0.88, 0.85, 1),
                font_name='fonts/NotoSansJP-Regular.ttf'
            )
            
            confirm_btn = Button(
                text='Go Back',
                background_normal='',
                background_color=(0.70, 0.65, 0.20, 1),
                color=(0.90, 0.88, 0.85, 1),
                font_name='fonts/NotoSansJP-Regular.ttf'
            )
            
            btn_box.add_widget(cancel_btn)
            btn_box.add_widget(confirm_btn)
            content.add_widget(btn_box)
            
            popup = Popup(
                title='Confirm Go Back',
                content=content,
                size_hint=(0.8, 0.35),
                background_color=(0.18, 0.18, 0.20, 1)
            )
            
            cancel_btn.bind(on_release=lambda *_: popup.dismiss())
            confirm_btn.bind(on_release=lambda *_: self._do_drill_handwriting_back(popup, vector))
            
            popup.open()
            
        except Exception as e:
            Logger.error(f'Drill: Error in handwriting back: {e}')
    
    def _do_drill_handwriting_back(self, popup, vector):
        """Actually go back to previous character in drill."""
        try:
            popup.dismiss()
            
            current_idx = vector.get('current_char_index', 0)
            characters = vector.get('characters', [])
            
            if current_idx > 0:
                # Check if we just completed all characters (result was submitted)
                # If so, undo the submission first before going back
                if current_idx >= len(characters):
                    Logger.info('Drill: Going back after completion - undoing submission first')
                    conn = None
                    try:
                        conn = dict_db.init_db(get_db_path())
                        import dictionary.learning as learning
                        result = learning.undo_last_submission(conn, self._current_drill_session_id)
                        if result.get('status') == 'restored':
                            Logger.info('Drill: Auto-undo successful before going back')
                            
                            # Get the restored vector from the session
                            session = dict_db.get_learning_session(conn, self._current_drill_session_id)
                            if session:
                                in_progress = session['data'].get('in_progress', [])
                                # Find our vector in the restored in_progress list
                                restored_vector = None
                                for v in in_progress:
                                    if v['id'] == vector['id']:
                                        restored_vector = v
                                        break
                                
                                if restored_vector:
                                    # Update our local vector with the restored state (especially streak)
                                    vector['streak'] = restored_vector.get('streak', 0)
                                    Logger.info(f'Drill: Restored streak to {vector["streak"]}')
                        else:
                            Logger.warning(f'Drill: Undo failed: {result}')
                        conn.close()
                    except Exception as e:
                        Logger.error(f'Drill: Error auto-undoing before back: {e}')
                        if conn:
                            conn.close()
                
                # Now go back to previous character
                vector['current_char_index'] = current_idx - 1
                if 'char_results' in vector and vector['char_results']:
                    vector['char_results'].pop()
                
                # Clear waiting continue state if going back after wrong answer
                self._drill_waiting_continue = False
                
                # Reset submit button if it was changed to Continue
                submit_btn = self.root.ids.get('drill_hw_submit')
                if submit_btn:
                    submit_btn.text = 'Check'
                    submit_btn.background_color = (0.25, 0.35, 0.50, 1)
                
                # Clear feedback
                feedback_label = self.root.ids.get('drill_feedback')
                if feedback_label:
                    feedback_label.text = ''
                
                # Update streak label with restored streak
                streak_label = self.root.ids.get('drill_streak_label')
                if streak_label and not self.hide_review_counter:
                    current_streak = vector.get('streak', 0)
                    streak_label.text = f'Streak: {current_streak}/3'
                    streak_label.color = (0.15, 0.45, 0.65, 1)
                
                self._load_handwriting_drill(vector)
                Logger.info(f'Drill: Went back to character {vector["current_char_index"]} with streak {vector.get("streak", 0)}')
        except Exception as e:
            Logger.error(f'Drill: Error in _do_drill_handwriting_back: {e}')
            import traceback
            traceback.print_exc()
    
    def on_drill_handwriting_auto(self):
        """Handle auto button for drill - mark current character as correct automatically."""
        try:
            if not hasattr(self, '_current_drill_vector'):
                return
            
            vector = self._current_drill_vector
            characters = vector.get('characters', [])
            current_idx = vector.get('current_char_index', 0)
            
            if current_idx >= len(characters):
                Logger.info('Drill: Already at last character')
                return
            
            # Mark current character as correct (auto)
            if 'char_results' not in vector:
                vector['char_results'] = []
            vector['char_results'].append(True)
            
            # Update display immediately to show the character in green
            question_label = self.root.ids.get('drill_question')
            if question_label:
                blanks = []
                for i, char in enumerate(characters):
                    if i < len(vector['char_results']):
                        # Already filled in - show in green (auto'd as correct)
                        blanks.append(f'[color=60ff60]{char}[/color]')
                    elif i == current_idx + 1:
                        # Next blank to fill
                        blanks.append('[b]_[/b]')
                    else:
                        # Future blank
                        blanks.append('_')
                display_text = ' '.join(blanks)
                question_label.text = display_text
                question_label.markup = True
            
            # Clear canvas
            if hasattr(self, '_drill_handwriting_canvas'):
                self._drill_handwriting_canvas.clear_canvas()
            
            # Move to next character
            vector['current_char_index'] = current_idx + 1
            
            # Check if all characters are done
            if vector['current_char_index'] >= len(characters):
                # All done - finish handwriting drill
                all_correct = all(vector['char_results'])
                Logger.info(f'Drill: Auto-marked to end. Results: {vector["char_results"]}, Overall: {all_correct}')
                
                answer = vector.get('answer', '')
                
                # Submit to learning system
                conn = None
                result = {}
                try:
                    conn = dict_db.init_db(get_db_path())
                    import dictionary.learning as learning
                    
                    result = learning.submit_vector_result(
                        conn,
                        self._current_drill_session_id,
                        vector['id'],
                        all_correct
                    )
                    
                    Logger.info(f'Drill: Submit result (auto): {result}')
                    
                    # Track completion only when vector is promoted (finished 3 correct)
                    if result.get('status') == 'promoted':
                        if not vector.get('is_filler', False):
                            self._drill_completed_count = getattr(self, '_drill_completed_count', 0) + 1
                            
                            # Track drilled vector ID for weak words and lesson drills
                            if self._drill_mode != 'tools_drill':
                                vector_id = f"{vector['entry_id']}:{vector['vector_type']}"
                                self._drilled_today.add(vector_id)
                                Logger.info(f'Drill: Added {vector_id} to drilled_today set')
                        
                except Exception as e:
                    Logger.error(f'Drill: Error submitting: {e}')
                finally:
                    if conn:
                        conn.close()
                
                # Update UI with feedback
                feedback_label = self.root.ids.get('drill_feedback')
                streak_label = self.root.ids.get('drill_streak_label')
                
                # Check if this is a filler or already in SRS (these pass immediately)
                is_filler_or_already = result.get('status') in ('filler_pass', 'already_in_srs')
                
                # Update streak counter (but not for fillers)
                if streak_label and not is_filler_or_already and not self.hide_review_counter:
                    current_streak = vector.get('streak', 0)
                    if all_correct:
                        new_streak = current_streak + 1
                        streak_label.text = f'Streak: {new_streak}/3'
                        streak_label.color = (0.20, 0.65, 0.30, 1)
                    else:
                        streak_label.text = f'Streak: 0/3'
                        streak_label.color = (0.85, 0.40, 0.35, 1)
                    # Reset to default color after 0.5 seconds
                    from kivy.clock import Clock
                    Clock.schedule_once(lambda dt: setattr(streak_label, 'color', (0.25, 0.35, 0.50, 1)), 0.5)
                
                # Show feedback and wait for user to click Continue
                if feedback_label:
                    if all_correct:
                        feedback_label.text = '✓ Correct!'
                        feedback_label.color = (0.20, 0.65, 0.30, 1)
                    else:
                        max_length = 60
                        display_answer = answer
                        if len(answer) > max_length:
                            display_answer = answer[:max_length] + '...'
                        feedback_label.text = f'✗ Incorrect - Answer: {display_answer}'
                        feedback_label.color = (0.85, 0.40, 0.35, 1)
                
                # Set waiting flag and change button to Continue
                self._drill_waiting_continue = True
                submit_btn = self.root.ids.get('drill_hw_submit')
                if submit_btn:
                    submit_btn.text = 'Continue'
                    submit_btn.background_color = (0.15, 0.65, 0.15, 1)  # Green
            else:
                # More characters - move to next character after brief delay
                Logger.info(f'Drill: Auto-marked, moving to next character ({vector["current_char_index"]}/{len(characters)})')
                from kivy.clock import Clock
                Clock.schedule_once(lambda dt: self._load_handwriting_drill(vector), 0.1)
            
        except Exception as e:
            Logger.error(f'Drill: Error in handwriting auto: {e}')

    def on_drill_submit(self):
        """Handle drill answer submission."""
        try:
            # ── Handwriting fast-path: must happen BEFORE any focus or debounce
            # logic so the keyboard never opens during handwriting mode and taps
            # on Check / Continue are never eaten by the 250 ms debounce.
            if hasattr(self, '_current_drill_vector') and self._current_drill_vector:
                if self._current_drill_vector.get('vector_type') == 'handwriting':
                    Logger.info('Drill: Routing to handwriting submit')
                    return self.on_drill_handwriting_submit()

            # Keep the keyboard alive immediately.  The Submit *button* already
            # sets focus in on_press (before on_release fires this handler).
            # But the Enter / IME action key fires on_text_validate which calls
            # this directly — Android has already sent ACTION_DONE and begun
            # dismissing the keyboard before we get here.  Refocusing now
            # cancels that dismissal so the keyboard stays up for the next
            # question.  Skip when waiting for Continue (wrong-answer state)
            # because in that state the keyboard should remain closed.
            if not getattr(self, '_drill_waiting_continue', False):
                _di = self.root.ids.get('drill_input')
                if _di and not _di.readonly:
                    _di.focus = True

            # Debounce: Android's IME can fire on_text_validate (ACTION_DONE) a
            # second time immediately after the first, which would eat the wrong-
            # answer feedback screen before the user sees it.
            import time as _time
            _now = _time.monotonic()
            if _now - getattr(self, '_drill_last_submit_ts', 0) < 0.25:
                Logger.info('Drill: Submit debounced (< 250 ms since last)')
                return
            self._drill_last_submit_ts = _now
            Logger.info('Drill: Submit button pressed')
            
            # TIME ATTACK MODE HANDLING
            if hasattr(self, '_drill_mode') and self._drill_mode == 'time_attack':
                return self._on_time_attack_submit()
            
            # Check if we're in "continue" mode (after wrong answer)
            if getattr(self, '_drill_waiting_continue', False):
                # User clicked Continue, load next vector
                self._drill_waiting_continue = False
                
                # Reset submit button
                submit_btn = self.root.ids.get('drill_submit_btn')
                if submit_btn:
                    submit_btn.text = 'Submit'
                    submit_btn.background_color = (0.15, 0.45, 0.65, 1)  # Blue
                
                # Clear feedback
                feedback_label = self.root.ids.get('drill_feedback')
                if feedback_label:
                    feedback_label.text = ''
                
                # Load next
                self._load_current_drill()
                return
            
            if not hasattr(self, '_current_drill_vector') or not self._current_drill_vector:
                Logger.info('Drill: No current vector (session may have just finished)')
                return
            
            text_input = self.root.ids.get('drill_input')
            if not text_input:
                return
            
            user_answer = text_input.text.strip()
            if not user_answer:
                return
            
            # Handle grammar vectors differently
            is_grammar = self._current_drill_vector.get('kind') == 'grammar'
            vector_type = self._current_drill_vector.get('vector_type', '')
            
            if is_grammar and vector_type == 'fill-blank':
                # Validate grammar fill-blank answer with flexible input conversion
                exercise_data = getattr(self, '_current_grammar_exercise', {})
                correct_answer = exercise_data.get('correct_answer', '') or self._current_drill_vector.get('answer', '')
                alt_answers = exercise_data.get('alternative_answers', []) or []
                
                # Check primary answer
                is_correct = user_answer == correct_answer
                if not is_correct:
                    is_correct = self._flexible_sentence_match(user_answer, correct_answer)
                
                # Check alternative answers if primary didn't match
                if not is_correct and alt_answers:
                    for alt in alt_answers:
                        if user_answer == alt or self._flexible_sentence_match(user_answer, alt):
                            is_correct = True
                            break
            elif is_grammar and vector_type == 'scramble':
                correct_sentence = getattr(self, '_current_scramble_correct', '') or self._current_drill_vector.get('answer', '')
                is_correct = self._flexible_sentence_match(user_answer, correct_sentence)
                correct_answer = correct_sentence
                Logger.info(f'Drill Scramble: user="{user_answer}" correct="{correct_sentence}" match={is_correct}')
            elif is_grammar and vector_type == 'translate':
                correct_sentence = self._current_drill_vector.get('answer', '')
                is_correct = self._flexible_sentence_match(user_answer, correct_sentence)
                correct_answer = correct_sentence
                Logger.info(f'Drill Translate: user="{user_answer}" correct="{correct_sentence}" match={is_correct}')
            elif is_grammar and vector_type == 'dictation':
                correct_sentence = self._current_drill_vector.get('answer', '')
                is_correct = self._flexible_sentence_match(user_answer, correct_sentence)
                correct_answer = correct_sentence
                Logger.info(f'Drill Dictation: user="{user_answer}" correct="{correct_sentence}" match={is_correct}')
            else:
                # Regular vocab/kanji answer validation
                # Normalize answers: remove punctuation and parentheses
                import re
                def normalize_answer(text):
                    # Remove anything in parentheses
                    text = re.sub(r'\([^)]*\)', '', text)
                    # Remove common punctuation (but keep Japanese characters)
                    text = re.sub(r'[.,;:!?"\'\-]', '', text)
                    return text.strip()
                
                # Check answer using the same logic as reviews for consistency
                correct_answer = self._current_drill_vector.get('answer', '')
                
                # Use check_answer_match for consistent answer validation across reviews/drills
                from dictionary.learning import check_answer_match
                is_correct = check_answer_match(user_answer, correct_answer, vector_type)
                
                Logger.info(f'Drill: Answer "{user_answer}" vs "{correct_answer}" (vector_type={vector_type}) = {is_correct}')
                
                # If still wrong, check if user answered a different vector for same entry
                if not is_correct:
                    entry_id = self._current_drill_vector.get('entry_id')
                    entry_kind = self._current_drill_vector.get('kind')
                    
                    # Get all vectors for this entry
                    conn2 = None
                    all_vectors = []
                    try:
                        conn2 = dict_db.init_db(get_db_path())
                        import dictionary.learning as learning
                        all_vectors = learning.make_vectors_for_entries(conn2, [entry_id], entry_kind)
                    except Exception as e:
                        Logger.error(f'Drill: Error getting vectors: {e}')
                    finally:
                        if conn2:
                            try:
                                conn2.close()
                            except Exception:
                                pass
                    
                    # Check if answer matches any other vector using check_answer_match
                    for other_vec in all_vectors:
                        if other_vec['vector_type'] == vector_type:
                            continue  # Skip current vector
                        
                        other_answer = other_vec.get('answer', '')
                        other_vector_type = other_vec.get('vector_type', '')
                        
                        # Use check_answer_match for consistent validation
                        matches_other = check_answer_match(user_answer, other_answer, other_vector_type)
                        
                        if matches_other:
                            # User answered the wrong vector type
                            feedback_label = self.root.ids.get('drill_feedback')
                            if feedback_label:
                                # Determine what they typed vs what's asked
                                other_type_name = 'reading' if 'reading' in other_vec['vector_type'] or other_vec['vector_type'] in ('show_kana', 'show_romaji') else 'meaning'
                                current_type_name = 'reading' if 'reading' in vector_type or vector_type in ('show_kana', 'show_romaji') else 'meaning'
                                
                                feedback_label.text = f"That's the {other_type_name}, this asks for the {current_type_name}"
                                feedback_label.color = (0.9, 0.6, 0.1, 1)  # Orange/warning color
                            
                            # Clear input and keep focus so user can try again immediately
                            if text_input:
                                text_input.text = ''
                                Clock.schedule_once(lambda dt: setattr(text_input, 'focus', True), 0.05)
                            
                            # Don't submit, let them try again
                            return
                    
                    # Check for synonym confusion (e.g. なぜ vs どうして)
                    # Show character count hint and let user retry
                    if vector_type == 'meaning_to_kana' and not is_correct:
                        _synonym_hints = {
                            'なぜ': 2,
                            'どうして': 4,
                        }
                        expected_kana = correct_answer.strip()
                        user_kana = user_answer.strip()
                        if expected_kana in _synonym_hints and user_kana in _synonym_hints and user_kana != expected_kana:
                            char_count = _synonym_hints[expected_kana]
                            feedback_label = self.root.ids.get('drill_feedback')
                            if feedback_label:
                                feedback_label.text = f"Hint: {char_count} characters"
                                feedback_label.color = (0.9, 0.6, 0.1, 1)
                            if text_input:
                                text_input.text = ''
                                Clock.schedule_once(lambda dt: setattr(text_input, 'focus', True), 0.05)
                            return

                    # Check for homonym confusion (e.g. やさしい easy vs kind)
                    if vector_type in ('kana_to_meaning', 'orthography_to_meaning'):
                        _homonym_map = {
                            'やさしい': [
                                {'gloss': 'easy; plain; simple', 'kanji': '易しい'},
                                {'gloss': 'tender; kind; gentle; graceful; affectionate; amiable', 'kanji': '優しい'},
                            ],
                        }
                        kana_key = self._current_drill_vector.get('prompt', '').strip()
                        if kana_key in _homonym_map:
                            for other in _homonym_map[kana_key]:
                                if check_answer_match(user_answer, other['gloss'], vector_type):
                                    if check_answer_match(user_answer, correct_answer, vector_type):
                                        break
                                    feedback_label = self.root.ids.get('drill_feedback')
                                    if feedback_label:
                                        feedback_label.text = f"That's {other['kanji']} — this one means something else"
                                        feedback_label.color = (0.9, 0.6, 0.1, 1)
                                    if text_input:
                                        text_input.text = ''
                                        Clock.schedule_once(lambda dt: setattr(text_input, 'focus', True), 0.05)
                                    return
            
            # Submit to learning session
            conn = dict_db.init_db(get_db_path())
            import dictionary.learning as learning
            result = learning.submit_vector_result(
                conn, 
                self._current_drill_session_id, 
                self._current_drill_vector['id'], 
                is_correct
            )
            conn.close()
            
            Logger.info(f'Drill: Submit result: {result}')
            
            # Check if this is a filler or already_in_srs - these pass automatically but still show feedback
            is_filler_or_already = result.get('status') in ('filler_pass', 'already_in_srs')
            
            # Show feedback
            feedback_label = self.root.ids.get('drill_feedback')
            submit_btn = self.root.ids.get('drill_submit_btn')
            streak_label = self.root.ids.get('drill_streak_label')
            
            # Flash streak counter color and update text based on result (but not for fillers)
            if streak_label and not is_filler_or_already and not self.hide_review_counter:
                current_streak = self._current_drill_vector.get('streak', 0)
                if is_correct:
                    new_streak = current_streak + 1
                    streak_label.text = f'Streak: {new_streak}/3'
                    streak_label.color = (0.20, 0.70, 0.20, 1)  # Green
                else:
                    streak_label.text = f'Streak: 0/3'
                    streak_label.color = (0.85, 0.20, 0.20, 1)  # Red
                # Reset to default color after 0.5 seconds
                Clock.schedule_once(lambda dt: setattr(streak_label, 'color', (0.15, 0.45, 0.65, 1)), 0.5)
            
            if feedback_label:
                if is_correct:
                    feedback_label.text = '✓ Correct!'
                    feedback_label.color = (0.15, 0.65, 0.15, 1)
                else:
                    # Truncate long answers
                    max_length = 60
                    display_answer = correct_answer
                    if len(correct_answer) > max_length:
                        display_answer = correct_answer[:max_length] + '...'
                    
                    # Ensure proper encoding for display
                    try:
                        feedback_label.text = f'✗ Incorrect - Answer: {display_answer}'
                    except UnicodeEncodeError:
                        feedback_label.text = f'X Incorrect - Answer: {display_answer}'
                    feedback_label.color = (0.85, 0.20, 0.20, 1)
            
            # Track completion
            if result.get('status') == 'promoted':
                self._drill_completed_count += 1
                # Track drilled vector ID for weak words AND lesson drills (but NOT tools_drill)
                if self._drill_mode != 'tools_drill':
                    vector_id = f"{self._current_drill_vector['entry_id']}:{self._current_drill_vector['vector_type']}"
                    self._drilled_today.add(vector_id)
                    Logger.info(f'Drill: Added {vector_id} to drilled_today set')
                    
                    # Clear forced drill flag for weak words that complete successfully
                    if self._drill_mode == 'weak_words':
                        try:
                            entry_id = self._current_drill_vector['entry_id']
                            kind = self._current_drill_vector['kind']
                            conn = dict_db.init_db(get_db_path())
                            
                            # Clear the forced drill flag for this entry/kind
                            cur = conn.cursor()
                            cur.execute('SELECT data FROM srs WHERE entry_id = ?', (entry_id,))
                            row = cur.fetchone()
                            if row:
                                import json
                                data = json.loads(row[0] or '{}')
                                per_kind = data.get('per_kind', {})
                                if kind in per_kind:
                                    if per_kind[kind].get('flag_forced_drill'):
                                        per_kind[kind]['flag_forced_drill'] = False
                                        per_kind[kind]['consecutive_review_wrongs'] = 0
                                        per_kind[kind]['consecutive_wrong_days'] = 0
                                        per_kind[kind]['last_wrong_date'] = None
                                        data['per_kind'] = per_kind
                                        cur.execute('UPDATE srs SET data = ? WHERE entry_id = ?', 
                                                  (json.dumps(data), entry_id))
                                        conn.commit()
                                        Logger.info(f'Drill: Cleared forced drill flag for entry {entry_id} kind {kind}')
                            conn.close()
                        except Exception as e:
                            Logger.error(f'Drill: Error clearing forced flag: {e}')
                else:
                    Logger.info(f'Drill: Tools drill mode - NOT tracking to drilled_today')

            
            # Auto TTS after answering
            self._auto_tts_after_answer(self._current_drill_vector)
            
            if is_correct:
                # Correct - check if we need to show a new info card (progressive unlock)
                if result.get('show_next_info') and self._drill_mode == 'lesson':
                    # Show the unlocked info card
                    def show_unlocked_card(dt):
                        self._show_progressive_unlock_card()
                    Clock.schedule_once(show_unlocked_card, 0.5)
                else:
                    # Keyboard is already up (kept by on_press refocus in KV).
                    # Load next question after the 0.5s green feedback pause.
                    def load_next_drill(dt):
                        self._load_current_drill()
                    Clock.schedule_once(load_next_drill, 0.5)
            else:
                # Incorrect — keep keyboard up (below_target will keep the layout
                # above it).  User sees the red feedback and the button has changed
                # to 'Continue'; they press Enter or tap it to proceed.
                self._drill_waiting_continue = True
                if submit_btn:
                    submit_btn.text = 'Continue'
                    submit_btn.background_color = (0.15, 0.65, 0.15, 1)  # Green
            
        except Exception as e:
            Logger.error(f'Drill: Error submitting: {e}')
            import traceback
            traceback.print_exc()

    def on_drill_reveal(self):
        """Handle reveal button press in drill - show answer and mark as wrong."""
        try:
            reveal_btn = self.root.ids.get('drill_reveal_btn')
            
            if not reveal_btn:
                return
            
            # TIME ATTACK MODE HANDLING
            if hasattr(self, '_drill_mode') and self._drill_mode == 'time_attack':
                return self._on_time_attack_reveal()
            
            # Check if this is a handwriting drill
            if hasattr(self, '_current_drill_vector') and self._current_drill_vector:
                if self._current_drill_vector.get('vector_type') == 'handwriting':
                    return self._on_handwriting_drill_reveal()
            
            # Check if we need confirmation
            reveal_confirm = getattr(self, '_drill_reveal_confirm', False)
            
            if not reveal_confirm:
                # First click: show confirmation
                reveal_btn.text = 'Really Reveal?'
                reveal_btn.background_color = (0.95, 0.85, 0.30, 1)
                self._drill_reveal_confirm = True
                Logger.info('Drill: Reveal confirmation requested')
                return
            
            # Second click: actually reveal
            if not hasattr(self, '_current_drill_vector'):
                return
            
            vector = self._current_drill_vector
            
            # Get correct answer - different for grammar vs regular vectors
            is_grammar = vector.get('kind') == 'grammar'
            if is_grammar and vector.get('vector_type') == 'scramble':
                correct_answer = getattr(self, '_current_scramble_correct', '') or vector.get('answer', '')
            elif is_grammar and vector.get('vector_type') in ('translate', 'dictation'):
                correct_answer = vector.get('answer', '')
            elif is_grammar and hasattr(self, '_current_grammar_exercise'):
                correct_answer = self._current_grammar_exercise.get('correct_answer', '')
            else:
                correct_answer = vector.get('answer', '')
            
            # Show answer in text input (read-only)
            text_input = self.root.ids.get('drill_input')
            submit_btn = self.root.ids.get('drill_submit_btn')
            reveal_btn = self.root.ids.get('drill_reveal_btn')
            feedback_label = self.root.ids.get('drill_feedback')
            
            # Show answer in feedback only (don't put it in the text input
            # or set readonly — that causes Android Kivy to leave a stale
            # IME/selection state that blocks typing after undo).
            if feedback_label:
                feedback_label.text = f'Answer: {correct_answer}'
                feedback_label.color = (0.85, 0.20, 0.20, 1)
            
            # Change Submit button to "Continue"
            if submit_btn:
                submit_btn.text = 'Continue'
                submit_btn.background_color = (0.15, 0.65, 0.15, 1)
            
            # Disable Reveal button
            if reveal_btn:
                reveal_btn.disabled = True
                reveal_btn.opacity = 0.5
            
            Logger.info(f'Drill: Revealed answer "{correct_answer}"')
            
            # Submit as incorrect
            conn = dict_db.init_db(get_db_path())
            import dictionary.learning as learning
            result = learning.submit_vector_result(
                conn, 
                self._current_drill_session_id, 
                vector['id'], 
                False  # Incorrect
            )
            conn.close()
            
            Logger.info(f'Drill: Reveal submitted as incorrect, result: {result}')
            
            # Set waiting continue flag
            self._drill_waiting_continue = True
            self._drill_revealed = True
            
            # Auto TTS after reveal
            self._auto_tts_after_answer(vector)
            
        except Exception as e:
            Logger.error(f'Drill: Error revealing answer: {e}')
            import traceback
            traceback.print_exc()
    
    def _on_time_attack_submit(self):
        """Handle time attack answer submission."""
        try:
            if not hasattr(self, '_current_drill_vector') or not self._current_drill_vector:
                return
            
            text_input = self.root.ids.get('drill_input')
            if not text_input:
                return
            
            user_answer = text_input.text.strip()
            if not user_answer:
                return
            
            # Check answer
            correct_answer = self._current_drill_vector.get('answer', '')
            vector_type = self._current_drill_vector.get('vector_type', '')
            
            from dictionary.learning import check_answer_match
            is_correct = check_answer_match(user_answer, correct_answer, vector_type)
            
            Logger.info(f'TimeAttack: Answer "{user_answer}" vs "{correct_answer}" = {is_correct}')
            
            # Increment total attempts
            self._time_attack_total_attempts += 1
            
            feedback_label = self.root.ids.get('drill_feedback')
            
            if is_correct:
                # Correct answer!
                self._time_attack_correct_count += 1
                self._time_attack_timer += 1.0  # Add 1 second
                
                # Mark this vector as completed
                vector_key = f"{self._current_drill_vector['entry_id']}:{vector_type}"
                self._time_attack_completed_items.add(vector_key)
                
                # Show feedback
                if feedback_label:
                    feedback_label.text = '✓ Correct! +1s'
                    feedback_label.color = (0.15, 0.65, 0.15, 1)
                
                # Check if all items completed in regular mode
                conn = None
                try:
                    conn = dict_db.init_db(get_db_path())
                    session = dict_db.get_learning_session(conn, self._current_drill_session_id)
                    if session:
                        data = session.get('data', {})
                        meta = data.get('meta', {})
                        total_vectors = meta.get('total_vectors', 0)
                        
                        if self._time_attack_mode == 'regular' and len(self._time_attack_completed_items) >= total_vectors:
                            # All items completed in regular mode
                            conn.close()
                            self._end_time_attack()
                            return
                except Exception as e:
                    Logger.error(f'TimeAttack: Error checking completion: {e}')
                finally:
                    if conn:
                        try:
                            conn.close()
                        except Exception:
                            pass
                
                # Move to next item
                self._time_attack_advance_to_next()
                
            else:
                # Wrong answer - just show feedback and let them try again
                if feedback_label:
                    feedback_label.text = '✗ Try again'
                    feedback_label.color = (0.85, 0.20, 0.20, 1)
                
                # Clear input and refocus
                if text_input:
                    text_input.text = ''
                    Clock.schedule_once(lambda dt: setattr(text_input, 'focus', True), 0.05)
            
            self._update_time_attack_display()
            
        except Exception as e:
            Logger.error(f'TimeAttack: Error submitting: {e}')
            import traceback
            traceback.print_exc()
    
    def _time_attack_advance_to_next(self):
        """Advance to next item in time attack mode."""
        try:
            conn = dict_db.init_db(get_db_path())
            session = dict_db.get_learning_session(conn, self._current_drill_session_id)
            
            if not session:
                conn.close()
                return
            
            data = session.get('data', {})
            in_progress = data.get('in_progress', [])
            pending = data.get('pending', [])
            meta = data.get('meta', {})
            
            # Remove current from in_progress
            current_id = self._current_drill_vector['id']
            in_progress = [v for v in in_progress if v['id'] != current_id]
            
            # Add next item
            if pending:
                # Take from pending
                next_item = pending.pop(0)
                in_progress.append(next_item)
            elif self._time_attack_mode == 'unlimited':
                # Recycle: find a completed item and reuse it
                all_vectors = meta.get('all_vectors', [])
                if all_vectors:
                    # Find vectors that have been completed
                    import random
                    completed_vectors = [v for v in all_vectors 
                                       if f"{v['entry_id']}:{v.get('vector_type', '')}" in self._time_attack_completed_items]
                    
                    if completed_vectors:
                        # Mark as filler for display purposes
                        next_item = random.choice(completed_vectors).copy()
                        next_item['is_filler'] = True
                        in_progress.append(next_item)
            
            # Update session
            data['in_progress'] = in_progress
            data['pending'] = pending
            dict_db.update_learning_session(conn, self._current_drill_session_id, data)
            conn.close()
            
            # Load next drill
            self._load_current_drill()
            
        except Exception as e:
            Logger.error(f'TimeAttack: Error advancing: {e}')
            import traceback
            traceback.print_exc()
    
    def _on_time_attack_reveal(self):
        """Handle reveal in time attack mode - lose 5 seconds and advance."""
        try:
            reveal_btn = self.root.ids.get('drill_reveal_btn')
            if not reveal_btn:
                return
            
            # Check if we need confirmation
            reveal_confirm = getattr(self, '_time_attack_reveal_confirm', False)
            
            if not reveal_confirm:
                # First click: show confirmation
                reveal_btn.text = 'Really? -5s'
                reveal_btn.background_color = (0.95, 0.85, 0.30, 1)
                self._time_attack_reveal_confirm = True
                Logger.info('TimeAttack: Reveal confirmation requested')
                return
            
            # Reset confirmation
            self._time_attack_reveal_confirm = False
            reveal_btn.text = 'Reveal'
            reveal_btn.background_color = (0.85, 0.40, 0.35, 1)
            
            # Deduct 5 seconds
            self._time_attack_timer -= 5.0
            if self._time_attack_timer < 0:
                self._time_attack_timer = 0
            
            # Show feedback
            feedback_label = self.root.ids.get('drill_feedback')
            if feedback_label:
                correct_answer = self._current_drill_vector.get('answer', '')
                feedback_label.text = f'Answer: {correct_answer} (-5s)'
                feedback_label.color = (0.85, 0.40, 0.35, 1)
            
            # Increment total attempts
            self._time_attack_total_attempts += 1
            
            # Update display
            self._update_time_attack_display()
            
            # Check if timer ran out
            if self._time_attack_timer <= 0:
                self._end_time_attack()
                return
            
            # Move to next item
            self._time_attack_advance_to_next()
            
        except Exception as e:
            Logger.error(f'TimeAttack: Error revealing: {e}')
            import traceback
            traceback.print_exc()
    
    def on_drill_undo(self):
        """Handle undo button press in drill."""
        try:
            Logger.info('Drill: Undo button pressed')
            
            # Check if this is a handwriting drill - undo should remove last stroke
            if hasattr(self, '_current_drill_vector') and self._current_drill_vector:
                if self._current_drill_vector.get('vector_type') == 'handwriting':
                    # If stroke order is showing, switch to free-draw canvas
                    if getattr(self, '_drill_stroke_order_active', False):
                        self._switch_to_drill_free_draw()
                        return
                    
                    # If free-draw canvas is active, clear it
                    if getattr(self, '_drill_free_draw_active', False):
                        if hasattr(self, '_drill_free_draw_canvas'):
                            self._drill_free_draw_canvas.clear_canvas()
                            Logger.info('Drill: Cleared free-draw canvas')
                        return
                    
                    if hasattr(self, '_drill_handwriting_canvas'):
                        self._drill_handwriting_canvas.undo_stroke()
                        Logger.info('Drill: Undid last stroke')
                    return
            
            undo_btn = self.root.ids.get('drill_undo_btn')
            
            if not undo_btn:
                return
            
            if not hasattr(self, '_current_drill_session_id'):
                Logger.info('Drill: No active session')
                return
            
            # First click: show confirmation (yellow)
            undo_confirm = getattr(self, '_drill_undo_confirm', False)
            if not undo_confirm:
                undo_btn.text = 'Undo last?'
                undo_btn.background_color = (0.95, 0.85, 0.30, 1)
                self._drill_undo_confirm = True
                Logger.info('Drill: Undo confirmation requested')
            else:
                # Second click: actually undo
                conn = None
                was_promoted = False
                try:
                    conn = dict_db.init_db(get_db_path())
                    import dictionary.learning as learning
                    
                    # Get the last history item before undoing to check if we promoted
                    session = dict_db.get_learning_session(conn, self._current_drill_session_id)
                    if session:
                        history = session['data'].get('history', [])
                        if history:
                            last_item = history[-1]
                            last_result = last_item.get('result', {})
                            was_promoted = last_result.get('status') == 'promoted'
                    
                    result = learning.undo_last_submission(conn, self._current_drill_session_id)
                except Exception as e:
                    Logger.error(f'Drill: Error during undo: {e}')
                    return
                finally:
                    if conn:
                        try:
                            conn.close()
                        except Exception as e:
                            Logger.warning(f'Drill: Error closing connection: {e}')
                
                if result.get('status') == 'restored':
                    Logger.info('Drill: Undo successful')
                    
                    # If we undid a promotion, decrement the completed count
                    if was_promoted and self._drill_completed_count > 0:
                        self._drill_completed_count -= 1
                        Logger.info(f'Drill: Decremented completed count to {self._drill_completed_count}')
                        
                        # Also remove from drilled_today set if applicable
                        prev_vector = result.get('prev_vector', {})
                        if prev_vector:
                            vector_id = f"{prev_vector.get('entry_id')}:{prev_vector.get('vector_type')}"
                            if vector_id in self._drilled_today:
                                self._drilled_today.remove(vector_id)
                                Logger.info(f'Drill: Removed {vector_id} from drilled_today set')
                    
                    self._drill_undo_confirm = False
                    # Reload current drill
                    self._load_current_drill()
                else:
                    Logger.info(f'Drill: Undo failed: {result.get("message")}')
                
        except Exception as e:
            Logger.error(f'Drill: Error in undo: {e}')
            import traceback
            traceback.print_exc()

    def on_drill_exit(self):
        """Exit drill session early."""
        try:
            # Clean up info card / writing practice overlays
            self._hide_info_card_overlay()
            self._hide_writing_practice()
            self._finish_drill_session(early_exit=True)
        except Exception as e:
            Logger.error(f'Drill: Error exiting: {e}')

    def _recycle_drill_vectors(self, conn, session):
        """Recycle all promoted vectors back into the session for unlimited mode."""
        import random
        try:
            data = session['data']
            meta = data.get('meta', {})

            # Gather the original non-filler vectors from in_progress + pending + history
            original_vectors = []
            for v in data.get('in_progress', []):
                if not v.get('is_filler'):
                    original_vectors.append(v)
            for v in data.get('pending', []):
                if not v.get('is_filler'):
                    original_vectors.append(v)
            # Also pull any vectors stored in history that were promoted
            for h in data.get('history', []):
                vec = h.get('result', {}).get('vector')
                if vec and not vec.get('is_filler'):
                    # Only add if not already in our list (by entry_id + vector_type)
                    key = (vec.get('entry_id'), vec.get('vector_type'))
                    existing_keys = {(v.get('entry_id'), v.get('vector_type')) for v in original_vectors}
                    if key not in existing_keys:
                        original_vectors.append(vec)

            if not original_vectors:
                self._finish_drill_session()
                return

            # Reset streak on all vectors
            for v in original_vectors:
                v['streak'] = 0

            random.shuffle(original_vectors)

            DEFAULT_SLOTS = meta.get('num_slots', 7)
            data['in_progress'] = original_vectors[:DEFAULT_SLOTS]
            data['pending'] = original_vectors[DEFAULT_SLOTS:]
            data['history'] = []

            # Update total_vectors in meta to match recycled set
            meta['total_vectors'] = len(original_vectors)
            data['meta'] = meta

            dict_db.update_learning_session(conn, session['id'], data)

            # Reset completed count
            self._drill_completed_count = 0

            Logger.info(f'UnlimitedDrill: Recycled {len(original_vectors)} vectors')

            # Continue drilling
            self._load_current_drill()

        except Exception as e:
            Logger.error(f'UnlimitedDrill: Error recycling: {e}')
            import traceback
            traceback.print_exc()
            self._finish_drill_session()

    def _finish_drill_session(self, early_exit=False):
        """Finish the drill session."""
        try:
            Logger.info(f'Drill: Session {"exited early" if early_exit else "complete"}')
            
            # Dismiss keyboard before leaving drill screen
            _di = self.root.ids.get('drill_input')
            if _di and _di.focus:
                _di.focus = False
            
            # Clean up info card / writing practice overlays
            self._hide_info_card_overlay()
            self._hide_writing_practice()
            
            # Clear incomplete drill flag since session is finishing
            if hasattr(self, '_incomplete_drill'):
                self._incomplete_drill = None
                Logger.info('Drill: Cleared incomplete drill flag')
            
            # Mark weak words as completed for this session (only for study screen weak words, not tools)
            if self._drill_mode == 'weak_words':
                self._weak_words_completed_this_session = True
            
            # For tools drill, save stats then clean up and go back
            if self._drill_mode == 'tools_drill':
                Logger.info('ToolsDrill: Session complete, no study screen updates')
                # Save drill stat
                try:
                    stat_conn = dict_db.init_db(get_db_path())
                    sess = dict_db.get_learning_session(stat_conn, self._current_drill_session_id)
                    hist = sess['data'].get('history', []) if sess else []
                    total_att = len(hist)
                    correct = sum(1 for h in hist if h.get('result', {}).get('status') == 'promoted' or h.get('correct', False))
                    elapsed = __import__('time').time() - getattr(self, '_drill_start_time', __import__('time').time())
                    total_v = sess['data'].get('meta', {}).get('total_vectors', 0) if sess else 0
                    acc = (correct / total_att * 100) if total_att > 0 else 0
                    dict_db.save_drill_stat(
                        stat_conn, 'drill', 'custom',
                        self._drill_completed_count, total_v,
                        correct, total_att, elapsed, acc
                    )
                    stat_conn.close()
                except Exception as e:
                    Logger.error(f'DrillStats: Error saving: {e}')

                self._current_drill_session_id = None
                self._current_drill_vector = None
                self._drill_mode = None
                self._drill_completed_count = 0
                self._drill_config_unlimited = False
                
                # Navigate back to drill config page
                sm = self._get_screen_manager()
                if sm:
                    sm.current = 'drill_config'
                    # Refresh the config page so counts update
                    Clock.schedule_once(lambda dt: self.show_drill_config(), 0.1)
                return
            
            # For lesson drills, remove completed entries from the queue
            if self._drill_mode == 'lesson' and not early_exit:
                self._clean_fully_done_queue_items()
            
            # Clean up
            self._current_drill_session_id = None
            self._current_drill_vector = None
            self._drill_mode = None
            self._drill_completed_count = 0
            
            # Navigate back to study screen
            sm = self._get_screen_manager()
            if sm:
                sm.current = 'study'
                # Update stats
                Clock.schedule_once(lambda dt: self._update_study_stats(), 0.1)
            
        except Exception as e:
            Logger.error(f'Drill: Error finishing session: {e}')

    def _populate_dev_data(self):
        """Populate dev database with N5 test data (1 vocab + 1 kanji with all vectors)."""
        try:
            from datetime import datetime, timedelta
            import json
            Logger.info('DevData: Resetting SRS data for dev testing')
            
            conn = dict_db.init_db(get_db_path())
            cursor = conn.cursor()
            
            # DELETE ALL SRS ROWS - clean slate for dev testing
            now = datetime.utcnow()
            
            cursor.execute('DELETE FROM srs')
            conn.commit()
            
            # Mark erasure for sync
            try:
                from sync.sync import set_srs_erased_flag
                set_srs_erased_flag()
            except Exception:
                pass
            
            Logger.info(f'DevData: Deleted all SRS records for clean dev environment')
            
            # Get 1 N5 vocab entry with kanji (for reviews - due now)
            cursor.execute('''
                SELECT id, kanji, kana, gloss FROM entries
                WHERE kind = 'vocab' AND jlpt_level = 'N5' AND kanji IS NOT NULL AND kanji != ''
                ORDER BY study_order ASC
                LIMIT 1
            ''')
            vocab_row = cursor.fetchone()
            if not vocab_row:
                Logger.error('DevData: No N5 vocab with kanji found')
                return
            review_vocab_id = vocab_row[0]
            Logger.info(f'DevData: Review vocab: {vocab_row[0]} - {vocab_row[1]} ({vocab_row[2]}) = {vocab_row[3]}')
            
            # Get 1 N5 kanji entry (for weak words - low stability)
            cursor.execute('''
                SELECT id, kanji, kana FROM entries
                WHERE kind = 'kanji' AND jlpt_level = 'N5'
                ORDER BY study_order ASC
                LIMIT 1
            ''')
            kanji_row = cursor.fetchone()
            if not kanji_row:
                Logger.error('DevData: No N5 kanji found')
                return
            weak_kanji_id = kanji_row[0]
            Logger.info(f'DevData: Weak kanji: {kanji_row[0]} - {kanji_row[1]} ({kanji_row[2]})')
            
            # Get 1 more N5 vocab for lesson queue (not in SRS yet)
            cursor.execute('''
                SELECT id, kanji, kana, gloss FROM entries
                WHERE kind = 'vocab' AND jlpt_level = 'N5' AND id != ?
                ORDER BY study_order ASC
                LIMIT 1 OFFSET 1
            ''', (review_vocab_id,))
            lesson_row = cursor.fetchone()
            if not lesson_row:
                Logger.error('DevData: No second N5 vocab found')
                return
            lesson_vocab_id = lesson_row[0]
            Logger.info(f'DevData: Lesson vocab: {lesson_row[0]} - {lesson_row[1]} ({lesson_row[2]}) = {lesson_row[3]}')
            
            # Set up lesson queue
            if not hasattr(self, '_lesson_queue'):
                self._lesson_queue = []
            self._lesson_queue = [lesson_vocab_id]
            self._save_lesson_queue()
            Logger.info(f'DevData: Set lesson queue to 1 N5 vocab entry')
            
            # Set up review entry (vocab - due now, high stability)
            past = now - timedelta(hours=1)
            past_iso = past.isoformat()
            
            import dictionary.learning as learning
            
            # Review vocab (stability 5.0, due now)
            vectors = learning.make_vectors_for_entries(conn, [review_vocab_id], 'vocab')
            per_vector_data = {}
            for vec in vectors:
                vector_type = vec.get('vector_type')
                per_vector_data[vector_type] = {
                    'stability': 5.0,
                    'difficulty': 5.0,
                    'due_at': past_iso,
                    'streak': 1,
                    'reps': 1,
                    'lapses': 0,
                    'state': 2,
                    'interval': 1,
                    'last_review': past_iso
                }
            
            # Store in per_kind structure with nested per_vector
            per_kind_data = {
                'vocab': {
                    'stability': 5.0,
                    'difficulty': 5.0,
                    'due_at': past_iso,
                    'streak': 1,
                    'reps': 1,
                    'lapses': 0,
                    'state': 2,
                    'interval': 1,
                    'last_review': past_iso,
                    'per_vector': per_vector_data
                }
            }
            data = {'per_kind': per_kind_data}
            
            cursor.execute('INSERT INTO srs (entry_id, data) VALUES (?, ?)',
                          (review_vocab_id, json.dumps(data)))
            Logger.info(f'DevData: Created review SRS for vocab {review_vocab_id} with {len(per_vector_data)} vectors')
            
            # Set up weak kanji entry (low stability, not due yet)
            future_week = now + timedelta(days=7)
            future_week_iso = future_week.isoformat()
            
            vectors = learning.make_vectors_for_entries(conn, [weak_kanji_id], 'kanji')
            per_vector_data = {}
            for vec in vectors:
                vector_type = vec.get('vector_type')
                per_vector_data[vector_type] = {
                    'stability': 1.5,
                    'difficulty': 7.0,
                    'due_at': future_week_iso,
                    'streak': 1,
                    'reps': 2,
                    'lapses': 1,
                    'state': 2,
                    'interval': 7,
                    'last_review': (now - timedelta(days=2)).isoformat()
                }
            
            # Store in per_kind structure with nested per_vector
            per_kind_data = {
                'kanji': {
                    'stability': 1.5,
                    'difficulty': 7.0,
                    'due_at': future_week_iso,
                    'streak': 1,
                    'reps': 2,
                    'lapses': 1,
                    'state': 2,
                    'interval': 7,
                    'last_review': (now - timedelta(days=2)).isoformat(),
                    'per_vector': per_vector_data
                }
            }
            data = {'per_kind': per_kind_data}
            
            cursor.execute('INSERT INTO srs (entry_id, data) VALUES (?, ?)',
                          (weak_kanji_id, json.dumps(data)))
            Logger.info(f'DevData: Created weak SRS for kanji {weak_kanji_id} with {len(per_vector_data)} vectors')
            
            conn.commit()
            conn.close()
            
            # Reset session flags so buttons appear
            self._reviews_completed_this_session = False
            self._weak_words_completed_this_session = False
            self._drilled_today = set()
            
            Logger.info(f'DevData: Dev mode enabled - 1 N5 vocab (reviews), 1 N5 kanji (weak words), 1 N5 vocab (lesson queue)')
            
        except Exception as e:
            Logger.error(f'DevData: Error populating dev data: {e}')
            import traceback
            traceback.print_exc()

    def _record_screen_visit(self, screen_name: str):
        """Record a screen visit for back-navigation.

        We treat 'dictionary' as the home fallback. During back-navigation we
        suppress recording to avoid polluting history.
        
        Screens with explicit back handlers (collection_detail, custom_lesson_detail)
        are not recorded to avoid navigation loops.
        """
        try:
            if getattr(self, '_nav_back_in_progress', False):
                return
            if not screen_name:
                return
            # Don't record detail screens with explicit back navigation
            if screen_name in ('collection_detail', 'custom_lesson_detail'):
                return
            hist = getattr(self, '_nav_history', None)
            if not isinstance(hist, list):
                hist = []
                self._nav_history = hist
            # Avoid duplicates
            if hist and hist[-1] == screen_name:
                return
            hist.append(screen_name)
            # Cap growth
            if len(hist) > 100:
                self._nav_history = hist[-100:]
        except Exception:
            pass

    def show_spoonfed_menu(self):
        """Delegate to the LessonsScreen implementation with loading overlay."""
        try:
            if getattr(self, 'root', None):
                ls = self.root.ids.get('lessons_screen')
                if ls and hasattr(ls, 'show_spoonfed_menu'):
                    loading = [None]
                    def _show_overlay(dt):
                        loading[0] = self._show_loading_overlay('Loading lessons')
                    overlay_event = Clock.schedule_once(_show_overlay, 0.5)
                    def _do_load(dt):
                        try:
                            ls.show_spoonfed_menu()
                        finally:
                            overlay_event.cancel()
                            if loading[0]:
                                loading[0]['dismiss']()
                    Clock.schedule_once(_do_load, 0)
        except Exception:
            pass

    def show_custom_lessons(self, query: str | None = None, record_nav: bool = True):
        """Navigate to custom lessons management screen."""
        try:
            sm = self._get_screen_manager()
            if sm:
                sm.current = 'custom_lessons'
                # Track current view for search
                self._current_lessons_view = 'custom'
                self._view_payload = {'query': (query or '').strip()}

                # If there's a search query, filter the lessons
                if query and query.strip():
                    self.on_custom_lessons_search()
                else:
                    self._load_custom_lessons_list()
        except Exception as e:
            Logger.error(f'CustomLessons: Error showing custom lessons: {e}')

    def _get_lesson_progress(self, lesson_id: int) -> tuple[int, int, int]:
        """Get progress stats for a custom lesson.
        
        Returns: (unknown_count, in_srs_count, known_count)
        - unknown: no SRS data (interval == 0)
        - in_srs: has SRS (0 < interval < 180)
        - known: mastered (interval >= 180)
        """
        import json
        
        try:
            conn = dict_db.init_db(get_db_path())
            entry_ids = dict_db.get_custom_lesson_entry_ids(conn, lesson_id)
            
            unknown = 0
            in_srs = 0
            known = 0
            
            cursor = conn.cursor()
            
            for entry_id in entry_ids:
                try:
                    # Get both interval column and JSON data
                    cursor.execute('SELECT interval, data FROM srs WHERE entry_id = ?', (entry_id,))
                    srs_row = cursor.fetchone()
                    
                    if srs_row:
                        interval_col = srs_row[0] or 0
                        max_interval = interval_col
                        
                        # Also check per_vector and per_kind in JSON data
                        if srs_row[1]:
                            try:
                                data = json.loads(srs_row[1])
                                # Check per_vector (vocab vectors, grammar fill-blank, kanji vectors)
                                per_vector = data.get('per_vector', {})
                                for vec_data in per_vector.values():
                                    vec_interval = vec_data.get('interval', 0) or 0
                                    if vec_interval > max_interval:
                                        max_interval = vec_interval
                                # Check per_kind (kana, grammar, kanji kind-level intervals)
                                per_kind = data.get('per_kind', {})
                                for kind_data in per_kind.values():
                                    kind_interval = kind_data.get('interval', 0) or 0
                                    if kind_interval > max_interval:
                                        max_interval = kind_interval
                            except (json.JSONDecodeError, TypeError):
                                pass
                        
                        # Classify based on max interval found
                        if max_interval >= 180:
                            known += 1
                        elif max_interval > 0:
                            in_srs += 1
                        else:
                            unknown += 1
                    else:
                        # No SRS data at all
                        unknown += 1
                        
                except Exception as e:
                    Logger.error(f'CustomLessons: Error checking progress for entry {entry_id}: {e}')
                    unknown += 1
            
            conn.close()
            return (unknown, in_srs, known)
            
        except Exception as e:
            Logger.error(f'CustomLessons: Error getting lesson progress: {e}')
            return (0, 0, 0)

    def _get_collection_progress(self, collection_id: int, all_lessons: list) -> tuple[int, int, int]:
        """Get aggregate progress stats for a collection (all child lessons).
        
        Args:
            collection_id: ID of the collection
            all_lessons: List of all lessons to find children
            
        Returns: (unknown_count, in_srs_count, known_count)
        """
        try:
            # Find all child lessons in this collection
            child_lessons = [l for l in all_lessons if l.get('parent_id') == collection_id]
            
            if not child_lessons:
                return (0, 0, 0)
            
            # Aggregate progress from all child lessons
            total_unknown = 0
            total_in_srs = 0
            total_known = 0
            
            for child in child_lessons:
                unknown, in_srs, known = self._get_lesson_progress(child['id'])
                total_unknown += unknown
                total_in_srs += in_srs
                total_known += known
            
            return (total_unknown, total_in_srs, total_known)
            
        except Exception as e:
            Logger.error(f'CustomLessons: Error getting collection progress: {e}')
            return (0, 0, 0)

    def _classify_srs_interval(self, max_interval: int) -> str:
        """Classify an entry based on its max SRS interval."""
        if max_interval >= 180:
            return 'known'
        elif max_interval > 0:
            return 'in_srs'
        return 'unknown'

    def _batch_get_srs_status(self, entry_ids: list[int]) -> dict[int, str]:
        """Batch-query SRS status for many entry_ids in one go.
        
        Returns: {entry_id: 'unknown'|'in_srs'|'known'}
        Missing entry_ids are classified as 'unknown'.
        """
        import json
        
        if not entry_ids:
            return {}
        
        result = {eid: 'unknown' for eid in entry_ids}
        
        try:
            conn = dict_db.init_db(get_db_path())
            cursor = conn.cursor()
            
            # Query in batches of 500 to avoid SQLite variable limit
            batch_size = 500
            for i in range(0, len(entry_ids), batch_size):
                batch = entry_ids[i:i + batch_size]
                placeholders = ','.join('?' * len(batch))
                cursor.execute(
                    f'SELECT entry_id, interval, data FROM srs WHERE entry_id IN ({placeholders})',
                    batch
                )
                for row in cursor.fetchall():
                    eid, interval_col, data_str = row
                    max_interval = interval_col or 0
                    
                    if data_str:
                        try:
                            data = json.loads(data_str)
                            for vec_data in data.get('per_vector', {}).values():
                                vi = vec_data.get('interval', 0) or 0
                                if vi > max_interval:
                                    max_interval = vi
                            for kind_data in data.get('per_kind', {}).values():
                                ki = kind_data.get('interval', 0) or 0
                                if ki > max_interval:
                                    max_interval = ki
                        except (json.JSONDecodeError, TypeError):
                            pass
                    
                    result[eid] = self._classify_srs_interval(max_interval)
            
            conn.close()
        except Exception as e:
            Logger.error(f'SRS: Batch query error: {e}')
        
        return result

    def _get_sakubo_lessons_progress_batch(self, collection_name: str) -> dict[str, tuple[int, int, int]]:
        """Get progress for ALL lessons in a Sakubo collection with a single batch query.
        
        Returns: {lesson_path: (unknown, in_srs, known)}
        """
        from pathlib import Path
        
        try:
            app = App.get_running_app()
            lessons_root = Path('dictionary') / 'lessons' / 'spoonfed_japanese'
            index_file = lessons_root / 'index.json'
            
            if not index_file.exists():
                return {}
            
            idx = app._load_lesson_json(index_file).get('lessons', {})
            
            def _norm(p):
                sp = str(p)
                if sp.lower().startswith('dictionary'):
                    return str(Path(sp))
                return str(lessons_root / Path(sp))
            
            # Define lesson ranges (must match show_*_lessons methods)
            ranges = {
                'kana': (1, 50), 'n5': (51, 263), 'n4': (264, 443),
                'n3': (444, 874), 'n2': (875, 1329), 'n1': (1330, 2062),
            }
            if collection_name not in ranges:
                return {}
            min_lesson, max_lesson = ranges[collection_name]
            
            # Phase 1: Collect all entry_ids per lesson
            # lesson_path -> list of entry_ids
            lesson_entry_ids: dict[str, list[int]] = {}
            all_entry_ids: list[int] = []
            
            for num, types in idx.items():
                n = int(num)
                if not (min_lesson <= n <= max_lesson):
                    continue
                
                # Path resolution must match the show methods:
                # kana: kana→grammar→vocab; n5-n1: vocab→grammar→fallback
                if collection_name == 'kana':
                    if 'kana' in types:
                        lp = _norm(types['kana'])
                    elif 'grammar' in types:
                        lp = _norm(types['grammar'])
                    elif 'vocab' in types:
                        lp = _norm(types['vocab'])
                    elif types:
                        lp = _norm(list(types.values())[0])
                    else:
                        continue
                else:
                    resolved = types.get('vocab') or types.get('grammar') or (list(types.values())[0] if types else None)
                    if not resolved:
                        continue
                    lp = _norm(resolved)
                
                lesson_data = app._load_lesson_json(lp)
                eids = []
                
                if lesson_data.get('lesson_type') == 'grammar':
                    eid = lesson_data.get('entry_id')
                    if not eid:
                        g_items = lesson_data.get('items', [])
                        if g_items:
                            eid = g_items[0].get('entry_id')
                    if eid:
                        eids.append(eid)
                else:
                    for item in lesson_data.get('items', []):
                        eid = item.get('entry_id')
                        if eid:
                            eids.append(eid)
                
                lesson_entry_ids[lp] = eids
                all_entry_ids.extend(eids)
            
            # Phase 2: One batch SRS query for ALL entry_ids
            srs_status = self._batch_get_srs_status(all_entry_ids)
            
            # Phase 3: Tally per lesson
            result = {}
            for lp, eids in lesson_entry_ids.items():
                unknown = sum(1 for eid in eids if srs_status.get(eid, 'unknown') == 'unknown')
                in_srs = sum(1 for eid in eids if srs_status.get(eid, 'unknown') == 'in_srs')
                known = sum(1 for eid in eids if srs_status.get(eid, 'unknown') == 'known')
                result[lp] = (unknown, in_srs, known)
            
            return result
            
        except Exception as e:
            Logger.error(f'Sakubo: Batch progress error for {collection_name}: {e}')
            return {}

    def _get_sakubo_lesson_progress(self, lesson_path: str) -> tuple[int, int, int]:
        """Get progress stats for a single Sakubo lesson file.
        
        Returns: (unknown_count, in_srs_count, known_count)
        """
        import json
        
        try:
            app = App.get_running_app()
            lesson_data = app._load_lesson_json(lesson_path)
            
            # Collect entry_ids to check
            entry_ids = []
            
            # Grammar lessons have entry_id at top level or in items[0]
            if lesson_data.get('lesson_type') == 'grammar':
                eid = lesson_data.get('entry_id')
                if not eid:
                    g_items = lesson_data.get('items', [])
                    if g_items:
                        eid = g_items[0].get('entry_id')
                if eid:
                    entry_ids.append(eid)
            else:
                # Vocab/kana lessons have entry_ids inside items
                items = lesson_data.get('items', [])
                for item in items:
                    eid = item.get('entry_id')
                    if eid:
                        entry_ids.append(eid)
            
            if not entry_ids:
                return (0, 0, 0)
            
            conn = dict_db.init_db(get_db_path())
            cursor = conn.cursor()
            
            unknown = 0
            in_srs = 0
            known = 0
            
            for entry_id in entry_ids:
                try:
                    cursor.execute('SELECT interval, data FROM srs WHERE entry_id = ?', (entry_id,))
                    srs_row = cursor.fetchone()
                    
                    if srs_row:
                        interval_col = srs_row[0] or 0
                        max_interval = interval_col
                        
                        # Check per_vector and per_kind in JSON data
                        if srs_row[1]:
                            try:
                                data = json.loads(srs_row[1])
                                # Check per_vector (vocab vectors, grammar fill-blank, kanji vectors)
                                per_vector = data.get('per_vector', {})
                                for vec_data in per_vector.values():
                                    vec_interval = vec_data.get('interval', 0) or 0
                                    if vec_interval > max_interval:
                                        max_interval = vec_interval
                                # Check per_kind (kana, grammar, kanji kind-level intervals)
                                per_kind = data.get('per_kind', {})
                                for kind_data in per_kind.values():
                                    kind_interval = kind_data.get('interval', 0) or 0
                                    if kind_interval > max_interval:
                                        max_interval = kind_interval
                            except (json.JSONDecodeError, TypeError):
                                pass
                        
                        if max_interval >= 180:
                            known += 1
                        elif max_interval > 0:
                            in_srs += 1
                        else:
                            unknown += 1
                    else:
                        unknown += 1
                        
                except Exception:
                    unknown += 1
            
            conn.close()
            return (unknown, in_srs, known)
            
        except Exception as e:
            Logger.error(f'Sakubo: Error getting lesson progress for {lesson_path}: {e}')
            return (0, 0, 0)

    def _get_sakubo_collection_progress(self, collection_name: str) -> tuple[int, int, int]:
        """Get aggregate progress for a Sakubo collection.
        
        Args:
            collection_name: 'kana', 'n5', 'n4', 'n3', 'n2', 'n1'
            
        Returns: (unknown_count, in_srs_count, known_count)
        """
        try:
            progress_batch = self._get_sakubo_lessons_progress_batch(collection_name)
            total_unknown = sum(v[0] for v in progress_batch.values())
            total_in_srs = sum(v[1] for v in progress_batch.values())
            total_known = sum(v[2] for v in progress_batch.values())
            return (total_unknown, total_in_srs, total_known)
        except Exception as e:
            Logger.error(f'Sakubo: Error getting collection progress for {collection_name}: {e}')
            return (0, 0, 0)

    def _load_custom_lessons_list(self):
        """Load and display all custom lessons in the list (async)."""
        try:
            grid = self.root.ids.get('custom_lessons_grid')
            if not grid:
                return
            
            grid.clear_widgets()

            # Show loading state immediately
            loading_label = Label(
                text='Loading lessons...',
                size_hint_y=None, height=dp(100),
                halign='center', valign='middle',
                font_name='fonts/NotoSansJP-Regular.ttf',
                color=(0.65, 0.63, 0.60, 1)
            )
            loading_label.bind(size=loading_label.setter('text_size'))
            grid.add_widget(loading_label)

            # Capture filter state before threading
            filter_collections_btn = self.root.ids.get('custom_lessons_filter_collections')
            filter_lessons_btn = self.root.ids.get('custom_lessons_filter_lessons')
            active_filter = 'all'
            if filter_collections_btn and filter_collections_btn.state == 'down':
                active_filter = 'collections'
            elif filter_lessons_btn and filter_lessons_btn.state == 'down':
                active_filter = 'lessons'

            search_input = self.root.ids.get('lessons_search_input')
            query = ''
            query_raw = ''
            if search_input and search_input.text.strip():
                query_raw = search_input.text.strip()
                query = query_raw.lower()

            app = App.get_running_app()

            def _fetch_data():
                """Background: fetch lessons, progress, FTS data."""
                conn = dict_db.init_db(get_db_path())
                lessons = dict_db.get_all_custom_lessons(conn)
                conn.close()

                if not lessons:
                    return {'lessons': [], 'rows': [], 'shown_count': 0}

                # FTS search
                _fts_match_ids = None
                _entry_ids_by_lesson = {}
                if query:
                    try:
                        _fc = dict_db.init_db(get_db_path())
                        _fts_match_ids = {row[0] for row in dict_db.search_entries(_fc, query_raw, limit=10000)}
                        _all_lids = [l['id'] for l in lessons if not l.get('is_collection')]
                        if _all_lids:
                            _cur2 = _fc.cursor()
                            _cur2.execute('SELECT lesson_id, entry_id FROM custom_lesson_items WHERE lesson_id IN ({})'.format(','.join('?'*len(_all_lids))), _all_lids)
                            for _r in _cur2.fetchall():
                                _entry_ids_by_lesson.setdefault(_r[0], []).append(_r[1])
                        _fc.close()
                    except Exception:
                        pass

                rows = []
                for lesson in lessons:
                    if lesson.get('parent_id') is not None:
                        continue
                    is_collection = lesson.get('is_collection', False)
                    if active_filter == 'collections' and not is_collection:
                        continue
                    if active_filter == 'lessons' and is_collection:
                        continue
                    type_label = 'Collection' if is_collection else 'Lesson'
                    if is_collection:
                        child_count = sum(1 for l in lessons if l.get('parent_id') == lesson['id'])
                        count_text = f"({child_count} lessons)"
                    else:
                        count_text = f"({lesson['item_count']} items)"
                    if query:
                        name_match = query in lesson['name'].lower()
                        type_match = query in type_label.lower()
                        if not name_match and not type_match:
                            if _fts_match_ids is not None:
                                if is_collection:
                                    _cids = [l['id'] for l in lessons if l.get('parent_id') == lesson['id']]
                                    _hit = any(eid in _fts_match_ids for cid in _cids for eid in _entry_ids_by_lesson.get(cid, []))
                                else:
                                    _hit = any(eid in _fts_match_ids for eid in _entry_ids_by_lesson.get(lesson['id'], []))
                                if not _hit:
                                    continue
                            else:
                                continue
                    lesson_id = f"custom_lesson:{lesson['id']}"
                    if is_collection:
                        child_lessons = [l for l in lessons if l.get('parent_id') == lesson['id']]
                        is_queued = all(f"custom_lesson:{l['id']}" in getattr(app, '_lesson_queue', []) for l in child_lessons) if child_lessons else False
                    else:
                        is_queued = lesson_id in getattr(app, '_lesson_queue', [])
                    unknown_count = 0
                    in_srs_count = 0
                    known_count = 0
                    if is_collection:
                        unknown_count, in_srs_count, known_count = self._get_collection_progress(lesson['id'], lessons)
                    elif lesson['item_count'] > 0:
                        unknown_count, in_srs_count, known_count = self._get_lesson_progress(lesson['id'])
                    rows.append({
                        'lesson': lesson,
                        'lesson_id': lesson_id,
                        'is_collection': is_collection,
                        'type_label': type_label,
                        'count_text': count_text,
                        'is_queued': is_queued,
                        'unknown_count': unknown_count,
                        'in_srs_count': in_srs_count,
                        'known_count': known_count,
                    })
                return {'lessons': lessons, 'rows': rows, 'shown_count': len(rows)}

            def _build_ui(dt):
                """Main thread: build widgets from pre-fetched data."""
                try:
                    data = _result[0]
                    grid.clear_widgets()

                    if not data['lessons']:
                        label = Label(
                            text='No custom lessons yet.\nClick "New Lesson/Collection" to get started!',
                            size_hint_y=None, height=dp(100),
                            halign='center', valign='middle',
                            font_name='fonts/NotoSansJP-Regular.ttf',
                            color=(0.4, 0.4, 0.4, 1)
                        )
                        label.bind(size=label.setter('text_size'))
                        grid.add_widget(label)
                        return

                    if data['shown_count'] == 0:
                        msg = 'No matching lessons found.'
                        if active_filter != 'all':
                            msg = f'No {active_filter} found.'
                        if query:
                            msg = f'No results for "{query_raw}".'
                        label = Label(
                            text=msg, size_hint_y=None, height=dp(100),
                            halign='center', valign='middle',
                            font_name='fonts/NotoSansJP-Regular.ttf',
                            color=(0.4, 0.4, 0.4, 1)
                        )
                        label.bind(size=label.setter('text_size'))
                        grid.add_widget(label)
                        return

                    from kivy.uix.behaviors import ButtonBehavior
                    from kivy.graphics import Color, Rectangle

                    class LessonButton(ButtonBehavior, BoxLayout):
                        def __init__(self, **kwargs):
                            super().__init__(**kwargs)
                            with self.canvas.before:
                                Color(0.35, 0.35, 0.35, 1)
                                self.rect = Rectangle(pos=self.pos, size=self.size)
                            self.bind(pos=self._update_rect, size=self._update_rect)
                        def _update_rect(self, *args):
                            self.rect.pos = self.pos
                            self.rect.size = self.size

                    for row_data in data['rows']:
                        lesson = row_data['lesson']
                        is_collection = row_data['is_collection']
                        unknown_count = row_data['unknown_count']
                        in_srs_count = row_data['in_srs_count']
                        known_count = row_data['known_count']

                        container = BoxLayout(orientation='vertical', size_hint_y=None, height=dp(48), spacing=0)
                        row = BoxLayout(size_hint_y=None, height=dp(44), spacing=dp(8))

                        lbl_container = LessonButton(orientation='horizontal', padding=[dp(10), dp(4)])
                        left_box = BoxLayout(orientation='vertical', size_hint_x=0.7, spacing=0)
                        name_label = Label(
                            text=lesson['name'], halign='left', valign='bottom',
                            font_name='fonts/NotoSansJP-Regular.ttf', font_size='14sp',
                            color=(0.9, 0.88, 0.85, 1), size_hint_y=0.6,
                            shorten=True, shorten_from='right', text_size=(None, None)
                        )
                        name_label.bind(width=lambda s, w: setattr(s, 'text_size', (w, None)))
                        count_label = Label(
                            text=row_data['count_text'], halign='left', valign='top',
                            font_name='fonts/NotoSansJP-Regular.ttf', font_size='11sp',
                            color=(0.65, 0.63, 0.60, 1), size_hint_y=0.4
                        )
                        count_label.bind(size=lambda s, w: setattr(s, 'text_size', (w[0], None)))
                        left_box.add_widget(name_label)
                        left_box.add_widget(count_label)
                        type_label_widget = Label(
                            text=row_data['type_label'], size_hint_x=0.3, halign='right', valign='middle',
                            font_name='fonts/NotoSansJP-Regular.ttf', font_size='12sp',
                            color=(0.65, 0.63, 0.60, 1)
                        )
                        type_label_widget.bind(size=lambda s, w: setattr(s, 'text_size', (w[0], None)))
                        lbl_container.add_widget(left_box)
                        lbl_container.add_widget(type_label_widget)

                        if is_collection:
                            lbl_container.bind(on_release=lambda *_, lid=lesson['id']: self._view_collection_detail(lid))
                        else:
                            lbl_container.bind(on_release=lambda *_, lid=lesson['id']: self._view_custom_lesson_detail(lid))
                        row.add_widget(lbl_container)

                        action_btn = Button(
                            text='\ue145', size_hint=(None, None), width=dp(44), height=dp(44),
                            font_name='fonts/MaterialSymbolsOutlined.ttf', font_size='18sp',
                            background_normal='', background_down='',
                            background_color=(0.20, 0.45, 0.25, 1) if row_data['is_queued'] else (0.22, 0.22, 0.25, 1),
                            color=(0.90, 0.88, 0.85, 1), halign='center', valign='middle'
                        )
                        action_btn.text_size = (dp(44), dp(44))
                        def make_action_handler(lid, lname, is_coll, raw_id):
                            def handler(*args):
                                self._show_custom_lesson_action_popup(lid, lname, is_coll, raw_id)
                            return handler
                        action_btn.bind(on_release=make_action_handler(
                            row_data['lesson_id'], lesson['name'], is_collection, lesson['id']
                        ))
                        row.add_widget(action_btn)
                        container.add_widget(row)

                        total = unknown_count + in_srs_count + known_count
                        if total > 0:
                            progress_row = BoxLayout(size_hint_y=None, height=dp(4), spacing=dp(8))
                            progress_bar = BoxLayout(spacing=0)
                            unknown_pct = unknown_count / total
                            in_srs_pct = in_srs_count / total
                            known_pct = known_count / total
                            if known_count > 0:
                                known_widget = Widget(size_hint_x=known_pct)
                                with known_widget.canvas.before:
                                    Color(0.545, 0.459, 0.125, 1)
                                    known_widget.rect = Rectangle(pos=known_widget.pos, size=known_widget.size)
                                known_widget.bind(
                                    pos=lambda inst, val: setattr(inst.rect, 'pos', val),
                                    size=lambda inst, val: setattr(inst.rect, 'size', val)
                                )
                                progress_bar.add_widget(known_widget)
                            if in_srs_count > 0:
                                in_srs_widget = Widget(size_hint_x=in_srs_pct)
                                with in_srs_widget.canvas.before:
                                    Color(0.15, 0.65, 0.15, 1)
                                    in_srs_widget.rect = Rectangle(pos=in_srs_widget.pos, size=in_srs_widget.size)
                                in_srs_widget.bind(
                                    pos=lambda inst, val: setattr(inst.rect, 'pos', val),
                                    size=lambda inst, val: setattr(inst.rect, 'size', val)
                                )
                                progress_bar.add_widget(in_srs_widget)
                            if unknown_count > 0:
                                unknown_widget = Widget(size_hint_x=unknown_pct)
                                with unknown_widget.canvas.before:
                                    Color(0.85, 0.20, 0.15, 1)
                                    unknown_widget.rect = Rectangle(pos=unknown_widget.pos, size=unknown_widget.size)
                                unknown_widget.bind(
                                    pos=lambda inst, val: setattr(inst.rect, 'pos', val),
                                    size=lambda inst, val: setattr(inst.rect, 'size', val)
                                )
                                progress_bar.add_widget(unknown_widget)
                            progress_row.add_widget(progress_bar)
                            progress_row.add_widget(Widget(size_hint_x=None, width=dp(44)))
                            container.add_widget(progress_row)
                        grid.add_widget(container)
                except Exception as e:
                    Logger.error(f'CustomLessons: Error building lessons UI: {e}')
                    import traceback
                    traceback.print_exc()

            _result = [None]
            def _do_fetch():
                _result[0] = _fetch_data()
                Clock.schedule_once(_build_ui, 0)

            import threading
            threading.Thread(target=_do_fetch, daemon=True).start()
                
        except Exception as e:
            Logger.error(f'CustomLessons: Error loading lessons list: {e}')
            import traceback
            traceback.print_exc()
    
    def on_custom_lessons_filter_change(self):
        """Handle filter toggle change on custom lessons page."""
        self._load_custom_lessons_list()
    
    def _toggle_collection_expansion(self, collection_id):
        """Toggle the expansion state of a collection."""
        if not hasattr(self, '_expanded_collections'):
            self._expanded_collections = set()
        
        if collection_id in self._expanded_collections:
            self._expanded_collections.remove(collection_id)
        else:
            self._expanded_collections.add(collection_id)
        
        # Reload the list to reflect the change
        self._load_custom_lessons_list()
    
    def _toggle_collection_queue(self, collection_id):
        """Toggle all lessons in a collection to/from the queue."""
        try:
            conn = dict_db.init_db(get_db_path())
            all_lessons = dict_db.get_all_custom_lessons(conn)
            conn.close()
            
            # Get all child lessons
            child_lessons = [l for l in all_lessons if l.get('parent_id') == collection_id]
            
            if not child_lessons:
                Logger.info(f'Collection {collection_id} has no lessons')
                return
            
            # Check if all are queued
            app = App.get_running_app()
            if not hasattr(app, '_lesson_queue'):
                app._lesson_queue = []
            
            child_ids = [f"custom_lesson:{l['id']}" for l in child_lessons]
            all_queued = all(cid in app._lesson_queue for cid in child_ids)
            
            if all_queued:
                # Remove all from queue
                for cid in child_ids:
                    if cid in app._lesson_queue:
                        app._lesson_queue.remove(cid)
                app._save_lesson_queue()
                Logger.info(f'Removed collection {collection_id} lessons from queue')
            else:
                # Add all to queue (that aren't already there) — ask position
                to_add = [cid for cid in child_ids if cid not in app._lesson_queue]
                def _do_add(position):
                    if position == 'front':
                        for i, cid in enumerate(to_add):
                            app._lesson_queue.insert(i, cid)
                    else:
                        app._lesson_queue.extend(to_add)
                    app._save_lesson_queue()
                    Logger.info(f'Added collection {collection_id} lessons to queue ({position})')
                    app._refresh_lesson_menus()
                app._show_queue_position_popup(_do_add)
                return
            
        except Exception as e:
            Logger.error(f'Error toggling collection queue: {e}')
    
    def _show_custom_lesson_action_popup(self, lesson_queue_id: str, lesson_name: str, is_collection: bool, raw_id: int):
        """Show action popup for a custom lesson/collection row."""
        from kivy.uix.popup import Popup
        from kivy.uix.boxlayout import BoxLayout
        from kivy.uix.button import Button
        from kivy.uix.label import Label
        
        app = App.get_running_app()
        
        content = BoxLayout(orientation='vertical', padding=dp(12), spacing=dp(8))
        
        popup = Popup(
            title=lesson_name,
            content=content,
            size_hint=(0.8, None),
            height=dp(276) if is_collection else dp(330),
            background_color=(0.11, 0.11, 0.12, 1)
        )
        
        BTN_FONT = 'fonts/NotoSansJP-Regular.ttf'
        BTN_H = dp(48)
        
        # Add to Queue / Remove from Queue
        if is_collection:
            conn = dict_db.init_db(get_db_path())
            all_lessons = dict_db.get_all_custom_lessons(conn)
            conn.close()
            child_lessons = [l for l in all_lessons if l.get('parent_id') == raw_id]
            child_ids = [f"custom_lesson:{l['id']}" for l in child_lessons]
            is_queued = all(cid in getattr(app, '_lesson_queue', []) for cid in child_ids) if child_ids else False
        else:
            is_queued = lesson_queue_id in getattr(app, '_lesson_queue', [])
        
        queue_btn = Button(
            text='Remove from Queue' if is_queued else 'Add to Queue',
            size_hint_y=None, height=BTN_H,
            background_normal='', background_down='',
            background_color=(0.20, 0.45, 0.25, 1),
            color=(0.90, 0.88, 0.85, 1),
            font_name=BTN_FONT
        )
        def _toggle_queue(*_):
            popup.dismiss()
            if is_collection:
                self._toggle_collection_queue(raw_id)
            else:
                app.toggle_lesson_queue(lesson_queue_id)
            app._custom_lessons_needs_reload = True
            self._load_custom_lessons_list()
        queue_btn.bind(on_release=_toggle_queue)
        content.add_widget(queue_btn)
        
        # Add to Collection (lessons only, not collections)
        if not is_collection:
            add_coll_btn = Button(
                text='Add to Collection',
                size_hint_y=None, height=BTN_H,
                background_normal='', background_down='',
                background_color=(0.25, 0.35, 0.50, 1),
                color=(0.90, 0.88, 0.85, 1),
                font_name=BTN_FONT
            )
            def _add_to_collection(*_):
                popup.dismiss()
                self._show_add_to_collection_picker(raw_id, lesson_name)
            add_coll_btn.bind(on_release=_add_to_collection)
            content.add_widget(add_coll_btn)
        
        # Delete
        delete_btn = Button(
            text='Delete',
            size_hint_y=None, height=BTN_H,
            background_normal='', background_down='',
            background_color=(0.65, 0.15, 0.15, 1),
            color=(1, 1, 1, 1),
            font_name=BTN_FONT
        )
        def _delete(*_):
            popup.dismiss()
            self._confirm_delete_custom_lesson(raw_id, lesson_name)
        delete_btn.bind(on_release=_delete)
        content.add_widget(delete_btn)
        
        # Close
        close_btn = Button(
            text='Close',
            size_hint_y=None, height=BTN_H,
            background_normal='', background_down='',
            background_color=(0.30, 0.30, 0.32, 1),
            color=(0.90, 0.88, 0.85, 1),
            font_name=BTN_FONT
        )
        close_btn.bind(on_release=lambda *_: popup.dismiss())
        content.add_widget(close_btn)
        
        popup.open()
    
    def _show_add_to_collection_picker(self, lesson_id: int, lesson_name: str):
        """Show popup to pick a collection to add a lesson to."""
        from kivy.uix.popup import Popup
        from kivy.uix.boxlayout import BoxLayout
        from kivy.uix.scrollview import ScrollView
        from kivy.uix.gridlayout import GridLayout
        from kivy.uix.button import Button
        from kivy.uix.label import Label
        
        conn = dict_db.init_db(get_db_path())
        all_lessons = dict_db.get_all_custom_lessons(conn)
        conn.close()
        
        # Find all collections
        collections = [l for l in all_lessons if l.get('is_collection', False)]
        
        layout = BoxLayout(orientation='vertical', spacing=dp(8), padding=dp(8))
        
        if not collections:
            label = Label(
                text='No collections exist yet.\nCreate one from the New Lesson/Collection button.',
                halign='center', valign='middle',
                font_name='fonts/NotoSansJP-Regular.ttf',
                color=(0.90, 0.88, 0.85, 1)
            )
            label.bind(size=label.setter('text_size'))
            layout.add_widget(label)
            
            close_btn = Button(
                text='Close', size_hint_y=None, height=dp(48),
                background_normal='', background_down='',
                background_color=(0.25, 0.35, 0.50, 1),
                color=(0.90, 0.88, 0.85, 1),
                font_name='fonts/NotoSansJP-Regular.ttf'
            )
            layout.add_widget(close_btn)
            
            popup = Popup(
                title=f'Add "{lesson_name}" to Collection',
                content=layout, size_hint=(0.85, 0.4),
                background_color=(0.11, 0.11, 0.12, 1)
            )
            close_btn.bind(on_release=popup.dismiss)
            popup.open()
            return
        
        scroll = ScrollView(do_scroll_x=False)
        grid = GridLayout(cols=1, spacing=dp(6), size_hint_y=None)
        grid.bind(minimum_height=grid.setter('height'))
        
        popup = Popup(
            title=f'Add "{lesson_name}" to Collection',
            content=layout, size_hint=(0.85, 0.6),
            background_color=(0.11, 0.11, 0.12, 1)
        )
        
        def add_to_collection(collection_id):
            try:
                conn = dict_db.init_db(get_db_path())
                cur = conn.cursor()
                cur.execute('SELECT MAX(display_order) FROM custom_lessons WHERE parent_id = ?', (collection_id,))
                max_order = cur.fetchone()[0] or 0
                cur.execute('UPDATE custom_lessons SET parent_id = ?, display_order = ? WHERE id = ?', (collection_id, max_order + 1, lesson_id))
                conn.commit()
                conn.close()
                self._custom_lessons_needs_reload = True
                self._load_custom_lessons_list()
                popup.dismiss()
            except Exception as e:
                Logger.error(f'Collections: Error adding lesson to collection: {e}')
        
        for coll in collections:
            child_count = sum(1 for l in all_lessons if l.get('parent_id') == coll['id'])
            btn = Button(
                text=f"{coll['name']} ({child_count} lessons)",
                size_hint_y=None, height=dp(48),
                background_normal='', background_down='',
                background_color=(0.22, 0.22, 0.25, 1),
                color=(0.90, 0.88, 0.85, 1),
                font_name='fonts/NotoSansJP-Regular.ttf'
            )
            btn.bind(on_release=lambda x, cid=coll['id']: add_to_collection(cid))
            grid.add_widget(btn)
        
        scroll.add_widget(grid)
        layout.add_widget(scroll)
        popup.open()

    def _confirm_delete_custom_lesson(self, lesson_id: int, lesson_name: str):
        """Show confirmation popup before deleting a custom lesson."""
        from kivy.uix.popup import Popup
        from kivy.uix.boxlayout import BoxLayout
        from kivy.uix.button import Button
        from kivy.uix.label import Label
        
        content = BoxLayout(orientation='vertical', padding=dp(20), spacing=dp(15))
        
        # Confirmation message
        msg_label = Label(
            text=f'Are you sure you want to delete\n"{lesson_name}"?',
            size_hint_y=None,
            height=dp(80),
            font_name='fonts/NotoSansJP-Regular.ttf',
            color=(0.90, 0.88, 0.85, 1),
            halign='center'
        )
        msg_label.bind(size=msg_label.setter('text_size'))
        
        # Button row
        button_row = BoxLayout(size_hint_y=None, height=dp(50), spacing=dp(10))
        
        # No button (red)
        no_btn = Button(
            text='No',
            background_normal='',
            background_down='',
            background_color=(0.85, 0.30, 0.25, 1),
            color=(1, 1, 1, 1),
            font_name='fonts/NotoSansJP-Medium.ttf'
        )
        
        # Yes button (green)
        yes_btn = Button(
            text='Yes',
            background_normal='',
            background_down='',
            background_color=(0.15, 0.65, 0.15, 1),
            color=(1, 1, 1, 1),
            font_name='fonts/NotoSansJP-Medium.ttf'
        )
        
        popup = Popup(
            title='Delete Lesson',
            content=content,
            size_hint=(0.8, None),
            height=dp(220),
            auto_dismiss=False
        )
        
        no_btn.bind(on_release=lambda x: popup.dismiss())
        yes_btn.bind(on_release=lambda x: (popup.dismiss(), self._delete_custom_lesson_internal(lesson_id)))
        
        button_row.add_widget(no_btn)
        button_row.add_widget(yes_btn)
        
        content.add_widget(msg_label)
        content.add_widget(button_row)
        
        popup.open()
    
    def _delete_custom_lesson_internal(self, lesson_id: int):
        """Delete a custom lesson (internal implementation)."""
        try:
            conn = dict_db.init_db(get_db_path())
            
            # Remove from queue if present
            lesson_queue_id = f"custom_lesson:{lesson_id}"
            app = App.get_running_app()
            if lesson_queue_id in getattr(app, '_lesson_queue', []):
                app._lesson_queue.remove(lesson_queue_id)
                app.save_lesson_queue()
            
            # Delete the lesson
            dict_db.delete_custom_lesson(conn, lesson_id)
            conn.close()
            
            # Reload the list
            self._custom_lessons_needs_reload = True
            self._load_custom_lessons_list()
            
            Logger.info(f'CustomLessons: Deleted lesson {lesson_id}')
            
        except Exception as e:
            Logger.error(f'CustomLessons: Error deleting lesson: {e}')
            import traceback
            traceback.print_exc()
    
    def _confirm_delete_custom_lesson_from_detail(self, lesson_id: int, lesson_name: str):
        """Show confirmation popup before deleting a custom lesson from detail screen."""
        from kivy.uix.popup import Popup
        from kivy.uix.boxlayout import BoxLayout
        from kivy.uix.button import Button
        from kivy.uix.label import Label
        
        content = BoxLayout(orientation='vertical', padding=dp(20), spacing=dp(15))
        
        # Confirmation message
        msg_label = Label(
            text=f'Are you sure you want to delete\n"{lesson_name}"?',
            size_hint_y=None,
            height=dp(80),
            font_name='fonts/NotoSansJP-Regular.ttf',
            color=(0.90, 0.88, 0.85, 1),
            halign='center'
        )
        msg_label.bind(size=msg_label.setter('text_size'))
        
        # Button row
        button_row = BoxLayout(size_hint_y=None, height=dp(50), spacing=dp(10))
        
        # No button (red)
        no_btn = Button(
            text='No',
            background_normal='',
            background_down='',
            background_color=(0.85, 0.30, 0.25, 1),
            color=(1, 1, 1, 1),
            font_name='fonts/NotoSansJP-Medium.ttf'
        )
        
        # Yes button (green)
        yes_btn = Button(
            text='Yes',
            background_normal='',
            background_down='',
            background_color=(0.15, 0.65, 0.15, 1),
            color=(1, 1, 1, 1),
            font_name='fonts/NotoSansJP-Medium.ttf'
        )
        
        popup = Popup(
            title='Delete Lesson',
            content=content,
            size_hint=(0.8, None),
            height=dp(220),
            auto_dismiss=False
        )
        
        no_btn.bind(on_release=lambda x: popup.dismiss())
        yes_btn.bind(on_release=lambda x: (popup.dismiss(), self._delete_custom_lesson_and_go_back(lesson_id)))
        
        button_row.add_widget(no_btn)
        button_row.add_widget(yes_btn)
        
        content.add_widget(msg_label)
        content.add_widget(button_row)
        
        popup.open()
    
    def _delete_custom_lesson_and_go_back(self, lesson_id: int):
        """Delete a custom lesson and navigate back to custom lessons list."""
        try:
            conn = dict_db.init_db(get_db_path())
            
            # Remove from queue if present
            lesson_queue_id = f"custom_lesson:{lesson_id}"
            app = App.get_running_app()
            if lesson_queue_id in getattr(app, '_lesson_queue', []):
                app._lesson_queue.remove(lesson_queue_id)
                app.save_lesson_queue()
            
            # Delete the lesson
            dict_db.delete_custom_lesson(conn, lesson_id)
            conn.close()
            
            Logger.info(f'CustomLessons: Deleted lesson {lesson_id}')
            
            # Navigate back to custom lessons list
            sm = app._get_screen_manager()
            if sm:
                sm.current = 'custom_lessons'
                # Reload the list
                self._custom_lessons_needs_reload = True
                self._load_custom_lessons_list()
            
        except Exception as e:
            Logger.error(f'CustomLessons: Error deleting lesson: {e}')
            import traceback
            traceback.print_exc()

    def _add_all_custom_lessons_to_queue(self):
        """Add all custom lessons to queue (only those with new vectors)."""
        try:
            conn = dict_db.init_db(get_db_path())
            lessons = dict_db.get_all_custom_lessons(conn)
            conn.close()
            
            app = App.get_running_app()
            added_count = 0
            skipped_count = 0
            
            for lesson in lessons:
                lesson_id = f"custom_lesson:{lesson['id']}"
                if lesson_id not in getattr(app, '_lesson_queue', []):
                    # Only add if lesson has new vectors
                    if app._lesson_has_new_vectors(lesson_id):
                        app.toggle_lesson_queue(lesson_id)
                        added_count += 1
                    else:
                        skipped_count += 1
                        Logger.info(f'CustomLessons: Skipped lesson {lesson["id"]} - all vectors in SRS')
            
            Logger.info(f'CustomLessons: Added {added_count} lessons, skipped {skipped_count} (already mastered)')
            
            # Reload the list to update buttons
            self._load_custom_lessons_list()
            
        except Exception as e:
            Logger.error(f'CustomLessons: Error adding all to queue: {e}')
    
    def _remove_all_custom_lessons_from_queue(self):
        """Remove all custom lessons from queue."""
        try:
            conn = dict_db.init_db(get_db_path())
            lessons = dict_db.get_all_custom_lessons(conn)
            conn.close()
            
            app = App.get_running_app()
            for lesson in lessons:
                lesson_id = f"custom_lesson:{lesson['id']}"
                if lesson_id in getattr(app, '_lesson_queue', []):
                    app.toggle_lesson_queue(lesson_id)
            
            # Reload the list to update buttons
            self._load_custom_lessons_list()
            
        except Exception as e:
            Logger.error(f'CustomLessons: Error removing all from queue: {e}')

    def on_custom_lessons_search(self):
        """Filter custom lessons by search query (delegates to unified list builder)."""
        self._load_custom_lessons_list()

