    def _show_create_lesson_dialog(self, is_collection=False):
        """Show dialog to create a lesson or collection with name input."""
        try:
            from kivy.uix.popup import Popup
            from kivy.uix.textinput import TextInput
            from kivy.uix.widget import Widget
            
            item_type = "Collection" if is_collection else "Lesson"
            
            content = BoxLayout(orientation='vertical', spacing=dp(8), padding=dp(8))
            
            # Add spacing widget to push label below separator line
            content.add_widget(Widget(size_hint_y=None, height=dp(20)))
            
            label = Label(
                text=f'Enter {item_type.lower()} name:',
                size_hint_y=None,
                height=dp(30),
                color=(0.90, 0.88, 0.85, 1),
                font_name='fonts/NotoSansJP-Regular.ttf'
            )
            content.add_widget(label)
            
            name_input = TextInput(
                multiline=False,
                size_hint_y=None,
                height=dp(40),
                font_name='fonts/NotoSansJP-Regular.ttf'
            )
            content.add_widget(name_input)
            
            # Collection selection (only for lessons, not for collections)
            collection_spinner = None
            if not is_collection:
                # Get list of collections
                conn = dict_db.init_db(get_db_path())
                all_lessons = dict_db.get_all_custom_lessons(conn)
                conn.close()
                
                collections = [{'id': None, 'name': '(No Collection)'}]
                collections.extend([l for l in all_lessons if l.get('is_collection')])
                
                if len(collections) > 1:  # Only show if there are actual collections
                    from kivy.uix.spinner import Spinner
                    collection_label = Label(
                        text='Add to collection:',
                        size_hint_y=None,
                        height=dp(25),
                        color=(0.90, 0.88, 0.85, 1),
                        font_name='fonts/NotoSansJP-Regular.ttf',
                        font_size='12sp'
                    )
                    content.add_widget(collection_label)
                    
                    collection_names = [c['name'] for c in collections]
                    collection_spinner = Spinner(
                        text=collection_names[0],
                        values=collection_names,
                        size_hint_y=None,
                        height=dp(40),
                        background_normal='',
                        background_down='',
                        background_color=(0.85, 0.85, 0.85, 1),
                        color=(0.90, 0.88, 0.85, 1),
                        font_name='fonts/NotoSansJP-Regular.ttf'
                    )
                    content.add_widget(collection_spinner)
            
            buttons = BoxLayout(size_hint_y=None, height=dp(44), spacing=dp(8))
            
            popup = Popup(
                title=f'Create {item_type}',
                content=content,
                size_hint=(0.8, None),
                height=dp(280) if collection_spinner else dp(180),
                separator_color=(0, 0, 0, 0)
            )
            
            cancel_btn = Button(
                text='Cancel',
                background_normal='',
                background_down='',
                background_color=(0.6, 0.6, 0.6, 1),
                color=(1, 1, 1, 1),
                font_name='fonts/NotoSansJP-Regular.ttf'
            )
            cancel_btn.bind(on_release=popup.dismiss)
            buttons.add_widget(cancel_btn)
            
            create_btn = Button(
                text='Create',
                background_normal='',
                background_down='',
                background_color=(0.15, 0.65, 0.35, 1),
                color=(1, 1, 1, 1),
                font_name='fonts/NotoSansJP-Regular.ttf'
            )
            
            def create_item(*args):
                name = name_input.text.strip()
                if not name:
                    return
                
                # Get parent_id from spinner if applicable
                parent_id = None
                if collection_spinner and not is_collection:
                    selected_name = collection_spinner.text
                    if selected_name != '(No Collection)':
                        conn = dict_db.init_db(get_db_path())
                        all_lessons = dict_db.get_all_custom_lessons(conn)
                        conn.close()
                        for l in all_lessons:
                            if l['name'] == selected_name and l.get('is_collection'):
                                parent_id = l['id']
                                break
                
                try:
                    conn = dict_db.init_db(get_db_path())
                    lesson_id = dict_db.create_custom_lesson(conn, name, is_collection=is_collection, parent_id=parent_id)
                    conn.close()
                    Logger.info(f'CustomLessons: Created {item_type.lower()} "{name}" with ID {lesson_id}')
                    popup.dismiss()
                    self._custom_lessons_needs_reload = True
                    self._load_custom_lessons_list()
                except Exception as e:
                    Logger.error(f'CustomLessons: Error creating {item_type.lower()}: {e}')
            
            create_btn.bind(on_release=create_item)
            name_input.bind(on_text_validate=create_item)
            buttons.add_widget(create_btn)
            
            content.add_widget(buttons)
            popup.open()
            
        except Exception as e:
            Logger.error(f'CustomLessons: Error showing create dialog: {e}')

