    def on_rename_custom_lesson(self):
        """Show popup to rename the current lesson."""
        try:
            lesson_id = getattr(self, '_current_custom_lesson_id', None)
            if lesson_id is None:
                return
            
            conn = dict_db.init_db(get_db_path())
            lesson = dict_db.get_custom_lesson(conn, lesson_id)
            conn.close()
            
            if not lesson:
                return
            
            from kivy.uix.popup import Popup
            from kivy.uix.textinput import TextInput
            
            layout = BoxLayout(orientation='vertical', padding=dp(12), spacing=dp(8))
            
            name_input = TextInput(
                text=lesson['name'],
                multiline=False,
                font_name='fonts/NotoSansJP-Regular.ttf',
                font_size='16sp',
                size_hint_y=None,
                height=dp(40)
            )
            layout.add_widget(name_input)
            
            buttons = BoxLayout(spacing=dp(8), size_hint_y=None, height=dp(40))
            
            save_btn = Button(text='Save', background_normal='', background_color=(0.07, 0.6, 0.2, 1))
            cancel_btn = Button(text='Cancel', background_normal='', background_color=(0.1098, 0.1098, 0.1098, 1))
            
            buttons.add_widget(cancel_btn)
            buttons.add_widget(save_btn)
            layout.add_widget(buttons)
            
            popup = Popup(title='Rename Lesson', content=layout, size_hint=(0.88, None), height=dp(180))
            
            def save_name(*args):
                new_name = name_input.text.strip()
                if new_name:
                    conn = dict_db.init_db(get_db_path())
                    cur = conn.cursor()
                    cur.execute('UPDATE custom_lessons SET name = ? WHERE id = ?', (new_name, lesson_id))
                    conn.commit()
                    conn.close()
                    self._custom_lessons_needs_reload = True  # Mark for reload when returning to list
                    self._load_custom_lesson_detail(lesson_id)
                    popup.dismiss()
            
            save_btn.bind(on_release=save_name)
            cancel_btn.bind(on_release=popup.dismiss)
            name_input.bind(on_text_validate=save_name)
            
            popup.open()
        except Exception as e:
            Logger.error(f'CustomLessons: Error renaming lesson: {e}')

    def on_custom_lesson_search_change(self, search_text):
        """Filter custom lesson items based on search text."""
        try:
            lesson_id = getattr(self, '_current_custom_lesson_id', None)
            if lesson_id is None:
                return
            
            conn = dict_db.init_db(get_db_path())
            lesson = dict_db.get_custom_lesson(conn, lesson_id)
            
            if not lesson:
                conn.close()
                return
            
            items = lesson.get('items', [])
            
            # Batch fetch all entries at once for filtering and display
            entry_ids = [item['entry_id'] for item in items]
            entries_map = dict_db.get_entries_by_ids(conn, entry_ids) if entry_ids else {}
            
            # Filter items if search text is provided
            if search_text.strip():
                # Use same FTS engine as dictionary (handles romaji/kana/kanji/deinflect)
                try:
                    fts_set = {row[0] for row in dict_db.search_entries(conn, search_text.strip(), limit=10000)}
                    items = [item for item in items if item['entry_id'] in fts_set]
                except Exception:
                    # Fallback: substring match on kanji/kana/gloss
                    search_lower = search_text.lower().strip()
                    filtered_items = []
                    for item in items:
                        entry = entries_map.get(item['entry_id'])
                        if entry:
                            searchable = ' '.join([
                                str(entry.get('kanji', '')),
                                str(entry.get('kana', '')),
                                str(entry.get('gloss', ''))
                            ]).lower()
                            if search_lower in searchable:
                                filtered_items.append(item)
                    items = filtered_items
            
            # Reload grid with filtered items
            grid = self.root.ids.get('custom_lesson_items_grid')
            if not grid:
                conn.close()
                return
            
            grid.clear_widgets()
            
            if not items:
                label = Label(
                    text='No matching items found.' if search_text.strip() else 'No items in this lesson yet.\nClick "Add Items" to add dictionary entries.',
                    size_hint_y=None,
                    height=dp(100),
                    halign='center',
                    valign='middle'
                )
                label.bind(size=label.setter('text_size'))
                try:
                    label.font_name = 'fonts/NotoSansJP-Regular.ttf'
                    label.color = (0.4, 0.4, 0.4, 1)
                except Exception:
                    pass
                grid.add_widget(label)
                conn.close()
                return
            
            # Display filtered items using pre-fetched entries
            for item in items:
                entry_id = item['entry_id']
                entry = entries_map.get(entry_id)
                
                if not entry:
                    continue
                
                row = BoxLayout(size_hint_y=None, height=dp(60), spacing=dp(8))
                
                # Entry display - make BoxLayout clickable with ButtonBehavior
                from kivy.uix.behaviors import ButtonBehavior
                
                class ClickableBox(ButtonBehavior, BoxLayout):
                    pass
                
                entry_box = ClickableBox(orientation='vertical', padding=[dp(8), dp(4), dp(8), dp(4)])
                entry_box.bind(on_release=lambda *_, eid=entry_id: self._show_entry_detail_from_lesson(eid))
                
                top_text = entry.get('kanji') or entry.get('kana') or ''
                if entry.get('kanji') and entry.get('kana'):
                    top_text = f"{entry['kanji']} ({entry['kana']})"
                
                top_label = Label(
                    text=top_text,
                    font_size='15sp',
                    halign='left',
                    valign='middle',
                    color=(0.90, 0.88, 0.85, 1),
                    shorten=True,
                    shorten_from='right',
                    text_size=(None, None)
                )
                top_label.bind(width=lambda instance, value: setattr(instance, 'text_size', (value, None)))
                try:
                    top_label.font_name = 'fonts/NotoSansJP-Regular.ttf'
                except Exception:
                    pass
                
                kind = entry.get('kind', 'vocab').capitalize()
                gloss = entry.get('gloss', '')
                bottom_text = f"{gloss} • {kind}"
                
                bottom_label = Label(
                    text=bottom_text,
                    font_size='12sp',
                    halign='left',
                    valign='middle',
                    color=(0.65, 0.63, 0.60, 1),
                    shorten=True,
                    shorten_from='right',
                    text_size=(None, None)
                )
                bottom_label.bind(width=lambda instance, value: setattr(instance, 'text_size', (value, None)))
                
                entry_box.add_widget(top_label)
                entry_box.add_widget(bottom_label)
                
                row.add_widget(entry_box)
                
                remove_btn = Button(
                    text='×',
                    size_hint=(None, None),
                    width=dp(56),
                    height=dp(56),
                    font_size='20sp',
                    background_normal='',
                    background_down='',
                    background_color=(0.85, 0.30, 0.25, 1),
                    color=(1, 1, 1, 1)
                )
                remove_btn.bind(on_release=lambda *_, eid=entry_id: self._remove_item_from_custom_lesson(lesson_id, eid))
                try:
                    remove_btn.font_name = 'fonts/NotoSansJP-Regular.ttf'
                except Exception:
                    pass
                row.add_widget(remove_btn)
                
                grid.add_widget(row)
            
            conn.close()
                
        except Exception as e:
            Logger.error(f'CustomLessons: Error filtering lesson items: {e}')
            import traceback
            Logger.error(traceback.format_exc())

