    def _delete_custom_lesson_from_detail(self, lesson_id: int):
        """Delete a custom lesson and navigate back to custom lessons list."""
        try:
            conn = dict_db.init_db(get_db_path())
            
            # Remove from queue if present
            lesson_queue_id = f"custom_lesson:{lesson_id}"
            if lesson_queue_id in getattr(self, '_lesson_queue', []):
                self._lesson_queue.remove(lesson_queue_id)
                self.save_lesson_queue()
            
            # Delete the lesson
            dict_db.delete_custom_lesson(conn, lesson_id)
            conn.close()
            
            Logger.info(f'CustomLessons: Deleted lesson {lesson_id}')
            
            # Navigate back to custom lessons list
            sm = self._get_screen_manager()
            if sm:
                sm.current = 'custom_lessons'
                # Reload the list
                ls = self.root.ids.get('lessons_screen')
                if ls and hasattr(ls, '_load_custom_lessons_list'):
                    ls._load_custom_lessons_list()
            
        except Exception as e:
            Logger.error(f'CustomLessons: Error deleting lesson from detail: {e}')
            import traceback
            traceback.print_exc()

