    def _clear_all_lesson_items(self, lesson_id: int):
        """Delete all items from a custom lesson."""
        try:
            conn = dict_db.init_db(get_db_path())
            cur = conn.cursor()
            cur.execute('DELETE FROM custom_lesson_items WHERE lesson_id = ?', (lesson_id,))
            conn.commit()
            conn.close()
            self._custom_lessons_needs_reload = True
            self._load_custom_lesson_detail(lesson_id)
        except Exception as e:
            Logger.error(f'CustomLessons: Error clearing lesson items: {e}')

    def show_lesson_reorder(self, lesson_id: int):
        """Show lesson items in reorder mode, rendered inside custom_lesson_detail screen."""
        try:
            ls_screen = None
            try:
                if getattr(self, 'root', None):
                    ls_screen = self.root.ids.get('lessons_screen')
            except Exception:
                pass
            loading = ls_screen._show_loading_popup('Loading reorder list...') if ls_screen and hasattr(ls_screen, '_show_loading_popup') else None

            def fetch_data():
                try:
                    conn = dict_db.init_db(get_db_path())
                    lesson = dict_db.get_custom_lesson(conn, lesson_id)
                    if not lesson:
                        conn.close()
                        return [], 'Lesson'
                    items = lesson.get('items', [])
                    entry_ids = [it['entry_id'] for it in items]
                    entries_map = dict_db.get_entries_by_ids(conn, entry_ids) if entry_ids else {}
                    conn.close()
                    return items, lesson['name'], entries_map
                except Exception as e:
                    Logger.error(f'Lesson reorder fetch error: {e}')
                    return [], 'Lesson', {}

            def build_ui(items, lesson_name, entries_map):
                try:
                    grid = self.root.ids.get('custom_lesson_items_grid') if getattr(self, 'root', None) else None
                    bottom_bar = self.root.ids.get('custom_lesson_detail_bottom_bar') if getattr(self, 'root', None) else None
                    if grid is None:
                        return
                    grid.clear_widgets()
                    if bottom_bar:
                        bottom_bar.clear_widgets()

                    from kivy.graphics import Color, Rectangle

                    n = len(items)
                    self._lesson_reorder_items = list(items)
                    label_pairs = []
                    self._lesson_reorder_label_pairs = label_pairs
                    self._lesson_reorder_id = lesson_id
                    self._lesson_reorder_active = True

                    # Header row
                    header = BoxLayout(size_hint_y=None, height=dp(36), padding=[dp(8), dp(4)])
                    with header.canvas.before:
                        Color(0.18, 0.18, 0.20, 1)
                        header._bg = Rectangle(pos=header.pos, size=header.size)
                    header.bind(pos=lambda w, v: setattr(w._bg, 'pos', v),
                                size=lambda w, v: setattr(w._bg, 'size', v))
                    title_lbl = Label(
                        text=f'Reorder — {lesson_name}',
                        halign='left', valign='middle',
                        color=(0.90, 0.88, 0.85, 1), size_hint_x=1,
                    )
                    try:
                        title_lbl.font_name = 'fonts/NotoSansJP-Regular.ttf'
                    except Exception:
                        pass
                    title_lbl.bind(size=lambda s, v: setattr(s, 'text_size', (v[0], v[1])))
                    header.add_widget(title_lbl)
                    grid.add_widget(header)

                    for idx in range(n):
                        item = items[idx]
                        entry = entries_map.get(item['entry_id'])
                        if entry:
                            kanji = entry.get('kanji') or ''
                            kana = entry.get('kana') or ''
                            gloss = entry.get('gloss') or ''
                            top = f"{kanji} ({kana})" if kanji and kana else (kanji or kana)
                            disp_name = f"{top} — {gloss.split(';')[0][:30]}"
                        else:
                            disp_name = f"Entry {item['entry_id']}"

                        row = BoxLayout(size_hint_y=None, height=dp(54), spacing=dp(4),
                                        padding=[dp(4), dp(2), dp(4), dp(2)])
                        with row.canvas.before:
                            Color(0.28, 0.28, 0.30, 1)
                            row._bg = Rectangle(pos=row.pos, size=row.size)
                        row.bind(pos=lambda w, v: setattr(w._bg, 'pos', v),
                                 size=lambda w, v: setattr(w._bg, 'size', v))

                        up_btn = Button(
                            text='↑', size_hint=(None, 1), width=dp(46),
                            background_normal='', background_down='',
                            background_color=(0.22, 0.22, 0.24, 1) if idx == 0 else (0.30, 0.45, 0.62, 1),
                            color=(0.50, 0.50, 0.52, 1) if idx == 0 else (0.90, 0.88, 0.85, 1),
                            disabled=(idx == 0), font_size='18sp',
                        )
                        try:
                            up_btn.font_name = 'fonts/NotoSansJP-Regular.ttf'
                        except Exception:
                            pass

                        down_btn = Button(
                            text='↓', size_hint=(None, 1), width=dp(46),
                            background_normal='', background_down='',
                            background_color=(0.22, 0.22, 0.24, 1) if idx == n - 1 else (0.30, 0.45, 0.62, 1),
                            color=(0.50, 0.50, 0.52, 1) if idx == n - 1 else (0.90, 0.88, 0.85, 1),
                            disabled=(idx == n - 1), font_size='18sp',
                        )
                        try:
                            down_btn.font_name = 'fonts/NotoSansJP-Regular.ttf'
                        except Exception:
                            pass

                        def make_move(i, d):
                            def handler(*args):
                                self._lesson_reorder_swap_inplace(i, d)
                            return handler

                        up_btn.bind(on_release=make_move(idx, -1))
                        down_btn.bind(on_release=make_move(idx, 1))

                        name_box = BoxLayout(orientation='vertical', size_hint_x=1,
                                             padding=[dp(6), 0, dp(4), 0])
                        name_lbl = Label(
                            text=disp_name, halign='left', valign='middle',
                            color=(0.90, 0.88, 0.85, 1),
                            shorten=True, shorten_from='right', size_hint_y=1,
                        )
                        try:
                            name_lbl.font_name = 'fonts/NotoSansJP-Regular.ttf'
                        except Exception:
                            pass
                        name_lbl.bind(size=lambda s, v: setattr(s, 'text_size', (v[0], v[1])))

                        type_lbl = Label(
                            text=(entry.get('kind') or 'entry').capitalize() if entry else '',
                            halign='right', valign='middle',
                            color=(0.55, 0.53, 0.50, 1), font_size='10sp',
                            size_hint=(None, 1), width=dp(58),
                        )
                        try:
                            type_lbl.font_name = 'fonts/NotoSansJP-Regular.ttf'
                        except Exception:
                            pass
                        type_lbl.bind(size=lambda s, v: setattr(s, 'text_size', (v[0], v[1])))

                        label_pairs.append((name_lbl, type_lbl))
                        row.add_widget(up_btn)
                        row.add_widget(down_btn)
                        name_box.add_widget(name_lbl)
                        row.add_widget(name_box)
                        row.add_widget(type_lbl)
                        grid.add_widget(row)

                    # Done button in bottom bar
                    if bottom_bar is not None:
                        done_btn = Button(
                            text='Done',
                            background_normal='', background_down='',
                            background_color=(0.20, 0.45, 0.25, 1),
                            color=(0.90, 0.88, 0.85, 1),
                            font_name='fonts/NotoSansJP-Regular.ttf'
                        )
                        done_btn.bind(on_release=lambda *_: self._load_custom_lesson_detail(lesson_id))
                        bottom_bar.add_widget(done_btn)

                except Exception as e:
                    Logger.error(f'Lesson reorder build_ui error: {e}')
                    import traceback
                    Logger.error(traceback.format_exc())

            def on_loaded(dt):
                if loading is not None:
                    loading.dismiss()
                items, lesson_name, entries_map = self._lesson_reorder_data
                build_ui(items, lesson_name, entries_map)

            def bg_fetch():
                self._lesson_reorder_data = fetch_data()
                Clock.schedule_once(on_loaded, 0)

            threading.Thread(target=bg_fetch, daemon=True).start()

        except Exception as e:
            Logger.error(f'Lesson show_lesson_reorder error: {e}')

    def _lesson_reorder_swap_inplace(self, i: int, d: int):
        """Swap two lesson items by updating label texts and position in DB."""
        try:
            label_pairs = getattr(self, '_lesson_reorder_label_pairs', None)
            items = getattr(self, '_lesson_reorder_items', None)
            if not label_pairs or not items:
                return
            j = i + d
            if j < 0 or j >= len(label_pairs):
                return
            lid = getattr(self, '_lesson_reorder_id', None)
            # Swap positions in DB
            pos_i = items[i]['position']
            pos_j = items[j]['position']
            if lid is not None:
                self._swap_lesson_item_positions(lid, items[i]['entry_id'], items[j]['entry_id'], pos_i, pos_j)
            # Swap in local list
            items[i], items[j] = items[j], items[i]
            items[i]['position'], items[j]['position'] = pos_i, pos_j
            # Swap label texts
            name_i, type_i = label_pairs[i]
            name_j, type_j = label_pairs[j]
            name_i.text, name_j.text = name_j.text, name_i.text
            type_i.text, type_j.text = type_j.text, type_i.text
            self._custom_lessons_needs_reload = True
        except Exception as e:
            Logger.error(f'Lesson _lesson_reorder_swap_inplace error: {e}')

    def _swap_lesson_item_positions(self, lesson_id: int, entry_a: int, entry_b: int, pos_a: int, pos_b: int):
        """Swap position values of two items in custom_lesson_items."""
        try:
            conn = dict_db.init_db(get_db_path())
            cur = conn.cursor()
            cur.execute('UPDATE custom_lesson_items SET position = ? WHERE lesson_id = ? AND entry_id = ?',
                        (pos_b, lesson_id, entry_a))
            cur.execute('UPDATE custom_lesson_items SET position = ? WHERE lesson_id = ? AND entry_id = ?',
                        (pos_a, lesson_id, entry_b))
            conn.commit()
            conn.close()
        except Exception as e:
            Logger.error(f'Lesson _swap_lesson_item_positions error: {e}')

