    def _flash_button(self, btn, duration: float = 0.12):
        """Flash a button briefly with the pressed color so clicks have visible feedback."""
        try:
            if not btn:
                return
            pressed = (0.06, 0.09, 0.15, 1)
            idle = (0.1098, 0.1098, 0.1098, 1)
            # set pressed color immediately
            try:
                btn.background_color = pressed
                btn.opacity = 0.92
            except Exception:
                pass
            from kivy.clock import Clock
            def _reset(_dt):
                try:
                    btn.background_color = idle
                    btn.opacity = 1.0
                except Exception:
                    pass
            Clock.schedule_once(_reset, duration)
        except Exception:
            pass

    def _press_button(self, btn):
        """Immediate visual press feedback for buttons."""
        try:
            if not btn:
                return
            pressed = (0.06, 0.09, 0.15, 1)
            try:
                btn.background_color = pressed
                btn.opacity = 0.92
            except Exception:
                pass
        except Exception:
            pass

    def _release_button(self, btn):
        """Restore visual state after press."""
        try:
            if not btn:
                return
            idle = (0.1098, 0.1098, 0.1098, 1)
            try:
                btn.background_color = idle
                btn.opacity = 1.0
            except Exception:
                pass
        except Exception:
            pass

    def _reset_clear_button(self, btn):
        """Reset clear button to its original red color."""
        try:
            if not btn:
                return
            try:
                btn.background_color = (0.85, 0.2, 0.2, 1)
                btn.opacity = 1.0
            except Exception:
                pass
        except Exception:
            pass

    def schedule_dict_search(self, *args):
        """App-level wrapper that routes to correct search handler based on current screen."""
        try:
            # Check if we're on add_items_to_lesson screen
            sm = self._get_screen_manager()
            if sm and sm.current == 'add_items_to_lesson':
                Logger.info('DictSearch: Routing to on_add_items_search (on add_items_to_lesson screen)')
                # Cancel previous and schedule add_items search
                if hasattr(self, '_dict_search_clock') and self._dict_search_clock:
                    self._dict_search_clock.cancel()
                self._dict_search_clock = Clock.schedule_once(lambda dt: self.on_add_items_search(), 0.15)
                return
            
            # Otherwise delegate to DictionaryScreen
            ds = self.root.ids.get('dict_screen') if getattr(self, 'root', None) else None
            if ds and hasattr(ds, 'schedule_search'):
                try:
                    ds.schedule_search()
                except Exception:
                    pass
        except Exception:
            pass

    def _get_lessons_search_query(self):
        """Read current text from the lessons search input."""
        try:
            if getattr(self, 'root', None):
                gi = self.root.ids.get('lessons_search_input')
                if gi is not None:
                    return (gi.text or '').strip()
        except Exception:
            pass
        return ''

    def schedule_lessons_search(self, *args):
        """App-level wrapper that delegates to LessonsScreen.schedule_lessons_search."""
        try:
            # Check if we're on custom_lesson_detail screen - if so, filter the lesson items
            sm = self._get_screen_manager()
            if sm and sm.current == 'custom_lesson_detail':
                # Get search text
                search_input = self.root.ids.get('lessons_search_input')
                if search_input:
                    search_text = search_input.text or ''
                    # Call the custom lesson search method directly
                    self.on_custom_lesson_search_change(search_text)
                return
            
            # Check if we're on collection_detail screen - if so, filter the collection lessons
            if sm and sm.current == 'collection_detail':
                # Get search text
                search_input = self.root.ids.get('lessons_search_input')
                if search_input:
                    search_text = search_input.text or ''
                    # Call the collection search method directly
                    self.on_collection_search_change(search_text)
                return

            # Check if we're on the custom_lessons list screen
            if sm and sm.current == 'custom_lessons':
                self.on_custom_lessons_search()
                return
            
            # Otherwise delegate to LessonsScreen
            ls = self.root.ids.get('lessons_screen') if getattr(self, 'root', None) else None
            if ls and hasattr(ls, 'schedule_lessons_search'):
                try:
                    ls.schedule_lessons_search()
                except Exception:
                    pass
        except Exception:
            pass

    def show_study_settings(self):
        """Navigate to the study settings screen."""
        try:
            sm = self._get_screen_manager()
            if sm is not None:
                sm.current = 'study_settings'
                # Sync switch state
                sw = self.root.ids.get('remember_my_stuff_switch')
                if sw:
                    sw.active = getattr(self, '_remember_my_stuff_position', False)
        except Exception:
            pass

    def on_erase_srs_data(self):
        """Show triple-confirmation dialogs before erasing all SRS data."""
        from kivy.uix.popup import Popup
        from kivy.uix.boxlayout import BoxLayout
        from kivy.uix.label import Label
        from kivy.uix.button import Button
        from kivy.metrics import dp

        def _make_popup(title, message, confirm_text, confirm_color, on_confirm):
            content = BoxLayout(orientation='vertical', padding=dp(20), spacing=dp(14))
            msg = Label(
                text=message,
                font_name='fonts/NotoSansJP-Regular.ttf',
                color=(1, 1, 1, 1),
                halign='center',
                valign='middle',
                size_hint_y=None,
                height=dp(100),
            )
            msg.bind(size=msg.setter('text_size'))
            content.add_widget(msg)

            btn_row = BoxLayout(size_hint_y=None, height=dp(48), spacing=dp(10))

            p = Popup(
                title=title,
                content=content,
                size_hint=(0.88, None),
                height=dp(240),
                auto_dismiss=False,
            )

            cancel_btn = Button(
                text='Cancel',
                background_normal='', background_down='',
                background_color=(0.28, 0.28, 0.30, 1),
                color=(0.90, 0.88, 0.85, 1),
                font_name='fonts/NotoSansJP-Regular.ttf',
            )
            cancel_btn.bind(on_release=lambda *a: p.dismiss())

            confirm_btn = Button(
                text=confirm_text,
                background_normal='', background_down='',
                background_color=confirm_color,
                color=(1, 1, 1, 1),
                font_name='fonts/NotoSansJP-Regular.ttf',
            )
            def _on_confirm(instance):
                p.dismiss()
                on_confirm()
            confirm_btn.bind(on_release=_on_confirm)

            btn_row.add_widget(cancel_btn)
            btn_row.add_widget(confirm_btn)
            content.add_widget(btn_row)
            p.open()

        def _warning3():
            _make_popup(
                title='FINAL WARNING',
                message='This is your FINAL WARNING.\n\nAll SRS progress, streaks, and review history will be permanently deleted. There is no undo.',
                confirm_text='Erase Everything',
                confirm_color=(0.85, 0.10, 0.10, 1),
                on_confirm=self._do_erase_srs_data,
            )

        def _warning2():
            _make_popup(
                title='Are You Really Sure?',
                message='This will permanently delete ALL your SRS data.\n\nEvery word you have studied will be reset to zero.',
                confirm_text='Yes, Erase It',
                confirm_color=(0.75, 0.15, 0.10, 1),
                on_confirm=_warning3,
            )

        _make_popup(
            title='Erase All SRS Data?',
            message='This will reset all your study progress.\n\nAre you sure you want to continue?',
            confirm_text='Continue',
            confirm_color=(0.55, 0.20, 0.20, 1),
            on_confirm=_warning2,
        )

    def _do_erase_srs_data(self):
        """Actually erase all SRS data from the database."""
        try:
            # Set the erase flag FIRST so any concurrent sync sees it
            # before it can observe empty SRS tables.
            try:
                from sync.sync import set_srs_erased_flag
                set_srs_erased_flag()
            except Exception as e:
                Logger.warning(f'Settings: could not set erase flag: {e}')

            conn = dict_db.init_db(get_db_path())
            cur = conn.cursor()
            cur.execute('DELETE FROM srs')
            cur.execute('DELETE FROM learning_sessions')
            conn.commit()
            conn.close()
            Logger.info('Settings: All SRS data erased')

            # Directly delete remote SRS data for immediate effect.
            # The flag stays set so subsequent syncs won't re-download.
            try:
                from sync import supabase_client as sb_client
                if sb_client.is_logged_in() and sb_client.is_configured():
                    uid = sb_client.get_user_id()
                    ok = sb_client._delete('srs_sync', {'user_id': f'eq.{uid}'})
                    if ok:
                        Logger.info('Settings: remote SRS data deleted')
                    else:
                        Logger.warning('Settings: remote SRS delete failed — will retry on next sync')
            except Exception as e:
                Logger.warning(f'Settings: remote SRS delete error: {e}')

            # Show success notification
            from kivy.uix.popup import Popup
            from kivy.uix.boxlayout import BoxLayout
            from kivy.uix.label import Label
            from kivy.uix.button import Button
            from kivy.metrics import dp
            content = BoxLayout(orientation='vertical', padding=dp(20), spacing=dp(14))
            lbl = Label(
                text='All SRS data has been erased.\nYour progress has been reset.',
                font_name='fonts/NotoSansJP-Regular.ttf',
                color=(0.90, 0.88, 0.85, 1),
                halign='center',
                valign='middle',
                size_hint_y=None,
                height=dp(60),
            )
            lbl.bind(size=lbl.setter('text_size'))
            content.add_widget(lbl)
            p = Popup(
                title='Done',
                content=content,
                size_hint=(0.75, None),
                height=dp(210),
            )
            ok_btn = Button(
                text='OK',
                size_hint_y=None,
                height=dp(44),
                background_normal='', background_down='',
                background_color=(0.25, 0.35, 0.50, 1),
                color=(1, 1, 1, 1),
                font_name='fonts/NotoSansJP-Regular.ttf',
            )
            ok_btn.bind(on_release=lambda *a: p.dismiss())
            content.add_widget(ok_btn)
            p.open()
        except Exception as e:
            Logger.error(f'Settings: Error erasing SRS data: {e}')
            import traceback
            traceback.print_exc()

    def _confirm_exit_drill(self):
        """Show confirmation popup when user tries to leave an active drill/time attack session."""
        try:
            from kivy.uix.popup import Popup
            from kivy.uix.boxlayout import BoxLayout
            from kivy.uix.label import Label
            from kivy.uix.button import Button
            from kivy.metrics import dp

            # Determine session type
            is_time_attack = hasattr(self, '_time_attack_active') and self._time_attack_active
            session_type = "time attack" if is_time_attack else "drill"

            # Create popup content
            content = BoxLayout(orientation='vertical', padding=dp(20), spacing=dp(15))
            
            # Confirmation message
            msg_label = Label(
                text=f'This will end your {session_type} session.\nAre you sure?',
                size_hint_y=None,
                height=dp(80),
                font_name='fonts/NotoSansJP-Regular.ttf',
                color=(1, 1, 1, 1),
                halign='center'
            )
            msg_label.bind(size=msg_label.setter('text_size'))
            
            # Button row
            button_row = BoxLayout(size_hint_y=None, height=dp(50), spacing=dp(10))
            
            popup = Popup(
                title='Exit Session?',
                content=content,
                size_hint=(0.8, None),
                height=dp(220),
                auto_dismiss=False
            )

            def on_yes(instance):
                popup.dismiss()
                # Clean up writing practice if active (resets Practice tag,
                # restores drill_main_container visibility, etc.)
                if getattr(self, 'writing_practice_active', False):
                    self._hide_writing_practice()
                # Clean up info card overlay if active
                self._hide_info_card_overlay()
                # Clean up session state
                if is_time_attack:
                    self._cleanup_time_attack_state()
                # Save incomplete drill session info for resuming
                drill_mode = getattr(self, '_drill_mode', None)
                if hasattr(self, '_current_drill_session_id') and drill_mode:
                    session_id = self._current_drill_session_id
                    # Store incomplete session info (only for study-screen drills)
                    if drill_mode in ('weak_words', 'lesson'):
                        self._incomplete_drill = {
                            'mode': drill_mode,
                            'session_id': session_id
                        }
                        Logger.info(f'Drill: Saved incomplete {drill_mode} session {session_id} for resuming')
                # If this was a tools drill or time attack, go back to drill config
                is_tools = drill_mode in ('tools_drill', 'time_attack')
                # Clear drill session
                if hasattr(self, '_current_drill_session_id'):
                    delattr(self, '_current_drill_session_id')
                if hasattr(self, '_drill_mode'):
                    delattr(self, '_drill_mode')
                self._drill_config_unlimited = False
                if is_tools:
                    sm = self._get_screen_manager()
                    if sm:
                        sm.current = 'drill_config'
                        Clock.schedule_once(lambda dt: self.show_drill_config(), 0.1)
                else:
                    # Now actually navigate back
                    self.go_back()

            def on_no(instance):
                popup.dismiss()

            # No button (red)
            btn_no = Button(
                text='No',
                background_normal='',
                background_down='',
                background_color=(0.85, 0.30, 0.25, 1),
                color=(1, 1, 1, 1),
                font_name='fonts/NotoSansJP-Medium.ttf',
                on_press=on_no
            )
            
            # Yes button (green)
            btn_yes = Button(
                text='Yes',
                background_normal='',
                background_down='',
                background_color=(0.15, 0.65, 0.15, 1),
                color=(1, 1, 1, 1),
                font_name='fonts/NotoSansJP-Medium.ttf',
                on_press=on_yes
            )
            
            button_row.add_widget(btn_no)
            button_row.add_widget(btn_yes)
            
            content.add_widget(msg_label)
            content.add_widget(button_row)

            popup.open()
        except Exception as e:
            Logger.exception('_confirm_exit_drill: error: %s', e)
            # If we fail to show popup, just go back anyway
            self.go_back()

    def _confirm_close_app(self):
        """Show confirmation popup when user tries to close the app from dictionary page."""
        try:
            from kivy.uix.popup import Popup
            from kivy.uix.boxlayout import BoxLayout
            from kivy.uix.label import Label
            from kivy.uix.button import Button
            from kivy.metrics import dp

            # Create popup content
            content = BoxLayout(orientation='vertical', padding=dp(20), spacing=dp(15))
            
            # Confirmation message
            msg_label = Label(
                text='Close Sakubo?',
                size_hint_y=None,
                height=dp(60),
                font_name='fonts/NotoSansJP-Regular.ttf',
                color=(1, 1, 1, 1),
                halign='center',
                font_size='18sp'
            )
            msg_label.bind(size=msg_label.setter('text_size'))
            
            # Button row
            button_row = BoxLayout(size_hint_y=None, height=dp(50), spacing=dp(10))
            
            popup = Popup(
                title='',
                content=content,
                size_hint=(0.7, None),
                height=dp(180),
                auto_dismiss=True,
                separator_height=0
            )

            def on_yes(instance):
                popup.dismiss()
                # Actually close the app
                try:
                    from kivy.utils import platform
                    if platform == 'android':
                        from jnius import autoclass
                        PythonActivity = autoclass('org.kivy.android.PythonActivity')
                        activity = PythonActivity.mActivity
                        activity.moveTaskToBack(True)
                    else:
                        App.get_running_app().stop()
                except Exception as e:
                    Logger.error('_confirm_close_app: collapse failed: %s', e)
                    try:
                        App.get_running_app().stop()
                    except Exception as e2:
                        Logger.error('_confirm_close_app: final stop failed: %s', e2)

            def on_no(instance):
                popup.dismiss()

            # No button (cancel)
            btn_no = Button(
                text='Cancel',
                background_normal='',
                background_down='',
                background_color=(0.5, 0.5, 0.5, 1),
                color=(1, 1, 1, 1),
                font_name='fonts/NotoSansJP-Medium.ttf',
                on_press=on_no
            )
            
            # Yes button (close)
            btn_yes = Button(
                text='Close',
                background_normal='',
                background_down='',
                background_color=(0.85, 0.30, 0.25, 1),
                color=(1, 1, 1, 1),
                font_name='fonts/NotoSansJP-Medium.ttf',
                on_press=on_yes
            )
            
            button_row.add_widget(btn_no)
            button_row.add_widget(btn_yes)
            
            content.add_widget(msg_label)
            content.add_widget(button_row)

            popup.open()
        except Exception as e:
            Logger.exception('_confirm_close_app: error: %s', e)
            # If we fail to show popup, don't close the app

    def go_back(self):
        """Back navigation.

        - Dictionary is treated as the home fallback.
        - Back returns to the previously visited ScreenManager screen.
        - If on Lessons and inside a subview (spoonfed/custom), Back returns to the Lessons main menu first.
        - Pressing Back on the Dictionary collapses the app (minimize on Android).
        """
        try:
            sm = self._get_screen_manager()
            if sm is None:
                Logger.info('go_back: no screen manager')
                return

            cur = sm.current or 'dictionary'
            Logger.info('go_back: current screen = %s', cur)
            
            # Check if on review screen - go back to study screen
            if cur == 'review':
                Logger.info('go_back: on review — switching to study')
                self._nav_back_in_progress = True
                sm.current = 'study'
                Clock.schedule_once(lambda dt: setattr(self, '_nav_back_in_progress', False), 0)
                Clock.schedule_once(lambda dt: self._update_study_stats(), 0.1)
                return
            
            # Check if on drill screen with active session
            if cur == 'drill' and hasattr(self, '_current_drill_session_id') and self._current_drill_session_id:
                # Show confirmation popup
                self._confirm_exit_drill()
                return

            # If already on Dictionary, check if viewing a lesson or treat as app collapse
            try:
                if cur == 'dictionary':
                    # Check if we're viewing a lesson (return to lessons screen instead of closing)
                    if hasattr(self, '_lesson_view_return_screen') and self._lesson_view_return_screen:
                        return_screen = self._lesson_view_return_screen
                        self._lesson_view_return_screen = None
                        Logger.info(f'go_back: returning from lesson view to {return_screen}')
                        self._nav_back_in_progress = True
                        sm.current = return_screen
                        
                        # Restore lessons screen internal state if saved
                        if return_screen == 'lessons' and hasattr(self, '_saved_lessons_view'):
                            try:
                                ls = self.root.ids.get('lessons_screen')
                                if ls:
                                    saved_view = self._saved_lessons_view
                                    saved_payload = getattr(self, '_saved_lessons_payload', {})
                                    Logger.info(f'go_back: restoring lessons state: view={saved_view}, payload={saved_payload}')
                                    delattr(self, '_saved_lessons_view')
                                    if hasattr(self, '_saved_lessons_payload'):
                                        delattr(self, '_saved_lessons_payload')
                                    # If the old view is still intact (RV with data), just restore scroll
                                    # instead of rebuilding everything (avoids flash)
                                    current_view = getattr(ls, '_current_lessons_view', None)
                                    rv = ls._get_lessons_rv()
                                    if current_view == saved_view and rv is not None and rv.data:
                                        scroll_y = saved_payload.get('_scroll_y')
                                        if scroll_y is not None:
                                            def _restore_scroll(dt, _sy=scroll_y, _rv=rv):
                                                try:
                                                    _rv.scroll_y = _sy
                                                except Exception:
                                                    pass
                                            Clock.schedule_once(_restore_scroll, 0)
                                        Logger.info('go_back: lessons view intact, restored scroll only')
                                    else:
                                        Clock.schedule_once(lambda dt: ls._restore_view_state((saved_view, saved_payload)), 0.1)
                            except Exception as e:
                                Logger.error(f'go_back: failed to restore lessons state: {e}')
                        
                        Clock.schedule_once(lambda dt: setattr(self, '_nav_back_in_progress', False), 0)
                        return
                    
                    # Show confirmation popup before closing app
                    Logger.info('go_back: on dictionary — showing close confirmation')
                    self._confirm_close_app()
                    return
            except Exception as e:
                Logger.error('go_back: dictionary branch exception: %s', e)

            # Entry detail navigation (back to previous screen from history)
            try:
                if cur == 'entry_detail':
                    # First check if there's internal entry-to-entry history
                    entry_screen = sm.get_screen('entry_detail')
                    entry_content = entry_screen.children[0] if entry_screen.children else None
                    
                    if entry_content and hasattr(entry_content, '_internal_entry_history') and entry_content._internal_entry_history:
                        # Navigate back to previous entry with its view state
                        history_item = entry_content._internal_entry_history.pop()
                        prev_entry_id = history_item['entry_id']
                        was_in_breakdown = history_item.get('in_kanji_breakdown', False)
                        Logger.info(f'go_back: on entry_detail — returning to entry {prev_entry_id} (breakdown={was_in_breakdown}) from internal history')
                        
                        # Load the entry
                        conn = dict_db.init_db(get_db_path())
                        entry = dict_db.get_entry_by_id(conn, prev_entry_id)
                        conn.close()
                        
                        if entry:
                            # If it was in breakdown view, restore that
                            if was_in_breakdown:
                                entry_content._show_kanji_breakdown(entry)
                            else:
                                entry_content.load_entry(prev_entry_id)
                        return
                    
                    # No internal history, check screen-level navigation history
                    if hasattr(self, '_entry_nav_history') and self._entry_nav_history:
                        prev_screen = self._entry_nav_history.pop()
                        Logger.info(f'go_back: on entry_detail — returning to {prev_screen} from history')
                        self._nav_back_in_progress = True
                        sm.current = prev_screen
                        
                        # Clean up _nav_history to remove entry_detail since it has its own navigation
                        if hasattr(self, '_nav_history') and isinstance(self._nav_history, list):
                            # Remove any entry_detail entries from main nav history
                            self._nav_history = [s for s in self._nav_history if s != 'entry_detail']
                        
                        # If returning to lessons screen, check if we need to restore popup state
                        if prev_screen == 'lessons':
                            Clock.schedule_once(lambda dt: self._restore_lessons_popup_state(), 0.2)
                        Clock.schedule_once(lambda dt: setattr(self, '_nav_back_in_progress', False), 0)
                    else:
                        # No history, default to dictionary
                        Logger.info('go_back: on entry_detail — returning to dictionary (no history)')
                        self._nav_back_in_progress = True
                        sm.current = 'dictionary'
                        Clock.schedule_once(lambda dt: setattr(self, '_nav_back_in_progress', False), 0)
                    return
            except Exception as e:
                Logger.error('go_back: entry_detail branch exception: %s', e)

            # Lessons internal navigation (doesn't change ScreenManager)
            try:
                if cur == 'lessons':
                    ls = self.root.ids.get('lessons_screen') if getattr(self, 'root', None) else None
                    Logger.info('go_back: lessons_screen present=%s', bool(ls))
                    view = getattr(ls, '_current_lessons_view', 'main') if ls else 'main'
                    Logger.info('go_back: lessons view = %s', view)
                    # First, give Lessons a chance to handle Back internally (queue/spoonfed/custom/etc)
                    try:
                        if ls and hasattr(ls, 'nav_back') and ls.nav_back():
                            return
                    except Exception:
                        pass
                    # If Lessons didn't handle it (already on main), go to Dictionary
                    Logger.info('go_back: lessons at root — switching to dictionary')
                    self._nav_back_in_progress = True
                    sm.current = 'dictionary'
                    Clock.schedule_once(lambda dt: setattr(self, '_nav_back_in_progress', False), 0)
                    return
                elif cur == 'custom_lesson_detail':
                    # If reorder is active, back exits reorder rather than leaving the screen
                    if getattr(self, '_lesson_reorder_active', False):
                        self._lesson_reorder_active = False
                        lid = getattr(self, '_current_custom_lesson_id', None)
                        if lid is not None:
                            Clock.schedule_once(lambda dt: self._load_custom_lesson_detail(lid), 0)
                        return
                    # Custom lesson detail should go back to wherever we came from (collection_detail or custom_lessons)
                    prev_screen = getattr(self, '_previous_screen', 'custom_lessons')
                    Logger.info(f'go_back: on custom_lesson_detail — returning to {prev_screen}')
                    self._nav_back_in_progress = True
                    sm.current = prev_screen
                    
                    # Reload the previous screen to update progress bars
                    if prev_screen == 'collection_detail':
                        collection_id = getattr(self, '_current_collection_id', None)
                        if collection_id:
                            Clock.schedule_once(lambda dt: self._load_collection_detail(collection_id), 0.1)
                    elif prev_screen == 'custom_lessons':
                        Clock.schedule_once(lambda dt: self._load_custom_lessons_list(), 0.1)
                    
                    Clock.schedule_once(lambda dt: setattr(self, '_nav_back_in_progress', False), 0)
                    return
                elif cur == 'collection_detail':
                    # If reorder is active, back exits reorder rather than leaving the screen
                    if getattr(self, '_collection_reorder_active', False):
                        self._collection_reorder_active = False
                        cid = getattr(self, '_current_collection_id', None)
                        if cid is not None:
                            Clock.schedule_once(lambda dt: self._load_collection_detail(cid), 0)
                        return
                    # Otherwise go back to custom lessons list
                    Logger.info('go_back: on collection_detail — returning to custom_lessons')
                    self._nav_back_in_progress = True
                    sm.current = 'custom_lessons'
                    Clock.schedule_once(lambda dt: self._load_custom_lessons_list(), 0.1)
                    Clock.schedule_once(lambda dt: setattr(self, '_nav_back_in_progress', False), 0)
                    return
                elif cur in ('settings', 'profile'):
                    # Settings and Profile (first page) should go to Dictionary
                    Logger.info('go_back: on settings/profile — switching to dictionary')
                    self._nav_back_in_progress = True
                    sm.current = 'dictionary'
                    Clock.schedule_once(lambda dt: setattr(self, '_nav_back_in_progress', False), 0)
                    return
                elif cur == 'my_stats':
                    # My Stats goes back to Settings
                    Logger.info('go_back: on my_stats — switching to settings')
                    self._nav_back_in_progress = True
                    sm.current = 'settings'
                    Clock.schedule_once(lambda dt: setattr(self, '_nav_back_in_progress', False), 0)
                    return
                elif cur == 'study_settings':
                    # Study settings behaves like other settings pages and returns to Settings
                    Logger.info('go_back: on study_settings — switching to settings')
                    self._nav_back_in_progress = True
                    sm.current = 'settings'
                    Clock.schedule_once(lambda dt: setattr(self, '_nav_back_in_progress', False), 0)
                    return
                elif cur == 'download_data':
                    # Download Data goes back to Settings
                    Logger.info('go_back: on download_data — switching to settings')
                    self._nav_back_in_progress = True
                    sm.current = 'settings'
                    Clock.schedule_once(lambda dt: setattr(self, '_nav_back_in_progress', False), 0)
                    return
                elif cur == 'drill_config':
                    # Drill config goes back to tools
                    Logger.info('go_back: on drill_config — switching to tools')
                    self._nav_back_in_progress = True
                    sm.current = 'tools'
                    Clock.schedule_once(lambda dt: setattr(self, '_nav_back_in_progress', False), 0)
                    return
                elif cur == 'study':
                    # Study has its own back behavior (undo if possible); it already falls back to Dictionary.
                    Logger.info('go_back: on study — delegating to on_drill_back')
                    try:
                        self.on_drill_back()
                    except Exception as e:
                        Logger.error('go_back: on_drill_back failed: %s', e)
                        try:
                            self._nav_back_in_progress = True
                            sm.current = 'dictionary'
                            Clock.schedule_once(lambda dt: setattr(self, '_nav_back_in_progress', False), 0)
                        except Exception:
                            pass
                    return
            except Exception as e:
                Logger.error('go_back: lessons/settings branch exception: %s', e)

            # Fallback: use navigation history to go to previous screen
            hist = getattr(self, '_nav_history', None)
            if not isinstance(hist, list):
                hist = []
                self._nav_history = hist

            # Ensure history ends with current
            if not hist or hist[-1] != cur:
                hist.append(cur)

            # Pop current and navigate to previous
            try:
                if hist and hist[-1] == cur:
                    hist.pop()
            except Exception as e:
                Logger.error('go_back: history pop failed: %s', e)

            target = hist[-1] if hist else 'dictionary'
            Logger.info('go_back: history target = %s', target)
            self._nav_back_in_progress = True
            sm.current = target
            Clock.schedule_once(lambda dt: setattr(self, '_nav_back_in_progress', False), 0)
        except Exception as e:
            Logger.exception('go_back: unexpected exception: %s', e)
            try:
                self._nav_back_in_progress = False
            except Exception:
                pass

    def _restore_lessons_popup_state(self):
        """Restore popup state when returning to lessons screen from entry_detail."""
        try:
            if hasattr(self, 'root') and self.root:
                ls = self.root.ids.get('lessons_screen')
                if ls and hasattr(ls, 'restore_popup_state'):
                    ls.restore_popup_state()
        except Exception as e:
            Logger.error(f'Error restoring lessons popup state: {e}')

    def go_back_ui(self):
        """Wrapper called from the top-left UI button so we can always log UI clicks."""
        # Debounce to avoid double-triggering
        try:
            from time import monotonic
            now = monotonic()
            last = getattr(self, '_last_back_ui_ts', 0.0)
            if (now - last) < 0.5:
                return
            self._last_back_ui_ts = now
        except Exception:
            pass

        Logger.info('go_back_ui: UI back pressed')
        try:
            self.go_back()
        except Exception as e:
            Logger.exception('go_back_ui: error invoking go_back: %s', e)

    def _on_window_keyboard(self, window, key, scancode, codepoint, modifiers):
        """Handle hardware back (Android) / escape (desktop).

        Kivy typically maps Android back to key==27 ('escape'). Return True to consume.
        """
        try:
            if key == 27:
                self.go_back_ui()
                return True
        except Exception as e:
            Logger.exception('nav: on_keyboard handler failed: %s', e)
        return False

    def _bind_back_handlers(self):
        """Ensure the top-left back button + hardware back key are wired."""
        try:
            if getattr(self, '_back_handlers_bound', False):
                return
            self._back_handlers_bound = True

            # 1) UI back button — handled by KV on_release binding, no Python bind needed
            try:
                bb = None
                if getattr(self, 'root', None) is not None:
                    bb = self.root.ids.get('back_button')
                if bb is not None:
                    Logger.info('nav: back_button found (KV-bound on_release)')
                else:
                    Logger.warning('nav: back_button id not found on root')
            except Exception as e:
                Logger.exception('nav: failed checking back_button: %s', e)

            # 2) Hardware back / escape
            try:
                Window.bind(on_keyboard=self._on_window_keyboard)
                Logger.info('nav: bound Window.on_keyboard')
            except Exception as e:
                Logger.exception('nav: failed binding Window.on_keyboard: %s', e)
        except Exception as e:
            Logger.exception('nav: failed binding back handlers: %s', e)

    def _find_widget_by_id(self, root_widget, id_str):
        """Recursively search for a widget with the given id."""
        if not root_widget:
            return None
        if hasattr(root_widget, 'ids') and id_str in root_widget.ids:
            return root_widget.ids[id_str]
        for child in getattr(root_widget, 'children', []):
            found = self._find_widget_by_id(child, id_str)
            if found:
                return found
        return None

    def _on_keyboard_height(self, window, height):
        """No-op.  With the bottom-spacer layout, content sits at the top of
        the screen and the keyboard covers only the empty spacer below the
        buttons.  No runtime layout adjustment is needed."""
        pass

    def on_search_focus(self, focused):
        """No-op placeholder — search bars use default keyboard behavior."""
        pass

    def _check_daily_reset(self):
        """Reset daily drill tracking if it's a new day."""
        try:
            from datetime import datetime
            today = datetime.utcnow().date()
            if not hasattr(self, '_last_drill_reset'):
                self._last_drill_reset = today
                self._drilled_today = set()
            elif self._last_drill_reset != today:
                self._drilled_today = set()
                self._last_drill_reset = today
                Logger.info('Study: Reset daily drill tracking')
        except Exception as e:
            Logger.error(f'Study: Error resetting daily tracking: {e}')

    def on_start(self):
        # Layout strategy: content clusters at the top of the screen with an
        # empty spacer at the bottom.  The Android soft keyboard covers only
        # the spacer, keeping question + input + buttons visible on any device.
        # softinput_mode is set per-screen in _on_screen_current.

        # Pre-load LeapBridge on the main thread so pyjnius caches the class.
        # Background threads cannot find APK classes via JNI FindClass.
        try:
            from reading.translation import preload_leap_bridge
            preload_leap_bridge()
        except Exception as e:
            Logger.warning(f'AppInit: LeapBridge preload: {e}')

        # Migrate app_settings.json to user_data_dir on Android so it
        # survives APK updates (old location was inside extracted assets).
        try:
            from dictionary.paths import get_settings_path
            new_settings = get_settings_path()
            if not os.path.exists(new_settings):
                old_settings = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'dictionary', 'app_settings.json')
                if os.path.exists(old_settings):
                    import shutil
                    shutil.copy2(old_settings, new_settings)
                    Logger.info(f'Settings: migrated to {new_settings}')
        except Exception as e:
            Logger.warning(f'Settings: migration skipped: {e}')

        # initialize lesson queue from disk
        try:
            self._load_lesson_queue()
        except Exception:
            self._lesson_queue = []
            self._lesson_queue = []
        
        # Initialize drill tracking variables
        from datetime import datetime, date
        try:
            self._reviews_completed_this_session = False
            self._weak_words_completed_this_session = False
            self._drilled_today = set()  # Vector IDs drilled today
            self._last_drill_reset = datetime.utcnow().date()
            self._drill_mode = None  # 'weak_words' or None
        except Exception:
            pass
        
        # Bind to screen changes so we can handle Study selection and manage top bar
        try:
            sm = self.root.ids.screen_manager
            Logger.info("AppInit: Binding _on_screen_current to screen_manager.current")
            sm.bind(current=self._on_screen_current)
            Logger.info(f"AppInit: Binding successful, current screen is '{sm.current}'")
            # Make sure back navigation is always wired (KV callback can be finicky across platforms).
            try:
                self._bind_back_handlers()
            except Exception:
                pass
            # Navigation history
            try:
                self._nav_back_in_progress = False
                self._nav_history = []
                # Seed history with current screen so Back behaves predictably.
                self._record_screen_visit(sm.current or 'dictionary')
            except Exception:
                pass
            # Apply the initial top-bar state immediately (prevents width/opacity glitches on first render)
            try:
                Logger.info(f"AppInit: Manually calling _on_screen_current with '{sm.current}'")
                self._on_screen_current(sm, sm.current)
                Logger.info("AppInit: Manual call completed")
            except Exception as e:
                Logger.error(f"AppInit: Error calling _on_screen_current: {e}")
        except Exception as e:
            Logger.error(f"AppInit: Error setting up screen binding: {e}")
        
        # Update handwriting toggle labels to match saved state
        try:
            self._update_handwriting_toggle_labels()
        except Exception:
            pass

        # Show lock icons if handwriting is gated
        try:
            self._update_handwriting_lock_state()
        except Exception:
            pass

        # Wire native input for CJK IME support on Android
        try:
            self._setup_native_search_inputs()
        except Exception as e:
            Logger.warning(f'AppInit: Native input setup: {e}')

        # ── Supabase sync init ────────────────────────────────────────────────
        try:
            from sync.sync import ensure_updated_at_columns
            from sync import supabase_client as sb
            import os as _os
            if _os.path.exists(get_db_path()):
                ensure_updated_at_columns()
            sb.load_saved_session()
            # Validate saved session by refreshing the token
            if sb.is_logged_in():
                if not sb.refresh_session():
                    Logger.info('Sync: saved session expired, clearing')
                    sb.sign_out()
            self._update_sync_btn_label()
            # If still logged in after validation, sync in the background
            if sb.is_logged_in():
                import threading
                from sync.sync import run_full_sync
                def _bg_sync():
                    ok, msg = run_full_sync()
                    Logger.info(f'Sync: startup sync: {msg}')
                threading.Thread(target=_bg_sync, daemon=True).start()
        except Exception as e:
            Logger.warning(f'Sync: startup init skipped: {e}')

        # Navigate to preferred home screen
        try:
            if self.home_screen == 'study':
                sm = self.root.ids.screen_manager
                sm.current = 'study'
        except Exception:
            pass

        # Check DB exists; prompt download if not (first launch on a new device)
        from kivy.clock import Clock as _Clock
        _Clock.schedule_once(self._check_db_ready, 0.5)

    # ── First-launch DB download / version-update ─────────────────────────────

    def _get_db_version_path(self):
        """Path of the small local file that stores the current DB version string."""
        import os
        return get_db_path() + '.version'

    def _read_local_db_version(self):
        """Return the locally stored version string, or None if absent."""
        try:
            with open(self._get_db_version_path(), 'r', encoding='utf-8') as f:
                return f.read().strip()
        except Exception:
            return None

    def _write_local_db_version(self, version: str):
        """Persist the version string next to the DB."""
        try:
            with open(self._get_db_version_path(), 'w', encoding='utf-8') as f:
                f.write(version.strip())
        except Exception as e:
            Logger.warning(f'DBVersion: could not write version file: {e}')

    def _check_db_ready(self, dt=None):
        """Background version-check: download/update DB if needed."""
        import os
        import threading
        db_missing = not os.path.exists(get_db_path())
        if db_missing:
            # First launch — show full onboarding flow
            self._show_onboarding()
            return
        # DB exists — check quietly in the background whether a newer version exists
        threading.Thread(target=self._version_check_worker, daemon=True).start()

