    def _onboarding_download_worker(self):
        """Download dictionary.db, then transition to tutorial pages."""
        import os
        import requests
        from kivy.clock import Clock

        progress_bar = self._onboarding_progress
        status_lbl = self._onboarding_status
        btn = self._onboarding_btn

        def ui(pct, text):
            Clock.schedule_once(lambda dt: setattr(progress_bar, 'value', pct), 0)
            Clock.schedule_once(lambda dt: setattr(status_lbl, 'text', text), 0)

        url = DB_DOWNLOAD_URL
        if not url or 'YOUR_USERNAME' in url:
            ui(0, 'DB_DOWNLOAD_URL is not configured.')
            Clock.schedule_once(lambda dt: setattr(btn, 'disabled', False), 0)
            Clock.schedule_once(lambda dt: setattr(btn, 'text', 'Retry'), 0)
            return

        db_path = get_db_path()
        tmp_path = db_path + '.tmp'

        try:
            os.makedirs(os.path.dirname(db_path) or '.', exist_ok=True)
            ui(0, 'Connecting…')
            resp = requests.get(url, stream=True, timeout=60)
            resp.raise_for_status()

            total = int(resp.headers.get('content-length', 0))
            downloaded = 0

            with open(tmp_path, 'wb') as f:
                for chunk in resp.iter_content(chunk_size=131072):
                    if chunk:
                        f.write(chunk)
                        downloaded += len(chunk)
                        if total:
                            pct = int(downloaded / total * 100)
                            mb_done = downloaded / 1048576
                            mb_total = total / 1048576
                            ui(pct, f'{mb_done:.1f} / {mb_total:.1f} MB  ({pct}%)')
                        else:
                            ui(0, f'{downloaded / 1048576:.1f} MB downloaded…')

            os.replace(tmp_path, db_path)

            # Fetch and persist the remote version so version-check won't re-trigger
            try:
                ver_resp = requests.get(DB_VERSION_URL, timeout=10)
                ver_resp.raise_for_status()
                self._write_local_db_version(ver_resp.text.strip())
            except Exception as ve:
                Logger.warning(f'Onboarding: could not write version file: {ve}')

            ui(100, 'Download complete!')
            Logger.info('Onboarding: download finished, scheduling tutorial')

            # Transition to tutorial after a brief pause
            def _safe_show_tutorial(dt):
                try:
                    self._show_onboarding_tutorial()
                except Exception as e:
                    Logger.error(f'Onboarding: tutorial transition error: {e}')
                    import traceback
                    traceback.print_exc()
            Clock.schedule_once(_safe_show_tutorial, 1.0)

        except Exception as exc:
            Logger.error(f'Onboarding: download error: {exc}')
            if os.path.exists(tmp_path):
                try:
                    os.remove(tmp_path)
                except Exception:
                    pass

            def show_error(dt):
                status_lbl.text = f'Download failed. Tap Retry.'
                btn.disabled = False
                btn.text = 'Retry'

            Clock.schedule_once(show_error, 0)

