    def _version_check_worker(self):
        """Fetch the remote version string; show update popup if it differs."""
        import requests
        from kivy.clock import Clock
        if not DB_VERSION_URL or 'YOUR_USERNAME' in DB_VERSION_URL:
            return  # Not configured yet
        try:
            resp = requests.get(DB_VERSION_URL, timeout=10)
            resp.raise_for_status()
            remote_version = resp.text.strip()
        except Exception as e:
            Logger.info(f'DBVersion: could not fetch remote version: {e}')
            return
        local_version = self._read_local_db_version()
        Logger.info(f'DBVersion: local={local_version!r}  remote={remote_version!r}')
        if remote_version != local_version:
            Clock.schedule_once(
                lambda dt: self._show_db_download_popup(is_update=True, remote_version=remote_version),
                0,
            )

    def _show_db_download_popup(self, is_update=False, remote_version=None):
        """Popup that downloads/updates dictionary.db."""
        import threading
        from kivy.uix.popup import Popup
        from kivy.uix.boxlayout import BoxLayout
        from kivy.uix.label import Label
        from kivy.uix.button import Button
        from kivy.uix.progressbar import ProgressBar
        from kivy.metrics import dp, sp

        FONT = 'fonts/NotoSansJP-Regular.ttf'

        content = BoxLayout(orientation='vertical', padding=dp(24), spacing=dp(14))

        title_lbl = Label(
            text='Dictionary Update' if is_update else 'Welcome to Sakubo',
            font_name=FONT,
            font_size=sp(22),
            bold=True,
            size_hint_y=None,
            height=dp(44),
            halign='center',
            valign='middle',
        )

        if is_update:
            ver_str = f'  (version {remote_version})' if remote_version else ''
            msg_text = (
                f'A new dictionary database is available{ver_str}.\n\n'
                'Download it now to get the latest vocabulary,\n'
                'grammar, and fixes (~270 MB).\n'
                'You can skip and update later from Settings.'
            )
        else:
            msg_text = (
                'The dictionary database needs to be downloaded '
                'before the app can be used.\n\n'
                'This is a one-time download (~270 MB).\n'
                'Please connect to Wi-Fi before continuing.'
            )

        msg_lbl = Label(
            text=msg_text,
            font_name=FONT,
            font_size=sp(14),
            halign='center',
            size_hint_y=None,
        )
        msg_lbl.bind(
            width=lambda i, v: setattr(i, 'text_size', (v, None)),
            texture_size=lambda i, v: setattr(i, 'height', v[1]),
        )

        progress_bar = ProgressBar(max=100, value=0, size_hint_y=None, height=dp(18))

        status_lbl = Label(
            text='Ready to download.',
            font_name=FONT,
            font_size=sp(12),
            size_hint_y=None,
            height=dp(28),
            halign='center',
        )

        download_btn = Button(
            text='Update Now' if is_update else 'Download Now',
            font_name=FONT,
            font_size=sp(16),
            size_hint_y=None,
            height=dp(50),
            background_color=(0.18, 0.55, 0.95, 1),
        )

        popup_height = dp(440) if is_update else dp(400)
        widgets = [title_lbl, msg_lbl, progress_bar, status_lbl, download_btn]

        if is_update:
            skip_btn = Button(
                text='Skip for now',
                font_name=FONT,
                font_size=sp(14),
                size_hint_y=None,
                height=dp(38),
                background_color=(0.3, 0.3, 0.3, 1),
            )
            widgets.append(skip_btn)
            popup_height = dp(480)

        for w in widgets:
            content.add_widget(w)

        popup = Popup(
            title='',
            separator_height=0,
            content=content,
            size_hint=(0.92, None),
            height=popup_height,
            auto_dismiss=False,
        )
        popup.open()

        if is_update:
            skip_btn.bind(on_release=lambda *a: popup.dismiss())

        def on_download(btn):
            btn.disabled = True
            btn.text = 'Downloading…'
            if is_update:
                skip_btn.disabled = True
            threading.Thread(
                target=self._db_download_worker,
                args=(popup, progress_bar, status_lbl, btn, remote_version),
                daemon=True,
            ).start()

        download_btn.bind(on_release=on_download)

    def _db_download_worker(self, popup, progress_bar, status_lbl, btn, remote_version=None):
        """Background thread: stream dictionary.db from GitHub Releases."""
        import os
        import requests
        from kivy.clock import Clock

        def ui(pct, text):
            Clock.schedule_once(lambda dt: setattr(progress_bar, 'value', pct), 0)
            Clock.schedule_once(lambda dt: setattr(status_lbl, 'text', text), 0)

        url = DB_DOWNLOAD_URL
        if not url or 'YOUR_USERNAME' in url:
            Clock.schedule_once(lambda dt: setattr(
                status_lbl, 'text',
                'DB_DOWNLOAD_URL is not configured.\nSet it in main.py and rebuild.'
            ), 0)
            Clock.schedule_once(lambda dt: setattr(btn, 'disabled', False), 0)
            Clock.schedule_once(lambda dt: setattr(btn, 'text', 'Retry'), 0)
            return

        db_path = get_db_path()
        tmp_path = db_path + '.tmp'

        try:
            os.makedirs(os.path.dirname(db_path) or '.', exist_ok=True)
            ui(0, 'Connecting…')
            resp = requests.get(url, stream=True, timeout=60)
            resp.raise_for_status()

            total = int(resp.headers.get('content-length', 0))
            downloaded = 0

            with open(tmp_path, 'wb') as f:
                for chunk in resp.iter_content(chunk_size=131072):
                    if chunk:
                        f.write(chunk)
                        downloaded += len(chunk)
                        if total:
                            pct = int(downloaded / total * 100)
                            mb_done = downloaded / 1048576
                            mb_total = total / 1048576
                            ui(pct, f'{mb_done:.1f} / {mb_total:.1f} MB  ({pct}%)')
                        else:
                            ui(0, f'{downloaded / 1048576:.1f} MB downloaded…')

            os.replace(tmp_path, db_path)
            # Persist the version so we don't re-download until the next release
            if remote_version:
                self._write_local_db_version(remote_version)
            ui(100, 'Download complete! Starting app…')
            Clock.schedule_once(lambda dt: popup.dismiss(), 1.0)

        except Exception as exc:
            Logger.error(f'DBDownload: {exc}')
            if os.path.exists(tmp_path):
                try:
                    os.remove(tmp_path)
                except Exception:
                    pass

            def show_error(dt):
                status_lbl.text = f'Download failed:\n{exc}\n\nTap Retry to try again.'
                btn.disabled = False
                btn.text = 'Retry'

            Clock.schedule_once(show_error, 0)

    # ── Download Data screen ──────────────────────────────────────────────────

    def show_download_data(self):
        """Navigate to the Download Data management screen and refresh statuses."""
        try:
            sm = self._get_screen_manager()
            if sm:
                sm.current = 'download_data'
            self._refresh_download_data_status()
        except Exception as e:
            Logger.error(f'DownloadData: show error: {e}')

