    def _refresh_download_data_status(self):
        """Check current state of DB and LLM and update labels + buttons."""
        import os, threading
        if not self.root:
            return

        # ── DB status ──
        db_status_lbl = self.root.ids.get('download_data_db_status')
        db_btn = self.root.ids.get('download_data_db_btn')
        db_progress = self.root.ids.get('download_data_db_progress')
        if db_status_lbl and db_btn:
            db_exists = os.path.exists(get_db_path())
            local_ver = self._read_local_db_version()
            if db_exists:
                ver_text = f' (version {local_ver})' if local_ver else ''
                db_status_lbl.text = f'Installed{ver_text}'
                db_status_lbl.color = (0.4, 0.8, 0.4, 1)
                db_btn.text = 'Check for Updates'
                db_btn.disabled = False
                db_btn.background_color = (0.22, 0.22, 0.25, 1)
            else:
                db_status_lbl.text = 'Not installed'
                db_status_lbl.color = (0.9, 0.5, 0.3, 1)
                db_btn.text = 'Download Dictionary'
                db_btn.disabled = False
                db_btn.background_color = (0.18, 0.55, 0.95, 1)
        if db_progress:
            db_progress.value = 0
            db_progress.opacity = 0

        # ── LLM status (check in background thread) ──
        llm_status_lbl = self.root.ids.get('download_data_llm_status')
        llm_btn = self.root.ids.get('download_data_llm_btn')
        llm_progress = self.root.ids.get('download_data_llm_progress')
        if llm_status_lbl:
            llm_status_lbl.text = 'Checking…'
            llm_status_lbl.color = (0.65, 0.63, 0.60, 1)
        if llm_btn:
            llm_btn.disabled = True
        if llm_progress:
            llm_progress.value = 0
            llm_progress.opacity = 0

        threading.Thread(target=self._check_llm_status_worker, daemon=True).start()

    def _check_llm_status_worker(self):
        """Background: query LLM download/load status and update UI."""
        from kivy.clock import Clock
        try:
            from reading.translation import get_download_status, is_model_loaded, _is_android
            if not _is_android():
                def _set(dt):
                    lbl = self.root.ids.get('download_data_llm_status') if self.root else None
                    btn = self.root.ids.get('download_data_llm_btn') if self.root else None
                    if lbl:
                        lbl.text = 'Not available (desktop)'
                        lbl.color = (0.65, 0.63, 0.60, 1)
                    if btn:
                        btn.text = 'Not available'
                        btn.disabled = True
                        btn.background_color = (0.22, 0.22, 0.25, 1)
                Clock.schedule_once(_set, 0)
                return

            status = get_download_status()
            loaded = is_model_loaded()

            def _update(dt):
                if not self.root:
                    return
                lbl = self.root.ids.get('download_data_llm_status')
                btn = self.root.ids.get('download_data_llm_btn')
                if not lbl or not btn:
                    return

                if loaded:
                    lbl.text = 'Installed and ready'
                    lbl.color = (0.4, 0.8, 0.4, 1)
                    btn.text = 'Already Downloaded'
                    btn.disabled = True
                    btn.background_color = (0.22, 0.22, 0.25, 1)
                elif status == 'downloaded':
                    lbl.text = 'Downloaded (loads on first translation)'
                    lbl.color = (0.4, 0.8, 0.4, 1)
                    btn.text = 'Already Downloaded'
                    btn.disabled = True
                    btn.background_color = (0.22, 0.22, 0.25, 1)
                elif status == 'downloading':
                    lbl.text = 'Downloading…'
                    lbl.color = (0.9, 0.8, 0.3, 1)
                    btn.text = 'Download in Progress'
                    btn.disabled = True
                    btn.background_color = (0.22, 0.22, 0.25, 1)
                elif status == 'not_downloaded':
                    lbl.text = 'Not installed (~220 MB)'
                    lbl.color = (0.9, 0.5, 0.3, 1)
                    btn.text = 'Download Translation Model'
                    btn.disabled = False
                    btn.background_color = (0.18, 0.55, 0.95, 1)
                else:
                    lbl.text = f'Status: {status}'
                    lbl.color = (0.9, 0.5, 0.3, 1)
                    btn.text = 'Download Translation Model'
                    btn.disabled = False
                    btn.background_color = (0.18, 0.55, 0.95, 1)

            Clock.schedule_once(_update, 0)
        except Exception as e:
            Logger.error(f'DownloadData: LLM status check: {e}')

    def download_data_db_pressed(self):
        """Handle DB download/update button press on the Download Data screen."""
        import os, threading
        if not self.root:
            return

        db_exists = os.path.exists(get_db_path())
        db_btn = self.root.ids.get('download_data_db_btn')
        db_status = self.root.ids.get('download_data_db_status')
        db_progress = self.root.ids.get('download_data_db_progress')

        # If user tapped "Update Now" after an update was found
        remote_version = getattr(db_btn, '_pending_remote_version', None) if db_btn else None
        if remote_version:
            db_btn._pending_remote_version = None
            if db_btn:
                db_btn.disabled = True
                db_btn.text = 'Downloading…'
            if db_progress:
                db_progress.opacity = 1
                db_progress.value = 0
            threading.Thread(
                target=self._download_data_db_worker,
                args=(remote_version,),
                daemon=True,
            ).start()
            return

        if db_exists and db_btn and db_btn.text in ('Check for Updates', 'Up to date'):
            # Check for update in background
            db_btn.disabled = True
            db_btn.text = 'Checking…'
            threading.Thread(
                target=self._download_data_db_check_update_worker,
                daemon=True,
            ).start()
            return

        # DB missing or user confirmed → download
        if db_btn:
            db_btn.disabled = True
            db_btn.text = 'Downloading…'
        if db_progress:
            db_progress.opacity = 1
            db_progress.value = 0
        threading.Thread(
            target=self._download_data_db_worker,
            args=(None,),
            daemon=True,
        ).start()

    def _download_data_db_check_update_worker(self):
        """Background: check if a DB update is available."""
        import requests
        from kivy.clock import Clock
        try:
            resp = requests.get(DB_VERSION_URL, timeout=10)
            resp.raise_for_status()
            remote_version = resp.text.strip()
        except Exception as e:
            def _err(dt):
                btn = self.root.ids.get('download_data_db_btn') if self.root else None
                lbl = self.root.ids.get('download_data_db_status') if self.root else None
                if btn:
                    btn.disabled = False
                    btn.text = 'Check for Updates'
                if lbl:
                    lbl.text = f'Could not check for updates: {e}'
                    lbl.color = (0.9, 0.5, 0.3, 1)
            Clock.schedule_once(_err, 0)
            return

        local_version = self._read_local_db_version()
        if remote_version == local_version:
            def _uptodate(dt):
                btn = self.root.ids.get('download_data_db_btn') if self.root else None
                lbl = self.root.ids.get('download_data_db_status') if self.root else None
                if lbl:
                    lbl.text = f'Up to date (version {local_version})'
                    lbl.color = (0.4, 0.8, 0.4, 1)
                if btn:
                    btn.disabled = False
                    btn.text = 'Check for Updates'
            Clock.schedule_once(_uptodate, 0)
        else:
            def _has_update(dt):
                btn = self.root.ids.get('download_data_db_btn') if self.root else None
                lbl = self.root.ids.get('download_data_db_status') if self.root else None
                prog = self.root.ids.get('download_data_db_progress') if self.root else None
                if lbl:
                    lbl.text = f'Update available: {remote_version}'
                    lbl.color = (0.9, 0.8, 0.3, 1)
                if btn:
                    btn.disabled = False
                    btn.text = 'Update Now'
                    btn.background_color = (0.18, 0.55, 0.95, 1)
                    # Rebind so next press triggers download
                    btn._pending_remote_version = remote_version
            Clock.schedule_once(_has_update, 0)

    def _download_data_db_worker(self, remote_version):
        """Background: download dictionary.db and update the Download Data screen."""
        import os, requests
        from kivy.clock import Clock

        def ui(pct, text, color=None):
            def _u(dt):
                if not self.root:
                    return
                prog = self.root.ids.get('download_data_db_progress')
                lbl = self.root.ids.get('download_data_db_status')
                if prog:
                    prog.value = pct
                if lbl:
                    lbl.text = text
                    if color:
                        lbl.color = color
            Clock.schedule_once(_u, 0)

        url = DB_DOWNLOAD_URL
        db_path = get_db_path()
        tmp_path = db_path + '.tmp'

        try:
            os.makedirs(os.path.dirname(db_path) or '.', exist_ok=True)
            ui(0, 'Connecting…')
            resp = requests.get(url, stream=True, timeout=60)
            resp.raise_for_status()
            total = int(resp.headers.get('content-length', 0))
            downloaded = 0

            with open(tmp_path, 'wb') as f:
                for chunk in resp.iter_content(chunk_size=131072):
                    if chunk:
                        f.write(chunk)
                        downloaded += len(chunk)
                        if total:
                            pct = int(downloaded / total * 100)
                            mb_done = downloaded / 1048576
                            mb_total = total / 1048576
                            ui(pct, f'Downloading… {mb_done:.1f} / {mb_total:.1f} MB  ({pct}%)')

            os.replace(tmp_path, db_path)
            if remote_version:
                self._write_local_db_version(remote_version)
            else:
                # Fetch the version to store it
                try:
                    r = requests.get(DB_VERSION_URL, timeout=10)
                    r.raise_for_status()
                    self._write_local_db_version(r.text.strip())
                except Exception:
                    pass

            def _done(dt):
                self._refresh_download_data_status()
            ui(100, 'Download complete!', color=(0.4, 0.8, 0.4, 1))
            Clock.schedule_once(_done, 1.5)

        except Exception as exc:
            Logger.error(f'DownloadData DB: {exc}')
            if os.path.exists(tmp_path):
                try:
                    os.remove(tmp_path)
                except Exception:
                    pass
            def _err(dt):
                if not self.root:
                    return
                btn = self.root.ids.get('download_data_db_btn')
                lbl = self.root.ids.get('download_data_db_status')
                if btn:
                    btn.disabled = False
                    btn.text = 'Retry'
                    btn.background_color = (0.18, 0.55, 0.95, 1)
                if lbl:
                    lbl.text = f'Download failed: {exc}'
                    lbl.color = (0.9, 0.4, 0.3, 1)
            Clock.schedule_once(_err, 0)

    def download_data_llm_pressed(self):
        """Handle LLM download button press on the Download Data screen."""
        import threading
        if not self.root:
            return

        llm_btn = self.root.ids.get('download_data_llm_btn')
        llm_status = self.root.ids.get('download_data_llm_status')
        llm_progress = self.root.ids.get('download_data_llm_progress')

        if llm_btn:
            llm_btn.disabled = True
            llm_btn.text = 'Starting download…'
        if llm_status:
            llm_status.text = 'Starting download…'
            llm_status.color = (0.9, 0.8, 0.3, 1)
        if llm_progress:
            llm_progress.opacity = 1
            llm_progress.value = 0

        threading.Thread(target=self._download_data_llm_worker, daemon=True).start()

    def _download_data_llm_worker(self):
        """Background: start LLM download and poll status until complete."""
        from kivy.clock import Clock
        try:
            from reading.translation import start_model_download, get_download_status

            result = start_model_download()
            if result != 'OK' and not result.startswith('error:'):
                result = 'OK'  # Some status string — download started

            if result.startswith('error:'):
                def _err(dt):
                    if not self.root:
                        return
                    btn = self.root.ids.get('download_data_llm_btn')
                    lbl = self.root.ids.get('download_data_llm_status')
                    if btn:
                        btn.disabled = False
                        btn.text = 'Retry'
                        btn.background_color = (0.18, 0.55, 0.95, 1)
                    if lbl:
                        lbl.text = f'Error: {result[6:]}'
                        lbl.color = (0.9, 0.4, 0.3, 1)
                Clock.schedule_once(_err, 0)
                return

            # Poll until downloaded (up to 15 min)
            import time
            start = time.time()
            while time.time() - start < 900:
                time.sleep(3)
                status = get_download_status()

                def _update(dt, s=status):
                    if not self.root:
                        return
                    lbl = self.root.ids.get('download_data_llm_status')
                    if lbl:
                        if s == 'downloaded':
                            lbl.text = 'Download complete!'
                            lbl.color = (0.4, 0.8, 0.4, 1)
                        elif s == 'downloading':
                            lbl.text = 'Downloading… (this may take a few minutes)'
                            lbl.color = (0.9, 0.8, 0.3, 1)
                        else:
                            lbl.text = f'Status: {s}'
                Clock.schedule_once(_update, 0)

                if status == 'downloaded':
                    # Done!
                    def _done(dt):
                        self._refresh_download_data_status()
                    Clock.schedule_once(_done, 1.0)
                    return

            # Timed out
            def _timeout(dt):
                if not self.root:
                    return
                btn = self.root.ids.get('download_data_llm_btn')
                lbl = self.root.ids.get('download_data_llm_status')
                if btn:
                    btn.disabled = False
                    btn.text = 'Retry'
                    btn.background_color = (0.18, 0.55, 0.95, 1)
                if lbl:
                    lbl.text = 'Download timed out. Tap Retry.'
                    lbl.color = (0.9, 0.4, 0.3, 1)
            Clock.schedule_once(_timeout, 0)

        except Exception as e:
            Logger.error(f'DownloadData LLM: {e}')
            def _exc(dt):
                if not self.root:
                    return
                btn = self.root.ids.get('download_data_llm_btn')
                lbl = self.root.ids.get('download_data_llm_status')
                if btn:
                    btn.disabled = False
                    btn.text = 'Retry'
                    btn.background_color = (0.18, 0.55, 0.95, 1)
                if lbl:
                    lbl.text = f'Error: {e}'
                    lbl.color = (0.9, 0.4, 0.3, 1)
            Clock.schedule_once(_exc, 0)

    def _show_llm_download_popup(self, on_complete_callback=None):
        """Show a popup prompting the user to download the translation model.
        
        Used when the user tries to translate but the model isn't available.
        on_complete_callback(success: bool) is called when download finishes or is skipped.
        """
        import threading
        from kivy.uix.popup import Popup
        from kivy.uix.boxlayout import BoxLayout
        from kivy.uix.label import Label
        from kivy.uix.button import Button
        from kivy.metrics import dp, sp

        FONT = 'fonts/NotoSansJP-Regular.ttf'

        content = BoxLayout(orientation='vertical', padding=dp(24), spacing=dp(14))

        title_lbl = Label(
            text='Translation Model Needed',
            font_name=FONT,
            font_size=sp(20),
            bold=True,
            size_hint_y=None,
            height=dp(40),
            halign='center',
            valign='middle',
        )

        msg_lbl = Label(
            text=(
                'The translator needs to download a language\n'
                'model before it can work offline (~220 MB).\n\n'
                'This is a one-time download.\n'
                'Connect to Wi-Fi for the best experience.'
            ),
            font_name=FONT,
            font_size=sp(14),
            halign='center',
            size_hint_y=None,
        )
        msg_lbl.bind(
            width=lambda i, v: setattr(i, 'text_size', (v, None)),
            texture_size=lambda i, v: setattr(i, 'height', v[1]),
        )

        status_lbl = Label(
            text='',
            font_name=FONT,
            font_size=sp(12),
            size_hint_y=None,
            height=dp(28),
            halign='center',
            color=(0.65, 0.63, 0.60, 1),
        )

        download_btn = Button(
            text='Download Now',
            font_name=FONT,
            font_size=sp(16),
            size_hint_y=None,
            height=dp(50),
            background_color=(0.18, 0.55, 0.95, 1),
        )

        cancel_btn = Button(
            text='Not now',
            font_name=FONT,
            font_size=sp(14),
            size_hint_y=None,
            height=dp(38),
            background_color=(0.3, 0.3, 0.3, 1),
        )

        for w in [title_lbl, msg_lbl, status_lbl, download_btn, cancel_btn]:
            content.add_widget(w)

        popup = Popup(
            title='',
            separator_height=0,
            content=content,
            size_hint=(0.92, None),
            height=dp(400),
            auto_dismiss=False,
        )
        popup.open()

        def on_cancel(*a):
            popup.dismiss()
            if on_complete_callback:
                on_complete_callback(False)

        cancel_btn.bind(on_release=on_cancel)

        def on_download(btn_inst):
            btn_inst.disabled = True
            btn_inst.text = 'Downloading…'
            cancel_btn.disabled = True
            status_lbl.text = 'Starting download…'

            def _worker():
                from kivy.clock import Clock
                try:
                    from reading.translation import start_model_download, get_download_status
                    result = start_model_download()
                    if result.startswith('error:'):
                        def _e(dt):
                            status_lbl.text = f'Error: {result[6:]}'
                            btn_inst.disabled = False
                            btn_inst.text = 'Retry'
                            cancel_btn.disabled = False
                        Clock.schedule_once(_e, 0)
                        return

                    import time
                    start = time.time()
                    while time.time() - start < 900:
                        time.sleep(3)
                        status = get_download_status()
                        def _u(dt, s=status):
                            if s == 'downloaded':
                                status_lbl.text = 'Download complete!'
                                status_lbl.color = (0.4, 0.8, 0.4, 1)
                            elif s == 'downloading':
                                status_lbl.text = 'Downloading… please wait'
                        Clock.schedule_once(_u, 0)

                        if status == 'downloaded':
                            def _done(dt):
                                popup.dismiss()
                                if on_complete_callback:
                                    on_complete_callback(True)
                            Clock.schedule_once(_done, 1.0)
                            return

                    def _to(dt):
                        status_lbl.text = 'Download timed out. Tap Retry.'
                        btn_inst.disabled = False
                        btn_inst.text = 'Retry'
                        cancel_btn.disabled = False
                    Clock.schedule_once(_to, 0)

                except Exception as e:
                    Logger.error(f'LLM download popup: {e}')
                    def _ex(dt):
                        status_lbl.text = f'Error: {e}'
                        btn_inst.disabled = False
                        btn_inst.text = 'Retry'
                        cancel_btn.disabled = False
                    Clock.schedule_once(_ex, 0)

            threading.Thread(target=_worker, daemon=True).start()

        download_btn.bind(on_release=on_download)

    def on_stop(self):
        """Save state when app closes."""
        try:
            # Save lesson queue to disk
            self._save_lesson_queue()
            Logger.info('App: Saved lesson queue on app close')
        except Exception as e:
            Logger.error(f'App: Error saving state on close: {e}')
        # Stop any active reading timer so elapsed time is saved
        try:
            ls = self.root.ids.get('lessons_screen') if getattr(self, 'root', None) else None
            if ls is not None and hasattr(ls, '_stop_reading_timer'):
                ls._stop_reading_timer()
        except Exception as e:
            Logger.error(f'App: Error stopping reading timer on close: {e}')
        # Push data to Supabase before closing (blocking, short timeout)
        try:
            from sync import supabase_client as sb
            if sb.is_logged_in() and sb.is_configured():
                from sync.sync import run_full_sync
                ok, msg = run_full_sync()
                Logger.info(f'Sync: on_stop sync: {msg}')
        except Exception as e:
            Logger.warning(f'Sync: on_stop sync skipped: {e}')
        return True

        # Optional touch debug: helps diagnose invisible overlays stealing clicks.
        # Enable with env var SPOONFED_TOUCH_DEBUG=1
        try:
            if os.environ.get('SPOONFED_TOUCH_DEBUG', '').strip() == '1':
                if getattr(self, 'root', None) is not None:
                    self.root.bind(on_touch_down=self._touch_debug_on_touch_down)
                    Logger.info('touch_debug: enabled (SPOONFED_TOUCH_DEBUG=1)')
        except Exception:
            pass

    def _touch_debug_on_touch_down(self, widget, touch):
        """Touch debug disabled (removed study-related logic)."""
        return False


    def _touch_debug_hit_test(self, widget, pos):
        """Return the topmost child widget that collides with window pos."""
        try:
            if widget is None:
                return None
            # Traverse in draw order: last child is topmost.
            for child in reversed(getattr(widget, 'children', []) or []):
                try:
                    if child.collide_point(*pos):
                        deeper = self._touch_debug_hit_test(child, pos)
                        return deeper or child
                except Exception:
                    continue
            return widget if widget.collide_point(*pos) else None
        except Exception:
            return None
    
    def _lesson_has_new_vectors(self, lesson_path_or_id):
        """Check if a lesson has any entries with vectors not yet in SRS.
        
        Args:
            lesson_path_or_id: Either a lesson file path string or a custom_lesson:ID string
        
        Returns:
            True if lesson has at least one entry with learnable vectors, False otherwise
        """
        try:
            conn = dict_db.init_db(get_db_path())
            cursor = conn.cursor()
            
            # Helper: determine the actual vector types an entry would generate
            # (mirrors make_vectors_from_row in learning.py)
            def get_entry_vector_types(entry_id):
                """Return the set of vector_type strings this entry produces."""
                cursor.execute('SELECT kind, kanji, kana, study_vectors FROM entries WHERE id = ?', (entry_id,))
                row = cursor.fetchone()
                if not row:
                    return set()
                entry_kind = row[0] or 'vocab'
                kanji = row[1]
                kana_val = row[2]
                study_vectors_str = row[3] or ''

                # Detect kana chars stored as kind='kanji' (same as make_vectors_from_row)
                if entry_kind == 'kanji' and kanji and kana_val and kanji == kana_val and len(kanji) <= 2:
                    ch = kanji[0]
                    if ('\u3040' <= ch <= '\u309F') or ('\u30A0' <= ch <= '\u30FF'):
                        entry_kind = 'kana'
                
                # Base vectors determined by kind (same logic as make_vectors_from_row)
                base_vectors = set()
                if entry_kind == 'kana':
                    base_vectors = {'show_kana', 'show_romaji'}
                elif entry_kind == 'grammar':
                    base_vectors = {'fill-blank', 'scramble', 'translate', 'dictation'}
                elif entry_kind in ('vocab', 'kanji'):
                    if kanji and kanji.strip():
                        base_vectors = {'orthography_to_reading', 'orthography_to_meaning'}
                    else:
                        base_vectors = {'kana_to_meaning', 'meaning_to_kana'}
                else:
                    base_vectors = {'default'}
                
                # Add handwriting if listed in study_vectors column
                if 'handwriting' in study_vectors_str:
                    base_vectors.add('handwriting')
                
                return base_vectors, entry_kind
            
            # Helper function to check if an entry has new vectors
            def has_new_vectors(entry_id):
                try:
                    result = get_entry_vector_types(entry_id)
                    if not result:
                        return True  # Entry not in DB yet — treat as learnable, not mastered
                    available_vectors, entry_kind = result
                    
                    # Filter based on handwriting mode settings
                    if not self.handwriting_mode:
                        available_vectors.discard('handwriting')
                    elif self.handwriting_only_mode:
                        available_vectors = available_vectors & {'handwriting'}
                    
                    # If no vectors to check after filtering, return False
                    if not available_vectors:
                        return False
                    
                    # Check which vectors are already in SRS
                    cursor.execute('SELECT data FROM srs WHERE entry_id = ?', (entry_id,))
                    srs_row = cursor.fetchone()
                    if not srs_row:
                        return True  # Not in SRS at all, all vectors are new
                    
                    import json
                    srs_data = json.loads(srs_row[0]) if srs_row[0] else {}
                    per_vector = srs_data.get('per_vector', {})
                    per_kind = srs_data.get('per_kind', {})
                    
                    # Determine what's already learned
                    srs_vector_types = set()
                    
                    if per_vector:
                        # New format: specific vector types tracked
                        srs_vector_types = set(per_vector.keys())
                    elif entry_kind in per_kind:
                        # Legacy format: entire kind mastered (all vectors learned)
                        srs_vector_types = available_vectors.copy()
                    
                    # If any available vector is NOT in SRS, this entry has new vectors
                    new_vectors = available_vectors - srs_vector_types
                    return len(new_vectors) > 0
                    
                except Exception as e:
                    Logger.warning(f'LessonQueue: Error checking entry {entry_id}: {e}')
                    return False
            
            entry_ids = []
            
            # Get entry IDs based on lesson type
            if isinstance(lesson_path_or_id, str) and lesson_path_or_id.startswith('custom_lesson:'):
                # Custom lesson
                lesson_id = int(lesson_path_or_id.split(':')[1])
                lesson = dict_db.get_custom_lesson(conn, lesson_id)
                if lesson:
                    items = lesson.get('items', [])
                    for item in items:
                        if isinstance(item, dict):
                            entry_ids.append(item.get('entry_id'))
                        else:
                            entry_ids.append(item)
            elif isinstance(lesson_path_or_id, int):
                # Direct entry ID
                entry_ids = [lesson_path_or_id]
            else:
                # Lesson file path - extract entry_ids from items list
                lesson_data = self._load_lesson_json(lesson_path_or_id)
                items = lesson_data.get('items', [])
                for item in items:
                    if isinstance(item, dict):
                        eid = item.get('entry_id')
                        if eid is not None:
                            entry_ids.append(eid)
                    else:
                        entry_ids.append(item)
                # Fallback: some lessons might use a flat entry_ids list
                if not entry_ids:
                    entry_ids = lesson_data.get('entry_ids', [])
                # Grammar lessons have entry_id at top level (single entry)
                if not entry_ids and 'entry_id' in lesson_data:
                    entry_ids = [lesson_data['entry_id']]
            
            # Check if ANY entry has new vectors
            for entry_id in entry_ids:
                if has_new_vectors(entry_id):
                    conn.close()
                    return True
            
            conn.close()
            return False
            
        except Exception as e:
            Logger.error(f'LessonQueue: Error checking lesson for new vectors: {e}')
            return False  # Assume no new vectors on error

    def _show_queue_position_popup(self, on_chosen):
        """Show a popup asking user whether to add to front or back of queue.
        Calls on_chosen('front') or on_chosen('back')."""
        from kivy.uix.popup import Popup
        from kivy.uix.boxlayout import BoxLayout
        from kivy.uix.button import Button
        from kivy.uix.widget import Widget
        from kivy.metrics import dp

        content = BoxLayout(orientation='vertical', spacing=dp(8), padding=dp(12))
        content.add_widget(Widget(size_hint_y=None, height=dp(4)))

        front_btn = Button(
            text='Next in Queue',
            size_hint_y=None, height=dp(44),
            background_normal='', background_down='',
            background_color=(0.15, 0.45, 0.65, 1),
            color=(1, 1, 1, 1),
            font_size='15sp',
            font_name='fonts/NotoSansJP-Regular.ttf'
        )
        back_btn = Button(
            text='Last in Queue',
            size_hint_y=None, height=dp(44),
            background_normal='', background_down='',
            background_color=(0.15, 0.45, 0.65, 1),
            color=(1, 1, 1, 1),
            font_size='15sp',
            font_name='fonts/NotoSansJP-Regular.ttf'
        )

        popup = Popup(
            title='Queue Position',
            content=content,
            size_hint=(0.75, None),
            height=dp(240),
            separator_color=(0, 0, 0, 0)
        )

        def on_front(*_):
            popup.dismiss()
            on_chosen('front')
        def on_back(*_):
            popup.dismiss()
            on_chosen('back')

        front_btn.bind(on_release=on_front)
        back_btn.bind(on_release=on_back)

        content.add_widget(front_btn)
        content.add_widget(back_btn)

        close_btn = Button(
            text='Close',
            size_hint_y=None, height=dp(44),
            background_normal='', background_down='',
            background_color=(0.35, 0.35, 0.38, 1),
            color=(0.90, 0.88, 0.85, 1),
            font_size='15sp',
            font_name='fonts/NotoSansJP-Regular.ttf'
        )
        close_btn.bind(on_release=lambda *_: popup.dismiss())
        content.add_widget(close_btn)
        popup.open()

    def _refresh_lesson_menus(self):
        """Refresh lesson list views to update button visuals after queue change."""
        try:
            ls = self.root.ids.get('lessons_screen') if getattr(self, 'root', None) else None
            if ls:
                view = getattr(ls, '_current_lessons_view', 'main')
                payload = getattr(ls, '_view_payload', {})
                if view == 'spoonfed':
                    ls.show_spoonfed_menu(query=payload.get('query'), record_nav=False)
                elif view == 'kana_lessons':
                    ls.show_kana_lessons(query=payload.get('query'), record_nav=False)
                elif view == 'custom':
                    ls.show_custom_lessons(query=payload.get('query'), record_nav=False)
                elif view == 'n5_vocab_lessons':
                    ls.show_n5_vocab_lessons(query=payload.get('query'), record_nav=False)
                elif view == 'n4_vocab_lessons':
                    ls.show_n4_vocab_lessons(query=payload.get('query'), record_nav=False)
                elif view == 'n3_vocab_lessons':
                    ls.show_n3_vocab_lessons(query=payload.get('query'), record_nav=False)
                elif view == 'n2_vocab_lessons':
                    ls.show_n2_vocab_lessons(query=payload.get('query'), record_nav=False)
                elif view == 'n1_vocab_lessons':
                    ls.show_n1_vocab_lessons(query=payload.get('query'), record_nav=False)
        except Exception as e:
            Logger.error(f'LessonQueue: error refreshing menu: {e}')

    def toggle_lesson_queue(self, lesson_path: str | Path | int):
        """Toggle a lesson path or entry ID in the in-memory lesson queue."""
        # Keep integers as integers, convert paths to strings
        if isinstance(lesson_path, int):
            p = lesson_path
        else:
            p = str(lesson_path)
        Logger.info(f'LessonQueue: toggle {p}')
        if not hasattr(self, '_lesson_queue'):
            self._lesson_queue = []
        if p in self._lesson_queue:
            # remove and keep order
            try:
                self._lesson_queue.remove(p)
                self._save_lesson_queue()
                Logger.info(f'LessonQueue: removed {p}')
            except Exception as e:
                Logger.error(f'LessonQueue: error removing: {e}')
                pass
            # feedback
            try:
                ds = self._get_drill_screen()
                if ds:
                    pass
            except Exception:
                pass
            # refresh menus for remove
            self._refresh_lesson_menus()
        else:
            # Check if this is a custom lesson with 0 items
            if isinstance(p, str) and p.startswith('custom_lesson:'):
                try:
                    lesson_id = int(p.split(':')[1])
                    conn = dict_db.init_db(get_db_path())
                    lesson = dict_db.get_custom_lesson(conn, lesson_id)
                    conn.close()
                    
                    if lesson and len(lesson.get('items', [])) == 0:
                        # Show popup informing user
                        from kivy.uix.popup import Popup
                        from kivy.uix.widget import Widget
                        
                        content = BoxLayout(orientation='vertical', spacing=dp(8), padding=dp(8))
                        
                        # Add spacing widget to push label below separator line
                        content.add_widget(Widget(size_hint_y=None, height=dp(20)))
                        
                        label = Label(
                            text='This lesson has 0 items. To add this lesson to your queue, please add more items.',
                            size_hint_y=None,
                            height=dp(60),
                            halign='center',
                            valign='middle',
                            color=(0.90, 0.88, 0.85, 1)
                        )
                        label.bind(size=label.setter('text_size'))
                        content.add_widget(label)
                        
                        buttons = BoxLayout(size_hint_y=None, height=dp(44), spacing=dp(8))
                        
                        popup = Popup(
                            title='Cannot Add Empty Lesson',
                            content=content,
                            size_hint=(0.8, None),
                            height=dp(180),
                            separator_color=(0, 0, 0, 0)
                        )
                        
                        ok_btn = Button(text='OK')
                        try:
                            ok_btn.background_normal = ''
                            ok_btn.background_down = ''
                            ok_btn.background_color = (0.15, 0.45, 0.65, 1)
                            ok_btn.color = (1, 1, 1, 1)
                        except Exception:
                            pass
                        ok_btn.bind(on_release=popup.dismiss)
                        buttons.add_widget(ok_btn)
                        
                        content.add_widget(buttons)
                        popup.open()
                        return
                except Exception as e:
                    Logger.error(f'LessonQueue: Error checking custom lesson items: {e}')
            
            # Reading items skip SRS-related guards (study limits, mastered check)
            _is_reading_item = isinstance(p, str) and (p.startswith('reading:') or p.startswith('graded:'))
            
            # before appending, enforce study limits if enabled
            try:
                app = App.get_running_app()
                if not _is_reading_item and getattr(app, 'study_limit_new_lessons', False):
                    try:
                        conn = dict_db.init_db(get_db_path())
                        low = dict_db.count_low_stability_vectors(conn, threshold=int(getattr(app, 'study_stability_threshold', 3)))
                        max_allowed = int(getattr(app, 'study_max_low_stability_vectors', 125))
                        if low >= max_allowed:
                            # inform the user and refuse to add
                            ds = self._get_drill_screen()
                            if ds:
                                pass
                            # popup explaining the setting
                            try:
                                layout = BoxLayout(orientation='vertical', spacing=8, padding=8)
                                layout.add_widget(Label(text=(f'You have {low} study vectors below stability {int(getattr(app, "study_stability_threshold", 3))}.'), size_hint_y=None, height=dp(36)))
                                layout.add_widget(Label(text='To add new lessons, complete existing unstable items or disable this limit in Settings → Study Settings.', size_hint_y=None, height=dp(72)))
                                btn = Button(text='Close', size_hint_y=None, height=dp(40))
                                try:
                                    btn.background_normal = ''
                                    btn.background_down = ''
                                    btn.background_color = (0.1098, 0.1098, 0.1098, 1)
                                    btn.color = (1,1,1,1)
                                except Exception:
                                    pass
                                layout.add_widget(btn)
                                popup = Popup(title='Study limit prevents adding', content=layout, size_hint=(None, None), size=(min(dp(520), Window.width*0.8), min(dp(300), Window.height*0.4)), auto_dismiss=False)
                                btn.bind(on_release=lambda *_: popup.dismiss())
                                popup.open()
                            except Exception:
                                pass
                            return
                    except Exception:
                        pass
            except Exception:
                pass
            
            # Check if lesson has any new vectors
            if not _is_reading_item and not self._lesson_has_new_vectors(p):
                Logger.info(f'LessonQueue: Lesson {p} has no new vectors (all already in SRS)')
                # Show popup informing user
                try:
                    from kivy.uix.popup import Popup
                    from kivy.core.window import Window
                    
                    content = BoxLayout(orientation='vertical', spacing=dp(8), padding=dp(16))
                    
                    label = Label(
                        text='All items in this lesson are already mastered.\nYou have already learned all available vectors for this lesson.',
                        size_hint_y=None,
                        height=dp(80),
                        halign='center',
                        valign='middle',
                        color=(0.90, 0.88, 0.85, 1)
                    )
                    label.bind(size=label.setter('text_size'))
                    content.add_widget(label)
                    
                    buttons = BoxLayout(size_hint_y=None, height=dp(44), spacing=dp(8))
                    
                    popup = Popup(
                        title='Already Mastered',
                        content=content,
                        size_hint=(0.8, None),
                        height=dp(200),
                        separator_color=(0, 0, 0, 0)
                    )
                    
                    ok_btn = Button(text='OK')
                    try:
                        ok_btn.background_normal = ''
                        ok_btn.background_down = ''
                        ok_btn.background_color = (0.15, 0.45, 0.65, 1)
                        ok_btn.color = (1, 1, 1, 1)
                    except Exception:
                        pass
                    ok_btn.bind(on_release=popup.dismiss)
                    buttons.add_widget(ok_btn)
                    
                    content.add_widget(buttons)
                    popup.open()
                except Exception as e:
                    Logger.error(f'LessonQueue: Error showing mastered popup: {e}')
                return
            
            # Ask front or back, then add
            def _do_enqueue(position):
                try:
                    if position == 'front':
                        self._lesson_queue.insert(0, p)
                    else:
                        self._lesson_queue.append(p)
                    self._save_lesson_queue()
                    Logger.info(f'LessonQueue: added {p} to {position}, queue now has {len(self._lesson_queue)} items')
                except Exception as e:
                    Logger.error(f'LessonQueue: error adding: {e}')
                self._refresh_lesson_menus()
            self._show_queue_position_popup(_do_enqueue)

    def add_all_kana_to_queue(self):
        """Add all kana lessons (1-50) to the queue (only those with new vectors)."""
        lessons_root = Path('dictionary') / 'lessons' / 'spoonfed_japanese'
        index_file = lessons_root / 'index.json'
        if not index_file.exists():
            return
        with open(index_file, 'r', encoding='utf-8') as f:
            idx = json.load(f).get('lessons', {})
        def _norm(p):
            sp = str(p)
            if sp.lower().startswith('dictionary'):
                return str(Path(sp))
            return str(lessons_root / Path(sp))
        try:
            if not hasattr(self, '_lesson_queue'):
                self._lesson_queue = []
            to_add = []
            skipped_count = 0
            for num, types in idx.items():
                n = int(num)
                if not (1 <= n <= 50):
                    continue
                p = None
                if 'kana' in types:
                    p = _norm(types['kana'])
                elif 'grammar' in types:
                    p = _norm(types['grammar'])
                elif 'vocab' in types:
                    p = _norm(types['vocab'])
                if p and p not in self._lesson_queue:
                    if self._lesson_has_new_vectors(p):
                        to_add.append(p)
                    else:
                        skipped_count += 1
            if not to_add:
                Logger.info(f'Kana: No new lessons to add, skipped {skipped_count}')
                return
            def _do_add(position):
                if position == 'front':
                    for i, p in enumerate(to_add):
                        self._lesson_queue.insert(i, p)
                else:
                    self._lesson_queue.extend(to_add)
                Logger.info(f'Kana: Added {len(to_add)} lessons to queue ({position}), skipped {skipped_count} (already mastered)')
                self._save_lesson_queue()
                from kivy.clock import Clock
                def _refresh(dt):
                    try:
                        ls = self.root.ids.get('lessons_screen')
                        if ls and hasattr(ls, 'show_kana_lessons'):
                            ls.show_kana_lessons(record_nav=False)
                    except Exception:
                        pass
                Clock.schedule_once(_refresh, 0)
            self._show_queue_position_popup(_do_add)
        except Exception as e:
            Logger.error(f'Kana: Error adding to queue: {e}')

