    def add_all_n5_vocab_to_queue(self):
        """Add all N5 vocabulary lessons to the queue (only those with new vectors)."""
        lessons_root = Path('dictionary') / 'lessons' / 'spoonfed_japanese'
        index_file = lessons_root / 'index.json'
        if not index_file.exists():
            return
        with open(index_file, 'r', encoding='utf-8') as f:
            idx = json.load(f).get('lessons', {})
        def _norm(p):
            sp = str(p)
            if sp.lower().startswith('dictionary'):
                return str(Path(sp))
            return str(lessons_root / Path(sp))
        try:
            if not hasattr(self, '_lesson_queue'):
                self._lesson_queue = []
            # enforce study limit before adding
            app = App.get_running_app()
            if getattr(app, 'study_limit_new_lessons', False):
                try:
                    conn = dict_db.init_db(get_db_path())
                    low = dict_db.count_low_stability_vectors(conn, threshold=int(getattr(app, 'study_stability_threshold', 3)))
                    max_allowed = int(getattr(app, 'study_max_low_vectors', 150))
                    if low >= max_allowed:
                        ds = self._get_drill_screen()
                        if ds:
                            pass
                        return
                except Exception:
                    pass
            to_add = []
            skipped_count = 0
            # Filter for N5 lessons (51-251) - both vocab and grammar
            for num, types in idx.items():
                if 51 <= int(num) <= 251:
                    p = None
                    if 'vocab' in types:
                        p = _norm(types['vocab'])
                    elif 'grammar' in types:
                        p = _norm(types['grammar'])
                    if p and p not in self._lesson_queue:
                        if self._lesson_has_new_vectors(p):
                            to_add.append(p)
                        else:
                            skipped_count += 1
            # Also add N5 graded readings
            try:
                import glob as _glob
                for _rpath in sorted(_glob.glob('readings/n5/*.json')):
                    _rq = f'graded:{_rpath}'
                    if _rq not in self._lesson_queue:
                        to_add.append(_rq)
            except Exception:
                pass
            if not to_add:
                Logger.info(f'N5: No new lessons to add, skipped {skipped_count}')
                return
            def _do_add(position):
                if position == 'front':
                    for i, p in enumerate(to_add):
                        self._lesson_queue.insert(i, p)
                else:
                    self._lesson_queue.extend(to_add)
                Logger.info(f'N5: Added {len(to_add)} lessons to queue ({position}), skipped {skipped_count} (already mastered)')
                self._save_lesson_queue()
                from kivy.clock import Clock
                def _refresh(dt):
                    try:
                        ls = self.root.ids.get('lessons_screen')
                        if ls and hasattr(ls, 'show_n5_vocab_lessons'):
                            ls.show_n5_vocab_lessons(record_nav=False)
                    except Exception:
                        pass
                Clock.schedule_once(_refresh, 0)
            self._show_queue_position_popup(_do_add)
        except Exception:
            pass

