    def show_my_queue(self, active_filter: str = 'all', record_nav: bool = True, limit: int = 250, query: str = ''):
        """Show the lesson queue as a full Lessons screen with filters."""
        try:
            # Update Lessons internal view state so global Back can return to the previous Lessons page
            try:
                ls = self.root.ids.get('lessons_screen') if getattr(self, 'root', None) else None
                if ls is not None:
                    if record_nav and hasattr(ls, '_push_view_state'):
                        try:
                            ls._push_view_state()
                        except Exception:
                            pass
                    try:
                        ls._current_lessons_view = 'queue'
                        ls._queue_filter = active_filter
                        ls._view_payload = {'filter': active_filter}
                    except Exception:
                        pass
            except Exception:
                pass
            
            # Ensure the Lessons screen is visible so the queue we build is shown
            try:
                sm = self._get_screen_manager()
                if sm is not None:
                    sm.current = 'lessons'
            except Exception:
                pass

            # find the lessons quick area from the Lessons screen; if it's not available, fall back to direct id lookup
            qa = None
            try:
                if getattr(self, 'root', None):
                    ls = self.root.ids.get('lessons_screen')
                    if ls and hasattr(ls, '_get_quick_area'):
                        qa = ls._get_quick_area()
            except Exception as e:
                Logger.info('MyQueue: error getting quick area from lessons_screen: %s', e)
                qa = None
            if qa is None:
                qa = getattr(self, '_quick_area', None) or (self.root.ids.get('lessons_quick') if getattr(self, 'root', None) else None)
            Logger.info('MyQueue: quick_area found=%s', qa is not None)
            if qa is None:
                Logger.error('MyQueue: Could not find quick area widget!')
                return
            qa.clear_widgets()
            Logger.info('MyQueue: cleared quick area, building UI')
            
            # Show loading indicator while fetching data in background
            from kivy.uix.anchorlayout import AnchorLayout
            loading_label = Label(text='Loading queue...', halign='center', valign='middle')
            qa.add_widget(loading_label)
            
            # Fetch queue data in background thread to avoid UI freeze
            qlist = list(getattr(self, '_lesson_queue', []))
            
            def fetch_queue_data():
                """Background thread: fetch all needed data in batch."""
                try:
                    import json as _json
                    from pathlib import Path as _Path
                    from collections import defaultdict
                    conn = dict_db.init_db(get_db_path())
                    
                    # Partition queue items by type
                    entry_ids = [p for p in qlist if isinstance(p, int)]
                    lesson_path_items = [str(p) for p in qlist
                                         if isinstance(p, str) and not p.startswith('custom_lesson:') and not p.startswith('graded:') and not p.startswith('reading:')]
                    custom_lesson_ids = []
                    for p in qlist:
                        if isinstance(p, str) and p.startswith('custom_lesson:'):
                            try:
                                custom_lesson_ids.append(int(p.split(':')[1]))
                            except Exception:
                                pass
                    
                    # Batch fetch all directly-queued entries
                    entries_map = dict_db.get_entries_by_ids(conn, entry_ids) if entry_ids else {}
                    
                    # Load lesson JSON for each path item – get title + contained entry IDs
                    path_lesson_cache = {}  # str(path) -> {title, entry_ids}
                    for lp in lesson_path_items:
                        try:
                            lf = _Path(lp)
                            if lf.exists():
                                with open(lf, 'r', encoding='utf-8') as _f:
                                    ldata = _json.load(_f)
                                ltitle = ldata.get('title') or lf.stem.replace('_', ' ')
                                lentry_ids = [item['entry_id'] for item in ldata.get('items', [])
                                              if item.get('entry_id')]
                                path_lesson_cache[lp] = {'title': ltitle, 'entry_ids': lentry_ids}
                        except Exception:
                            pass
                    
                    # Fetch entry IDs for each custom lesson in the queue
                    custom_lesson_entry_ids = {}  # lesson_id -> [entry_id]
                    if custom_lesson_ids:
                        cur = conn.cursor()
                        _ph = ','.join('?' * len(custom_lesson_ids))
                        cur.execute(f'SELECT lesson_id, entry_id FROM custom_lesson_items '
                                    f'WHERE lesson_id IN ({_ph})', custom_lesson_ids)
                        _tmp = defaultdict(list)
                        for _row in cur.fetchall():
                            _tmp[_row[0]].append(_row[1])
                        custom_lesson_entry_ids = dict(_tmp)
                    
                    # Build the full candidate entry ID pool for FTS (direct + inside every lesson)
                    _all_eids = set(entry_ids)
                    for _lcd in path_lesson_cache.values():
                        _all_eids.update(_lcd['entry_ids'])
                    for _eids in custom_lesson_entry_ids.values():
                        _all_eids.update(_eids)
                    
                    # FTS search – use same engine as dictionary (handles romaji/kana/kanji/deinflect)
                    _search_q = (query or '').strip()
                    fts_match_ids = None  # None = no filter; set = active filter
                    if _search_q and _all_eids:
                        try:
                            results = dict_db.search_entries(conn, _search_q, limit=10000)
                            fts_match_ids = {row[0] for row in results}
                        except Exception as _fe:
                            Logger.error(f'MyQueue: FTS search error: {_fe}')
                    
                    # Batch fetch custom lessons and collections info
                    all_custom_lessons = dict_db.get_all_custom_lessons(conn) if custom_lesson_ids else []
                    custom_lessons_map = {l['id']: l for l in all_custom_lessons}
                    
                    # Build parent-child lookup for O(1) access (performance optimization)
                    children_by_parent = defaultdict(list)
                    for lesson in all_custom_lessons:
                        parent_id = lesson.get('parent_id')
                        if parent_id:
                            children_by_parent[parent_id].append(lesson)
                    
                    conn.close()
                    return (entries_map, custom_lessons_map, all_custom_lessons,
                            children_by_parent, fts_match_ids,
                            path_lesson_cache, custom_lesson_entry_ids)
                except Exception as e:
                    Logger.error(f'MyQueue: background fetch error: {e}')
                    from collections import defaultdict
                    return {}, {}, [], defaultdict(list), None, {}, {}
            
            def build_ui(entries_map, custom_lessons_map, all_custom_lessons, children_by_parent,
                          fts_match_ids=None, path_lesson_cache=None, custom_lesson_entry_ids=None):
                """Main thread: build UI with fetched data."""
                try:
                    _queue_q = (query or '').strip().lower()
                    _path_lesson_cache = path_lesson_cache or {}
                    _custom_lesson_entry_ids = custom_lesson_entry_ids or {}
                    qa.clear_widgets()
                    # Zero out the quick area's own padding/spacing so filters sit flush like dictionary
                    qa.padding = [0, 0, 0, 0]
                    qa.spacing = 0
                    container = BoxLayout(orientation='vertical', spacing=0, padding=0, size_hint=(1, 1))

                    # filter buttons - styled to match Dictionary filters exactly
                    from kivy.uix.togglebutton import ToggleButton
                    from kivy.graphics import Color, Rectangle
                    top = BoxLayout(size_hint_y=None, height=dp(30), spacing=dp(4), padding=[dp(4), dp(0), dp(4), dp(4)])
                    
                    # Add transparent background like dictionary filters
                    with top.canvas.before:
                        Color(0, 0, 0, 0)
                        Rectangle(pos=top.pos, size=top.size)
                    
                    def make_filter_btn(name, flt):
                        b = ToggleButton(text=name, group='queue_filter', size_hint_x=1)
                        b.state = 'down' if flt == active_filter else 'normal'
                        try:
                            b.background_normal = ''
                            b.background_down = ''
                            b.background_color = (0, 0, 0, 0)
                            normal_color = (0.28, 0.28, 0.30, 1)
                            down_color = (0.38, 0.38, 0.42, 1)
                            b.color = (0.90, 0.88, 0.85, 1)
                            
                            with b.canvas.before:
                                b._bg_color = Color(*(down_color if b.state == 'down' else normal_color))
                                b._bg_rect = Rectangle(pos=b.pos, size=b.size)
                            
                            def update_bg(*args):
                                b._bg_color.rgba = down_color if b.state == 'down' else normal_color
                                b._bg_rect.pos = b.pos
                                b._bg_rect.size = b.size
                            
                            b.bind(state=update_bg, pos=update_bg, size=update_bg)
                        except Exception:
                            pass
                        
                        def on_release_filter(*args):
                            self._filter_queue_display(flt)
                        
                        b.bind(on_release=on_release_filter)
                        return b
                    top.add_widget(make_filter_btn('All', 'all'))
                    top.add_widget(make_filter_btn('Sakubo', 'spoonfed'))
                    top.add_widget(make_filter_btn('Custom', 'custom'))
                    container.add_widget(top)

                    # ScrollView for queued lessons
                    scroll = ScrollView(size_hint=(1, 1))
                    grid = GridLayout(
                        cols=1,
                        size_hint_y=None,
                        spacing=dp(6),
                        padding=[dp(8), dp(8), dp(8), dp(8)]
                    )
                    grid.bind(minimum_height=grid.setter('height'))
                    scroll.add_widget(grid)
                    
                    # Store filter for refresh
                    self._queue_active_filter = active_filter
                    
                    count = 0
                    shown = 0
                    total_items = 0
                    
                    # Pre-process: group child lessons under parent collections
                    _queued_by_parent = {}  # parent_id -> [queue_item_key, ...]
                    _parent_for_item = {}  # lesson_id -> parent_id
                    for _p in qlist:
                        if isinstance(_p, str) and _p.startswith('custom_lesson:'):
                            try:
                                _lid = int(_p.split(':')[1])
                                _les = custom_lessons_map.get(_lid)
                                if _les and _les.get('parent_id'):
                                    _pid = _les['parent_id']
                                    _queued_by_parent.setdefault(_pid, []).append(_p)
                                    _parent_for_item[_lid] = _pid
                            except Exception:
                                pass
                    _rendered_parents = set()
                    
                    for p in qlist:
                        is_collection = False  # Track if it's a collection
                        _override_item_data = None  # Set for collection groups
                        _collection_children = None  # Set for collection groups
                        # Check type of queue item
                        if isinstance(p, int):
                            # Individual entry - use pre-fetched data
                            entry = entries_map.get(p)
                            if not entry:
                                continue
                            kanji = entry.get('kanji') or ''
                            kana = entry.get('kana') or ''
                            gloss = entry.get('gloss') or ''
                            entry_kind = entry.get('kind') or ''
                            name = f"{kanji or kana} - {gloss.split(';')[0][:40]}"
                            kind = 'custom'
                            if entry_kind == 'vocab':
                                type_label = 'Word'
                            elif entry_kind == 'kanji':
                                type_label = 'Kanji'
                            elif entry_kind == 'kana':
                                type_label = 'Kana'
                            elif entry_kind == 'grammar':
                                type_label = 'Grammar'
                            else:
                                type_label = 'Entry'
                        elif isinstance(p, str) and p.startswith('custom_lesson:'):
                            # Custom lesson - use pre-fetched data
                            try:
                                lesson_id = int(p.split(':')[1])
                                lesson = custom_lessons_map.get(lesson_id)
                                if not lesson:
                                    continue
                                # Check if this child belongs to a collection → group under parent
                                _par = _parent_for_item.get(lesson_id)
                                if _par:
                                    if _par in _rendered_parents:
                                        continue  # Already shown as collection group
                                    _rendered_parents.add(_par)
                                    parent_lesson = custom_lessons_map.get(_par)
                                    if parent_lesson:
                                        _qchildren = _queued_by_parent.get(_par, [])
                                        name = parent_lesson['name'] + f" ({len(_qchildren)} queued)"
                                        type_label = 'Collection'
                                        is_collection = True
                                        _override_item_data = f'custom_lesson:{_par}'
                                        _collection_children = list(_qchildren)
                                    else:
                                        name = lesson['name']
                                        item_count = lesson.get('item_count', 0)
                                        name += f" ({item_count} items)"
                                        type_label = 'Custom Lesson'
                                else:
                                    name = lesson['name']
                                    child_lessons = children_by_parent.get(lesson_id, [])
                                    is_collection = len(child_lessons) > 0
                                    if is_collection:
                                        name += f" ({len(child_lessons)} lessons)"
                                        type_label = 'Collection'
                                    else:
                                        item_count = lesson.get('item_count', 0)
                                        name += f" ({item_count} items)"
                                        type_label = 'Custom Lesson'
                                kind = 'custom'
                            except Exception as e:
                                Logger.error(f'MyQueue: error processing custom lesson {p}: {e}')
                                continue
                        elif isinstance(p, str) and p.startswith('reading:'):
                            # Reading material
                            try:
                                rmid = int(p.split(':')[1])
                                from reading.db_schema import get_reading_material
                                rmat = get_reading_material(get_db_path(), rmid)
                                if not rmat:
                                    continue
                                name = rmat['title']
                                type_label = 'Reading'
                                kind = 'custom'
                            except Exception:
                                continue
                        elif isinstance(p, str) and p.startswith('graded:'):
                            # Graded (Sakubo) reading
                            try:
                                import json as _grj
                                _grfp = p[len('graded:'):]
                                with open(_grfp, 'r', encoding='utf-8') as _grf:
                                    _grd = _grj.load(_grf)
                                _grfn = str(_grfp).rsplit('\\', 1)[-1].rsplit('/', 1)[-1]
                                _grpfx = _grfn.split('_')[0]
                                name = f'\U0001F4D6 {_grpfx}  {_grd.get("title_ja", "")}  ({_grd.get("title_en", "")})'
                                type_label = 'Reading'
                                kind = 'spoonfed'
                            except Exception:
                                continue
                        else:
                            # Lesson path
                            kind = 'spoonfed' if 'spoonfed_japanese' in str(p).lower() else ('custom' if 'lessons\\custom' in str(p).lower() or 'lessons/custom' in str(p).lower() else 'other')
                            # Use the cached lesson title if available (better than filename stem)
                            _lcd = _path_lesson_cache.get(str(p), {})
                            name = _lcd.get('title') or Path(p).stem.replace('_', ' ')
                            type_label = 'Lesson'
                        
                        # Filter
                        total_items += 1
                        should_show = active_filter == 'all' or kind == active_filter
                        # Text search filter
                        if should_show and _queue_q:
                            if fts_match_ids is None:
                                # No FTS results available – plain substring fallback
                                if _queue_q not in name.lower():
                                    should_show = False
                            elif isinstance(p, int):
                                # Direct dictionary entry: check FTS hit
                                if p not in fts_match_ids:
                                    should_show = False
                            elif isinstance(p, str) and p.startswith('custom_lesson:'):
                                # Custom lesson: match by name OR any contained entry hits FTS
                                try:
                                    _cid = int(p.split(':')[1])
                                except Exception:
                                    _cid = None
                                _cl_eids = _custom_lesson_entry_ids.get(_cid, []) if _cid else []
                                if (_queue_q not in name.lower() and
                                        not any(eid in fts_match_ids for eid in _cl_eids)):
                                    should_show = False
                            elif isinstance(p, str) and p.startswith('reading:'):
                                # Reading material: match by title only
                                if _queue_q not in name.lower():
                                    should_show = False
                            elif isinstance(p, str) and p.startswith('graded:'):
                                # Graded reading: match by title only
                                if _queue_q not in name.lower():
                                    should_show = False
                            else:
                                # Lesson file path: match by title OR any contained entry hits FTS
                                _lcd = _path_lesson_cache.get(str(p), {})
                                _lp_eids = _lcd.get('entry_ids', [])
                                if (_queue_q not in name.lower() and
                                        not any(eid in fts_match_ids for eid in _lp_eids)):
                                    should_show = False
                        if should_show:
                            count += 1
                            if shown >= limit:
                                continue
                            shown += 1

                            # Build row widget
                            row = BoxLayout(size_hint_y=None, height=dp(56), spacing=dp(8), padding=[dp(8), dp(4)])
                            
                            from kivy.uix.behaviors import ButtonBehavior
                            
                            class LessonButton(ButtonBehavior, BoxLayout):
                                def __init__(self, **kwargs):
                                    super().__init__(**kwargs)
                                    with self.canvas.before:
                                        Color(0.35, 0.35, 0.35, 1)
                                        self.rect = Rectangle(pos=self.pos, size=self.size)
                                    self.bind(pos=self._update_rect, size=self._update_rect)
                                
                                def _update_rect(self, *args):
                                    self.rect.pos = self.pos
                                    self.rect.size = self.size
                            
                            lbl_container = LessonButton(orientation='horizontal', padding=[dp(12), 0])
                            
                            inner = BoxLayout(orientation='horizontal', size_hint_x=1.0)
                            
                            name_label = Label(
                                text=name,
                                halign='left', valign='middle', size_hint_x=1,
                                font_name='fonts/NotoSansJP-Regular.ttf',
                                color=(0.90, 0.88, 0.85, 1),
                                shorten=True,
                                shorten_from='right'
                            )
                            name_label.bind(size=lambda s, w: setattr(s, 'text_size', (w[0], w[1])))
                            inner.add_widget(name_label)
                            
                            type_label_widget = Label(
                                text=type_label,
                                halign='right', valign='middle',
                                size_hint=(None, 1), width=dp(68),
                                font_name='fonts/NotoSansJP-Regular.ttf',
                                color=(0.65, 0.63, 0.60, 1),
                                font_size='11sp'
                            )
                            type_label_widget.bind(size=lambda s, w: setattr(s, 'text_size', (w[0], None)))
                            inner.add_widget(type_label_widget)
                            
                            lbl_container.add_widget(inner)
                            
                            # Click handler for lesson navigation
                            item_data = _override_item_data if _override_item_data else p
                            is_coll = is_collection
                            
                            def make_lesson_click(data, coll):
                                def handler(*args):
                                    if isinstance(data, int):
                                        dict_screen = self.root.ids.get('dict_screen') if getattr(self, 'root', None) else None
                                        if dict_screen and hasattr(dict_screen, 'open_entry'):
                                            dict_screen.open_entry(data)
                                    elif isinstance(data, str) and data.startswith('custom_lesson:'):
                                        lid = int(data.split(':')[1])
                                        if coll:
                                            self._view_collection_detail(lid)
                                        else:
                                            self._view_custom_lesson_detail(lid)
                                    elif isinstance(data, str) and data.startswith('reading:'):
                                        rmid = int(data.split(':')[1])
                                        ls = self.root.ids.get('lessons_screen') if getattr(self, 'root', None) else None
                                        if ls and hasattr(ls, 'open_reading_material'):
                                            sm = self._get_screen_manager()
                                            if sm:
                                                sm.current = 'lessons'
                                            ls.open_reading_material(rmid)
                                    elif isinstance(data, str) and data.startswith('graded:'):
                                        _grfp = data[len('graded:'):]
                                        ls = self.root.ids.get('lessons_screen') if getattr(self, 'root', None) else None
                                        if ls and hasattr(ls, 'open_graded_reading'):
                                            sm = self._get_screen_manager()
                                            if sm:
                                                sm.current = 'lessons'
                                            ls.open_graded_reading(_grfp)
                                    else:
                                        self._show_lesson_page(data)
                                return handler
                            
                            lbl_container.bind(on_release=make_lesson_click(item_data, is_coll))
                            row.add_widget(lbl_container)
                            
                            # Remove button
                            remove_btn = Button(
                                text='',
                                font_name='fonts/MaterialSymbolsOutlined.ttf',
                                size_hint=(None, 1), width=dp(56),
                                font_size='18sp',
                                background_normal='', background_down='',
                                background_color=(0.60, 0.15, 0.20, 1),
                                color=(0.90, 0.88, 0.85, 1)
                            )
                            
                            def make_remove_handler(data, row_widget, grid_widget):
                                def handler(*args):
                                    self.toggle_lesson_queue(data)
                                    try:
                                        grid_widget.remove_widget(row_widget)
                                    except Exception:
                                        pass
                                return handler
                            
                            def make_collection_remove_handler(children_keys, row_widget, grid_widget):
                                def handler(*args):
                                    q = getattr(self, '_lesson_queue', [])
                                    for ck in children_keys:
                                        if ck in q:
                                            q.remove(ck)
                                    self._save_lesson_queue()
                                    try:
                                        grid_widget.remove_widget(row_widget)
                                    except Exception:
                                        pass
                                return handler
                            
                            if _collection_children:
                                remove_btn.bind(on_release=make_collection_remove_handler(_collection_children, row, grid))
                            else:
                                remove_btn.bind(on_release=make_remove_handler(item_data, row, grid))
                            row.add_widget(remove_btn)
                            
                            grid.add_widget(row)

                    if count > limit:
                        remaining = count - limit
                        more_btn = Button(
                            text=f'Show more  ({remaining} remaining)',
                            size_hint_y=None, height=dp(48),
                            background_normal='', background_down='',
                            background_color=(0.22, 0.38, 0.55, 1),
                            color=(0.90, 0.88, 0.85, 1),
                        )
                        try:
                            more_btn.font_name = 'fonts/NotoSansJP-Regular.ttf'
                        except Exception:
                            pass
                        _new_limit = limit + 250
                        _af = active_filter
                        _qq = query
                        more_btn.bind(on_release=lambda *_, nl=_new_limit, af=_af, qq=_qq: self.show_my_queue(af, record_nav=False, limit=nl, query=qq))
                        grid.add_widget(more_btn)

                    if count == 0:
                        # Show empty message if no items - wrap in centered container
                        from kivy.uix.anchorlayout import AnchorLayout
                        empty_container = AnchorLayout(size_hint=(1, 1), anchor_x='center', anchor_y='center')
                        msg = Label(
                            text=("You have no items in your queue. To add items to your queue, "
                                  "press the + icon to add lessons or dictionary entries to your queue."),
                            size_hint=(None, None),
                            size=(Window.width * 0.7, dp(100)),
                            halign='center',
                            valign='middle'
                        )
                        try:
                            msg.font_name = 'fonts/NotoSansJP-Regular.ttf'
                            msg.color = (0.65, 0.65, 0.65, 1)
                        except Exception:
                            pass
                        msg.text_size = msg.size
                        empty_container.add_widget(msg)
                        container.add_widget(empty_container)
                    else:
                        container.add_widget(scroll)

                    # action buttons
                    bottom = BoxLayout(size_hint_y=None, height=dp(48), spacing=8)
                    if active_filter == 'all':
                        clear_text = 'Clear Entire Queue'
                        queue_name = 'your entire queue'
                    elif active_filter == 'spoonfed':
                        clear_text = 'Clear Sakubo Lessons'
                        queue_name = 'Sakubo lessons'
                    else:
                        clear_text = 'Clear Custom Lessons'
                        queue_name = 'Custom lessons'
                    
                    clear = Button(text=clear_text)
                    try:
                        clear.background_normal = ''
                        clear.background_down = ''
                        clear.background_color = (0.85, 0.2, 0.2, 1)
                        clear.color = (1,1,1,1)
                    except Exception:
                        pass
                    clear.bind(on_press=lambda *_: self._press_button(clear))
                    clear.bind(on_release=lambda *_, b=clear, f=active_filter, qn=queue_name: (self._show_clear_queue_confirmation(f, qn), Clock.schedule_once(lambda dt: self._reset_clear_button(b), 0.1)))
                    bottom.add_widget(clear)

                    if count > 1:
                        reorder_btn = Button(
                            text='⇅ Reorder',
                            size_hint_x=None, width=dp(110),
                            background_normal='', background_down='',
                            background_color=(0.22, 0.38, 0.55, 1),
                            color=(0.90, 0.88, 0.85, 1)
                        )
                        try:
                            reorder_btn.font_name = 'fonts/NotoSansJP-Regular.ttf'
                        except Exception:
                            pass
                        reorder_btn.bind(on_release=lambda *_: self.show_my_queue_reorder())
                        bottom.add_widget(reorder_btn)

                    container.add_widget(bottom)

                    qa.add_widget(container)
                    Logger.info('MyQueue: UI built successfully with %d items', count)
                except Exception as e:
                    Logger.error('MyQueue: Exception building UI: %s', e)
                    import traceback
                    Logger.error('MyQueue: Traceback: %s', traceback.format_exc())
            
            def on_data_loaded(dt):
                """Callback when background data fetch completes."""
                (entries_map, custom_lessons_map, all_custom_lessons,
                 children_by_parent, fts_match_ids,
                 path_lesson_cache, custom_lesson_entry_ids) = self._queue_data_result
                build_ui(entries_map, custom_lessons_map, all_custom_lessons, children_by_parent,
                         fts_match_ids, path_lesson_cache, custom_lesson_entry_ids)
            
            def background_fetch():
                """Run in background thread."""
                self._queue_data_result = fetch_queue_data()
                Clock.schedule_once(on_data_loaded, 0)
            
            thread = threading.Thread(target=background_fetch, daemon=True)
            thread.start()
            
        except Exception as e:
            Logger.error('MyQueue: Exception: %s', e)
            import traceback
            Logger.error('MyQueue: Traceback: %s', traceback.format_exc())

    def _filter_queue_display(self, filter_type: str):
        """Update queue display with new filter."""
        q = self._get_lessons_search_query()
        self.show_my_queue(filter_type, record_nav=False, query=q)

    def _refresh_queue_after_remove(self):
        """Refresh queue display after removing an item without full rebuild."""
        try:
            filter_type = getattr(self, '_queue_active_filter', 'all')
            q = self._get_lessons_search_query()
            # Just rebuild for now - could be optimized further to just remove the item
            self.show_my_queue(filter_type, record_nav=False, query=q)
        except Exception as e:
            Logger.error(f'MyQueue: Error refreshing after remove: {e}')

    def _move_queue_item(self, index: int, direction: int):
        """Move item at *index* up (-1) or down (+1) in _lesson_queue, then save."""
        try:
            q = getattr(self, '_lesson_queue', [])
            new_index = index + direction
            if new_index < 0 or new_index >= len(q):
                return
            q[index], q[new_index] = q[new_index], q[index]
            self._save_lesson_queue()
        except Exception as e:
            Logger.error(f'MyQueue: _move_queue_item error: {e}')

    def show_my_queue_reorder(self):
        """Show My Queue in reorder mode: all items listed with ↑ / ↓ buttons."""
        try:
            # Navigate to lessons screen
            try:
                sm = self._get_screen_manager()
                if sm is not None:
                    sm.current = 'lessons'
            except Exception:
                pass

            qa = None
            try:
                if getattr(self, 'root', None):
                    ls = self.root.ids.get('lessons_screen')
                    if ls and hasattr(ls, '_get_quick_area'):
                        qa = ls._get_quick_area()
            except Exception:
                pass
            if qa is None:
                qa = getattr(self, '_quick_area', None) or (self.root.ids.get('lessons_quick') if getattr(self, 'root', None) else None)
            if qa is None:
                return

            qlist = list(getattr(self, '_lesson_queue', []))

            # Show loading popup immediately — overlays existing content so no blank screen
            ls_screen = None
            try:
                if getattr(self, 'root', None):
                    ls_screen = self.root.ids.get('lessons_screen')
            except Exception:
                pass
            loading = ls_screen._show_loading_popup('Loading reorder list...') if ls_screen and hasattr(ls_screen, '_show_loading_popup') else None

            def fetch_reorder_data():
                try:
                    conn = dict_db.init_db(get_db_path())
                    entry_ids = [p for p in qlist if isinstance(p, int)]
                    entries_map = dict_db.get_entries_by_ids(conn, entry_ids) if entry_ids else {}
                    all_custom = dict_db.get_all_custom_lessons(conn)
                    custom_map = {l['id']: l for l in all_custom}
                    conn.close()
                    return entries_map, custom_map
                except Exception as e:
                    Logger.error(f'MyQueue reorder fetch error: {e}')
                    return {}, {}

            def build_reorder_ui(entries_map, custom_map):
                try:
                    qa.clear_widgets()
                    qa.padding = [0, 0, 0, 0]
                    qa.spacing = 0
                    qa.clear_widgets()
                    container = BoxLayout(orientation='vertical', spacing=0, padding=0, size_hint=(1, 1))

                    # Header bar
                    header = BoxLayout(size_hint_y=None, height=dp(40), spacing=dp(8),
                                       padding=[dp(8), dp(4), dp(8), dp(4)])
                    with header.canvas.before:
                        from kivy.graphics import Color, Rectangle
                        Color(0.18, 0.18, 0.20, 1)
                        header._bg = Rectangle(pos=header.pos, size=header.size)
                    header.bind(pos=lambda w, v: setattr(w._bg, 'pos', v),
                                size=lambda w, v: setattr(w._bg, 'size', v))
                    title_lbl = Label(
                        text='Reorder Queue',
                        halign='left', valign='middle',
                        color=(0.90, 0.88, 0.85, 1),
                        size_hint_x=1,
                    )
                    try:
                        title_lbl.font_name = 'fonts/NotoSansJP-Regular.ttf'
                    except Exception:
                        pass
                    title_lbl.bind(size=lambda s, v: setattr(s, 'text_size', (v[0], v[1])))
                    header.add_widget(title_lbl)
                    container.add_widget(header)

                    # Scrollable list with ↑/↓ rows
                    scroll = ScrollView(size_hint=(1, 1))
                    grid = GridLayout(cols=1, size_hint_y=None, spacing=dp(4),
                                      padding=[dp(6), dp(6), dp(6), dp(6)])
                    grid.bind(minimum_height=grid.setter('height'))
                    scroll.add_widget(grid)

                    from kivy.graphics import Color, Rectangle

                    def _item_display_name(p):
                        if isinstance(p, int):
                            entry = entries_map.get(p)
                            if not entry:
                                return ('?', 'Entry')
                            kanji = entry.get('kanji') or ''
                            kana = entry.get('kana') or ''
                            gloss = entry.get('gloss') or ''
                            kind_map = {'vocab': 'Word', 'kanji': 'Kanji', 'kana': 'Kana', 'grammar': 'Grammar'}
                            t = kind_map.get(entry.get('kind') or '', 'Entry')
                            return (f"{kanji or kana} – {gloss.split(';')[0][:35]}", t)
                        elif isinstance(p, str) and p.startswith('custom_lesson:'):
                            try:
                                lid = int(p.split(':')[1])
                                lesson = custom_map.get(lid)
                                if lesson:
                                    return (lesson['name'], 'Custom')
                            except Exception:
                                pass
                            return (p, 'Custom')
                        else:
                            return (Path(p).stem.replace('_', ' '), 'Lesson')

                    n = len(qlist)
                    # label_pairs[i] = (name_lbl, type_lbl) at physical row i.
                    # Physical row i always = queue index i; we keep them in sync by
                    # swapping label texts on move rather than moving widgets.
                    label_pairs = []
                    self._reorder_label_pairs = label_pairs

                    for idx in range(n):
                        p = qlist[idx]
                        disp_name, type_lbl_text = _item_display_name(p)

                        row = BoxLayout(size_hint_y=None, height=dp(54), spacing=dp(4),
                                        padding=[dp(4), dp(2), dp(4), dp(2)])
                        with row.canvas.before:
                            Color(0.28, 0.28, 0.30, 1)
                            row._bg = Rectangle(pos=row.pos, size=row.size)
                        row.bind(pos=lambda w, v: setattr(w._bg, 'pos', v),
                                 size=lambda w, v: setattr(w._bg, 'size', v))

                        # ↑ button
                        up_btn = Button(
                            text='↑',
                            size_hint=(None, 1), width=dp(46),
                            background_normal='', background_down='',
                            background_color=(0.22, 0.22, 0.24, 1) if idx == 0 else (0.30, 0.45, 0.62, 1),
                            color=(0.50, 0.50, 0.52, 1) if idx == 0 else (0.90, 0.88, 0.85, 1),
                            disabled=(idx == 0),
                            font_size='18sp',
                        )
                        try:
                            up_btn.font_name = 'fonts/NotoSansJP-Regular.ttf'
                        except Exception:
                            pass

                        # ↓ button
                        down_btn = Button(
                            text='↓',
                            size_hint=(None, 1), width=dp(46),
                            background_normal='', background_down='',
                            background_color=(0.22, 0.22, 0.24, 1) if idx == n - 1 else (0.30, 0.45, 0.62, 1),
                            color=(0.50, 0.50, 0.52, 1) if idx == n - 1 else (0.90, 0.88, 0.85, 1),
                            disabled=(idx == n - 1),
                            font_size='18sp',
                        )
                        try:
                            down_btn.font_name = 'fonts/NotoSansJP-Regular.ttf'
                        except Exception:
                            pass

                        # Handlers: swap label texts only — no rebuild, no scroll reset
                        def make_move(i, d):
                            def handler(*args):
                                self._reorder_swap_inplace(i, d)
                            return handler

                        up_btn.bind(on_release=make_move(idx, -1))
                        down_btn.bind(on_release=make_move(idx, 1))

                        # Name + type label
                        name_box = BoxLayout(orientation='vertical', size_hint_x=1,
                                             padding=[dp(6), 0, dp(4), 0])
                        name_lbl = Label(
                            text=disp_name,
                            halign='left', valign='middle',
                            color=(0.90, 0.88, 0.85, 1),
                            shorten=True, shorten_from='right',
                            size_hint_y=1,
                        )
                        try:
                            name_lbl.font_name = 'fonts/NotoSansJP-Regular.ttf'
                        except Exception:
                            pass
                        name_lbl.bind(size=lambda s, v: setattr(s, 'text_size', (v[0], v[1])))

                        type_lbl = Label(
                            text=type_lbl_text,
                            halign='right', valign='middle',
                            color=(0.55, 0.53, 0.50, 1),
                            font_size='10sp',
                            size_hint=(None, 1), width=dp(58),
                        )
                        try:
                            type_lbl.font_name = 'fonts/NotoSansJP-Regular.ttf'
                        except Exception:
                            pass
                        type_lbl.bind(size=lambda s, v: setattr(s, 'text_size', (v[0], v[1])))

                        label_pairs.append((name_lbl, type_lbl))

                        row.add_widget(up_btn)
                        row.add_widget(down_btn)
                        name_box.add_widget(name_lbl)
                        row.add_widget(name_box)
                        row.add_widget(type_lbl)
                        grid.add_widget(row)

                    container.add_widget(scroll)

                    # Done button
                    bottom = BoxLayout(size_hint_y=None, height=dp(48), spacing=dp(8))
                    done_btn = Button(
                        text='Done',
                        background_normal='', background_down='',
                        background_color=(0.20, 0.45, 0.25, 1),
                        color=(0.90, 0.88, 0.85, 1),
                    )
                    try:
                        done_btn.font_name = 'fonts/NotoSansJP-Regular.ttf'
                    except Exception:
                        pass
                    done_btn.bind(on_release=lambda *_: self.show_my_queue(
                        getattr(self, '_queue_active_filter', 'all'), record_nav=False))
                    bottom.add_widget(done_btn)
                    container.add_widget(bottom)

                    qa.add_widget(container)
                except Exception as e:
                    Logger.error(f'MyQueue reorder build_ui error: {e}')
                    import traceback
                    Logger.error(traceback.format_exc())

            def on_loaded(dt):
                if loading is not None:
                    loading.dismiss()
                entries_map, custom_map = self._queue_reorder_data
                build_reorder_ui(entries_map, custom_map)

            def bg_fetch():
                self._queue_reorder_data = fetch_reorder_data()
                Clock.schedule_once(on_loaded, 0)

            threading.Thread(target=bg_fetch, daemon=True).start()

        except Exception as e:
            Logger.error(f'MyQueue show_my_queue_reorder error: {e}')

    def _reorder_swap_inplace(self, i: int, d: int):
        """Swap queue items i and i+d by updating only the two label texts.
        No widget rebuild, no scroll position change.
        """
        try:
            label_pairs = getattr(self, '_reorder_label_pairs', None)
            if not label_pairs:
                return
            j = i + d
            if j < 0 or j >= len(label_pairs):
                return
            # Update underlying queue data
            self._move_queue_item(i, d)
            # Swap only the text of the two physical rows — everything else untouched
            name_i, type_i = label_pairs[i]
            name_j, type_j = label_pairs[j]
            name_i.text, name_j.text = name_j.text, name_i.text
            type_i.text, type_j.text = type_j.text, type_i.text
        except Exception as e:
            Logger.error(f'MyQueue _reorder_swap_inplace error: {e}')

