    def _collection_reorder_swap_inplace(self, i: int, d: int):
        """Swap two collection lessons by updating label texts and display_order in DB."""
        try:
            label_pairs = getattr(self, '_collection_reorder_label_pairs', None)
            lessons = getattr(self, '_collection_reorder_lessons', None)
            if not label_pairs or not lessons:
                return
            j = i + d
            if j < 0 or j >= len(label_pairs):
                return
            # Swap in the local list
            lessons[i], lessons[j] = lessons[j], lessons[i]
            # Update display_order in DB
            self._swap_collection_lesson_order(lessons[i]['id'], lessons[j]['id'],
                                                lessons[i]['display_order'], lessons[j]['display_order'])
            # Also swap display_order values in local dicts so further swaps stay correct
            lessons[i]['display_order'], lessons[j]['display_order'] = lessons[j]['display_order'], lessons[i]['display_order']
            # Swap label texts
            name_i, type_i = label_pairs[i]
            name_j, type_j = label_pairs[j]
            name_i.text, name_j.text = name_j.text, name_i.text
            type_i.text, type_j.text = type_j.text, type_i.text
            self._custom_lessons_needs_reload = True
        except Exception as e:
            Logger.error(f'Collection _collection_reorder_swap_inplace error: {e}')

    def _swap_collection_lesson_order(self, id_a: int, id_b: int, order_a: int, order_b: int):
        """Swap display_order of two lessons in the database."""
        try:
            conn = dict_db.init_db(get_db_path())
            cur = conn.cursor()
            cur.execute('UPDATE custom_lessons SET display_order = ? WHERE id = ?', (order_b, id_a))
            cur.execute('UPDATE custom_lessons SET display_order = ? WHERE id = ?', (order_a, id_b))
            conn.commit()
            conn.close()
        except Exception as e:
            Logger.error(f'Collection _swap_collection_lesson_order error: {e}')

    def _show_clear_queue_confirmation(self, filter_type, queue_name):
        """Show confirmation popup before clearing queue."""
        layout = BoxLayout(orientation='vertical', spacing=dp(12), padding=dp(16))
        
        # Warning message
        msg = Label(
            text="Clear Entire Queue?",
            size_hint_y=None,
            height=dp(80),
            halign='center',
            valign='middle'
        )
        try:
            msg.font_name = 'fonts/NotoSansJP-Regular.ttf'
            msg.color = (0.9, 0.9, 0.9, 1)
        except Exception:
            pass
        msg.text_size = (dp(300), None)
        layout.add_widget(msg)
        
        # Buttons
        btn_box = BoxLayout(size_hint_y=None, height=dp(44), spacing=dp(8))
        
        # Cancel button
        cancel_btn = Button(text='Cancel')
        try:
            cancel_btn.background_normal = ''
            cancel_btn.background_down = ''
            cancel_btn.background_color = (0.25, 0.25, 0.25, 1)
            cancel_btn.color = (1, 1, 1, 1)
        except Exception:
            pass
        
        # Confirm button
        confirm_btn = Button(text='Confirm')
        try:
            confirm_btn.background_normal = ''
            confirm_btn.background_down = ''
            confirm_btn.background_color = (0.07, 0.6, 0.2, 1)
            confirm_btn.color = (1, 1, 1, 1)
        except Exception:
            pass
        
        popup = Popup(
            title='Clear Queue?',
            content=layout,
            size_hint=(None, None),
            size=(min(dp(400), Window.width*0.8), min(dp(220), Window.height*0.4)),
            auto_dismiss=False
        )
        
        cancel_btn.bind(on_press=lambda *_: self._press_button(cancel_btn))
        cancel_btn.bind(on_release=lambda *_: popup.dismiss())
        confirm_btn.bind(on_press=lambda *_: self._press_button(confirm_btn))
        confirm_btn.bind(on_release=lambda *_, f=filter_type, p=popup: (popup.dismiss(), self._show_second_clear_queue_confirmation(f, queue_name)))
        
        btn_box.add_widget(cancel_btn)
        btn_box.add_widget(confirm_btn)
        layout.add_widget(btn_box)
        
        popup.open()

