    def _start_tools_weak_drill(self, count: int):
        """Start Tools Drill Mode with weak words."""
        conn = None
        try:
            Logger.info(f'ToolsDrill: Starting with {count} weak words')
            
            conn = dict_db.init_db(get_db_path())
            
            # Get random weak vectors
            weak_vectors = dict_db.get_tools_drill_weak_vectors(conn, limit=count)
            
            if not weak_vectors:
                Logger.info('ToolsDrill: No weak vectors available')
                return
            
            Logger.info(f'ToolsDrill: Got {len(weak_vectors)} vectors')
            
            # Filter for handwriting-only mode if enabled
            if self.handwriting_only_mode:
                weak_vectors = [v for v in weak_vectors if v.get('vector_type') == 'handwriting']
                Logger.info(f'ToolsDrill: Filtered to {len(weak_vectors)} handwriting vectors')
                if not weak_vectors:
                    Logger.info('ToolsDrill: No handwriting vectors available')
                    return
            
            # Create a learning session using the weak vectors
            import dictionary.learning as learning
            dict_db.ensure_learning_table(conn)
            
            # Build the session manually since we already have the vectors
            import json
            import random
            from datetime import datetime
            
            DEFAULT_SLOTS = 7
            in_progress = weak_vectors[:DEFAULT_SLOTS]
            pending = weak_vectors[DEFAULT_SLOTS:]
            
            # Add fillers if needed
            if len(in_progress) < DEFAULT_SLOTS and in_progress:
                first_kind = in_progress[0].get('kind', 'vocab')
                exclude = {v['id'] for v in in_progress}
                # Apply handwriting filter if enabled
                filter_type = 'handwriting' if self.handwriting_only_mode else None
                fillers = learning._select_fillers(conn, first_kind, DEFAULT_SLOTS - len(in_progress), 
                                                  exclude_ids=exclude, filter_vector_type=filter_type)
                in_progress.extend(fillers)
            
            # Shuffle in_progress to randomize initial order
            random.shuffle(in_progress)
            
            data = {
                'info': [],
                'info_index': 0,
                'phase': 'drill',
                'pending': pending,
                'in_progress': in_progress,
                'meta': {
                    'created_by': 'tools_drill',
                    'num_slots': DEFAULT_SLOTS,
                    'created_at': datetime.utcnow().isoformat(),
                    'drill_type': 'tools_weak',
                    'total_vectors': len([v for v in weak_vectors if not v.get('is_filler', False)]),
                    'filter_vector_type': 'handwriting' if self.handwriting_only_mode else None,
                    'exclude_vector_type': None  # Don't exclude handwriting in weak words mode
                },
                'history': []
            }
            
            kind = weak_vectors[0].get('kind', 'vocab') if weak_vectors else 'vocab'
            session_id = dict_db.create_learning_session(conn, kind, data)
            dict_db.update_learning_session(conn, session_id, data)
            
            # Store session info
            self._current_drill_session_id = session_id
            self._drill_mode = 'tools_drill'
            self._drill_completed_count = 0
            self._drill_start_time = __import__('time').time()
            
            # Clean up any time attack state
            self._cleanup_time_attack_state()
            
            # Navigate to drill screen
            sm = self._get_screen_manager()
            if sm:
                sm.current = 'drill'
                self._load_current_drill()
        
        except Exception as e:
            Logger.error(f'ToolsDrill: Error starting: {e}')
            import traceback
            traceback.print_exc()
        finally:
            if conn:
                try:
                    conn.close()
                except Exception as e:
                    Logger.warning(f'ToolsDrill: Error closing connection: {e}')

    def _start_tools_mywords_drill(self, count: int):
        """Start Tools Drill Mode with all words from the user's SRS (any stability)."""
        conn = None
        try:
            Logger.info(f'ToolsDrill: Starting My Words drill')
            import dictionary.db as dict_db
            import dictionary.learning as learning
            import json, random
            from datetime import datetime

            conn = dict_db.init_db(get_db_path())
            dict_db.ensure_learning_table(conn)

            # Build vectors from ALL SRS entries (same logic as weak, but no stability ceiling)
            cursor = conn.cursor()
            cursor.execute('''
                SELECT s.entry_id, s.data, e.kind, e.kanji, e.kana, e.gloss, e.study_vectors
                FROM srs s JOIN entries e ON e.id = s.entry_id
                GROUP BY s.entry_id
            ''')
            srs_rows = cursor.fetchall()

            import dictionary.learning as _learning
            all_vectors = []
            for entry_id, data_str, entry_kind, kanji, kana, gloss, study_vectors_str in srs_rows:
                try:
                    srs_data = json.loads(data_str or '{}')
                except Exception:
                    srs_data = {}
                per_kind = srs_data.get('per_kind', {})
                per_vector = srs_data.get('per_vector', {})
                # Entry is in SRS — include it even if no reviews yet
                vectors = _learning.make_vectors_from_row(
                    entry_id, entry_kind, kanji, kana, gloss, study_vectors_str
                )
                for vec in vectors:
                    vector_type = vec.get('vector_type')
                    # Look up stability from both storage paths
                    stability = 0
                    # New per_vector storage (data.per_vector.{type})
                    if per_vector:
                        pv = per_vector.get(vector_type, {})
                        stability = max(stability, pv.get('stability', 0))
                    # Legacy per_kind storage (data.per_kind.{kind}.per_vector.{type})
                    for kind_data in per_kind.values():
                        pv = kind_data.get('per_vector', {}).get(vector_type, {})
                        stability = max(stability, pv.get('stability', 0))
                    v = vec.copy()
                    v['stability'] = max(stability, 0.1)
                    v['streak'] = 0
                    all_vectors.append(v)

            if not all_vectors:
                Logger.info('ToolsDrill: No My Words vectors available')
                return

            # Apply mode filters
            if self.handwriting_only_mode:
                all_vectors = [v for v in all_vectors if v.get('vector_type') == 'handwriting']
            elif self._drill_grammar_only_mode:
                all_vectors = [v for v in all_vectors if v.get('kind') == 'grammar']
            elif not self._drill_grammar_mode:
                all_vectors = [v for v in all_vectors if v.get('kind') != 'grammar']
            if not self.handwriting_mode and not self.handwriting_only_mode:
                all_vectors = [v for v in all_vectors if v.get('vector_type') != 'handwriting']

            if not all_vectors:
                Logger.info('ToolsDrill: No My Words vectors after filtering')
                return

            random.shuffle(all_vectors)

            DEFAULT_SLOTS = 7
            in_progress = all_vectors[:DEFAULT_SLOTS]
            pending = all_vectors[DEFAULT_SLOTS:]

            if len(in_progress) < DEFAULT_SLOTS and in_progress:
                first_kind = in_progress[0].get('kind', 'vocab')
                exclude = {v['id'] for v in in_progress}
                filter_type = 'handwriting' if self.handwriting_only_mode else None
                fillers = _learning._select_fillers(
                    conn, first_kind, DEFAULT_SLOTS - len(in_progress),
                    exclude_ids=exclude, filter_vector_type=filter_type
                )
                in_progress.extend(fillers)

            random.shuffle(in_progress)

            data = {
                'info': [], 'info_index': 0, 'phase': 'drill',
                'pending': pending, 'in_progress': in_progress,
                'meta': {
                    'created_by': 'tools_drill',
                    'num_slots': DEFAULT_SLOTS,
                    'created_at': datetime.utcnow().isoformat(),
                    'drill_type': 'tools_mywords',
                    'total_vectors': len(all_vectors),
                    'filter_vector_type': 'handwriting' if self.handwriting_only_mode else None,
                    'exclude_vector_type': None,
                },
                'history': []
            }

            kind = all_vectors[0].get('kind', 'vocab')
            session_id = dict_db.create_learning_session(conn, kind, data)
            dict_db.update_learning_session(conn, session_id, data)

            self._current_drill_session_id = session_id
            self._drill_mode = 'tools_drill'
            self._drill_completed_count = 0
            self._drill_start_time = __import__('time').time()
            self._cleanup_time_attack_state()

            sm = self._get_screen_manager()
            if sm:
                sm.current = 'drill'
                self._load_current_drill()

        except Exception as e:
            Logger.error(f'ToolsDrill: MyWords error: {e}')
            import traceback
            traceback.print_exc()
        finally:
            if conn:
                try:
                    conn.close()
                except Exception:
                    pass

